window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["zh-Hant"]={"ICON-0001":{"nm":"腳印","de":"地板上留下的一抹土色印記。徘徊了許久，終究還是有人多邁出了一步啊。腳印刻下的不是停留的時間，而是下定決心要離開的那一瞬間。"},"ICON-0002":{"nm":"燈火","de":"火苗一觸到燈芯，黑暗便一寸寸悄然退去。借著暖手的微小溫度，從前的人們會寫下心願讓它飄向遠方。燈火點亮，不為照明，只為陪伴在側。"},"ICON-0003":{"nm":"緞帶","de":"一個結，便將心意包裝得漂漂亮亮。送出的手讓它易於解開，收下的手卻想慢慢解開。緞帶繫住的不是盒子，而是遞出前那份怦然心動。"},"ICON-0004":{"nm":"信箱","de":"張著紅色的口，佇立在巷口。即便手寫信變得稀罕的年代，這小小的箱子仍始終等待著某人的問候。在空無一物的那一刻最是明亮，是溫柔的容器。"},"ICON-0005":{"nm":"個人島嶼迷你地圖","de":"折起來放進口袋，攤開來便是大海與山脊並肩躺臥的一張紙。對初次抵達的人來說，每一處轉角都還是尚未揭開的約定。攤開的那一刻，小島也成了遼闊的世界。"},"ICON-0006":{"nm":"麥克風","de":"唱出第一個音之前，調勻呼吸的半拍。一旦察覺台下的目光在等著我的一句話，指尖便顫抖起來。麥克風不是放大聲音，而是將那份顫抖一路送達終點。"},"ICON-0007":{"nm":"時鐘","de":"秒針從不停歇，卻沒有人在催促你。到出道還有幾夜，到登台還有幾分——在錶盤上，等待與心動以相同的速度轉動。看時間這件事，是安撫內心的事。"},"ICON-0008":{"nm":"筆記本","de":"擁有最多空白的物件。舞蹈走位、清晨的決心、終究沒能寄出的話語，都堆積在這裡。攤開的那一刻，昨日的我靜靜向今日的我搭話。"},"ICON-0009":{"nm":"印章","de":"蘸飽紅色印泥，用力一按，約定便清晰地烙印下來。比文字更沉重，比話語更分明的痕跡。在文件的末尾，人們不留姓名，而是將心意託付給這小小的印章。"},"ICON-0010":{"nm":"底座","de":"盡量壓低自己的身軀，去托起其他事物。為了讓上面擺放的東西不晃動，在最底下默默撐著的位置。即使不耀眼，這裡也藏著讓人不致崩塌的溫柔。"},"ICON-0011":{"nm":"郵票","de":"在一個角落抹上口水用力貼上的小圖案。是為了寄往遠方的心意所標的、最誠實的價格。一張方形的風景，牽著信件的手越過大海。"},"ICON-0012":{"nm":"旗幟釘","de":"往地圖上一插，便成了「我已經走到這裡了」。不是征服而是記錄，是給下一個前來之人的加油。看到這面旗就再多走一步吧，無聲推著背的標記。"},"ICON-0013":{"nm":"樹枝","de":"彎曲過一次的枝椏，便忘了折斷這回事。每一處迎風彎過的地方，都牢牢嵌進了結瘤，真正的堅韌來自承受過的痕跡——古老的森林隨風如此叮囑。"},"ICON-0014":{"nm":"鈕扣","de":"反覆地解開又扣上，整理著衣領。一個小小的圓，靜靜擋下清晨的寒意，也擋下突如其來的羞赧。直到啵地掉落，才驚覺那位置原來這麼重要。"},"ICON-0015":{"nm":"信封","de":"封口的那一刻，才終於成了秘密。裡頭裝著什麼，唯有收信的人才知道。一層薄紙置於心與世界之間，是最薄也最溫柔的一扇門。"},"ICON-0016":{"nm":"箱子","de":"四角端正，所以能寬容地容納萬物。搬家時裝回憶，逢年過節裝禮物，平日裡裝雜物。緊閉的蓋子內側，總是塞滿了某人的「以後再說」。"},"ICON-0017":{"nm":"門把","de":"在門與人之間，最先伸出手的物件。要拉動一次，內外才終於相連。一切進出的決心，都會握過這冰冷的手一回才走。"},"ICON-0018":{"nm":"湯匙","de":"用凹陷的口，靜靜舀起溫熱的湯。是記得母親呼呼吹涼後先遞來的那一匙溫度的工具。在飯桌上最常觸到嘴邊的，是最溫柔的手。"},"ICON-0019":{"nm":"拖鞋","de":"踏過門檻的那一刻，腳先鬆了口氣。卸下了喀噠喀噠的一天，換上踢躂踢躂走著的傍晚之聲。整齊擺在玄關的一雙，對你說「現在到家了」。"},"ICON-0020":{"nm":"鑰匙","de":"比起鎖上，先學會了打開。在掌心被焐熱，某天又靜靜停在陌生的新門前的小鐵器。是最長久保存著離去之人溫度的物件。"},"ICON-0021":{"nm":"杯子","de":"空著時端莊，盛滿時無比溫暖。相對舉起的兩只叮地一碰的清脆聲響，盛著無言的約定。是為了兩人在一起時比獨自一人更耀眼而生的器皿。"},"ICON-0022":{"nm":"盤子","de":"圓圓的邊框裡，盛滿了一天份的心意。倒空、擦淨、再盛滿，反覆一生——最常閃耀，也最常被遺忘的家什。餐桌的舞台，總是擺設在這之上。"},"ICON-0023":{"nm":"燈光","de":"一個開關，便改變房間的表情。明亮便是日常，柔和便是慰藉。為晚歸的某人留到最後的一點光，成了世上最溫暖的迎接。"},"ICON-0024":{"nm":"茶匙","de":"在茶水上慢慢繞一圈，茶葉與水便彼此滲透。不必著急的手部動作，等候香氣瀰漫的小小等待。一只銀色的手，溫柔地放慢了午後的速度。"},"ICON-0025":{"nm":"書籤","de":"靜靜夾在讀到一半之處的約定。「在這裡停下了，所以一定會回來」這份決心，在書頁間沉睡。故事即使闔上，心意仍清晰地標記在那一行上。"},"ICON-0026":{"nm":"靠枕","de":"需要倚靠的背與膝，它無言地承接住。深深陷下又慢慢膨起，吸走今天一整天的疲憊。是最寬容地允許你擺出最慵懶姿勢的物件。"},"ICON-0027":{"nm":"相框","de":"方形的邊框，將一幅風景綁定為永恆。至少進入其中的那一瞬間，即使時光流逝也不會褪色。比起裝下什麼，更是決定要留下什麼的溫柔抉擇。"},"ICON-0028":{"nm":"地圖","de":"每一道折痕裡，都浸染著迷路後又重新找回的痕跡。攤開來，未曾去過的地方也能用指尖先行走過。一切冒險，都從攤開這一張紙的小小勇氣開始。"},"ICON-0029":{"nm":"明信片","de":"背面一半是照片，一半是空白。遠行的人在「我很好」短短幾字旁，附上那地方的風景寄來。沒有信封也不必為問候害羞，是最坦率的一張紙。"},"ICON-0030":{"nm":"出入證","de":"掛上脖子的那一刻，才終於踏入內側的世界。小小卡片上寫著我的名字，靜靜許可道「這裡，是你的位置」。不是通過的資格，而是歸屬於某處的證明。"},"ICON-0031":{"nm":"字母B","de":"在單字正中央最常被叫出來的字母。要把嘴唇先閉攏一下再啵地彈開，才終於發出聲音。既非開頭也非結尾，卻是穩穩抓住節拍的可靠第二位。"},"ICON-0032":{"nm":"名片","de":"遞出時用雙手，收下時對上眼。一張紙，靜靜壓縮了一個人的一天與自尊。在姓名與職稱之間狹窄的留白處，悄悄寄寓著那天的第一印象。"},"ICON-0033":{"nm":"封面","de":"在故事的最外層，率先承受風雨。為了守護裡頭的文字，從自己的邊角開始磨損。翻開前那短暫的悸動，總是從這一張先開始。"},"ICON-0034":{"nm":"教材","de":"用底線與螢光筆，密密麻麻記下一個人的奮鬥。新書時令人茫然，讀完後卻成了最可靠的朋友。從不懂到懂的痕跡，在每一頁裡漂亮地折疊著。"},"ICON-0035":{"nm":"舞蹈通行證","de":"這一張，便將練習室的門大大敞開。滿是鏡子的房間、踏腳的聲響、初次學習的八拍。即使舞還生疏也沒關係，一張小紙片靜靜推著那顫抖的背。"},"ICON-0036":{"nm":"文件夾","de":"曾散落漂泊的單張紙，整齊地串在同一根脊骨上，才終於得到了順序。有了順序便成了故事，越是變厚，便越是某人如此一頁頁認真活過的溫柔證據。"},"ICON-0037":{"nm":"試卷","de":"在空白的格線上短暫顫抖的指尖。比正確答案更可怕的，是與不懂之事正面相對。批改結束後，每一處答錯的地方，都靜靜留下了下次能成長的空白。"},"ICON-0038":{"nm":"字母A","de":"要把嘴張大才終於發得出來的第一個音。常站在隊伍的最前、名字的最初。無論做什麼開始時都從這個字母起頭——所以它總是稍微更勇敢一些。"},"ICON-0039":{"nm":"字母D","de":"以柔和彎曲的背，輕輕托住單字。圓圓的一側端正地掛在某人名字的尾端。雖不華麗，少了它卻會空落落的，是字母中安靜的一份陪伴。"},"ICON-0040":{"nm":"練習紙","de":"寫錯也沒關係的、世上獨一無二的紙。讓人把同樣的動作、同樣的句子重寫數十遍。被揉皺丟棄的張數有多少，某人就確實地進步了多少。"},"ICON-0041":{"nm":"作曲紙","de":"凌晨兩點，一段哼唱喚醒了睡眠。鉛筆在五線譜上猶豫，是因為旋律比手更快。每一處擦去又寫上的痕跡裡，還沒有名字的歌正一點點成長。"},"ICON-0042":{"nm":"通行證","de":"掛上脖子的那一刻，平凡的走廊便變成了另一個世界。電纜如蛇般橫穿黑暗，舞台另一頭聽不見的倒數開始了。踏入這裡的資格，由這一張代為訴說。"},"ICON-0043":{"nm":"印樣表","de":"每一格小小方框裡，都停著不同的表情。笑著、回頭、閉上眼。一格一格指過去，按下快門那天的悸動便回到指尖。連挑選一張，都已經是記錄。"},"ICON-0044":{"nm":"通告單","de":"明天幾點、在哪裡、做什麼。一張紙，預先描繪好一天份的行程。在以分計算密密麻麻的格子間，某人依著這裡寫下的順序，一步步走向夢想。"},"ICON-0045":{"nm":"吊牌","de":"價格標籤的背面，靜靜掛著製作者的時光。啵地撕下那短短一個動作，才終於成了我的東西的小紙片。被剪下的地方留下的，是新品的氣味與一把心動。"},"ICON-0046":{"nm":"作品集","de":"翻開封面，走過的路便一齊攤開。在自信的一頁旁，生澀的第一次挑戰羞赧地並排著。初次向某人遞出自己時，沒有比這更坦率的自我介紹。"},"ICON-0047":{"nm":"行事曆","de":"寫下今天、描繪下週，偶爾把一格塗得漆黑。即使從沒按計劃進行過，填格子的手也不停下。是預先把未來活過一遍的、宛如小小儀式般的東西。"},"ICON-0048":{"nm":"播放清單","de":"在慢歌與快節奏之間，配合那天心情的天氣，把歌曲排成一列。一想到某人的一天恰好依著這順序流過，連歌曲之間的靜默也變得溫柔。"},"ICON-0049":{"nm":"學生證","de":"姓名與照片，還有幾個數字。是證明在教室與練習室間來回的那段歲月的一張卡。在磨到邊角的卡片裡，烙印著再也回不去的青澀每一天。"},"ICON-0050":{"nm":"手環","de":"還記得把那天的顏色繫在手腕上的那一刻嗎？一起喊過的口號、一同被淋濕的演唱會之夜。即使繩子磨損、顏色褪去也不解開，是想讓那個夏天繼續活在手腕上。"},"ICON-0051":{"nm":"臂章","de":"圈在手臂上的那一刻，責任這份重量便悄悄加了上來。站在隊伍最前、最晚離開位置的人的標記。一塊布，讓某人多長大了一寸。"},"ICON-0052":{"nm":"環","de":"沒有斷處、圓圓相連的一條線。起點與終點相觸，所以人們在這裡看見了永恆的形狀。靜靜把兩隻手相連，比話語更早，約定便化為形狀留了下來。"},"ICON-0053":{"nm":"勳章","de":"別在胸前的小鐵片裡，刻著熬過的日子。閃耀的不是金屬，而是其後隱藏的無數練習之夜。比起驕傲更先湧上的，不知為何是感激的心情。"},"ICON-0054":{"nm":"圍裙","de":"在脖子後繫上帶子，雙手便自由了。是無論麵粉還是顏料，都做好了一頭栽進去準備的信號。污漬一點點增加，那天傾注的心意也一同變得濃烈。"},"ICON-0055":{"nm":"護耳帽","de":"把耳朵整個包住，外面的聲音便退遠一步。寒風刺骨的上學路上，悄悄躲進蓬鬆內裡的小小避難所。冬天的溫暖，有時就這樣從耳尖開始。"},"ICON-0056":{"nm":"戲服","de":"幕未開啟前，掛在衣架上屏息以待的一套。每一道接縫裡都折疊著舞蹈。穿上袖子的那一刻，人便成了角色，舞台成了這件衣服的第二層皮膚。"},"ICON-0057":{"nm":"王冠","de":"戴上頭頂的那一刻，彎著的背便自然挺直。金光低語的，是責任更勝於權力。觸到額頭的那份冰涼重量訴說著：越是耀眼的位置，便越是沉重。"},"ICON-0058":{"nm":"斗篷","de":"披在肩上，背後便有風飄揚。每次奔跑時都有一幅衣襬跟隨而來的那種心情。與其說是英雄的標記，不如說更接近單純想帥氣一回的童心。"},"ICON-0059":{"nm":"面具","de":"遮住臉，反而更加坦率。就像在面具之後盡情哭笑的舊時假面戲一般。在隱藏的表情之外，平日嚥下的真實聲音更響亮地洩了出來。"},"ICON-0060":{"nm":"口紅","de":"轉開蓋子畫上一筆，嘴角便立起一個小小的決心。鏡前最後的檢查，在猶豫上重新塗抹的紅色一道。上色的那短短一瞬，恐懼便悄悄讓出了位置。"},"ICON-0061":{"nm":"西裝外套","de":"肩線恰好合身時，人便稍微變得堅定。捲起袖子是做事的心，立起衣領是出發的心。一套衣服，靜靜定下了那天一整天的姿態。"},"ICON-0062":{"nm":"跆拳道帶","de":"顏色每升一級，其下累積的汗水量也隨之不同。繫緊腰帶行禮的道場清晨。透過繫帶的指尖，渙散的精神再次聚攏。"},"ICON-0063":{"nm":"護目鏡","de":"戴上眼前，世界便清晰了一個色階。在擋住風也擋住灰塵的圓形盾牌之外，連每天走的平凡道路都不知為何像起跑線般閃閃發亮。"},"ICON-0064":{"nm":"手套","de":"戴在手上，便湧起緊緊抓住任何東西的勇氣。原本怕摔落而蜷縮的手指，終於得以完全張開。守護的是手，真正被守護的卻是接下來要到來的挑戰。"},"ICON-0065":{"nm":"口罩","de":"遮住嘴邊，眼睛便說了更多話。在人潮擁擠的街上，稍稍遮掩著享受的小小匿名自由。所以全都摘下後留下的微笑，綻放得更加燦爛。"},"ICON-0066":{"nm":"帽子","de":"帽簷稍稍壓低，陽光與目光便偏開一寸。在頂在頭上的小屋頂下，至少今天可以帶著輕鬆的表情走著。最輕盈的變身，總是從這裡開始。"},"ICON-0067":{"nm":"襯衫","de":"沙沙作響，剛燙好的衣領散發著清晨的氣味。從上往下依序扣著鈕扣的同時，凌亂的心也一格格變得端正。一張潔白，開啟了一天的第一句話。"},"ICON-0068":{"nm":"圍巾","de":"在脖子繞一圈，風的路口便被擋住。衣襬在肩上輕擺的同時，寒意再也無法觸到內側。是擺在帥氣與溫暖之間某處的一幅。"},"ICON-0069":{"nm":"手套","de":"連指尖都被嚴實包住，再冰冷的東西也不怕。呼呼吹氣的手悄悄變得暖和，是冬天的小小奢侈。脫下遞出的一隻，有時也溫暖了某人的手。"},"ICON-0070":{"nm":"軍牌","de":"薄薄的兩片牌，靜靜彼此相望。三個字的名字與幾個數字，便讓某人被記到最後。明明是冰冷的金屬，卻不知為何，像極了最溫暖的約定。"},"ICON-0071":{"nm":"手機指環","de":"套上手指，怕摔落的擔憂便悄然消散。一隻手也能寬裕地拿穩、揮動的小小安心。為了留下一張照片而把手臂長長伸出時，靜靜托住手掌。"},"ICON-0072":{"nm":"花冠","de":"戴在頭上，便有一抱春天隨之而來。在原野摘下、圓圓編成的花朵輕輕環繞額頭。在照片裡燦爛的笑容之上，淡淡的青草香久久留存。"},"ICON-0073":{"nm":"眼罩","de":"蓋住眼睛，燈光與噪音便一齊退遠。看不見了，聽得到的便只有自己的呼吸聲。暫時關掉世界，步入內側的寂靜，背後便有一扇小門靜靜闔上。"},"ICON-0074":{"nm":"圍脖","de":"一圈、兩圈，每繞一次脖子，冬天便溫和一些。毛線之間的某處，或許摻著某人織進的心意。埋到鼻尖，世界便更加溫暖了一分。"},"ICON-0075":{"nm":"半月面具","de":"只遮住半張臉，舞會之夜便開始了。露出的嘴唇笑著，隱藏的眼睛懷著秘密。那似認得又認不出的狹窄間距，讓子夜的空氣悸動起來。"},"ICON-0076":{"nm":"貝雷帽","de":"斜斜地戴上，平凡的一天便悄悄添了情調。圓圓扁扁的一片布，在肩上靜靜披上一抹藝術家的模樣。連在鏡前挑選角度那短短片刻都覺得愉快。"},"ICON-0077":{"nm":"頸鏈","de":"緊貼脖子繞上，視線便自然往上聚攏。一條細細的繩，便將氛圍整個改變。雖小卻分明，宛如填滿今日一整天自信的鎖扣。"},"ICON-0078":{"nm":"派克大衣","de":"拉鍊一路拉到頂，暴風雪也退後一步。把手深深插進厚厚的內裡，全世界的喧囂便平靜下來。即使在狂風之中也終究溫暖，是一座小小的家。"},"ICON-0079":{"nm":"長褲","de":"套上腳、繫好腰，才終於做好出發的準備。每邁出一步，布料便順著紋理柔軟地擺動。在舒適與端正之間某處，一天就此開始。"},"ICON-0080":{"nm":"穿環","de":"即便只是添上小小一點，也需要些許勇氣。一個閃亮的金屬，在平凡的耳畔點下清晰的句號。雖然極小，卻分明照出了今日已然不同的我的光。"},"ICON-0081":{"nm":"波形","de":"對工程師而言，歌不是聽見的，而是看見的。從畫面上起伏的山脊，讀出那天的氣息在何處顫抖。看不見的聲音如山脈般橫臥，攤開一首歌的地形。"},"ICON-0082":{"nm":"調音器","de":"演出前，依序撫過六根弦，把走調的音安放回原位。哪怕只偏了0.5度，台下也會像神一般察覺。準到無人能發現——那便是對舞台的溫柔。"},"ICON-0083":{"nm":"背帶","de":"在手腕上繞一圈，怕摔落的擔憂便悄然鬆開。在舞台上最可怕的是從手中失落什麼，所以多虧這一條小小的帶子，心才終於安定下來。"},"ICON-0084":{"nm":"鈸","de":"只碰撞一次的那一瞬間，便為樂曲的最後一句打下清晰的句號。金色的圓盤懂得響得最短、餘韻拖得最長。結尾，就該這樣明亮地闔上。"},"ICON-0085":{"nm":"吉他","de":"手指在六根弦上滑過，狹小的房間便整個成了舞台。某人的第一段旋律、徹夜難眠的清晨的自言自語，都在這圓圓的木桶裡最先得到了呼吸。"},"ICON-0086":{"nm":"聲音雲","de":"天空一隅，音符如棉花般聚成一團悠悠飄浮。據說風一掃過，落下的便不是雨點而是旋律，島上的孩子們連傘也不帶便出去迎接。"},"ICON-0087":{"nm":"舞步","de":"舞台走位是用腳尖解的算術。這裡一步、那裡半拍——錯了也沒關係，慢慢來。踩過數百遍刻進身體的格子聚在一起，一首歌的地圖才終於完成。"},"ICON-0088":{"nm":"音箱","de":"把細語變成吶喊的箱子。即便如此，在把音量調高一格之前，總是停下手。比起更大的聲音，更準確的聲音才能傳到台下最後一排，這箱子明白。"},"ICON-0089":{"nm":"音符棉","de":"豆芽菜似的符頭聚成一團棉絮，像枕頭般蓬鬆。據說靜靜枕著躺下，便會流出若有似無的搖籃曲，是島上最溫柔的一則傳聞。"},"ICON-0090":{"nm":"卡帶","de":"按下倒帶鍵，咿軋一聲，磁帶慢慢轉回那個夏天的第一首歌。一個時節整個捲入的小盒子裡，再也無法觸碰的時光，原封不動地沉睡著。"},"ICON-0091":{"nm":"音叉","de":"輕敲分岔的兩股鐵，半空中便誕生一個基準音。所有樂器都隨這微小的顫動靜靜對齊音調。無論什麼，開始都來自這般纖細的振動。"},"ICON-0092":{"nm":"波形晶片","de":"把一小段聲音輕輕關進指甲大小的晶片裡。不曾刻意錄下的助興聲、以為已消失的某人的笑聲，都在這裡頭依然溫暖地活著、呼吸著。"},"ICON-0093":{"nm":"黑膠唱片","de":"唱針沿著紋路邁出第一步，便先聽見沙沙作響的淡淡氣息。連那細微的雜音都喜歡，所以有人始終無法把這黑色圓盤從手中放下。"},"ICON-0094":{"nm":"口袋","de":"最珍惜的東西，總是放在離胸口最近的地方。一個巴掌大的布袋，某天成了暖手爐，某天成了護身符，又某天成了秘密的收藏匣。"},"ICON-0095":{"nm":"OK繃","de":"練習拖長的夜裡，每個腳後跟都貼上一枚小小的勳章。為了嚥下喊痛而貼上的一片——是明天也定要起舞、無人知曉的安靜約定。"},"ICON-0096":{"nm":"枕頭","de":"把一天份的舞台全部放下的地方，終究是這蓬鬆的方形一片。靜靜把頭枕下，殘留耳畔的掌聲便慢慢平息，島上也終於降下了夜。"},"ICON-0097":{"nm":"鈴鐺","de":"叮鈴，短短一聲，便有人推門而入。是客人來了的信號，也是一天開啟的問候。一個小小的鐵器，整天只專心地為歡迎而響。"},"ICON-0098":{"nm":"外殼","de":"越是珍貴的東西，越要另外為它蓋一座堅固的家。開合的動作每次都變得小心翼翼，是因為裡頭裝著的不只是物件，而是不忍失去的心意。"},"ICON-0099":{"nm":"刷子","de":"連一根毛都順著紋理掃過，蜷縮在角落的灰塵便悄悄退去。有著連看不見的地方也不嫌棄的手，房間才能每天迎來新的清晨。"},"ICON-0100":{"nm":"草圖","de":"完成之前的線條，並不刻意隱藏猶豫。每一處擦去又重畫的痕跡裡，毫不虛假地留著它曾想成為什麼。越是生澀的開始，越是坦率。"},"ICON-0101":{"nm":"玩偶","de":"有些存在，光是無言地被擁進懷裡，就成了慰藉。在舞台後手不停顫抖的夜裡，在枕邊一同顫抖的棉花團朋友——人人心中都懷著這麼一個。"},"ICON-0102":{"nm":"鐘","de":"山寺的鐘一響，便整個越過了山谷。是想傳得更遠、更遠的鐵之心在長長地鳴響，那聲音在聆聽者的胸口慢慢沉澱下來。"},"ICON-0103":{"nm":"雨傘","de":"一起撐，總有一邊的肩膀必定會被淋濕。在悄悄傾斜的傘下，濕掉的肩膀才正是溫柔最分明的證據。共享一片屋頂的短短一段路，久久留在心上。"},"ICON-0104":{"nm":"墊子","de":"在光禿禿的地板上鋪一張，那裡便立刻成了練習室。滾倒、跌落也無言承接的位置——無數動作在這上面，第一次讓自己的身體記住了路。"},"ICON-0105":{"nm":"鈴鐺","de":"靜靜一搖，叮鈴鈴，清脆的聲音便從手中滾出。從前的孩子們綴在彩色衣襟末端、在庭院奔跑嬉戲的，小而圓的歡樂，在掌心上再度甦醒。"},"ICON-0106":{"nm":"玩具蛇","de":"細長垂落的模樣，調皮地把人嚇一大跳。害怕著逃跑，最後卻咯咯笑出來——這樣的惡作劇，終究也是朝向彼此的溫柔的一支。"},"ICON-0107":{"nm":"玩具","de":"即使長大成人，誰都有一個始終捨不得丟的盒子。那裡頭，最閃耀的歲月的笑聲，像沒鬆開的發條般，至今仍緊緊地纏繞著。"},"ICON-0108":{"nm":"飯桌","de":"把折起的腿打開，無論何處立刻就成了一家人的位置。圍坐一圈、湯匙相碰的聲音，那質樸的合奏，是一整天裡響得最溫暖的一首歌。"},"ICON-0109":{"nm":"肥皂","de":"在手中一點點變小，默默把某人洗淨。磨損自己去清洗他人——直到泡沫全數消退好一陣後，那安靜的心意才終於顯現。"},"ICON-0110":{"nm":"梳子","de":"像把糾纏的頭髮一絲絲解開那般，凌亂的一天也漸漸變得整齊。鏡前遞上的短短一個動作，越過髮絲，連內心的儀容也悄悄替你整理好。"},"ICON-0111":{"nm":"鳥籠","de":"即便門大大敞開，也有不離去、依舊歌唱的鳥。不是被關著，而是想留下才留下的心——那細微的差別，這鳥籠比誰都更早察覺。"},"ICON-0112":{"nm":"暖手包","de":"冬天演出場的候場隊伍裡，口袋中小小的溫度靜靜焐熱僵硬的手指。是想著會在寒冷中發抖的你，某人預先搖熱的、巴掌大的溫柔。"},"ICON-0113":{"nm":"手帕","de":"眼淚也好汗水也好，都毫無怨言地承接的一方布。角落上小小繡著的刺繡，宛如先一步離去的人留下的、別忘記的最後問候，漂亮地停在那裡。"},"ICON-0114":{"nm":"噴霧","de":"噗地噴一下，空氣的紋理便瞬間改變。在舞台上瀰漫的霧氣也好，清晨窗邊的花草也好，都在這細細的水珠中，暫時成了另一個世界閃閃發亮。"},"ICON-0115":{"nm":"試香紙","de":"挑選香氣這件事，不知為何與挑選記憶極為相似。細細紙條末端輕沾的一縷氣味，悄悄把以為已遺忘的某個季節，帶回了鼻尖。"},"ICON-0116":{"nm":"餐桌","de":"每一道磨損的木紋裡，都靜靜刻著一同分享過的餐食的數目。喧鬧的傍晚也好，獨自迎來的深夜也好——這方形無言地全都承接懷抱，泛著光澤。"},"ICON-0117":{"nm":"線團","de":"輕輕一拉一端便嘩啦解開，一針便又能重新接上。把斷裂的東西接起來這件事，總是這般從纖細的一縷線靜靜開始。"},"ICON-0118":{"nm":"雨衣","de":"即便在傾盆大雨的日子，也終究讓人走出門外的，便是這一件。唯有懂得在雨中嘩啦嘩啦走著之樂的人，才不會拿雨當藉口留在家裡。"},"ICON-0119":{"nm":"束口袋","de":"把袋口圓圓收攏，裡頭的東西才終於安全。一個沾滿手澤的小袋子裡，硬幣也好、某天的回憶也好、終究沒能說出口的話也好，都一同盛著搖晃。"},"ICON-0120":{"nm":"書架","de":"沿著插立的書脊慢慢滑過手指，走過的季節便在指尖被觸摸到。讀完的書始終捨不得丟，是因為那時的我，至今仍住在那裡。"},"ICON-0121":{"nm":"書塔","de":"讀過的書橫躺一旁，沒讀的書往上堆疊。即使總有一天要全部讀完的約定在天花板附近微微晃動，連那晃動都喜歡，所以今天又多疊上一本。"},"ICON-0122":{"nm":"滾輪","de":"再怎麼努力奔跑似乎都在原地，但小小的腳正先學著腳尖的節奏。不曾停下的那些昨天聚在一起，某天便在真正的路上燦爛地閃耀。"},"ICON-0123":{"nm":"罩布","de":"不讓灰塵落下、不讓陽光曬褪——蓋起來這件事，也傾注著指尖的心意。越是珍惜的東西，越是在看不見的地方被更溫柔地守護著。"},"ICON-0124":{"nm":"毛線","de":"在奶奶膝上嘩啦嘩啦解開的一縷。看似糾纏，但找到線頭輕輕一拉，便毫不差地跟著過來。冬夜就這樣一針一針地變長了。"},"ICON-0125":{"nm":"收納包","de":"護唇膏、髮圈、漂亮折好的一封信——看似小巧，裡頭卻盛著一天份的心意。隨著拉鍊闔上的聲響，珍貴的零碎雜物整個變得安全。"},"ICON-0126":{"nm":"扶手","de":"讀書讀到睡著的午後，講著電話來回踱步的傍晚。坐得越久手澤越深的位置上，手肘記得的所有歇息，靜靜匯聚成一寸。"},"ICON-0127":{"nm":"卡包","de":"拆開前，還不屬於任何人。封著的一包裡滿是尚未開啟的期待，所以捏著邊角的指尖輕輕顫抖起來。那便是開封的心動。"},"ICON-0128":{"nm":"包裝紙","de":"比禮物早一步抵達的心意。對齊邊角折好、用緞帶繫起的同時，收禮之人微笑的臉龐便在手中提早燦爛地展開。"},"ICON-0129":{"nm":"遊戲手把","de":"拇指比頭腦更早記住的那些按鍵。輸了也再來一局——那一局終究熬成了通宵。恰好合手的重量，靜靜托起了今夜的冒險。"},"ICON-0130":{"nm":"號誌","de":"紅色是暫且停下，綠色是現在可以走了。僅憑一個簡單的約定，無數道路便不相糾纏地流動。等待也有先後次序，閃爍的燈光溫柔地告訴你。"},"ICON-0131":{"nm":"箭頭","de":"對迷路的人而言最溫柔的圖形。茫然不知該往何處時，某人先一步畫下的一個方向，讓停滯的腳步再次變得堅定。"},"ICON-0132":{"nm":"座標","de":"只要兩個數字，世上任何地方都能精準點出。約定碰面的位置、埋藏寶物的沙灘。為了讓約定不致迷路，一個小小的點，始終牢牢守著。"},"ICON-0133":{"nm":"磁磚","de":"獨自一塊，不過是方形的一片。肩並肩一同躺下的那一刻，便成了地板、成了牆。微小的事物聚在一起，造出讓某人安心落腳的位置。"},"ICON-0134":{"nm":"沙漏","de":"上格一空，下格便慢慢被填滿。望著簌簌流下的沙，我們便相信時間正在流逝。倒過來又是從頭——那便是沙子溫柔的謊言。"},"ICON-0135":{"nm":"球","de":"丟出去會回來，踢出去會滾走。因為圓，不知會彈往何處，這便是最大的魅力。運動場正中央，笑聲總是從這小小的球體圓圓地開始。"},"ICON-0136":{"nm":"開關","de":"喀噠，一下就開，一下就關。走進漆黑房間時按下的那細小聲響，把渙散一天的開始與結束，分成了清晰的一條線。"},"ICON-0137":{"nm":"問號","de":"不知道答案並不是丟臉的事。因為那是好奇心仍然活著的可喜證據。當這小小的鉤子在腦海裡叩叩敲響時，學習才終於邁出第一步。"},"ICON-0138":{"nm":"火柴","de":"劃過自己身軀以遞出火光的一根。短短燃燒便安靜消逝，但在那短暫之間，蠟燭被點亮，灶火被焐暖。微小的給予，成了溫暖的第一顆鈕扣。"},"ICON-0139":{"nm":"踏板","de":"只要踏上一步，原本搆不著的層架也能伸手碰到。是暫時為某人增高的事。低低俯下、悄悄把我們抬高的溫柔位置，就在這裡。"},"ICON-0140":{"nm":"手錶","de":"下定決心運動那天，最先繫在手腕上的東西。為你數著心跳與步數的小小教練，今天會叩叩敲著告訴你：比起昨天多走了一些。"},"ICON-0141":{"nm":"鬧鐘","de":"每天早上最被嫌棄、卻最勤奮的朋友。多虧它每次都替你對抗被窩裡再睡五分鐘的誘惑，約定與夢想才不致遲到。那令人惱火的響聲，其實是加油。"},"ICON-0142":{"nm":"核心","de":"把外層全數剝去，到最後仍留下的最內側。蘋果的籽、心的真意——無論什麼，正中央都裝著最堅硬的東西。是即使動搖也終究留下的一點。"},"ICON-0143":{"nm":"筆","de":"墨水乾之前蹭在手側悄悄暈開的痕跡。無論寫得順不順，在白紙前劃下的第一筆，總藏著一點小小的勇氣。是讓思緒越過到指尖的橋。"},"ICON-0144":{"nm":"毛筆","de":"含著墨經過宣紙時，連猶豫的一絲顫抖都原原本本地留下。一想著要寫快些起了貪心，立刻就會露餡。毛筆最先讀懂寄寓在指尖的那份誠實。"},"ICON-0145":{"nm":"對話框","de":"話語還來不及說出口前，先在頭頂圓圓浮起的位置。想說的一句話便盛在這裡。空著的時候，是正在挑選要填上什麼話。"},"ICON-0146":{"nm":"核取方塊","de":"在空白的方框裡劃上兩道槓，心便輕鬆許多。是為完成的事自己頒給自己的小小勳章。一天的盡頭，望著被填滿的格子，我們安心今天也好好活過了。"},"ICON-0147":{"nm":"平板","de":"手指觸到何處，圖畫便在那裡暈染，文字便在那裡流動。靜靜放在膝上，便有一個世界明亮地亮起。雖輕薄，裡頭盛著的可能性卻絕不單薄。"},"ICON-0148":{"nm":"遙控器","de":"在躲進沙發縫隙這件事上，有著天賦異稟的才能。轉台的權力，總屬於握著它的人。家人之間最小、最溫馨的爭執，就在這一掌之上展開。"},"ICON-0149":{"nm":"配重","de":"為了抓住搖晃的東西，自己降到最低處的重量。即使上方劇烈晃動，只要下方沉穩，便終究不會倒下。平衡，總是在看不見的地方撐著。"},"ICON-0150":{"nm":"拼圖","de":"為了找最後一塊而摸到沙發底下的夜晚。恰好嵌進去那一瞬間無聲的快感。曾散落各處的東西找到各自位置時，圖案終於完成了。"},"ICON-0151":{"nm":"尺","de":"測量長度，其實也是一種守約。為了讓每個人的一拃都一樣，刻度誠實地一格格排列著。一條筆直的線，連歪斜的心也能撫得整整齊齊。"},"ICON-0152":{"nm":"畫布","de":"空無一物的白面最令人畏懼，也最令人雀躍。因為在落下第一筆之前，它能成為任何模樣。空白並非終點，而是開始的另一個名字。"},"ICON-0153":{"nm":"魔術方塊","de":"為了拼齊六個面而通宵到天明的人，可不只一兩個。轉了又轉，指尖那份執著。當錯亂的色彩各歸其位的瞬間，一個小小的宇宙便被整理得井然有序。"},"ICON-0154":{"nm":"遊戲機","de":"放假時和表兄弟姊妹湊在一起盯著看的小螢幕。整個冒險世界恰好收進掌心。光是聽到開機的那一小段旋律，那年夏天便整個回來了。"},"ICON-0155":{"nm":"握把","de":"緊緊一握便服貼於手的那份手感，悄悄遞來幾分自信。不打滑，不脫手。在最重要的時刻，將手與器具牢牢繫成一體的連結點。"},"ICON-0156":{"nm":"鋼筆","de":"灌墨書寫的時候，連字跡都會變得端正幾分。隨著筆尖沙沙作響整頓心緒，慢慢寫下手寫信的第一行——它靜靜地像極了那份用心。"},"ICON-0157":{"nm":"調色盤","de":"紅旁是藍，黃上是綠。在這方色彩整齊並臥的小盤上，畫終於有了表情。調和與疊塗的所有冒險，都從這裡邁出第一步。"},"ICON-0158":{"nm":"套組","de":"單個看來平凡，並列在一起卻成了一篇故事。一片不缺、樣樣齊全時的那份踏實。把散落之物聚於一處，藏著一份小小完成的喜悅。"},"ICON-0159":{"nm":"羽毛球","de":"被球拍擊中而騰起時，羽毛揚起的那陣柔軟風聲。看似太輕飛不遠，可一旦認真擊出，便筆直飛向球場盡頭。輕盈，也是一種堂堂正正的力量。"},"ICON-0160":{"nm":"天線","de":"為了抓住看不見的訊號，靜靜地朝天而立。連遠方的聲音也終究牽引而來的那份耐心。收訊不佳的日子，只要稍稍轉一下角度，便又清晰起來。"},"ICON-0161":{"nm":"聽診器","de":"冰涼觸上胸口的圓端，以及短暫屏住的呼吸。把耳朵湊向那一聲小小的鼓動，活著的這最古老的節拍，便透過指尖傳來。一件以聆聽為先的器具。"},"ICON-0162":{"nm":"西洋棋子","de":"緩慢地、一次只走一格的小棋子。即便如此，觸到底線的瞬間便能化為任何模樣。那以遲鈍腳步翻轉整盤的一著，老舊的棋盤靜靜地守望著。"},"ICON-0163":{"nm":"手把","de":"還記得用兩根拇指馳騁宇宙的那些夜晚嗎？輸了氣得一摔，又訕訕撿回的那磨出手痕的握把。隔著螢幕與某人無言交換的，最漫長也最溫暖的對話。"},"ICON-0164":{"nm":"主機","de":"一開電源，小小的開機音便如問候般響起。整個假期躲在被窩裡開開關關的方形盒子，兒時的第一場冒險，總是從這片螢幕的光亮中開始。"},"ICON-0165":{"nm":"時間軸","de":"左端是起初，右端是尚未到來的日子。在其間任何一處拖放一個點，以為早已遺忘的瞬間便再度展開。一個將時間橫躺成一行的所在。"},"ICON-0166":{"nm":"稜鏡","de":"原以為只是清透的光，竟懷藏著七種色彩。穿過一片玻璃的瞬間化作彩虹綻放的祕密。越是端整的事物，內裡藏著越多的顏色。"},"ICON-0167":{"nm":"高爾夫球座","de":"一個靜靜擱放球的小托座。越想送得遠，越需要先有個穩穩托住的東西。草地上這枚小小的釘，撐起了第一步。"},"ICON-0168":{"nm":"毛線針","de":"一針，又一針。漏掉一針就得全部拆開、回到最初。整個冬日在膝上緩緩長長的圍巾，指尖的耐心織成溫暖的所在。"},"ICON-0169":{"nm":"旋律線","de":"在歌詞填上之前，從唇邊哼哼漏出的那一小段。在那尚未黏上字句的朦朧旋律裡，藏著一首歌最坦率的第一張臉。"},"ICON-0170":{"nm":"雷達","de":"朝著看不見的黑暗發射訊號，靜靜等候歸來的一個亮點。即便什麼也看不見，仍相信那裡有著什麼的，圓圓綠光的耐心。"},"ICON-0171":{"nm":"節奏墊","de":"輕輕一敲，光與聲便同時彈起。讓手比腦先記住節拍的所在。在掌心上展開的，最小巧也最溫柔的舞台。"},"ICON-0172":{"nm":"顏料","de":"昔日的畫工磨石碾土以取色。靛藍來自草，赤紅出於土。如今擠在指尖的這一滴裡，也流淌著將自然細細移納的古老用心。"},"ICON-0173":{"nm":"線","de":"在下定決心連起點與點的那一刻，才終於誕生之物。無論短長、彎曲或筆直，都是「想往某處去」的心最簡單留下的痕跡。一切畫的開端。"},"ICON-0174":{"nm":"快門","de":"喀嚓，那短短一次黑暗便將一個場景永遠留住。連眨眼間險些錯過的一個表情，也將光稍稍切下、凝成回憶的小刀刃。"},"ICON-0175":{"nm":"安全繩","de":"比攀向高處的人先一步牢牢繫住的繩。替你接住怕墜落而忐忑的心，無形中守在身旁的約定之繩。它總在你的背後。"},"ICON-0176":{"nm":"鎖","de":"從前掛在倉房上的厚重鐵鎖。並非為了囚禁什麼，而是想安心地放好珍貴之物的那份心。連上鎖的手勢都懷著用心，那是老屋的踏實。"},"ICON-0177":{"nm":"天秤","de":"一邊變重，另一邊便自然變輕。在猶豫該放上什麼、放多少的那瞬間，人學會了公平。搖搖晃晃間，是教人懂得平衡的兩臂。"},"ICON-0178":{"nm":"剖開器","de":"再牢牢黏合之物，順著紋理終究會裂開。一件把任何東西一分為二、窺看內裡的小工具。是想把合在一起之物再拆開來瞧瞧的，充滿好奇的指尖。"},"ICON-0179":{"nm":"計數器","de":"一、二、三。代替手指默默數著數字的小夥伴。把生怕漏數的忐忑，喀噠喀噠換成安心的，計數的溫柔同伴。"},"ICON-0180":{"nm":"游標","de":"在螢幕某處閃爍著、等候下一道指令的小箭。即使你躊躇不前，它也不離開那個位置，是輕聲招手說「現在就開始吧」的光之尖端。"},"ICON-0181":{"nm":"攀岩點","de":"在指尖力氣將盡的前一刻，最後抓住的那一點。有些瞬間，是憑著「絕不放手」這一個心念撐過去的——牆上的小小突起，靜靜地這樣告訴你。"},"ICON-0182":{"nm":"鵝卵石","de":"在溪中久久翻滾、把稜角全都讓出的石頭。變得圓潤，是被磨去的時間的另一個名字。靜靜握進掌心，便摸得到那流水的耐心。"},"ICON-0183":{"nm":"紋章","de":"古時的家族在一幅旗上刻下走獸與星辰，藉以表明自己。是比言語更先傳遞心意的圖畫。將一個人的驕傲細細壓縮進一方小格的古老標記。"},"ICON-0184":{"nm":"盾","de":"擋在身前，從來都是為了背後的人。替人接下飛來的箭矢，守護某人平凡一天的，厚重而又溫柔的牆。"},"ICON-0185":{"nm":"復活","de":"有一種心，熄滅了又會重新點亮。唯有曾經倒下一回，才終於懂得重新站起的方法。在以為是終點的地方，靜靜湧上的第二口氣息。"},"ICON-0186":{"nm":"弓","de":"想送得遠的手，會先把弦拉到極致。要送走，就得先那般貼近地擁入懷中——緊繃彎曲的弓身，靜靜無言地這樣告訴你。"},"ICON-0187":{"nm":"愛心","de":"「喜歡」這句話，總是不斷縮成一個小小的形狀。在應援棒的尖端，在相抵的指尖之間，悄悄畫出的這個形狀。是心最常見也最誠實的縮寫。"},"ICON-0188":{"nm":"雲","de":"朝著風吹的方向緩緩流去，每一次都成了不同的臉。是兔子，又是棉花，什麼都不長久執著、任其飄逝的，天空最輕盈的心。"},"ICON-0189":{"nm":"迷宮","de":"是在死路前學會折返的地方。即便在徬徨之中，腳步也一點一點朝著出口生長。總得迷一次路，方向感才會開竅。"},"ICON-0190":{"nm":"牙齒","de":"從前有把掉落的牙丟上屋頂的習俗。那是盼新牙長得齊整的小小祈願。是「成長途中總得失去一回，才能換來更堅實之物」的那個兒時溫柔約定。"},"ICON-0191":{"nm":"行星","de":"一次也不曾偏離自己軌道、繞著恆星轉的圓潤之身。看似孤獨，卻總讓某物一同相伴運轉的重力。默默守住自己位置這件事，便成就了一個世界。"},"ICON-0192":{"nm":"星","de":"迷途的夜裡，人們會仰望那最明亮的一點。即便遙不可及，卻清楚指明方向的光。正因遙遠，那約定反而更加堅定。"},"ICON-0193":{"nm":"剪影","de":"背光而立，人便只剩輪廓。一個抹去了名字與表情的黑色形影。正因空著，反而讓人想像出更多，是個未曾填滿的所在。"},"ICON-0194":{"nm":"耳朵","de":"想唱得好，得先聽得好。節拍也好、心意也好，終究都從聆聽開始。是世間所有聲響最先抵達並停駐的，圓圓敞開的一扇小門。"},"ICON-0195":{"nm":"落葉","de":"有一種葉子，墜落的那一刻最是美麗動人。將一季的青翠燃成赤紅，再輕輕放下的那份輕盈。連終結也能如此美麗——秋天這樣示現給你看。"},"ICON-0196":{"nm":"月","de":"曾有過在中秋圓光下雙手合十許願的夜晚。盈虧交替、不曾有一回相同過的那張臉。在變幻之中卻總照亮原地的燈火。"},"ICON-0197":{"nm":"心臟","de":"即便在舞台上，最誠實的終究是這份搏動。再緊張也不停歇，一旦激動便跳得更響。代替言語未盡的應援為你怦然跳動的，紅色小鼓。"},"ICON-0198":{"nm":"影子","de":"只要有光便絕不離去的同行者。越明亮便越濃，越昏暗便越淡，是跟隨我最久的另一個我。連獨處的日子，也立在身旁的一個人。"},"ICON-0199":{"nm":"尾巴","de":"高興便自然搖擺，害怕便悄悄捲起。即使緊閉著嘴，終究藏不住心思的誠實末梢。是身體先一步洩漏出的心底。"},"ICON-0200":{"nm":"尾繩","de":"像髮帶那樣繫於末端收尾的小繩。怕它鬆開而又多打一個結牢牢繫緊的那份心。把易散之物聚攏在一處、細細安撫好的溫柔收結。"},"ICON-0201":{"nm":"瞳孔","de":"話語可以斟酌，眼神卻藏不住。是被看穿的心最先洩漏出的所在，那黑色圓點的內側。即便嚥下「喜歡」這句話，瞳孔也早已朝你而晃動了。"},"ICON-0202":{"nm":"馬蹄鐵","de":"奔過遠路的足尖越磨損，便越發堅實的一塊鐵。據說倒掛在門上，來往的福氣便會盈聚其中。它靜靜托起某人平安的歸途。"},"ICON-0203":{"nm":"紋章石","de":"縱使風雨將字跡磨得模糊，以指尖摩挲，刻下的紋理便清晰復活。那是某顆不願被遺忘之心的重量。石頭就這樣，將一個名字長久懷藏。"},"ICON-0204":{"nm":"蹼","de":"憑著趾間相連的一層薄膜，學會了推水的方法。是自然悄悄遞給不擅游泳者的一支小槳。雖慢，卻終究讓你抵達河對岸的溫柔設計。"},"ICON-0205":{"nm":"亮片","de":"大家都抱怨它沾上手便跟著好幾天，可逢喜慶之日，又最先尋找這閃亮的小顆粒。撒上一把星塵，平凡的紙也閃閃發光，今天便變得特別。"},"ICON-0206":{"nm":"爪子","de":"森林的野獸用爪子刨土，留下自己的路。那不是威脅，而是痕跡——「我曾經過此地」的安靜署名。鋒利的尖端，對某些人而言也成了溫柔的路標。"},"ICON-0207":{"nm":"閃電","de":"天空短暫攤開掌紋的剎那，光比雷聲更早抵達。彷彿在說，大聲響到來之前先調勻一口氣。恐懼與驚嘆，總是在同一道光中一同誕生。"},"ICON-0208":{"nm":"護身符","de":"在紅紙上以墨重重按下的一行心願。據說放在枕下，惡夢便會避開。為某人祈求平安的心意，憑一張薄紙也能這般溫暖。"},"ICON-0209":{"nm":"筆翼","de":"有那麼一個瞬間，筆尖化作了翅膀。劃下一筆時在紙上滑行的那份輕盈。「書寫即是飛翔」這件事，從前磨墨的那雙手，想必也隱約知曉。"},"ICON-0210":{"nm":"骨","de":"唯有血肉盡皆消散之後，才留下之物。正因最堅實，才撐到最後的白色骨架。即使時間帶走一切，終究只記得形狀的，一個安靜的證據。"},"ICON-0211":{"nm":"鼻子","de":"氣味是通往記憶最快的捷徑。節慶廚房的油香、初雪清晨冰涼的空氣——鼻尖先一步察覺，心才慢半拍跟上。"},"ICON-0212":{"nm":"吐司","de":"忙碌的早晨，最快抓在手中的一餐。咬下烤得金黃的麵片，一天份的勇氣便酥脆地碎開。不必盛大也叫人踏實的事物，會把人重新扶起。"},"ICON-0213":{"nm":"餅乾","de":"在烤箱前等得最久的人，能得到第一口。剛烤好的邊角那份溫熱，片刻的甜。越是想著某人而烤的，不知為何便越發甜。"},"ICON-0214":{"nm":"點心","de":"練習拖長的午後，從包包深處掏出的小袋子。對半分開，踏實感竟神奇地加倍。比起飢餓，先填滿心的那一把溫柔。"},"ICON-0215":{"nm":"扭蛋","de":"在轉開之前，誰也無從得知。圓圓的殼裡裝著的，總是同樣的那份怦然。買賣著小小偶然的，世上最誠實的雀躍。"},"ICON-0216":{"nm":"門把","de":"開門關門的無數雙手最先觸到的所在。從冰涼開始，在掌心被焐暖，是家的第一聲問候。手痕越積越多，那個房間便一點一點成了某人的家。"},"ICON-0217":{"nm":"散步","de":"漫無目的地走，也有它的理由。那是把糾結的思緒順著腳步一縷縷理開的時光。繞一圈回來，答案雖原封不動，心卻輕快了許多。"},"ICON-0218":{"nm":"速克達","de":"劃過窄巷奔馳的兩個輪子。雖不算快，卻以全身承接著風。不必去遠也無妨，只想今天痛痛快快奔一回——人總有這樣的日子。"},"ICON-0219":{"nm":"安全桿","de":"在乘上之前，朝胸前牢牢落下的一道橫桿。是陪你撐到底、一同熬過驚險路段的踏實約定。它冰涼而無言地告訴你，緊緊抓著也沒關係。"},"ICON-0220":{"nm":"階梯","de":"一階一階往上爬，不知不覺風景便已不同。沒有一步登頂這回事，腳掌先一步學會了這道理。那上上下下本身，對某人而言便是一天份的步伐。"},"ICON-0221":{"nm":"玻璃生態瓶","de":"並非把森林關進玻璃裡，而是用心培育一個世界。青苔蔓延、水珠凝結的掌心大小的宇宙。越是凝望，心便越被緩緩染成一片綠。"},"ICON-0222":{"nm":"講台","de":"登上高出一拃的位置，所見的風景便不同了。是恐懼與自豪在同一高度相遇的地方。隨著誰站上去，那一階每次都化作不同的舞台。"},"ICON-0223":{"nm":"飛機","de":"雲鋪在腳下的那一刻，才終於思念起離開之地。那不是遠離，而是世界變得更寬廣。在小島上長大的夢，也這樣越過了天空。"},"ICON-0224":{"nm":"滑板","de":"得先學會跌倒，才終於能駕馭之物。每當膝蓋擦破，平衡便一點一點銘刻進身體。摔得越漂亮，便滾得越遠的，誠實的四個輪子。"},"ICON-0225":{"nm":"護照","de":"翻開封面，滿是空白的頁。每一枚將被蓋上的章，都成了活過的證據。它是一本懷著「比起去過哪裡，更在於能往任何地方去」這份可能的小書。"},"ICON-0226":{"nm":"簡圖","de":"雖無精確的距離與比例，卻因是親手畫的路，全然不必擔心迷失。巷弄與店名親切地交纏其上的紙。懷著心意的指引，總比路本身更先溫暖。"},"ICON-0227":{"nm":"走位圖","de":"舞台上每一個腳步都化作線條畫在紙上。何處停下、何處轉身，箭頭早已預先約定好。看似自由的舞，其實也始於這一張紙。"},"ICON-0228":{"nm":"座位指引單","de":"在陌生的空間裡，最先摸索尋找的是我的位置。順著排與號，終於抵達的那一格。一張紙，把數千份雀躍一一安放回各自的位置。"},"ICON-0229":{"nm":"巷弄指引卡","de":"為了在迷宮般的巷弄裡迷路的人，某人親手寫下的指引。「在第幾個轉角拐彎」的溫柔字跡。整個街坊的人情，工工整整地盛在一張小卡片上。"},"ICON-0230":{"nm":"識別證","de":"唯有把這張卡掛上脖子，內側世界的門才終於開啟。是准許出入的一份小小權限，也是「歸屬於此」的安靜憑證。唯有懂得取得它所花時間的人，才知其分量。"},"ICON-0231":{"nm":"臨時入場帶","de":"一旦套上手腕，到撕下為止便是那天的一員。一條紙帶劃開內與外，成了「共度同一天」的標記。即便剪斷之後，那痕跡仍久久留著。"},"ICON-0232":{"nm":"來賓標籤","de":"憑貼在胸前的一個小小名牌，陌生之地便成了我的位置。當「歡迎」這句話載於一張紙遞來時，初來乍到的人也才終於成了客人。"},"ICON-0233":{"nm":"海報筒","de":"把捲起的海報一絲皺褶不留地守護好的堅固圓筒。越是珍貴的圖，越得筆直地舒展寄出。雖看不見內裡，它卻懷著某人的用心上了路。"},"ICON-0234":{"nm":"資料集封面","de":"包覆厚厚一疊資料的第一張。是比內容更先觸手的臉。封面端整，連其中的心態都顯得端整——小小格式那份溫柔的開端。"},"ICON-0235":{"nm":"紀念明信片","de":"在遠方風景的一隅寫下問候寄出。等抵達之時，連寄出的心意也一同微微泛舊，更顯親切。是螢幕裡的訊息終究追不上的，手寫信那緩慢的溫度。"},"ICON-0236":{"nm":"禮物吊牌","de":"繫在禮物上的一張小紙。光是「給你」這兩個字，包裝便已大功告成。是寫下「比起送什麼、更在於想起了誰」的，世上最短的信。"},"ICON-0237":{"nm":"包裝貼紙捲","de":"每撕下一格使用，收尾便更顯俐落幾分。是把欲鬆開的尾端端整繫住的小結。用心包好的包裝那最後一著，總是出自這捲捲起的帶子。"},"ICON-0238":{"nm":"透明信封套","de":"為使手寫信不被歲月褪色而包覆的一層透明。字跡照樣看得見，唯獨手痕觸不到。某人珍視的心意，由一層看不見的膜靜靜守護著。"},"ICON-0239":{"nm":"彩色封緘貼","de":"封住信封的最後一點，顏色越鮮明，心意便越不外洩。是「拆開之前未經任何人之手」的約定。連祕密，也需要這樣漂亮的一個結。"},"ICON-0240":{"nm":"便箋掛冊","de":"把短短的字條集束在一起的小冊子。每一張都是要遞給某人的一句話。將尚未說出口的話一一收攏起來，總有一天定能傳達的勇氣便會生長。"},"ICON-0241":{"nm":"折疊指引牌","de":"展開便是「這邊請」，折起便是「今天到此為止」。在巷口張開雙腿而立，為怕迷路的某人整整站上一天。折起的傍晚，是我最溫柔的歇息。"},"ICON-0242":{"nm":"郵件整理帶","de":"把一大疊明信片攬在腰間，欲散開的問候便終於成了一束心意。一條輕巧的帶子，把要送往遠方的話語端整地繫好，靜靜目送那啟程的背影。"},"ICON-0243":{"nm":"感謝便箋束","de":"因為「謝謝」這句話總在嘴邊滑落，便寫在掌心大小的紙上靜靜束好。束子越厚，欠下某人那份心意的厚度，也並肩長著。"},"ICON-0244":{"nm":"應援口號樣張","de":"寫著「請這樣喊」的一張範本。尚未被嗓音披上的應援，像等待第一拍的空白樂譜，靜靜地只懷著一份雀躍。"},"ICON-0245":{"nm":"預錄申請便條","de":"寫著「請排預錄」的便條，總停在凌晨五點那一格。為了減眠去搶位的那份心，小小的紙彷彿全都明白似的，默默替你記了下來。"},"ICON-0246":{"nm":"簽售順序券","de":"決定你是第幾個遞上問候的一張。排隊並非等候輪到自己，而是因為無法給喜歡的心意排上號碼，才暫且借來一個順序。"},"ICON-0247":{"nm":"候位號碼手環","de":"憑一個數字，便分出了今天排隊的先後。無論前排後排，把這條小巧輕盈的帶子繫上手腕的人，終究都是為看同一個舞台而聚來的同心同志。"},"ICON-0248":{"nm":"小卡整理表","de":"明明是同一張臉卻說各不相同，一格格分開記下。表格越填越滿，心便越發端整，而空著的一格，化作今天想填滿的雀躍，叫胸口怦怦跳。"},"ICON-0249":{"nm":"專輯確認單","de":"從版本、小卡，到是否封緘——以數字一行行寫下的愛之清單。預先描繪填滿那天的滿足，今天也在一行上細細畫了個圈。"},"ICON-0250":{"nm":"應援方式便條","de":"從手勢、呼喊的節拍，到調息的位置。為讓初來的人也迅速融入齊聲，小小的字條成了親切的嚮導，從一手傳到另一手。"},"ICON-0251":{"nm":"私密便條本","de":"只挑誰也不會給看的句子寫在這裡。「未曾翻開的那一頁最是坦率」這件事，這本子闔著封面，默默守護著。"},"ICON-0252":{"nm":"紀念日印章紙","de":"一按，又一天變得特別。憑著在平凡日期上「咚」地蓋下的小印，「今天」便悄悄把名字添上了想記住的日子名單。"},"ICON-0253":{"nm":"板夾封蓋","de":"縱使颳風，縱使雨潲，夾住的紙卻守到最後。自願當板夾鎧甲的我，是那些字句踏實的保鏢。"},"ICON-0254":{"nm":"檔案索引","de":"為了在厚厚資料中不迷失方向，伸出小小的舌頭告訴你「在這裡」。一張彩色標籤，一眼便能統御百張頁。"},"ICON-0255":{"nm":"分類標籤","de":"這個歸這格，那個歸那格。把世間的雜亂一行行整理得井然有序，便是我的工作。標籤一貼上，亂七八糟之物才終於各歸其位。"},"ICON-0256":{"nm":"迷你核決板","de":"「咚」地蓋下印章的瞬間，不知怎地便有了真正成為大人的感覺。尺寸雖小卻是俐落的權威，一枚通過章下去，堆積的事務便一一收尾。"},"ICON-0257":{"nm":"透明資料袋","de":"內裡一覽無遺，沒什麼好藏。它懷著重要的紙，怕被雨淋、怕被揉皺，以透明的身軀擁抱著，送到約定之處。"},"ICON-0258":{"nm":"出席打卡帶","de":"來了，又填上一格。當每日的足跡沿著帶子排隊堆疊，看不見的勤勉便終於成了一眼可見的紋路。"},"ICON-0259":{"nm":"錯題整理簿","de":"把答錯的記下來，並不是把羞愧攢起來。為了不在同一處跌倒兩回，把昨日的失誤改寫成今日的嚮導。"},"ICON-0260":{"nm":"行程印章板","de":"在空白行程表上蓋一個章，「約定」便產生了。手腕一甩便定下一天的魔法——那魔法其實是「提早張羅」這份勤快的另一個名字。"},"ICON-0261":{"nm":"書脊標籤","de":"是背對書架而立的書本們的名牌。寫在窄窄書背上的短短字句，從數百本之間一把招來你要找的那一本。"},"ICON-0262":{"nm":"照片保護膜","de":"徒手免談。它連一枚指紋都不許留下，輕輕將自身覆於珍貴的一格之上。喜歡的心意，便這樣以小心翼翼的手勢長長久久。"},"ICON-0263":{"nm":"底片索引紙","de":"為底片一格格標上號碼，散落的瞬間便重新尋回故事的順序。是把以光寫成的記憶照看得不致錯亂的小小嚮導。"},"ICON-0264":{"nm":"照片收納套","de":"把方形的幸福一張張供奉起來的透明之家。不必擔心邊角被壓，最珍愛的那張臉，在這裡頭四季常端整地閃耀著。"},"ICON-0265":{"nm":"迷你沖印信封","de":"剛沖出的照片餘溫尚未散去，小小的信封便張開雙臂接住懷抱。從掌心大小的口進去的一格，不知不覺便成了某人包包裡的寶物。"},"ICON-0266":{"nm":"光柵卡封套","de":"把傾斜便換表情的難纏照片，一道刮痕不留地守護好，是我的任務。要把每個角度的不同臉孔全都護住，我也得格外勤快才行。"},"ICON-0267":{"nm":"拍照分類標籤","de":"四格之中哪一格最佳，由標籤代你指認。把拍得好的與好笑的並排分開的這樁小事，正是讓回憶享受兩回的祕訣。"},"ICON-0268":{"nm":"四格收納帶","de":"把窄長的四格回憶端整地繞束起來。將那天欲飄散的笑容牢牢攬成一束，平安地帶到包包深處。"},"ICON-0269":{"nm":"照片角貼","de":"把照片貼進相簿時，輕輕托住四個角的小手。不必塗滿膠水也不脫落——所謂細膩，便是從邊角開始。"},"ICON-0270":{"nm":"沖印校色表","de":"再暖一點，再稍微暗一點。為了調出滿意的色調而把玩著數字的一張表，靜靜地把尋常的一格化作了作品。"},"ICON-0271":{"nm":"收據夾","de":"把皺巴巴的收據端整地咬住、絕不鬆口。用小小的嘴俐落地照管好一天的開銷，月底結算便輕鬆許多。"},"ICON-0272":{"nm":"預約確認單","de":"「已預約」這一行，便讓心緩緩放下。一張紙成了約定的證據，將雀躍一點一點保管到所等候的那天。"},"ICON-0273":{"nm":"歸還確認證","de":"把借來之物歸回原位的，雖小卻坦然的證據。這張紙握進手中的瞬間，壓在心頭一角的一筆債便輕快地抹去。"},"ICON-0274":{"nm":"保管證夾","de":"怕你弄丟取物的單據，就由我代你緊緊抓著吧。一張小紙的去向，有時也左右著某人一天的結尾。"},"ICON-0275":{"nm":"租借單尾標","de":"在每件借走之物上輕搖的小尾牌。順著這尾巴走去，誰拿走了什麼便一目了然，遺失之謎也即刻迎刃而解。"},"ICON-0276":{"nm":"驗收確認紙","de":"一件件以目光摩挲，查看有無缺漏。當核對記號排隊填滿時，看不見的細心，便終於得到「信賴」這個名字。"},"ICON-0277":{"nm":"結算便條袋","de":"把進帳與支出寫在信封上，雜亂的數字便沉穩地排起隊。結算的終點，總由這張小便條沉穩地畫上句點。"},"ICON-0278":{"nm":"配送標籤紙","de":"把要去往何處、抵達何人，寫在自己身上便啟程上路。這標籤一貼上，箱子便成了有了目的地的旅人，雀躍地出發。"},"ICON-0279":{"nm":"簽收確認帶","de":"把「已平安收到」這一句以一條帶子束好寄回。收件者的安心與寄件者的放心，在這條小繩上靜靜地彼此牽手。"},"ICON-0280":{"nm":"單字卡環","de":"怕散成單張就會遺失的單字們，由一個小環一併穿起抓牢。翻了又翻，陌生的詞語不知不覺便成了口中熟稔的朋友。"},"ICON-0281":{"nm":"發音便條帶","de":"在舌尖屢屢打滑的地方，掛上一個小小的記號。在口中迷路的陌生聲音，順著這便條走去，不知不覺便尋回了自己的發音。是把生澀的聲音一點點馴服的第一頁。"},"ICON-0282":{"nm":"翻譯便條盒","de":"跨越言語與言語之間的小橋，一座座細細折好收在格子裡。把好不容易揀選的一句話寫下悄悄遞出，原本不通的心意也隔著一張便條而靠近。"},"ICON-0283":{"nm":"佳句剪貼紙","de":"正中心扉的句子，得親手抄錄才留得長久。把從書角剪下的一行貼在書桌前，那些字句便靜靜托起了消沉的今日這一天。"},"ICON-0284":{"nm":"筆記索引","de":"為在厚書中不迷失方向而夾上的彩色小旗。「得知道回來的位置，才能徬徨得更遠」——探出頭的標籤在書頁間靜靜這樣告訴你。"},"ICON-0285":{"nm":"背誦確認籤","de":"在背好之物旁「咚」地按下的一點記號。它是把在腦中短暫停留便欲消逝之物拴住的小錨，每一格被塗黑的方格裡，都靜靜沾著昨夜流下的努力。"},"ICON-0286":{"nm":"測驗信封包","de":"在拆開信封之前，誰也不知道會冒出什麼。以指尖摩挲封口的那幾秒——一道題被細細折進其中，連那份怦然也一併封存的雀躍包裹。"},"ICON-0287":{"nm":"文法標籤筆記","de":"規則不是用腦記，而是用手熟稔的。從常翻那頁的色標，到被磨得柔軟的筆記本，那磨損的邊角，便成了你撐過的時間的年輪。"},"ICON-0288":{"nm":"口說練習表","de":"為世上最難開口的人準備的一張表。以手指一格格往下指，喉中顫抖的第一句話，也不知不覺尋回了自己的嗓音。因為勇氣也有它的次序。"},"ICON-0289":{"nm":"彩色草稿紙","de":"尚未完成的色彩粗略地橫躺著調息。並非正解，而是仍處於可能性的狀態——在這尚未修整的一張上，盛著比什麼都多的明日，盪漾不已。"},"ICON-0290":{"nm":"情緒板碎片","de":"把零零散散的印象聚在一處貼好，原本難以捉摸的氛圍便隱約顯出輪廓。一種尚無名字的感覺，由碎片彼此倚靠著，靜靜地指了出來。"},"ICON-0291":{"nm":"圖樣樣本冊","de":"包巾的格紋與窗櫺的編織，一冊冊井然整理在一起。同一花紋反覆到底的所在，棲息的不是怠惰而是約定——是守住一道紋理的堅定之心。"},"ICON-0292":{"nm":"服裝色樣紙","de":"明明是同一種光，每一塊布料卻沾染出不同的膚色與陰影。在挑選舞台服裝之前，以指尖反覆撫摸、躊躇不定的那一夜，原原本本地標本進一張小小的樣本裡。"},"ICON-0293":{"nm":"標誌禁用範例紙","de":"把不可為之事先一一工整寫下的紙。在劃了紅叉的輪廓之內，自由反而更顯清晰，原以為是死路的地方，反倒開出了新路。"},"ICON-0294":{"nm":"色感參考籤","de":"因為顏色實在無法以言語說明，才另行做好的樣本碎片。把晚霞最赤紅的某一剎那囚進小小掌心，好向下一個人精準地遞上「就是這個色」。"},"ICON-0295":{"nm":"排版草稿卡","de":"把什麼放在哪裡輕輕勾勒的第一張圖。決定位置這件事即是決定心意，因而在生澀散落的線條之間，整體的均衡緩緩睜開了眼。"},"ICON-0296":{"nm":"素材便條板","de":"木、土、石——可觸之物的名字密密麻麻寫著。唯有先以手讀過紋理再開始的人才知道的祕密：用什麼來造，便已大致半定了將成為什麼。"},"ICON-0297":{"nm":"圖樣描圖紙","de":"在底圖上覆一張薄紙，靜靜沿著線描摹。在暫借他人之路的同時，我的手熟悉了那條路，描摹的線條之間，不知不覺便悄悄長出了只屬於我的線。"},"ICON-0298":{"nm":"入場動線帶","de":"人們沿著長長貼在地上的帶子排隊魚貫而入。為使雀躍的腳步不致交纏而靜靜引導的一行——是托住雀躍不致崩塌的、看不見的溫柔之手。"},"ICON-0299":{"nm":"活動指引牌","de":"代你舉著「這邊請」這一句而立的牌子。為使人不致徬徨而豎在每個路口的小小親切，像牽手般靜靜領著初來者陌生的一天前行。"},"ICON-0300":{"nm":"攤位號碼標籤","de":"為每個攤位編上的一個號碼，分明地定下了那一格的主人。雖是小小的數字，卻是「這裡是你的位置」的約定，於是在陌生的活動場，便有了可歸返之處。"},"ICON-0301":{"nm":"工作人員同意書","de":"在決心攜手共事的場合留下的一行簽名。雖只是薄薄一張紙，裡頭卻載著願意彼此信任的分量，活動裡的每一份心力都正是從這裡開始。"},"ICON-0302":{"nm":"體驗券束","de":"厚厚一束、剛好握在手心的體驗券。它不是分送越多就越少，而是不斷為某人增添一個個「第一次」，越觸摸越溫暖的一束心意。"},"ICON-0303":{"nm":"排隊標示牌","de":"請從這裡開始等候——地面低聲這麼說著。守序的心一旦聚攏，長長的隊伍也成了一道風景，一個小小的標示便把焦急換成了從容。"},"ICON-0304":{"nm":"現場領取吊牌","de":"在親自領取預訂物品的地方輕輕掛上的小吊牌。握在手中那一刻，肩頭便緩緩放鬆下來的輕盈安心——是讓久候的心終於有了形體的一個結。"},"ICON-0305":{"nm":"隨機盒抽票","de":"在不知道裝著什麼的情況下挑選一個的樂趣。一晃動，裡頭叮噹作響的聲音便先讓心跳了起來，開啟前那短短一瞬，成了一天裡最膨脹雀躍的時刻。"},"ICON-0306":{"nm":"交換完成貼紙","de":"宣告互換順利結束的小小圓形印章。它是留在交付雙手之間光滑的句點，輕輕一貼，那筆交易才終於溫暖地圓滿起來。"},"ICON-0307":{"nm":"紀錄封緘帶","de":"用緞帶在珍貴的盒子上繞一圈，靜靜封好。既是請別隨意打開的託付，也是把裡頭之物視為珍寶的一份最安靜的禮節，全都凝在這一條帶子裡。"},"ICON-0308":{"nm":"祕密便箋膠囊","de":"把想說的一句話悄悄封進小小的筒裡保存。像埋藏沒能寄出的心意般牢牢闔上，直到有朝一日再次開啟的那天，掌心上這座小金庫都會替你守住時光。"},"ICON-0309":{"nm":"小剪貼卡","de":"剪下貼上的一小片裡，隱隱沾著那天的心情。比日記輕盈、比照片更有手感——容易從指縫間散落的一天，被掌心大小的紙片牢牢握住。"},"ICON-0310":{"nm":"初訪紀錄紙","de":"初次踏上這座島那天的悸動，化作短短一行留了下來。就在陌生轉為親切之前，那份最澄澈的初心，由紙片代為珍藏許久。"},"ICON-0311":{"nm":"回憶分類表","de":"依紋理與類別，一筆一筆細細分寫下回憶的表格。若把所有記憶胡亂堆進同一個抽屜，連最珍惜的那一天也會被埋沒，所以越珍貴的，越要為它好好安排一個位置。"},"ICON-0312":{"nm":"對話框便箋片","de":"想說的話像氣球般圓圓鼓起，浮在紙上。連難以開口的那一句，在圓圓的框線裡也悄悄鼓起了勇氣——是讓心意得以流瀉而出的小小溫暖通道。"},"ICON-0313":{"nm":"日期立架","de":"把今天是幾號端正地豎起、與你面對面的小底座。在一個接一個流逝的日子裡，挑出唯一的一天端坐正中央，再平凡的日期也會染上值得紀念的溫度。"},"ICON-0314":{"nm":"收藏編號吊牌","de":"為每一件珍愛之物逐一編上的專屬號碼。所謂收藏，是許下要把那唯一視為世上獨一無二的心願，於是小吊牌上的數字，清晰地刻著心的分量。"},"ICON-0315":{"nm":"典藏內襯","de":"為要長久珍藏觀賞之物，一張張夾入的薄薄內頁。把它與光與時間隔開薄薄一層——所謂愛一樣東西，終究是要好好把它保存下去。"},"ICON-0316":{"nm":"小卡卡套掛繩","de":"讓卡套能掛在頸間的纖細繩子。把本命安放在胸前走過一天，是追星的一種方式，整日溫柔的同行，全繫在這一條細繩上。"},"ICON-0317":{"nm":"小卡立架插銷","de":"一根小小的插銷，便讓小卡在桌上端正立起。橫放時只是一張紙，立起來才終於成了彼此對望的關係，靜靜為視線造出一處久久停留的位置。"},"ICON-0318":{"nm":"鐳射小卡膜","de":"隨角度傾瀉出彩虹的一層薄膜。將光微微鎖住的膜，為平凡的卡片披上星光，每當在腕間搖晃，便有不同的神情閃然甦醒——一場小小的魔法。"},"ICON-0319":{"nm":"小卡保護殼","de":"邊角只要被壓到一下，珍惜的心彷彿也跟著折了起來。它是緊緊擁住珍貴一張卡的透明鎧甲，真心去珍惜一件事，總會伴隨著這般的小心。"},"ICON-0320":{"nm":"小卡整理盤","de":"把數十張小卡依紋理整齊安放入眠的淺盤。散開時只是一堆，排好躺下便成了收藏，每一次整理的手勢，都把愛的次序一格一格刻了上去。"},"ICON-0321":{"nm":"小卡交換信封","de":"把一張小卡裝進信封遞出時，指尖會稍稍遲疑。這不是送走，而是拜託它去成為某人的本命。在折下信封口的瞬間，一段小小的緣分悄悄易了手。"},"ICON-0322":{"nm":"小卡裝飾筆","de":"填滿空白的不是字跡，而是心意。筆尖經過之處冒出小小的愛心與星星，平凡的一張紙便甦醒成世上獨一無二的應援。裝飾，正是告白的另一個名字。"},"ICON-0323":{"nm":"小卡夾環","de":"喀的一聲，夾子咬合的聲響。就憑那小小一鎖，差點散落的卡片便聚成一列。即使整天在包裡晃動，也不讓一個邊角受損。堅固，竟是這般安靜。"},"ICON-0324":{"nm":"小卡收納袋","de":"開合拉鍊的手勢裡，不知不覺已養成了習慣。即便遇上驟雨、即便被人潮推擠，唯獨裡頭始終乾燥。把最珍愛的放在最深處的心，便是「攜帶」這份溫柔的勞動。"},"ICON-0325":{"nm":"粉絲見面會手環帶","de":"有位粉絲久久記得，替自己把帶子繫上手腕的工作人員，那雙手很溫暖。一個結，便是今天屬於這個場合的印記。怕它鬆開而多繞一圈的那條帶子，牢牢握住了一整天份的雀躍。"},"ICON-0326":{"nm":"入場手環","de":"就在通過入口的那一刻，裡與外才終於清晰地分了開來。戴上一整天後不知不覺與肌膚相熟，要解下時，總會留下一道細細的痕。像是曾置身那處的證據。"},"ICON-0327":{"nm":"談話環節籌碼","de":"談話環節一開始，一枚籌碼便骨碌碌滾了出去。誰先開口、會抽到什麼問題——那小小的偶然，能把整個氣氛翻轉過來。比起排好的腳本，一枚籌碼的善變更教人喜愛。"},"ICON-0328":{"nm":"簽名會候號票","de":"手裡握著寫有號碼的紙片排隊。142號。在數著前面141人的同時，心臟早已先一步在數著輪到自己的次序。等待雖長，卻多虧這一張，連那段時光也成了雀躍的一部分。"},"ICON-0329":{"nm":"擊掌手套","de":"在掌心相觸的那一瞬，手套替你接下那短短的暖意。為了0.5秒的相會，整天暖著的手。即便隔著布料，也擋不住那份顫動——人人都是到那時才明白。"},"ICON-0330":{"nm":"紀念拍照別針","de":"喀嚓一聲，今天便原封不動地被定格了下來。被別針固定的畫面裡，連笨拙的笑容，日後也成了最教人懷念的一幕。紀錄，是想留住瞬間的、最溫柔的一份貪心。"},"ICON-0331":{"nm":"座位緞帶吊牌","de":"繫在座椅椅背上的小緞帶，明明無風卻輕輕搖曳。那是有人繫下的標記，是這裡曾有人在過的痕跡。演出散場後的空位上，唯獨緞帶彷彿仍記著那段節拍。"},"ICON-0332":{"nm":"禮物檢核標籤","de":"一份份禮物都貼上了標籤。送出了沒、確認了沒、有沒有漏掉的。連接受心意這件事也需要打理，這枚小貼紙便把一份份用心毫無遺漏地串連起來。"},"ICON-0333":{"nm":"紀念內襯","de":"為了長久觀賞而寫下的一張紙。那天的天氣、座位號碼，乃至最後一首歌的曲名。記憶會淡去，唯獨這張內襯不會褪色。原來收藏回憶，也需要一點小小的格式。"},"ICON-0334":{"nm":"應援毛巾扣環","de":"在毛巾末端扣上環，它便不會從肩上滑落。在擦汗、舉過頭頂揮舞、再掛回頸間的那些動作之間，一個小小的連結，讓應援的身姿綿延不斷。"},"ICON-0335":{"nm":"標語夾","de":"夾子牢牢咬住標語的兩端。即便高舉雙臂，字也不會折起或被風吹捲。在看不見的地方默默把訊息撐直的、最沉默的配角，就在這裡。"},"ICON-0336":{"nm":"防噪音收納袋","de":"拉鍊緩緩地、無聲地滑過。在約定要安靜的場合，為了不讓一絲雜音洩出而設計的沉默。所謂體貼，有時便是讓自己不被聽見——這只袋子靜靜地這麼說著。"},"ICON-0337":{"nm":"拍手節奏籌碼","de":"每當掌心相擊，籌碼便數著節拍。啪、啪、啪——四散的掌聲不知何時匯成了同一個節奏。讓數千人的拍手化為同一個呼吸的那場魔法，由小小的籌碼悄悄相助。"},"ICON-0338":{"nm":"應援法手冊","de":"翻開來，應援法一步步寫得清清楚楚。哪一句該舉什麼顏色、何時該喊出聲。初來乍到的人有了這一本，也立刻成了一家人。是一本分享約定的小指南。"},"ICON-0339":{"nm":"座位扇子掛繩","de":"在扇柄繫上繩，即便失手也不會掉落。炎熱的日子搧著搧著、雙手因歡呼而需要自由時，它便在腕間晃啊晃。一條繩子，把暑氣與興奮一併消解。"},"ICON-0340":{"nm":"閃亮膜碎片","de":"一受光，每一片便以不同的角度碎裂開來。放在掌心，便有小小的彩虹忽隱忽現，每一晃動，顏色都活了過來。所謂閃耀，或許就是把光細細地分而共享。"},"ICON-0341":{"nm":"小型橫幅桿","de":"把小桿展開，布料便迎風繃得緊緊的。雙手高舉，字便能越過觀眾席傳到遠方；一收，又「咻」地塞進包包一角。心意的大小，可不是用桿子的長度來量的。"},"ICON-0342":{"nm":"應援貼紙包","de":"一張張貼紙上都印著應援字句。貼在手帳上、手機上、筆電的邊角——每貼一處，日常便染上了應援的色彩。喜歡的心意，就這樣在處處留下痕跡。"},"ICON-0343":{"nm":"專輯保護封套","de":"用封套包覆專輯的手勢格外小心。怕邊角磨損、怕被陽光曬褪。音樂用耳朵聽，但這一張卻由手記著。是想把心愛之物長久留在身邊的、心的鎧甲。"},"ICON-0344":{"nm":"唱片內袋環","de":"把唱片放進內袋、再用環扣起來，便成了一本唱片冊。一張張翻動時那沙沙的聲響真好聽。把四散的音樂在掌中整齊聚攏，便是收藏家安靜的幸福。"},"ICON-0345":{"nm":"周邊收納隔板","de":"一塊隔板，便讓差點混作一團的周邊各歸其位。這裡是小卡、那裡是鑰匙圈，旁邊是應援棒。整理，就是替物品蓋一座家。隔出格子的那一刻，雜亂便化作了秩序。"},"ICON-0346":{"nm":"隨機包封口繩","de":"用繩把隨機包的開口綁緊，誰的命運都還未定。在拆開之前，每個人都是期待的主角。解開封緘時指尖的那份顫動，正是這條繩守護下來的樂趣。"},"ICON-0347":{"nm":"特典整理盒","de":"特典在盒裡依種類排起隊。明信片歸明信片、書籤歸書籤。看著越填越滿的格子，一路收集的時光便一目了然。整理，正是回憶的清單。"},"ICON-0348":{"nm":"版本辨別標籤","de":"有些看似相同卻並不相同。一枚標籤，便把A版與B版、初版與再版分了開來。多虧這小小的標記，混淆消失了，收藏的世界也多了一張清晰的名牌。"},"ICON-0349":{"nm":"初動確認便箋","de":"發行首週，一個數字便讓心起伏不定。便箋上工整記下的確認標記。幾天的紀錄一旦匯聚，便成了一份小小的應援成績單。是把喜歡之心翻譯成數字的、用心的習慣。"},"ICON-0350":{"nm":"海報固定蓋","de":"在捲起的海報末端套上蓋子，它便能攤平著乖乖安住。在猶豫該掛上牆、還是裝進相框的同時，也不讓它皺起。是把最喜愛的場景端正守護住的小小蓋子。"},"ICON-0351":{"nm":"立式照片底座","de":"照片在底座上斜斜立起。桌子一角，恰好與視線齊高的角度。是讓每次經過都能與之四目相對的發明。把喜愛的臉孔請進每日風景裡，最簡單的方法。"},"ICON-0352":{"nm":"彩排膠帶捲","de":"在地板貼上膠帶，標出該站的位置。一格、兩格，準確就在這裡。同一道痕跡踩上數十遍，動線便刻進了身體。華麗的舞台底下，鋪著這誠實的膠帶痕跡。"},"ICON-0353":{"nm":"舞台動線別針","de":"釘在舞台地板上的一根別針，指引著下一個步伐。即便在黑暗中，腳尖也會先一步尋向那個位置。看不見卻精準的路，是無數次練習所描繪的、一張看不見的地圖。"},"ICON-0354":{"nm":"工作人員耳塞蓋","de":"戴上耳塞蓋，觀眾席的歡呼便隔了一層而低沉，唯獨傳遞提示的聲音變得清晰。舞台後方工作人員的耳朵，總是同時聽著兩個世界。是在喧囂中揀出信號的小工具。"},"ICON-0355":{"nm":"休息室衣架牌","de":"每個衣架上都掛著名牌。1號服裝、2號服裝、安可服裝。看著那張寫滿換裝次序的牌，一整天的舞台便以衣裝的順序預先描繪出來。是駕馭忙亂的安靜秩序。"},"ICON-0356":{"nm":"道具檢核標牌","de":"登台之前，每一件道具都掛上標牌。有沒有漏的、完不完好。觀眾席不會知道，但這小小的檢查防住了事故。看似完美的舞台背後，總有一雙細心的手。"},"ICON-0357":{"nm":"提示信號籌碼","de":"提示信號的籌碼在手與手之間傳遞。就是現在，進場。不用一句話，時機便傳達了過去。在舞台旁的黑暗中，這小小的信號牢牢守住所有人的節拍，不讓它錯失。"},"ICON-0358":{"nm":"後台通行徽章","de":"有道門，只有別上這枚徽章的人才得以通過。在舞台後方，歡呼隔著牆傳來的地方。一小片布料，分隔了華麗的台前與忙碌的台後。是撐起舞台之人的標記。"},"ICON-0359":{"nm":"提詞機遮光板","de":"遮光板替你擋住提詞機的光，不讓它洩向觀眾席。只讓台上的人看見、看的人卻渾然不知。靜靜遮住一份不該被察覺的幫助，是舞台彬彬有禮的祕密守護者。"},"ICON-0360":{"nm":"休息室鏡子罩","de":"演出結束的休息室，用布把鏡子罩起。整日映照無數神情的玻璃，暫時闔上了眼。卸了妝的素顏最後面對的，不是鏡子，而是一片靜謐的黑暗。"},"ICON-0361":{"nm":"預錄入場手環","de":"一旦扣上、不剪斷便解不開的小小帶子。為了進入預錄觀眾席的唯一一張資格，有人搭上了天還沒亮的首班車。手腕上的分量，便成了那天一整日份的雀躍。"},"ICON-0362":{"nm":"錄影候場標籤","de":"在紅燈亮起的前一刻，把所有人的呼吸繫成一線，便是我的工作。在等候提示的寂靜裡，我默默撐到最後。被撕下的瞬間，正式播出的帷幕才終於升起。"},"ICON-0363":{"nm":"攝影機位置籌碼","de":"地上釘印的一個小標記，俐落地定下了六台攝影機的走位。該從哪裡入鏡才最明亮，導演早在彩排前就已知曉。是在畫面之外，預先描繪畫面之內的一雙手。"},"ICON-0364":{"nm":"音響檢測標籤","de":"對著空蕩的觀眾席輕輕敲打麥克風。回音若長，天花板便再添一層吸音材。在觀眾不知情的時候，把聲音的紋理一一打磨的用心，便從這小小的標籤靜靜開始。"},"ICON-0365":{"nm":"現場集章本","de":"每經過一處現場，便集滿一格印章。每一道暈開的墨痕裡，都一同印下了那天的天氣與悸動。集滿的那一頁，成了誰也模仿不來、唯獨屬於我的足跡地圖。"},"ICON-0366":{"nm":"電視台訪客證掛繩","de":"少了這條繩，大廳的閘門便不會開啟。掛在頸間、一步步走過走廊的同時，昨日還只在螢幕上見過的世界，慢慢近到伸手可及。"},"ICON-0367":{"nm":"攝影棚鞋套包","de":"攝影棚的地板總是又冷又滑。脫下鞋、穿上薄薄的鞋套，腳步聲便悄悄消失。攝影機收進畫面的是舞蹈，不是腳步聲，所以抹去聲響，也是對舞台的一份禮節。"},"ICON-0368":{"nm":"休息室點心吊牌","de":"彩排與正式播出之間，飢餓總是最誠實地找上門來。休息室一角，每份點心上都寫著是誰的份的小名牌。那份體貼地預備好的溫柔，讓漫長的一天得以撐到最後。"},"ICON-0369":{"nm":"監看筆記帶","de":"回放著畫面寫下筆記。這裡注意視線、那裡慢半拍。密密麻麻的字，是寫給明天的我的祕密信。末端貼上的這條帶子，是要比昨天進步一寸的安靜約定。"},"ICON-0370":{"nm":"展示會邀請內襯","de":"一張紙，對某人而言或許是整整一年的等待。「邀您出席展示會」這短短一句，連同拆開信封時指尖的顫動，化作了世上最小的一張邀請函。"},"ICON-0371":{"nm":"媒體證掛繩","de":"掛在採訪人員頸間，穿梭於快門聲的正中央。為尋最佳角度而奔忙的腳步，那份速度，便成了把舞台的熱度傳向外界的通道。"},"ICON-0372":{"nm":"謝幕順序表","de":"好讓掌聲嘩啦傾瀉而下的瞬間也不致亂了陣腳，把誰先誰後一一寫成一列。最後謝幕的排序，向來與初次登場一樣，是用心編排出來的。"},"ICON-0373":{"nm":"拍照牆地面標記","de":"拍照牆前的地面，早已刻好了該擺放腳尖的位置。只要偏一步，背景的標誌就會被切掉。拍得最明亮的那個位置的祕密，悄悄標記在腳下。"},"ICON-0374":{"nm":"試映會手環","de":"在劇院燈光熄滅前一刻扣上手腕的小帶子。帷幕一升起，所有人便在同一片黑暗裡，生平第一次相遇同一個畫面。是曾與彼此共處那第一瞬的、小小的入場印記。"},"ICON-0375":{"nm":"紀念布幕碎片","de":"末場那天，最後謝幕之後，布幕緩緩落了下來。剪下其中一幅、裝進相框的碎片。布上還微溫地沾著燈光的熱度與掌聲的震動，尚未冷卻。"},"ICON-0376":{"nm":"首度公開印章","de":"為了向世界初次揭開面貌的那天、那唯一一次而刻的印章。不會有第二次的初次公開，所以連墨水乾去的短短一瞬，都是再也不會回來的時光。"},"ICON-0377":{"nm":"舞台片段卡","de":"把某場舞台上最耀眼的一格剪下，收進了卡片。音樂與燈光雖已停下，但握在手中的瞬間，那天的歡呼便在耳邊再度膨脹起來。是讓定格畫面復甦的小小魔法。"},"ICON-0378":{"nm":"結尾姿勢便箋","de":"在最後一個音符結束的剎那，畫下該定住的指尖與視線角度的便箋。唯有深知一個結尾畫面能左右好幾天的人，才會把這小小的圖珍重地折好收起。"},"ICON-0379":{"nm":"巡演城市別針","de":"地圖上，每去過一座城市便插上一根別針。釜山的海風、光州的正午，都釘在這小小的釘尖上。把那些點靜靜連起，便看見一條橫貫一整個季節的漫長旅程之線。"},"ICON-0380":{"nm":"座位區夾","de":"把數萬個座位分成區塊來引路。為了不迷路、不相撞。只要跟著我，誰都能抵達自己的位置。所謂秩序，終究是為了所有人的一份小小善意。"},"ICON-0381":{"nm":"入場閘口吊牌","de":"在閘口前，一個接一個依序通過確認。是把握票的手與雀躍的心放進場內的最後一道關卡。通過我的瞬間，漫長的等待便結束，今天的舞台就此開始。"},"ICON-0382":{"nm":"手環收藏膠囊","de":"即便顏色褪去，那天的歡呼仍原封不動地被封存。捨不得丟掉手腕上的帶子，便細細捲好收進小膠囊裡。連珍貴的回憶，也想為它備一格安身的位置。"},"ICON-0383":{"nm":"現場交遞桿","de":"粉絲與舞台之間，有什麼從手傳到了手。或許是封信，或許是份小禮。我為那份心意鋪路、讓它平安抵達，是現場最忙碌的一座橋。"},"ICON-0384":{"nm":"演出日期封籤","de":"那天的日期被印進圓圓的封籤裡，永遠停了下來。日曆會翻頁，唯獨這小小的圓會原地停留在那一天。遇上不想遺忘的日子，人們總會把什麼封存起來。"},"ICON-0385":{"nm":"巡演背包貼布","de":"一同巡演的背包上，每座城市便添上一片貼布。縫在布上的地名，不知不覺成了一份履歷。連磨損起毛的邊角，也成了曾一同走遍各地的證據。"},"ICON-0386":{"nm":"票牌掛繩","de":"在入場隊伍尾端搖晃的牌子，牢牢綁住它一端的一條繩。在高舉著票的雙手長長排開的風景裡，我靜靜標出那列雀躍隊伍的最前端。"},"ICON-0387":{"nm":"安可緞帶碎片","de":"在呼喊安可的聲音最響亮的那一夜，裝飾舞台的緞帶掉下了一片。像因不捨結束而唱得更長的歌一般，這片緞帶上，也打著不想離去的心結。"},"ICON-0388":{"nm":"訊息膠囊瓶","de":"玻璃瓶裡細細折好放入的一句話。像盼望終有一天能抵達而放流的小船，我懷著心意，在時光之上緩緩漂泊。直到被開啟的那天，約定都在裡頭靜靜沉睡。"},"ICON-0389":{"nm":"小小告白吊牌","de":"把難以開口的話寫在小吊牌上，悄悄夾了進去。字跡雖在發抖，唯獨真心格外清晰。最小的一張紙，有時懷著最大的勇氣。"},"ICON-0390":{"nm":"匿名應援紙條箱","de":"即便不署名，心意也能傳達。進到箱裡的每張紙條，都把某人的應援匿名地一張張疊起。即使不知是誰寫的，唯獨溫暖格外清晰——是一本沒有臉孔的溫柔合集。"},"ICON-0391":{"nm":"摺心紙","de":"方方的紙隨著指尖化作紙鶴、化作星星。每摺一次，所盼的心願也一層層疊了上去。在用心摺出的形狀裡，棲著比言語更長久的真心。"},"ICON-0392":{"nm":"封緘緞帶火漆","de":"滴下燭蠟、用印章重重一壓，信便終於封好。一如那把心意牢牢凝固的古老方式。在漸漸冷卻的紅色蠟上，一個祕密靜靜上了鎖。"},"ICON-0393":{"nm":"禮物緩衝紙","de":"怕禮物受損，便柔柔地把它的周圍包覆起來。每一道皺褶的紋理裡，都滲著別碎掉的叮囑。是收禮的人不會察覺、不顯眼之處的、一層小心翼翼的心意。"},"ICON-0394":{"nm":"彩色信繩","de":"綁信的繩也有顏色。黃色是應援，藍色是思念。把言語道不盡的情感，挑一種色彩來打結。還沒解開，心的溫度便已先一步傳到了指尖。"},"ICON-0395":{"nm":"手寫遮蓋帶","de":"在遞出之前一刻都把字跡遮住的一條帶子。把怕被看穿而忐忑不安的告白，守護到最後一刻。輕輕一掀便顯露的真心，那份顫動的分量，我在最近處最是明白。"},"ICON-0396":{"nm":"應援句籌碼","de":"在應援棒如波浪翻湧的夜裡，要齊聲喊出的那一句，刻在籌碼之中。是把四散的心聚成一線的約定之語。當大家一同呼喊時，那句話便閃耀得最為明亮。"},"ICON-0397":{"nm":"老舊練習室鑰匙圈","de":"把練習室的門開了又關數百回的鑰匙圈。漆已剝落、環已鬆動，但那上頭以手垢留住了最笨拙時期的汗水。所謂老舊，正意味著曾經停留得那麼久。"},"ICON-0398":{"nm":"舞台妝筆碎段","de":"舞台妝唯有在燈光底下才終於完成。那濃色的一截。為了汗也不暈而牢牢上妝的痕跡裡，原原本本滲著想把表情傳到遠方觀眾席的那份用心。"},"ICON-0399":{"nm":"耳塞收納盒","de":"在舞台上讓自己聽見自己嗓音的小小耳塞。演出結束後，便細細地讓它躺進盒裡。越是在最近處傳遞音樂之物，越想更用心地為它保管。"},"ICON-0400":{"nm":"個人置物櫃標籤","de":"宿舍走廊盡頭，每個置物櫃上貼著的名牌。告訴你這是誰的位置的小小字跡，把陌生的空間變成了家。有了自己的一格，便是「你留在這裡也好」的一份溫柔許可。"},"ICON-0401":{"nm":"隨身護嗓瓶","de":"彩排空檔，慢慢嚥下一口溫水。嗓子是歌手借來使用的樂器，所以趁它變涼前便先注滿的這只小瓶，預先守住了明天的第一個音。珍惜的心，總是這般安靜。"},"ICON-0402":{"nm":"行程提醒別針","de":"在以分鐘為單位密密排滿的一天上，一根別針指向下一格。在那緊密的格線之間，最教人欣慰的，是空著的那一格。可以稍稍望望窗外的時間，就在那兒小小地藏著。"},"ICON-0403":{"nm":"休息室毛毯夾","de":"妝都化好了、靠在椅上打盹的那個午後，有人輕輕在肩上替我蓋上毛毯。為了不讓它滑落而咬住的這個夾子，把那份手心的暖意一路握到登台之時。"},"ICON-0404":{"nm":"小香水樣品","de":"在手腕內側輕輕一拍，香氣便只在一掌之內綻放。不必飄向遠方也無妨。正因是只有靠近的人才察覺得到的痕跡，才更隱密，也才更像我自己。"},"ICON-0405":{"nm":"練習服洗滌吊牌","de":"無論洗幾回，深深沁進布料裡的汗味終究無法全然抹去。把曬在陽光下、蓬鬆乾透的練習服重新疊起時，我想——那抹不去的痕跡，其實才是最誠實的印記。"},"ICON-0406":{"nm":"燈光色片膜","de":"夾上薄薄一張色片，白色的燈光便暈染成晚霞色，再疊一張，便降下了破曉。要把舞台染成哪個季節、連光也要替它穿上衣裳的那雙手，正在幕後屏息以待。"},"ICON-0407":{"nm":"聚光鏡頭蓋","de":"即便攝影機關著的時候，也有人會掀開這小小的蓋子去擦拭鏡頭。為了還沒拍下的下一幕。在不會被收進畫面的時光上，最忙碌的一雙手，預先對好了焦。"},"ICON-0408":{"nm":"舞台反光板","de":"有一塊板，即便自己不發光，也把接到的光朝向陰影中的臉龐反送回去。舞台正中央之所以如此明亮，是因為邊緣有一隻手臂默默調著角度、為人照亮。"},"ICON-0409":{"nm":"彩色濾片內襯","de":"在透明內襯裡夾上藍光，觀眾席便整片化作大海；換成紅光，那兒便落下了晚霞。同一座舞台憑一種顏色就成了不同季節的魔法，便從這薄薄一層開始。"},"ICON-0410":{"nm":"燈光編號別針","de":"為數眾多的每盞燈，都貼著小小的號碼。哪一盞亮起、哪一盞沉睡，今晚演出的流程，早已依這些數字的順序預先編排好。耀眼的帷幕背後，總攤著一份細心的清單。"},"ICON-0411":{"nm":"燈光膠帶標記","de":"暗場的舞台地板上，螢光膠帶靜靜照亮腳步該停的位置。觀眾席看不見，但表演者的腳尖會摸索著這微弱的光，尋向自己的位置。即便在黑暗中，也有溫柔的引路人。"},"ICON-0412":{"nm":"陰影遮擋板","de":"擋住洩入之光、讓陰影清晰落下的板。駕馭黑暗，終究也是駕馭光，所以要呈現什麼，先取決於要靜靜遮住什麼。"},"ICON-0413":{"nm":"照度檢測籌碼","de":"測量空間明亮度的小籌碼，在掌心上讀出數字。太亮、太暗，眼睛都不舒服。人待著最自在的那條看不見的適切界線，由這枚籌碼靜靜守護。"},"ICON-0414":{"nm":"聚光燈遮罩","de":"為了不讓聚光燈洩向別處而加上的遮罩。把光只聚到一個人身上，是一份溫柔的專注。踏進那圈圓圓光暈裡的瞬間，世界便暫時只凝望著唯一的一人。"},"ICON-0415":{"nm":"耳塞套組","de":"與耳朵嚴絲合縫的一對耳塞。尺寸只要稍有偏差聲音便會漏出，一漏，便錯了節拍。舞台上分毫不晃的歌唱，其實有時便始於這小小一只橡膠。"},"ICON-0416":{"nm":"線材魔鬼氈","de":"把糾纏的線整齊綁成一束的魔鬼氈帶。越是無人觀看的後台，整潔越顯耀眼。一束線材的端整，靜靜撐起了台前流淌不晃的聲音。"},"ICON-0417":{"nm":"線路檢測標籤","de":"數十條線上，用手寫標出各是哪件樂器的名牌。歪歪斜斜的那一個個字，唯有各守其位，原本各自為政的聲音才終於匯流成一首曲子。"},"ICON-0418":{"nm":"靜音墊","de":"連腳步聲與震動也靜靜吞下的一張靜音墊。鋪在非得安靜不可的地方。最清澈的聲音，有時正是在這不洩出半點雜音的安靜地面上，才終於誕生。"},"ICON-0419":{"nm":"音效測試代幣","de":"演出前對音的這段時間裡，在手心漸漸變暖的代幣。每檢查完一支麥克風、一只喇叭，便換手握住。正式舞台的完美，便在這安靜的預演中一步步雕琢而成。"},"ICON-0420":{"nm":"麥克風防護蓋","de":"因為是無數嗓音觸碰過的地方，便更用心擦拭包覆麥克風頂端的這個蓋。是承載歌聲的器皿，對歌手而言無異於另一隻手。擦拭的同時，預先描摹明天的第一句歌詞。"},"ICON-0421":{"nm":"防噴罩夾","de":"在唇與麥克風之間垂下的薄薄一層網。多虧固定那層膜的小夾子，原本粗糙洩出的氣息，不知不覺被打磨成圓潤柔和的嗓音流瀉而出。"},"ICON-0422":{"nm":"音響機櫃標牌","de":"漆黑的後台，為了不在層層堆疊的器材架間迷路而掛上的小標牌。填滿觀眾席的華麗聲響，其源頭總是這樣井然有序地整理在幽暗之處。"},"ICON-0423":{"nm":"喇叭網罩別針","de":"牢牢固定喇叭網罩的別針。聲音湧出的窗口，是最先沾上灰塵的位置，便用薄薄一層網守住音色。觸及耳朵的一切，都被一層層披上了看不見的保護。"},"ICON-0424":{"nm":"走位標記貼紙","de":"釘點貼在地板上的走位貼紙。群舞之所以整齊如刀的祕密，其實藏在腳下。在數十人踩著同一個點散開又再聚攏、無數次約定下來的痕跡之上。"},"ICON-0425":{"nm":"旋轉練習圓盤","de":"原地不停旋轉的練習用圓盤。要克服暈眩，得先從把視線釘在一個點上學起。無論轉得多快都不放開那一點，是慢慢刻進身體裡的平衡。"},"ICON-0426":{"nm":"護膝膠帶捲","de":"牢牢纏住膝蓋的一捲膠帶。跳了上千次、落地了上千次的關節終究沉默不語，但這一層靜靜把那份沉默撐住。撐到最後的身體背後，總有某人的照料。"},"ICON-0427":{"nm":"腳尖對齊板","de":"把腳尖的角度整齊擺正的板。人們都說，舞蹈比起指尖，是在腳尖才終於完成。朝同一方向伸出的數十只腳尖匯聚起來，便造出眾人看似一人的魔法。"},"ICON-0428":{"nm":"練習室防滑墊","de":"鋪在練習室地板的防滑墊。要盡情跳躍，得先安全。在不必擔心跌倒、能放心翻滾的地面上，最大膽、最無懼的動作才終於綻放。"},"ICON-0429":{"nm":"動作分解卡","de":"把編舞一拍一拍細細拆開畫下的卡。再難的動作，一格格分開後不知不覺也跟上了。舞台上行雲流水般流暢的銜接，正是由這些斷開背熟的圖匯聚而成。"},"ICON-0430":{"nm":"鏡子遮簾別針","de":"把練習室鏡子暫時遮住的簾子，由這根別針固定住。不看映出的身影，唯靠身體的感覺起舞的時間，也是必要的。蓋住鏡子的瞬間，便明白音樂終於滲進了肌膚。"},"ICON-0431":{"nm":"數拍計珠","de":"骨碌一聲，每一拍便用指尖把一顆珠子撥過去地數拍。像古老的算法般能握在手中。作為音樂骨架的節拍，得這樣用摸得到的東西去熟練，才終於牢牢長進身體裡。"},"ICON-0432":{"nm":"暖身確認繩","de":"標示身體有沒有充分舒展開的確認繩。正式練習之前，總是先迎來沉著的準備。比起受傷後才後悔，繫上一條繩、慢慢喚醒身體，終究更能跳得長久。"},"ICON-0433":{"nm":"服裝編號夾","de":"為了不讓好幾套服裝混在一起而咬上編號的夾子。在喘不過氣的換裝之間，只要搞錯一套便是大事，所以每件衣服上都清楚寫著各自的次序。忙亂也得有秩序撐著才優雅。"},"ICON-0434":{"nm":"修補室針插","de":"放在修補室一角的針插。把綻開的縫線、掉落的鈕釦默默補好的手，停駐於此。舞台上一絲不亂的衣著背後，藏著從沒看過舞台一眼的針腳的用心。"},"ICON-0435":{"nm":"布料碎片環","de":"把多餘的布料碎片串成一環。為了正式衣服受損時備用，便預先留下一模一樣的布。盼著別出事而備好的這份小小準備，反倒在大事臨頭的瞬間救了舞台服裝一命。"},"ICON-0436":{"nm":"速縫鈕釦包","de":"急用時能立刻縫上的一包鈕釦。演出前一刻若有顆鈕釦啪地掉落，整間化妝室會頓時一陣騷動。是把那短暫而驚險的緊急一舉平息的、雖小卻無比可靠的急救箱。"},"ICON-0437":{"nm":"舞台腰帶固定座","de":"把舞台服裝的腰帶牢牢扣住的固定座。即便激烈地跳躍旋轉，衣服也不會散亂。在舞台上盡情享受的那份自由，正是來自把看不見之處俐落地收束好。"},"ICON-0438":{"nm":"羽毛除塵刷","de":"燈光底下，連一點點起毛都格外顯眼，便用羽毛刷在服裝上輕輕掃過。就在踏向舞台的前一刻，最後整理衣裝的那份溫柔手勢，向來都交給這柔軟的羽毛。"},"ICON-0439":{"nm":"休息室拖鞋吊牌","de":"休息室裡每雙拖鞋上貼著的名牌吊牌。在一張寫著是誰的小標上，悄悄載著「我們是同一隊」的安心。脫了鞋、伸開腳的那個房間，成了後台最安適的家。"},"ICON-0440":{"nm":"造型夾板","de":"整理頭髮時，把髮絲分股固定住的夾板。在一絲一絲打理的同時，手指把快散開的髮絲暫且託付給這個夾子。所謂端整，終究是由這些小小的停頓匯聚而成。"},"ICON-0441":{"nm":"別針整理膠囊","de":"縫線綻開的清晨，打開膠囊蓋，便見小而冰涼的銀光整齊躺著。在看不見的內側把服裝固定得最牢的手——別針，總在舞台後方默默工作。"},"ICON-0442":{"nm":"鏡頭清潔布","de":"呼，吹一口氣、畫著圓圈擦拭，霧濛濛的世界便清晰了起來。因為喜歡那短短的剎那，便老忍不住擦起鏡頭。是替某人代為拭亮視野的、一張小小的春陽。"},"ICON-0443":{"nm":"三腳架橡膠腳","de":"在三只腳尖套上橡膠，地板便不再哀號。當那小小的一點吞下晃動，畫面裡的風景便如謊言般靜了下來。安定，向來都從腳下安靜地開始。"},"ICON-0444":{"nm":"攝影機防雨罩","de":"即便雨珠骨碌碌滑落，鏡頭也乾爽地收著世界。戶外拍攝陰沉的午後，攝影機上輕輕罩上透明的雨衣。珍貴的東西，總要在淋濕之前先包覆起來。"},"ICON-0445":{"nm":"拍攝標記膠帶","de":"站這裡、轉那邊——一道道彩色的短痕，不發一語卻清清楚楚地指明該走的路。舞台結束便毫不留戀地撕去，但熟悉的腳尖，仍會把那個位置久久記著。"},"ICON-0446":{"nm":"片段分隔夾","de":"一口咬住快散開的紙張的小夾子。喀的一聲清脆，昨天與今天便整齊地綁在了一起。整理，是把差點弄丟之物靜靜握住的一種溫柔習慣。"},"ICON-0447":{"nm":"白平衡板","de":"把白色的板照向畫面，色彩便悄悄各歸其位。泛黃的晚霞、泛藍的破曉，都毫不作假。一塊懂得真正白光的板，讓其餘的色彩誠實地說出自己。"},"ICON-0448":{"nm":"記憶收藏罐","de":"小小的鐵皮罐裡，回憶的記憶卡正安然沉睡。一掀開蓋，喀嚓一聲，往昔季節的畫面便傾瀉到掌心。記憶就這樣被妥妥盛在一只堅固的罐裡停駐。"},"ICON-0449":{"nm":"螢幕遮光罩","de":"在螢幕四周圍上黑色的遮簷，光的反射便戛然而止。即便在陽光傾瀉的窗邊，畫面也不失自己的色彩。要看得清楚，得先遮住雜光——遮光罩靜靜這麼提醒著。"},"ICON-0450":{"nm":"攝影棚隔音別針","de":"卡在門縫的一根小別針，悄悄切斷了外頭的噪音。走廊的腳步聲、隔壁房的笑聲，到這裡便再也傳不進來。要收進清澈的聲音，得先築起沉默才行。"},"ICON-0451":{"nm":"化妝海綿組","de":"柔軟的海綿一塊塊整齊疊放成一束。用指尖輕輕拍打蜜粉，臉色便亮上一個色階。舞台上燦爛的笑容背後，總藏著這些溫柔的手感。"},"ICON-0452":{"nm":"髮夾收納盒","de":"容易遺失的小髮夾的整潔之家。掀開蓋子，銀光便並排列隊相迎。散落時看不見，聚攏起來卻格外安心——再小的東西也需要自己的家。"},"ICON-0453":{"nm":"刷具殺菌筒","de":"整日含著色彩的刷具，在筒中沐浴紫外線。看不見的光洗去舊垢的同時，明日的筆尖便如初般清爽。潔淨也是用心的一種紋理。"},"ICON-0454":{"nm":"粉撲收納網","de":"圓滾滾的粉撲在網袋裡靜靜調息。風從網眼間進出，鬆軟便能持久。一顆晾乾的粉撲裡，預先盛著明早的明媚。"},"ICON-0455":{"nm":"定型噴霧蓋","de":"嘶——噴一下，任憑風吹也不凌亂。為精心打理的髮型守住整夜的小瓶蓋。在牢牢定型的髮絲上，明亮的燈光如碎光般傾瀉而下。"},"ICON-0456":{"nm":"唇刷護套","de":"輕輕包裹纖細刷尖的小蓋子。即使在包裡晃來晃去，刷子也能筆直又乾淨地被守護著。珍惜一支小刷子的心意，成就了唇上那一筆色彩。"},"ICON-0457":{"nm":"候場號碼鏡","de":"標示輪到我的號碼旁，悄悄貼著一面小鏡子。登台前的最後一刻，正是整理凌亂瀏海的位置。緊張也照一照，便輕鬆了幾分。"},"ICON-0458":{"nm":"腕帶毛巾","de":"用手腕一抹便拭去額前汗水的柔軟帶子。編舞越激烈，手就越常往那兒去。在每個氣喘吁吁的瞬間相伴，手腕上的一縷小小慰藉。"},"ICON-0459":{"nm":"道具包標籤","de":"化妝間裡十個一模一樣的包並排站著也不會弄錯。因為每個包上的名牌都清楚地指明了主人。寫上「我的」，雖是小事，卻是溫柔的記號。"},"ICON-0460":{"nm":"練習室預約釘","de":"今天誰來用這間練習室呢。門前看板上插著的小釘，無聲地分配著時間。等待下一輪的心情，靜靜地排在這一枚釘子上。"},"ICON-0461":{"nm":"掛鐘防塵罩","de":"透明的罩子輕輕落在掛鐘上擋住灰塵。滴答作響的指針不再模糊，時間便清澈地流淌。珍貴之物上，總需要一層看不見的守護。"},"ICON-0462":{"nm":"地板保護墊","de":"黏在椅腳下的薄墊，預先擋住木地板的傷痕。拖也不刮花，搬也不留痕。不著痕跡地疼惜地板的心意，正是耐久的祕訣。"},"ICON-0463":{"nm":"禁飲標示牌","de":"在這裡先把飲料放下吧，小牌子溫柔地拜託著。樂譜和器材弄濕了可不行。「禁止」這話這麼一說，不知不覺便成了溫暖的體貼。"},"ICON-0464":{"nm":"通風鍵標籤","de":"想換掉沉悶的空氣時就按這裡，按鍵旁的小標籤指引著方向。能順暢呼吸這件事，意外地就從這樣一個微小的標示靜靜開始。"},"ICON-0465":{"nm":"喇叭防震膠墊","de":"墊在喇叭下的橡膠墊，悄悄吞下沉悶的震動。低音不再沿著地板蔓延，聲音便愈發清晰。好的回響，要在穩固的踏腳上方才清亮。"},"ICON-0466":{"nm":"置物櫃號碼磁鐵","de":"啪一聲貼上置物櫃門的小號碼磁鐵。今天我的行李在第幾格安睡呢。每天位置都變，有一塊磁鐵便立刻有了我的格子。歸屬，正來自這樣輕巧的記號。"},"ICON-0467":{"nm":"鏡面清潔刮刀","de":"在鏡面上輕輕一掃，霧氣便消散得乾乾淨淨。模糊的臉龐清晰浮現的瞬間。想看清自己，得先靜靜擦去模糊之物。"},"ICON-0468":{"nm":"門邊緩衝墊","de":"塞在用力關閉的門縫裡的軟綿緩衝材。砰的聲響也好，夾手也罷，都被柔和地接住。在粗暴的碰撞間，悄悄夾入一層溫柔的小小安全。"},"ICON-0469":{"nm":"電纜護蓋塊","de":"在橫越地面的電纜上，堅固的護蓋俐落地架起一座橋。不會絆腳，也不會踩到線。不擋住路卻守護著路的，一塊默默無言。"},"ICON-0470":{"nm":"小心地滑錐","de":"在濕滑的地板上，黃色的錐筒獨自站著靜靜警示。小心，慢慢踩。明亮的舞台後方，就這樣默默守護腳步的小小守望者。"},"ICON-0471":{"nm":"緊急照明棒","de":"在停電的走廊裡啪地亮起的一束光。為了在黑暗中也不迷路，緊急的燈光被握進手中。在最黑暗的時刻最為明亮的東西，這世上確實存在。"},"ICON-0472":{"nm":"扶手防護帽","de":"套在樓梯扶手末端的圓帽，柔和地包住稜角。即使手不經意拂過也不會受傷。靜靜蓋住尖銳，那也是面向某人的體貼。"},"ICON-0473":{"nm":"舞台邊角護墊","de":"舞台末端的邊角圍上軟綿綿的護墊。即使激烈的編舞碰到腳尖也不會瘀青。每一個閃耀動作的背後，看不見的守護都一同起舞。"},"ICON-0474":{"nm":"地面標記圓盤","de":"放在地上的圓盤靜靜地說著「請站在這裡」。排隊的人也好，找位置的人也好，都看著這一點靜靜停下。秩序，從小小的標記中生長。"},"ICON-0475":{"nm":"手電筒腕帶","de":"把手電筒末端的繩子在手腕上繞一圈，黑暗中也不會弄丟光。不必擔心掉落，雙手便自由了——小巧卻可靠的一圈束縛。"},"ICON-0476":{"nm":"動線封鎖繩","de":"請別進到這裡，一條繩子柔和地劃出界線。靜靜地分開危險之處與安全之地的溫柔邊界。攔阻，也是守護某人的一種方式。"},"ICON-0477":{"nm":"安全確認釘","de":"每個檢查完畢的位置都留下一枚小釘標示「確認」。如同毫無遺漏巡視過一遍的心之印章。安全並非什麼宏大之事，而是這樣一一查點過的痕跡之總和。"},"ICON-0478":{"nm":"迷你場記板","de":"啪——一聲俐落地斷開第一拍，現場所有人的氣息瞬間統一。尺寸雖小，每個場景的起跑線卻總是這一拍。拍攝那令人雀躍的開始就在此揭幕。"},"ICON-0479":{"nm":"桌面麥克風套","de":"桌上的麥克風被輕輕套上鬆軟的套子。即使呼吸聲粗重地爆出，也能無雜訊地細膩傳遞。最溫暖地包裹聲音的，正是這小巧柔軟的一層。"},"ICON-0480":{"nm":"吸音板片","de":"嵌在牆上的一片吸音板，靜靜收走回音。聲音不再撞擊四散，歌聲便愈發清澈地凝聚。好的回響，源自用心修整寂靜的功夫。"},"ICON-0481":{"nm":"耳機掛勾帽","de":"把耳機掛在這裡是個小約定。為了讓下一個人能立刻取用，把線理順整齊。一個掛勾，為忙碌的錄音室引入安靜的秩序。"},"ICON-0482":{"nm":"錄音中標示燈","de":"紅燈亮起的瞬間，錄音室內所有呼吸都屏住。連門外的腳步聲都停下的那個信號。收錄聲音這件事，正從守護這份深沉的寂靜開始。"},"ICON-0483":{"nm":"撥片收納筒","de":"按顏色分格插放的撥片。粗細與重量塑造了指尖的習慣。登台前一刻，不看也能一把抓出的那份準確，便在此處養成。"},"ICON-0484":{"nm":"電纜標籤機","de":"在數十條糾纏的地面上不迷失方向，就得在兩端寫上名字。只有寫下從何而來、往何而去的人，在黑暗中手也不會徬徨。"},"ICON-0485":{"nm":"小型混音旋鈕","de":"轉動一指節的距離，聲音的質地便不同。調高則粗糙，調低則埋沒，在那之間摸索唯一一點。最細微的手感，雕出最大的變化。"},"ICON-0486":{"nm":"支架固定墊圈","de":"撐起舞台的不是華麗的燈光，而是這小小的環。牢牢綁住晃動，不被任何人的眼睛察覺，在自己的位置默默支撐。"},"ICON-0487":{"nm":"拆台標籤","de":"把搭起的一切再小心放倒，也有明確的順序。寫著從哪裡拆、往哪裡搬的一張紙。搭建的手有多俐落，收拾的手也一樣俐落。"},"ICON-0488":{"nm":"失物袋籤","de":"某人遺落的物品，各自蘊藏著故事。裝進小袋子等待主人姓名這件事，是連遺失之人的心情都暫時代為保管的溫柔。"},"ICON-0489":{"nm":"清掃動線標記","de":"順著畫在地上的箭頭走，便能擦拭得毫無遺漏。掃帚也得有路才不會白費力。最閃亮的地方，就在描繪得最好的腳步盡頭。"},"ICON-0490":{"nm":"退場引導棒","de":"最後的掌聲漸歇，這根棒子便開啟道路。不傷及仍激動的心情，慢慢地引導離去的手。引導收尾這件事，也飽含溫暖的體貼。"},"ICON-0491":{"nm":"剩餘膠帶球","de":"把用剩的零頭捲成圓團，便又生出一次用處。差點被丟棄的末端聚攏成堅實的球，正如珍惜之心，從小小的指尖生長。"},"ICON-0492":{"nm":"座椅號碼帽","de":"觀眾席的每張椅子都得標上號碼，誰才不會迷路。一頂指定座位的小帽子，把初來者的忐忑換成安心的釋然。"},"ICON-0493":{"nm":"垃圾分類釘","de":"把紙和塑膠分開插放的小釘。混在一起便只是垃圾，分開來卻成了能再利用的資源。分類，是還給物品第二次生命的溫柔之事。"},"ICON-0494":{"nm":"器材歸還掛牌","de":"借來的東西必定要回到原處。掛上吊牌歸還的每個指尖，都一層層累積起信任。善於歸還的人，下次也能安心地借用。"},"ICON-0495":{"nm":"休息室退房鑰匙","de":"卸下今日的妝容與服裝，最後歸還這把鑰匙。把進來時領到的，在離開時放回原位。一天的開始與結束，盛在同一隻手中。"},"ICON-0496":{"nm":"氣墊粉撲收納盒","de":"鬆軟的粉撲被壓便會失去原有的紋理。安放進一個圓圓的家，緣由就在這裡。想長久守住柔軟，得從溫柔對待開始。"},"ICON-0497":{"nm":"眼影片","de":"敷在眼皮上的一抹色彩，便整個改變了表情。沉睡在小片中的色彩，在燈光下方才甦醒，為望向舞台的眼神添上深度。"},"ICON-0498":{"nm":"腮紅刷帽","de":"刷尖壞了，顯色也跟著崩壞。套上小帽守住那份紋理，是想把好工具長久留在身邊之人安靜的習慣。"},"ICON-0499":{"nm":"纖薄唇彩盤","de":"厚厚的彩盤在包裡占去全部空間。懂得削薄成一條便已足夠的手。捨去，恰恰成了收納的瞬間。"},"ICON-0500":{"nm":"睫毛膏護罩","de":"為了讓一根根豎起的睫毛不暈染，小小的護罩輕輕守護那道弧線。用心抬起的就要用心守護，鏡前的時光如此叮嚀。"},"ICON-0501":{"nm":"棉花棒收納盒","de":"盛裝白色棉花棒不讓它四處散落的小家。為了最後一次修飾而總放在手邊的關照。瑣碎的準備，填補了大舞台的縫隙。"},"ICON-0502":{"nm":"睫毛夾膠墊包","de":"橡膠變硬，夾睫毛時便會刺痛。預先備好可替換的存貨，這份心意源自連微小疼痛都顧慮到的溫柔。"},"ICON-0503":{"nm":"遮瑕刷","de":"用纖細的刷尖輕輕抹去陰影。把光引入光照不到的地方。比起遮掩瑕疵，添上光的手收尾得更為細緻。"},"ICON-0504":{"nm":"蜜粉篩","de":"把細緻的粉末過篩一遍，便能毫無結塊地細膩敷上。再過一次篩的那份辛勞。所謂用心，終究滲透在多走一步的指尖。"},"ICON-0505":{"nm":"瀏海捲夾","de":"把瀏海捲圓暫時固定住的夾子。等待的同時，形狀便沉穩地定下。在不慌不忙懂得等待的位置，整潔便綻放。"},"ICON-0506":{"nm":"髮蠟匙","de":"髮蠟在沾上手之前，先用這小小的匙子舀取。只取剛好需要的那份節制。懂得不過量使用的手，才能造出最自然的紋理。"},"ICON-0507":{"nm":"電棒捲底墊","de":"燒得滾燙的電棒捲可不能隨意擱下。一張承墊便守護了桌子也守護了手。處理熱的地方，總需要一處安全的歇腳。"},"ICON-0508":{"nm":"護髮油試用瓶","de":"把一滴便足夠的光澤，細細裝進小試用瓶，悄悄放進包包一角。比起大瓶，小小一瓶反倒更常觸手可及。"},"ICON-0509":{"nm":"刷具清潔梳","de":"用梳齒慢慢梳下纏在刷上的髮絲。照料工具的時光，是完工後安靜的儀式。打理妥當的刷子，細緻地雕出明日的紋理。"},"ICON-0510":{"nm":"髮圈線軸","de":"只要繞在線軸上，便一目了然。圓圓整理好的這個小卷團，是橡皮筋四處滾動的忙亂早晨遞來的一份溫柔餘裕。"},"ICON-0511":{"nm":"染髮手套包","de":"為了不讓上色的手沾染顏色而戴上的薄手套。想在事畢之後也以乾淨的手迎接下一件事的心。所謂保護，正是那份準備的別名。"},"ICON-0512":{"nm":"髮網收納袋","de":"把守護髮型的網好好摺起裝入的小袋子。越是沒有體積之物越容易失去位置，為它定下家的細心手感令人感激。"},"ICON-0513":{"nm":"碎髮定型筆","de":"把翹出的碎髮輕輕一壓便整齊抓住的筆。大整理全部結束後的最後一次。所謂收尾，總是撫平最微小之處的事。"},"ICON-0514":{"nm":"香水試香蓋","de":"挑選香氣時不直接湊到鼻尖。沾在小蓋上撒入空氣中，真正的紋理才會顯現。香氣也要隔一步去聞，方才誠實。"},"ICON-0515":{"nm":"滾珠香水瓶","de":"圓圓的珠子咕嚕嚕滾動，在手腕上描出香氣。與輕點塗抹的舊香水瓶不同，是滑行般暈開的一道。香氣依觸碰的方式，留下不同的故事。"},"ICON-0516":{"nm":"身體噴霧蓋","de":"把如薄霧般擴散的香氣封住的小蓋子。打開才會飛散之物，關上加以守護。略加珍藏的心意，讓那香氣在身邊停留得更久。"},"ICON-0517":{"nm":"護手霜鑰匙圈","de":"為塗在手上的小霜裝上鑰匙圈，便能隨處同行。掛在包外晃啊晃的同伴，成了向乾燥指尖遞去的溫柔問候。"},"ICON-0518":{"nm":"沐浴球掛勾","de":"搓出泡泡之後得好好晾乾。掛在浴室一角勾子上的網球，咕嚕嚕甩落水珠，清爽地等待下一個早晨。"},"ICON-0519":{"nm":"按摩球收納袋","de":"把放鬆僵硬肩膀的堅實球裝進小袋子。舞台後短暫的休息，靜靜撫慰僵硬身體的時光。照顧，總是從自己開始。"},"ICON-0520":{"nm":"冰涼貼片筒","de":"把貼上便清涼降溫的貼片收攏的筒子。火熱舞台落幕的夜晚，慢慢平復發燙身心的小小慰藉，正沉睡在裡頭。"},"ICON-0521":{"nm":"指緣油筆","de":"按一下、抹一抹、閃亮。乾燥的指尖只需一滴便足夠。無需華麗的療程，從小筆尖暈開的淡淡光澤，在指甲上細細繚繞。照顧，便是從這小小的一滴開始。"},"ICON-0522":{"nm":"香囊夾","de":"把香氣繫在紙上的小結。每次拉開抽屜，淡淡的一縷便比手更先打招呼。看不見卻常伴身旁的溫柔——一個夾子，靜靜懷抱著一天份的慰藉。"},"ICON-0523":{"nm":"美甲片托盤","de":"預先攤開十指色彩的小舞台。哪個色調與今天相襯呢，托盤上開起一場安靜的試鏡。挑選的那一瞬竟有些雀躍，指尖的一天便從這裡開始。"},"ICON-0524":{"nm":"推甲皮帽","de":"推開這件事裡也有溫柔。用圓圓的尖端把一根倒刺輕輕地、不急不徐地推。匆忙的手總會錯過些什麼，整頓更近於慢慢端詳的心。"},"ICON-0525":{"nm":"迷你磨甲拋光棒","de":"粗面與細面，兩張臉握於一手。把稜角輕輕磨平、修得滑順雖是小事，但完成總來自這般細微的手感。最後終究是柔滑的份內事。"},"ICON-0526":{"nm":"指甲貼紙板","de":"星星、花朵、愛心——順著今天的心情挑一張輕輕貼上便好。指甲大小的小圖案列隊排在板上，一張貼紙閃耀如指尖留下的溫柔簽名。"},"ICON-0527":{"nm":"凝膠燈遮光板","de":"暫時封住光的薄膜。固化的同時眼睛歇息，唯指尖靜靜變得堅實。等待也需要一抹陰影——在不慌不忙的時光裡，今日的指尖方才完成。"},"ICON-0528":{"nm":"美甲飾品筒","de":"閃亮的碎片一格格安睡著。方鑽、珍珠、星粉——懷著開啟無名珠寶盒的雀躍掀開蓋子。要把哪一道光放上指甲呢，挑選的那一刻最為閃耀。"},"ICON-0529":{"nm":"護手手套包","de":"睡眠期間手所享受的短暫假期。在手套裡，乾燥的肌膚整夜慢慢變得滋潤。所謂照顧，終究是發生在看不見之處——一到早晨，指尖便先感知那份溫柔。"},"ICON-0530":{"nm":"卸甲液按壓瓶","de":"按一下，剛好需要的份量。滲入棉花暈開的清涼香氣，把指甲上的昨日抹得乾乾淨淨。清空也有節奏，一次按壓，靜靜空出重新塗抹的位置。"},"ICON-0531":{"nm":"方鑽鑷子","de":"要夾起比指尖更細的寶石，需要更細的手。毫無顫抖地移動一個點的鑷尖——細膩既是心意，也是工具的份內事。一道小小的光找到了自己的位置。"},"ICON-0532":{"nm":"耳環收納板","de":"為了讓落單的耳環不再在抽屜裡成為迷途者。一對對插回原位，忙亂早晨挑選的時間便輕鬆許多。整理，是遞給未來的我的小小善意。"},"ICON-0533":{"nm":"戒圍量環","de":"把手指周長換成數字的一束小環。一個個試戴合適格子的這件事，與慢慢認識那個與我恰好相襯之物相似。如同恰好合適時的那份安心。"},"ICON-0534":{"nm":"錶帶銷釘","de":"錶帶鬆動時，這一根小銷釘把時間重新繫回手腕。藏得最深的零件撐得最久——戴久了的錶，無聲地知曉這一點。"},"ICON-0535":{"nm":"項鍊防纏板","de":"為了讓細鍊彼此不糾纏而分格安放。不打結的早晨，從昨夜預先分開的小隔板開始。所謂餘裕，終究是在手觸及之前便整理好的心。"},"ICON-0536":{"nm":"胸針後扣","de":"正面越華麗，背面越沉默。牢牢托住別在衣襟上胸針的小扣——顯露的光芒背後，總有無名支撐的手。看不見才更令人安心的位置。"},"ICON-0537":{"nm":"太陽眼鏡收納袋","de":"柔軟的布靜靜包住擋過夏日陽光的鏡片。守護一副視野免於包內碰撞的小袋子。珍惜某物的心意，總是這樣化作柔軟的一層而來。"},"ICON-0538":{"nm":"皮帶打孔器","de":"腰圍少一格也好，季節多一格也罷。只要多打一個孔，皮帶便再次合身。改變的總是我，默默配合的則是這小工具的份內事。"},"ICON-0539":{"nm":"絲巾夾","de":"把滑落的絲巾聚於一點抓住的夾子。被風吹散的風采終於安頓下來。優雅有時也倚靠這小小夾子，把差點凌亂的一天整潔地收攏。"},"ICON-0540":{"nm":"吊飾環組","de":"可掛在包包一側的小環整組到來。把喜歡的東西帶在身邊的心情——把那天的心情掛在一個吊飾上，像只有自己知道的小小儀式，竟有些愉快。"},"ICON-0541":{"nm":"除毛球機筒","de":"毛衣一夜之間像老了似地起了毛球，便靜靜滾動這個筒子，重現新品的表情。除去老舊的輕快嗡嗡聲不知為何令人安心。珍惜的衣裳便如此再活一次。"},"ICON-0542":{"nm":"衣物香氛卡","de":"塞進衣櫃深處，便以香氣靜靜填滿數日。以香代字寫成的信——不必展開也讀得到的一張。每個取衣的早晨，昨日寫下的溫柔便先暈開。"},"ICON-0543":{"nm":"防靜電別針","de":"裙襬黏住雙腿的冬日早晨，一枚別針悄悄化解那份貼黏。連看不見的摩擦都安撫的小小平和——少了一點瑣碎的煩躁，一天便順滑許多。"},"ICON-0544":{"nm":"攜帶式衣刷","de":"出門前一刻，肩上輕輕落了一道塵。展開摺好的刷子刷一下，第一印象便再次整潔。收尾總發生在門前，整潔便在那一次手感中完成。"},"ICON-0545":{"nm":"洗衣袋標籤","de":"把不能混在一起的東西收進網袋，標籤靜靜寫上名字。洗衣也有位置，位置便有小小的標記。容易凌亂的一天，其秩序便從這小名牌生長。"},"ICON-0546":{"nm":"去漬筆","de":"咖啡一滴在襯衫上留下的痕跡，輕輕拍打便悄悄退去。不是遮掩失誤，而是靜靜抹去的筆。每個人都需要一次把一天重新乾淨開始的機會。"},"ICON-0547":{"nm":"擦鞋布","de":"用布輕拭一遍，皮革便找回原有的光澤。穿得越久的鞋，光澤入得越深。光澤是一同走過時光的回報——鞋子把那歲月靜靜刻在腳背上。"},"ICON-0548":{"nm":"運動鞋帶扣","de":"扣在散開鞋帶末端的小帽。為了直到終點都不分心，把末端牢牢封住。一條繫好的鞋帶把一步送得更遠——小小的看管，成了奔向終點的勇氣。"},"ICON-0549":{"nm":"衣架名牌片","de":"在相似的衣架之間，這一小片靜靜地指出「我的位置」。減少忙亂早晨混亂的安靜嚮導——尋找的辛勞少了，一天的開始也輕快許多。"},"ICON-0550":{"nm":"隱形眼鏡鑷子筒","de":"有時需要比指尖更精準的尖端。能毫無顫抖夾起小鏡片的鑷子，在筒中等候輪到自己。精密總是安靜地備妥沉睡著，一呼便立刻醒來。"},"ICON-0551":{"nm":"化妝棉迷你包","de":"只裝剛好用一次份量的小束。既減少包內體積，柔軟卻依舊。少帶一些也是一種溫柔——騰出的位置，便迎來輕盈的一天。"},"ICON-0552":{"nm":"吸油面紙盒","de":"正午暈在鼻梁上的油光，用薄薄一張靜靜按拭。整齊沉睡在盒中的紙——抽出一張的瞬間，誰都會暫時溫柔地端詳鏡前的自己。"},"ICON-0553":{"nm":"摺疊梳鏡","de":"摺起是掌心，展開是鏡與梳。在包包一角擔起緊急儀容的小小萬能。整潔並非什麼宏大之事，而更近於隨處可展開整理一次的心。"},"ICON-0554":{"nm":"攜帶刮鬍刀蓋","de":"把旅行包裡鋒利的刀刃安全地哄睡。多虧這看似鈍實則堅固的蓋子，忙亂早晨摸索的指尖也不會受傷。所謂關照，總是先一步把危險蓋住。"},"ICON-0555":{"nm":"護唇膏掛環","de":"晃在包帶上的小小保護殼。不必擔心在口袋裡滾來滾去摔碎，把乾燥的雙唇總放在觸手可及處。所謂帶在身邊，終究是把所需放在最近距離的心。"},"ICON-0556":{"nm":"乾洗手架","de":"單手一按，一掌清潔便落下。門前、桌上，哪裡掛上，洗手的心便靠近多少。好習慣並非宏大，而是從觸手可及之處開始。"},"ICON-0557":{"nm":"面紙纖薄包","de":"在俐落的身形裡懷著一把面紙。既不讓口袋鼓起，又總靜靜備妥應對突如其來的鼻水或眼淚。悄悄遞給某人的一張——準備越纖薄越帥氣。"},"ICON-0558":{"nm":"迷你漱口水瓶","de":"吃了辣泡麵卻得見人的日子，這小小的瓶子悄悄擔起清新口氣。一口的爽利有時成了莫大的自信，讓躊躇的招呼變得輕鬆許多。"},"ICON-0559":{"nm":"亮粉片","de":"用指尖輕沾敷在臉頰上，便如燈光下星粉飛散般暈開。平凡的臉頰一瞬閃耀，全靠這小小一片的魔法。光總是這樣，隨沾在指尖的粉而來。"},"ICON-0560":{"nm":"亮片消光貼","de":"在太過閃耀而顯負擔的場合，這貼紙輕輕壓下光芒。減去一層華麗也是裝扮的一部分——減去後留下的淡雅，有時成了另一種感性。"},"ICON-0561":{"nm":"拾石筆","de":"走在路上絆到腳尖的一顆小石頭。是特意彎腰撿起的筆。把原本可以路過之物用指尖靜靜拾起的心——溫柔，總是從停下腳步開始。"},"ICON-0562":{"nm":"假睫毛收納板","de":"一根根整齊安放的小板。即使取下後，那道優美的弧線也不凌亂。暫時放下之物也記得自己的位置，這便是安靜整潔的收納慰藉。"},"ICON-0563":{"nm":"雙面膠剪蓋","de":"兩刃咬合，一次便剪斷結頭。剪口越乾淨，下一個結便越整齊。在善於結束又善於斷開的指尖，新的開始也順暢輕快地展開。"},"ICON-0564":{"nm":"臉部輪廓膠帶","de":"順著下顎線一道，屏息小心地貼下去。輪廓並非畫出原本沒有的線，而是點出已然優美之處。是溫柔順著本就在那裡的紋理描繪的手感。"},"ICON-0565":{"nm":"燈光反射粉","de":"盡情含住光再細細歸還的粉末。自己不發光，卻把接收的光細碎散開而變得明亮。如同把收到的溫柔再傳給另一人，閃耀越分享越大。"},"ICON-0566":{"nm":"妝容定型風扇","de":"把費心的妝容把守到一天盡頭的扇風。別崩塌、別流下，靜靜地吹涼定住。讓用心整理的臉龐，直到舞台落幕都清晰分明。"},"ICON-0567":{"nm":"校色盤片","de":"把走偏的色彩一格格安撫導正的小片。獨自時格格不入的色，身旁擺上相襯的色才終於明亮。色與色牽起手，方才成為清澈的一幅。"},"ICON-0568":{"nm":"頸部圍巾包","de":"圍在脖子上，清晨練習室的冷空氣便緩和許多。如同奶奶為孫兒圍上的那份手感般溫暖。寒意總是從最細處來，所以從頸後開始包裹。"},"ICON-0569":{"nm":"熱敷眼罩袋","de":"盛裝加熱眼罩的小袋子。開口的瞬間，倦怠的暖意便沿著眼皮緩緩暈開。把辛勞的一天暫時封住再解開，是入睡前溫柔的儀式。"},"ICON-0570":{"nm":"攜帶加濕濾芯","de":"把水氣還給乾燥房間的小小濾膜。在看不見的內側默默濾去混濁。盈滿房間的滋潤，是某人看不見的辛勞所守護的清澈。"},"ICON-0571":{"nm":"維他命收納盒","de":"把一日份藥片一格格分裝的盒子。日復一日按時服用，便是明天也要站上舞台的決心。每一個小格裡，疼惜自己的心都工整地整理著。"},"ICON-0572":{"nm":"睡眠耳塞盒","de":"暫時關上世界聲響的耳塞之家。寂靜也需要呵護，便在盒中優雅安睡。要有酣眠的夜，隔日的嗓音才能清澈醒來——休息，深知這一點。"},"ICON-0573":{"nm":"涼感毛巾夾","de":"把冰過的毛巾牢牢咬在肩上不讓它滑落的夾子。炎熱日子裡觸及頸後的一縷涼意，撐過漫長的午後。小小的清涼，抓住了便長久停留。"},"ICON-0574":{"nm":"伸展球收納袋","de":"把放鬆身體的球收回的袋子。盡情伸展再縮回小巧，這件事與吸氣吐氣相似。在展開與收攏之間，身與心都慢慢變得堅實。"},"ICON-0575":{"nm":"彈性繃帶卷","de":"把扭傷的腳踝一圈圈包裹的帶子。不是束緊，而是靜靜托住。越是逞強的位置，越需要在身旁默默支撐的手，繃帶捲動著如此低語。"},"ICON-0576":{"nm":"狀態檢查吊牌","de":"把今日狀態一句寫下掛起的標牌。把好與壞誠實掛出，是小小的勇氣。比起逞強，寫下今天的我，便有人查看那一句靜靜照料。"},"ICON-0577":{"nm":"鞋用芳香膠囊","de":"啪地放進鞋裡的香氣膠囊。獻給整日馳騁舞台雙腳的小小淡雅慰藉。把最好的香氣給最辛苦的位置——溫柔，連腳尖都毫無遺漏地觸及。"},"ICON-0578":{"nm":"鞋墊尺寸表","de":"連一片鞋墊都清楚刻上腳尺寸的表。一雙合腳的鞋讓舞台上的腳步輕盈。體察各自不同步幅的事——所謂合身，終究是深深端詳對方的心。"},"ICON-0579":{"nm":"鞋拔鑰匙圈","de":"把鞋拔縮成掌心大小掛上的鑰匙圈。順滑地協助穿鞋那一瞬的小小體貼。踏上路途的腳上，總靜靜掛著某人溫柔的扶持。"},"ICON-0580":{"nm":"包包防塵罩","de":"把珍愛的包包輕輕罩起免於灰塵的布。在不被使用的期間也好好哄睡守住紋理。即使不常觸及，心卻停留之物，便寄寓著這般靜靜的呵護。"},"ICON-0581":{"nm":"肩帶調節釦","de":"把鬆掉的帶子調到貼合身體的釦子。太鬆則肩膀滑落，太緊則喘不過氣。在尋找適度的一格調節中，舞台服裝與心都終於舒適。"},"ICON-0582":{"nm":"拉鍊潤滑筆","de":"在卡澀的拉鍊上劃一下，便又順滑地滑動。堵住之物嘶地化開的那聲響多麼暢快。讓停滯之處重新流動的，正是一道滑順。"},"ICON-0583":{"nm":"運動鞋清潔刷頭","de":"把沾了塵土的運動鞋一點點擦淨的刷尖。用心抹去舞台外那看不見的練習痕跡。望著重新潔白的鞋頭，明天彷彿又能以全新的心奔跑。"},"ICON-0584":{"nm":"防水噴霧蓋","de":"把雨滴滾成圓珠抖落的防水瓶蓋。預先多披一層免於淋濕，是放眼長遠的溫柔。正因知曉會有雨天，才在晴朗的今天圍上一層膜。"},"ICON-0585":{"nm":"皮革保護布","de":"靜靜覆在皮革上防止皺褶的布。如同從前以韓紙包覆屏風的手感般守住紋理。越是要長久相伴之物越要慢慢來——馴養，是呵護時光的別名。"},"ICON-0586":{"nm":"行李箱名牌帶","de":"在無數行李間一眼認出我的那一條名字帶。在輸送帶上團團轉的行李中以一個字舉起手。無論走得多遠，只要一個名字便能重逢，那份安心。"},"ICON-0587":{"nm":"壓縮袋夾","de":"把鼓脹的行李壓扁封住的夾子。與其說清空，不如說是一層層好好摺疊。在工整縮減家當的指尖，貪念也一同變小，被牢牢壓住的行李靜靜訴說。"},"ICON-0588":{"nm":"旅行洗衣片","de":"一張便能在洗手台洗衣的洗衣片。如同遠路上也手洗衣物的客旅智慧。即使輕裝出發，唯獨整潔仍要帶上，這是路上旅人由來已久的心態。"},"ICON-0589":{"nm":"頸枕套","de":"為托住頸子的枕頭新換上的整潔罩子。倚靠之處總要乾淨，心才安穩。為讓某人安然倚靠而把位置鬆軟空出——款待，便從此開始。"},"ICON-0590":{"nm":"行李秤帶","de":"把包包高高提起估量重量的帶子。出發前，先用手抱量行李的重量。在要帶走與要留下之間，連心的重量也一同靜靜秤量的瞬間。"},"ICON-0591":{"nm":"鞋袋一對","de":"左腳右腳，並排盛裝兩隻鞋的一對鞋袋。分開放容易丟，成雙放便安心。總是一同出行之物，懷有靜靜守護彼此的力量。"},"ICON-0592":{"nm":"輔助包掛勾","de":"少一隻手的日子，把包包悄悄掛上的小勾。為實在拿不完的多行李日子準備的一格餘裕。光是有處暫掛，肩膀便輕鬆許多。"},"ICON-0593":{"nm":"旅行行程片","de":"把一天的動線工整刻在一片裡。在哪裡會合、往哪裡流轉，為認路不靈的腳步預先劃下的指引線。一同出行的路，一格格分開記下便鮮少迷失。"},"ICON-0594":{"nm":"萬用轉接頭蓋","de":"與陌生國度的插座也能恰好咬合插入的蓋子。形狀不同，終究連成一體。連接來自不同地方之物的事——相融，便從一個小小的轉換靜靜開始。"},"ICON-0595":{"nm":"交通卡套","de":"每次掠過閘門時守護卡片的透明一張。每天的通勤，連那磨到發亮的刷痕也細細包住。平凡的路珍藏起來便成回憶，這薄薄的一層便是明證。"},"ICON-0596":{"nm":"車票夾","de":"把轉眼便皺巴的一張票整潔咬住的夾子。在路上弄丟票，連心都會動搖。越是小張的紙越要牢牢抓住——旅途的安心，正來自那一格。"},"ICON-0597":{"nm":"轉乘備忘片","de":"把在哪裡轉乘一句寫下的小片。在每個令人困惑的岔路口，預先寫下的一句話便豁然開路。備忘，是悄悄遞給未來迷路的我的溫柔提點。"},"ICON-0598":{"nm":"閘門通行牌","de":"通過門時被靜靜感應的通行牌。看似阻塞的路，只要持有應有的資格便嘩地敞開。坦然通過，便是毫無躊躇輕快邁向下一格的事。"},"ICON-0599":{"nm":"計程車收據夾","de":"每張小紙上，都清楚印著那天走過的路的痕跡。把四處滾動的收據整齊夾攏在一處，原本不起眼的一天也一張張累積，成了一段堂堂的旅程。"},"ICON-0600":{"nm":"自行車反光帶","de":"在昏暗路上承接掠過燈光而靜靜閃爍的帶子。自己不發光，卻因某人的光而明亮。讓自己被看見，是黑夜路上「請務必平安歸來」的溫柔叮囑。"},"ICON-0601":{"nm":"行李箱輪罩","de":"在機場輸送帶上滾了數千次,邊角依然完好無損,全靠這片包覆輪子的小罩子。它走在最崎嶇的路上,總是最先觸地的那一處——默默守護某個人的事,往往就藏在這樣不起眼的地方。"},"ICON-0602":{"nm":"座椅頭枕套","de":"漫長的巴士旅程,給頭枕罩上一片,便倚向車窗。讓前座的氣味與昨日的疲憊都止步於此。能有個乾淨的地方可以倚靠,是陌生旅途上意外而巨大的慰藉。"},"ICON-0603":{"nm":"停車位置標釘","de":"「到底是幾層幾號來著。」在空蕩蕩的停車場裡徘徊許久的人,才懂這枚標釘有多可靠。與其任記憶模糊,不如一釘標記下來,把要回去的地方預先定好。"},"ICON-0604":{"nm":"房卡掛繩","de":"房間鑰匙怎麼那麼容易不見。穿上掛繩套在手腕上,今晚要回去的那個房間就再也不會忘記。即使在陌生的城市,手腕上也掛著一份「我有自己的位置」的小小安心。"},"ICON-0605":{"nm":"門掛提示牌","de":"彩排一開始,就在門上掛一片牌子。請勿打擾——意思是此刻是全然專注的時間。舞台幕後那份深沉的寧靜,正是被這些小小的信號無聲守護著。"},"ICON-0606":{"nm":"盥洗收納袋","de":"牙刷、洗面乳、巴掌大的毛巾。無論去到哪裡,只要帶上這個袋子,一天的結束與開始總能用同樣的手勢整理妥當。是一小把能讓陌生床鋪不知不覺變熟悉的居家智慧。"},"ICON-0607":{"nm":"備用毛巾夾","de":"洗手台旁,總是無處安放而濕答答的備用毛巾。用夾子夾起掛好,它才終於找到了自己的位置。給東西備一個能晾乾的地方——溫柔大多就是這麼大小的模樣。"},"ICON-0608":{"nm":"延長線收納袋","de":"每次打開包包都糾成一團的充電線。連著延長線一起捲起塞進去,裡頭頓時清爽整齊。電線理順了,也意味著出發前那一縷心緒,也悄悄鬆開了。"},"ICON-0609":{"nm":"床位編號標","de":"宿舍每張上下鋪都貼著號碼牌。一張告訴你哪個位置屬於你的標籤,就能讓初來乍到的陌生房間,在當晚不知不覺成了我們的家。起點總是這麼小。"},"ICON-0610":{"nm":"迷你曬衣繩","de":"把兩端掛在窗框之間,它就成了曬衣繩。陽光正好的日子,幾雙手洗的襪子隨風蓬鬆地搖晃。即使在遠離家鄉的地方,日常也這樣在繩子上晾乾。"},"ICON-0611":{"nm":"拖鞋區分牌","de":"玄關拖鞋堆成一片時,實在分不清是誰的。掛上一個小牌子,鞋子也能認出自己的主人。一群人相互依偎著生活,正需要這些貼心的小標記。"},"ICON-0612":{"nm":"早餐券夾","de":"夾著早餐券的夾子。飢腸轆轆的清晨,有這一張,就等於約好了一碗熱氣騰騰的湯。旅途中的一天,總是從溫熱的一餐裡緩緩展開。"},"ICON-0613":{"nm":"腳踝反光帶","de":"繞在腳踝上,便能在黑暗中把光反射回去。夜間散步時,對遠處駛來的車無聲揮手說「這裡有人喔」的小帶子。安全就這樣樸實地閃著光。"},"ICON-0614":{"nm":"隨身濕紙巾蓋","de":"正好卡進濕紙巾開口的蓋子。一張張柔順地抽出,剩下的也不會乾掉。看似微不足道,卻每天都要伸手去用的東西,背後都藏著它的道理。"},"ICON-0615":{"nm":"小野餐墊綁繩","de":"把野餐墊捲成圓筒,用繩子綁好。漢江河岸、櫻花樹蔭,無論在哪裡,展開的那一刻那兒就成了我們的地盤。一條把草地上巴掌大的領土整個帶著走的繩子。"},"ICON-0616":{"nm":"防蚊貼片盒","de":"夏夜的必需品,裝防蚊貼片的盒子。在發癢之前就先備好的那份心意,都裝在這一格裡。戶外舞台的後台,總靠這些小小的準備而踏實起來。"},"ICON-0617":{"nm":"散步水壺掛環","de":"出門散步時把水壺掛在包上的掛環。口渴時,水就在伸手可及之處,意味著能走得更遠一些。是一個不讓步行者停下腳步的小小連結。"},"ICON-0618":{"nm":"摺疊購物籃","de":"展開是購物籃,摺起是巴掌大。在市場小巷裡逛時,正好用來裝一把心儀的青菜。居家的智慧總是朝著縮小體積、方便攜帶的方向生長。"},"ICON-0619":{"nm":"防風夾","de":"颳風的日子,夾住翻飛的帳篷布角,牢牢固定住。一個夾子就把不停搖晃的東西按回原位。在戶外最可靠的,意外地就是這種手指般大小的東西。"},"ICON-0620":{"nm":"遮陽標釘","de":"插在窗上斜斜擋住陽光的標釘。正午的光太強時,悄悄垂下一把陰影。減輕刺眼的事,對某個人而言,也成了無比溫柔的撫慰。"},"ICON-0621":{"nm":"緊急哨子蓋","de":"蓋住緊急哨子吹口的蓋子。讓灰塵進不去,真正需要的瞬間能一吹即響。有些東西明明盼著永遠用不上,卻光是放在身邊就讓人安心。"},"ICON-0622":{"nm":"雨傘尖端蓋","de":"套在雨傘尖端的小蓋子。尖銳的末端變鈍了,旁邊的人、我的包包都不會被弄傷。雨天的禮貌,就這樣從把尖銳的末端包成圓潤開始,悄然展開。"},"ICON-0623":{"nm":"雨衣收納包","de":"把摺好的雨衣捲起塞進的收納包。在下一場驟雨來臨前,它就在包包一角靜靜等待。所謂未雨綢繆,終究是預先備好那或許永遠用不上之物的一縷心意。"},"ICON-0624":{"nm":"防水鞋套","de":"套在鞋子外面,雨水便再也滲不進來。即使是梅雨傾盆的上學路,襪子依然乾爽。一整天連腳尖都沒淋濕,比想像中更能大大改變心情。"},"ICON-0625":{"nm":"雪地防滑墊","de":"貼在鞋底,連結冰的路也沒那麼可怕了。在積雪的巷弄裡小碎步穿行的那個冬天,默默扶住你別滑倒的墊子。藏在謹慎步伐之下的那份踏實。"},"ICON-0626":{"nm":"涼感頸環","de":"繞在脖子上,一股清涼便靜靜環繞。即使在悶熱難當的三伏天,也能把一絲清涼掛在後頸帶著走的夏日智慧。對抗暑熱的法子,也年年漸漸更體貼了些。"},"ICON-0627":{"nm":"隨身電扇立架","de":"讓手持電扇立起來的底座。雙手一空出來,就能翻書頁,也能不用搧扇子而提筆寫字。一縷小小的風,讓書桌前漫長的夏天勉強變得能熬過去。"},"ICON-0628":{"nm":"暖暖包收納袋","de":"用來裝暖暖包帶著走的收納袋。為了暖一暖凍僵的指尖把手伸進口袋,那裡便有一份小小的暖意早已等候著。冬日的外出,就靠這一小把溫暖撐過去。"},"ICON-0629":{"nm":"防寒耳罩盒","de":"用來收納耳罩的盒子。是直到下次寒冷來臨前都悉心供奉的位置。即使季節更替也捨不得丟棄的東西,裝著對再度重逢的冬天那份靜默的信任。"},"ICON-0630":{"nm":"紫外線測量片","de":"輕輕對著光,就會用顏色告訴你今日紫外線強度的小片子。把原本看不見的陽光強度,終於變得肉眼可見。等於把一隻讀懂天空的小眼睛,靜靜戴在手腕上。"},"ICON-0631":{"nm":"巷弄集章板","de":"在巷口每家店蓋章一格格集滿的板子。每蓋上一格,社區的地圖就在心中愈發清晰。用雙腳走出來的回憶,就這樣以印章的痕跡留存下來。"},"ICON-0632":{"nm":"造訪地標釘板","de":"在去過的每個地方都釘上一枚標釘的小板子。隨著點一個個增多,我的世界邊界也一同拓寬。每一枚標釘,都是「我,曾在這裡」靜靜搭話的痕跡。"},"ICON-0633":{"nm":"小指南針掛繩","de":"徘徊再久,唯有北方始終在那兒不變。掛在胸前的小指南針,在實在不知該往哪走時,總是先輕輕撫平那顆動搖的心。"},"ICON-0634":{"nm":"問路便條環","de":"把問路時寫下的紙條穿進環裡。「在紅色郵筒處左轉。」某人笨拙的手寫字默默引領著陌生的巷弄。留在紙上的路,不容易模糊。"},"ICON-0635":{"nm":"地標貼紙簿","de":"用每個旅遊地買的貼紙一張張填滿的簿子。塔、橋、古老的城牆,一頁一頁地累積。蒐集去過的地方,就像用指尖再次觸摸走過的時光。"},"ICON-0636":{"nm":"地鐵轉乘片","de":"在路線分岔的轉乘站緊握在手的片子。決定往哪轉乘的那短短一瞬,有時竟把一整天的方向都改變了。一個小小的選擇,城市便露出不同的面貌。"},"ICON-0637":{"nm":"社區探險卡","de":"「今天就走到這個社區的麵包店吧。」抽一張卡,今日的探險地就定下了。連天天經過的熟悉巷弄,有了任務也成了新路。一張告訴你冒險不在遠方的卡片。"},"ICON-0638":{"nm":"店家名片夾","de":"插放在常去的店拿到的名片的夾子。好吃的店、招呼親切的老闆,一格格慢慢累積。與一座城市結下情誼,就是從這些小小的紙片開始的事。"},"ICON-0639":{"nm":"路線完成徽章板","de":"把散步路線從頭走到底,就能填上一枚徽章的板子。走完全程的成就感化作圓圓的金屬留在手中。唯有走到最後的人才懂的那份滿足,在此清晰地嵌印著。"},"ICON-0640":{"nm":"包包鎖鑰匙圈","de":"扣在包包拉鍊上、兼作鑰匙圈的小鎖。既牢牢守護珍貴之物,又在包包尾端叮鈴叮鈴搖晃。把保安與裝飾合為一體,是旅人相當聰明的同伴。"},"ICON-0641":{"nm":"防丟失標籤","de":"蜷縮在包包最深的黑暗裡,在所有人都放棄的那一刻小小地閃爍。「我在這裡喔。」是以為弄丟的那份心意回到指尖的聲音。雖小,卻守在主人身邊到最後。"},"ICON-0642":{"nm":"拉鍊上鎖環","de":"喀嚓,一旦扣上,尋常的手就打不開。倉促的指甲也好,悄悄靠近的手指也好,都一視同仁地擋下的那股韌勁。它以沉甸甸的份量告訴你,安全偶爾有點緊澀也沒關係。"},"ICON-0643":{"nm":"防盜鈴繩","de":"在結帳完成前,守護著貨架上的商品不得擅自外出的隱形守門人。誠實的手拂過時,它始終沉默。不會響起的鈴,才是最平和的鈴。"},"ICON-0644":{"nm":"聯絡方式遮蔽標","de":"在快遞箱上寫的姓名與號碼之上,悄悄覆上一層。誰住在這裡、要送往何處,只需收件人知道就好。遮蔽得當也是溫柔的一種,它靜靜守著自己的位置。"},"ICON-0645":{"nm":"護照套束帶","de":"陌生的機場,幾十本一模一樣的封面在輸送帶上旋轉的清晨。在那縫隙間,用只有我知道的顏色「在這邊喔」地招手。給遠行的證件披上的小外套。封面磨損了,旅程依舊明亮。"},"ICON-0646":{"nm":"現金分隔袋","de":"鈔票放左邊,硬幣放右邊,急用錢放沒人知道的格子。是逛完市場的手最先摸索的地方。再凌亂的一天,在這裡頭也整整齊齊、叮叮噹噹地各歸其位。"},"ICON-0647":{"nm":"保安貼紙封條","de":"一旦撕開就會留下痕跡。把「有人開過喔」始終藏不住的、小而誠實的良心。平安抵達的封箱底下,鋪的全是這位朋友始終如一的沉默。"},"ICON-0648":{"nm":"緊急聯絡片","de":"迷路孩子的口袋裡、筆電包的內側、狗繩的末端。即使來到開不了口的瞬間,也會代為一字一句喊出號碼。一枚小小的片子裡,完整裝著「請帶我回家」。"},"ICON-0649":{"nm":"自拍棒遙控蓋","de":"手臂不夠長,總有人被切掉的合照。如今只要在末端輕輕按個鈕,全家就能進入同一個畫面。大家一起笑的那一瞬,我悄悄按下快門,跳進那畫面之中。"},"ICON-0650":{"nm":"鏡頭收納袋繩","de":"為了讓備用鏡頭在包包裡不相互碰撞,用繩子緊緊抱住。一片玻璃就是一片風景,所以不隨意晃動它的份量。攝影者的謹慎,綁在每一個結上。"},"ICON-0651":{"nm":"濾鏡盒環","de":"薄薄一片,就能把同一片天空變成不同的光。把那些小小的魔法整齊供奉在圓圓的巢裡的地方。每次打開盒子,今天要捕捉怎樣的晚霞呢,指尖便微微雀躍。"},"ICON-0652":{"nm":"三腳架收納袋","de":"摺起一個手掌寬,展開是穩固不搖的三條腿。把這位能代替顫抖的手抓住風景的朋友,妥帖地捲起塞進去。愈是沉重的器材,愈該躺在柔軟的布上,才合情理。"},"ICON-0653":{"nm":"相機背帶墊片","de":"走了一整天,相機壓得肩膀痠疼的時刻總會到來。那時一片墊片便靜靜分擔了那份重量。為了一張好照片而走遠路的肩上,搭著一份小而柔軟的慰藉。"},"ICON-0654":{"nm":"記憶卡分類卡","de":"搞不清數百張回憶沉睡在哪張卡裡的夜晚。五彩繽紛的標記指點著路。春日旅行是藍,初次登台是黃。一位給記憶也分格的、小而貼心的圖書管理員。"},"ICON-0655":{"nm":"充電線捲收器","de":"趁充電線在包包裡上演打結秀之前,把它捲成圓圈端正安頓好。整理好一條線,心裡某一根線似乎也跟著鬆開了。捲成一圈圈的模樣,看著就讓人安寧。"},"ICON-0656":{"nm":"照片備份標籤","de":"「這些照片,備份了吧?」對深夜忽然湧上的那份不安,預先寫好的小備忘。愈是珍貴的瞬間,愈該在兩處以上活著,標籤一字一句地記下。"},"ICON-0657":{"nm":"構圖取景板","de":"透過方形的窗看世界,該裝進什麼、該留空什麼,一眼便分明。好照片不是加進更多,而是好好減去,空蕩蕩的取景框最先這麼教你。"},"ICON-0658":{"nm":"零錢包吊飾","de":"在包包尾端晃晃悠悠地掛著,懷抱幾枚零錢。在自動販賣機前、在熱氣騰騰的鯛魚燒攤前最先打開的小寶庫。那叮噹作響的聲音,正是小小幸福的音效。"},"ICON-0659":{"nm":"收據蒐集棒","de":"差點丟掉的紙片一張張穿了上去。今天吃了什麼買了什麼,收據是比帳本還誠實的日記。攢上一個月,便成了相當厚實的生活紀錄。"},"ICON-0660":{"nm":"市場購物籃標","de":"掛在出門買菜的手腕上,陪你穿梭市場街。一塊豆腐、一把大蔥,連店家多送的那份情都收下。它毫無怨言地承接這一切重量。比起清空,裝滿時更開心的朋友。"},"ICON-0661":{"nm":"紀念磁鐵板","de":"每個旅遊地各挑一個貼在冰箱門上,廚房便成了小小的世界地圖。去過的城市並排掛著,低語著「再去吧」。連平凡的鐵板也有留住回憶的力量。"},"ICON-0662":{"nm":"地區集章簿","de":"一頁一個印章,走過的巷弄以墨水再度復活。走遍全國蒐集的紅色痕跡,正是足跡的地圖。空格愈少,下一段旅程便靜靜招手。"},"ICON-0663":{"nm":"包裝繩卷","de":"為了綁一個禮物盒而無止境抽出的、長長的耐心。只允許懂得適時剪斷的手打出俐落的結。捲成一圈圈,靜靜等候下一回輪到自己。"},"ICON-0664":{"nm":"禮物緩衝包","de":"把易碎的心意鬆軟地包裹懷抱。即使在搖晃的快遞車廂裡,也鬆軟地撐著說「沒事,有我托著你」。等於連開箱者那燦爛的笑容,都預先守護下來。"},"ICON-0665":{"nm":"價格標遮蔽封","de":"把要送的禮物的價錢悄悄蓋住,一張溫柔的謊言。「不必知道多少錢,收下心意就好」,輕輕坐在價格標上。不是遮掩,而是讓那份心意更加閃耀的事。"},"ICON-0666":{"nm":"小購物車片","de":"雖然推不動真的購物車,但這位在指尖晃悠的小朋友,裝滿了逛賣場的雀躍。雖小,但「今天買點什麼呢」的那份心跳,絲毫不輸給真的。"},"ICON-0667":{"nm":"夜光鞋夾","de":"在夜間散步的運動鞋尖端閃一下,向經過的車送出「這裡有人喔」的信號。在黑暗巷弄裡最先出來迎接的小小光芒。安全總是從腳尖開始悄悄展開。"},"ICON-0668":{"nm":"小手電筒蓋","de":"套在手電筒頭上,光便散得更遠、更柔。是在漆黑的帳篷頂上畫出滿天星群的小魔術師。在有點怕黑的夜裡,再沒有比它更好的朋友了。"},"ICON-0669":{"nm":"到家提醒鈕","de":"用力一按,「平安到家了」一行字便飛向遠方的家人。深夜裡,代替玄關門響的小小一鈕傳達了平安。有人就等著這信號入眠。"},"ICON-0670":{"nm":"反光貼紙卷","de":"剪一格貼到包包、自行車、雨傘上,夜路便安全許多。一遇上車頭燈就明亮甦醒的瞌睡蟲。捲成一圈圈,等待下一片黑暗到來。"},"ICON-0671":{"nm":"緊急計程車卡","de":"插在錢包一格裡,深夜空蕩蕩的車站也沒那麼茫然。一個號碼、一行地址,像「會載你回家」的承諾般寫著。沒想到緊急這個詞,竟能如此令人安心。"},"ICON-0672":{"nm":"夜路地圖帶","de":"把路燈稀疏的路繞在手腕上走著。哪條巷子明亮、哪裡漆黑,悄悄告訴你只有夜晚知道的捷徑。是條即使在黑暗中也不讓你迷失方向、綁在身邊的帶子。"},"ICON-0673":{"nm":"安心鈴收納袋","de":"危急時一拉,便大聲喊到整條巷子都嚇一跳。平時乖乖藏在袋子裡,為了那唯一一次的瞬間珍惜著嗓音。是小袋子裡裝著的最大的吶喊。"},"ICON-0674":{"nm":"門前照明鑰匙圈","de":"漆黑走廊盡頭,摸索著找鑰匙孔的夜晚就此別過。掛在門前,用圓圓的燈光迎接回家的手。「辛苦了,到家了」,鑰匙圈先一步打了招呼。"},"ICON-0675":{"nm":"住處返回備忘","de":"「帶傘喔,關燈再出門。」貼在冰箱上的簡短叮嚀,守著空蕩蕩的住處。給將歸來之人的小紙條。一張紙上承載的溫柔,默默跟到玄關。"},"ICON-0676":{"nm":"線材整理梳","de":"像梳頭髮般,輕輕把糾結的電線梳理整齊。書桌後叢林般的電線林,梳幾下便清爽利落。亂糟糟的不只是頭髮,梳子靜靜地這麼提醒。"},"ICON-0677":{"nm":"筆筒隔板","de":"鉛筆放這邊,螢光筆放那邊,剪刀放末格。在一個筒裡分出小小的村落,給筆們定好位置。有了分格,手也不再徬徨。是書桌上小小秩序的開端。"},"ICON-0678":{"nm":"螢幕備忘夾","de":"掛在螢幕側邊,把「今日待辦」剛好遞到視線高度。是不會忘記、正面就能看見的小提示板。一個夾子,悄悄拉住那顆老想拖延的心。"},"ICON-0679":{"nm":"抽屜分類盤","de":"迴紋針與橡皮筋、圖釘與橡皮擦。給抽屜裡的小部族們各自一個房間。手伸向一格格分好的位置,找尋的時間便縮短,心裡某一角也輕鬆起來。"},"ICON-0680":{"nm":"除塵刷筒","de":"落在鏡頭上的一粒灰塵,在照片裡也成了巨大的汙漬。所以刷子總在筒裡乾乾淨淨地備好等待。守護那不顯眼的潔淨,是一雙勤快的指尖。"},"ICON-0681":{"nm":"書桌墊角","de":"鋪在書桌一角、一個手掌寬的柔軟。筆不會滾落,代替冰冷的玻璃,溫暖的質地托住手腕。為了讓漫長夜晚的字跡不晃動,最先讓出位置的貼心地面。"},"ICON-0682":{"nm":"滑鼠線托夾","de":"線一糾結,心也彷彿哪裡糾結了。把將要散亂的一縷預先抓住、整齊安放的手。既不顯眼,又默默理順書桌脈絡的、小而勤快的儀容。"},"ICON-0683":{"nm":"充電座托架","de":"把躺著的裝置斜斜扶起,螢幕這才與你對上眼。連充電時的等待都變得端正的時間。所謂托住,就是給暫歇之物也整理一下姿態的事。"},"ICON-0684":{"nm":"小垃圾桶標籤","de":"連最小的桶也貼上自己的名字。「丟這裡喔」一行字,在凌亂的書桌上喚來安靜的秩序。所謂標籤,終究是告訴物品「你的用處在這裡」的小小招呼。"},"ICON-0685":{"nm":"隔板布告釘","de":"在布告板上把一張紙咚地按住。把不想忘記的心意暫且託付給牆壁。釘尖上掛著的今日決心隨風微微搖晃,每次經過便拉住你。"},"ICON-0686":{"nm":"標籤框片","de":"一個方形邊框,就把平凡的字變成清晰的一句話。給容易散落的便條,圍上端正格調的片子。不是囚禁,而是包裹住重要的話、不讓它遺失的事。"},"ICON-0687":{"nm":"透明抽屜把手","de":"在透明可見的抽屜裝上把手,便能看著裡頭裝了什麼,卻不會隨意打開。看得見卻不靠近的一掌之距。透明也需要禮貌,抽屜這麼低語著。"},"ICON-0688":{"nm":"瓶蓋鎖夾","de":"敞著不蓋,香氣與色澤都會悄悄溜走。靠一個咬緊瓶蓋的小夾子,昨日的色彩便原封不動留到明日。上鎖這件事,其實是守護所珍惜之物的事。"},"ICON-0689":{"nm":"乾燥劑收納夾","de":"厭惡潮濕、默默守著崗位的小哨兵。把乾燥的空氣留在身邊,是長久保存的第一個條件,這端正的收納夾靜靜地告訴你。乾爽便這樣被守護著。"},"ICON-0690":{"nm":"整理籃標","de":"每個籃子一個小名牌。定好哪一格住著什麼,原本找東西的時間就化作休息的時間。所謂整理,是預先遞給未來的我的一張溫柔紙條。"},"ICON-0691":{"nm":"迷你隔板","de":"在書桌上三兩下立起一個小小房間的小隔板。光憑這一片,就生出一個微微背對世界的安靜角落。是個適合讓專注棲息、全然屬於我的舒適小天地。"},"ICON-0692":{"nm":"收納袋立架","de":"把老是撲撲倒下的袋子的背脊輕輕扶起立好的托架。光是整整齊齊地站著,挑選取用就輕鬆許多。把東西立正,就是預先為下一隻手著想的事。"},"ICON-0693":{"nm":"空格標示片","de":"刻意標示出「此處空著」的片子。把該填補的位置留下來,也是堂堂正正的計畫。空格不是懶散,而是為了即將到來的某物,鄭重空出的一掌餘白。"},"ICON-0694":{"nm":"牙刷套蓋","de":"對碰到嘴的刷毛,會多一份挑剔的用心。連一粒灰塵都擋下的小帽子。守護那看不見的潔淨,正是清爽開啟每個早晨的小小心意。"},"ICON-0695":{"nm":"肥皂瀝水架","de":"為了不讓肥皂泡在水裡軟掉,輕輕把它托起的瀝水架。讓水分流走,便能更久地相伴,這個道理,它在浴室最低最小的位置每天靜靜印證。"},"ICON-0696":{"nm":"洗髮精壓頭夾","de":"輕輕固定住壓頭,按一下就只流出恰好的份量。省著用的手上習慣,是長久居家的基礎。一個小夾子,溫柔地約束著浪費。"},"ICON-0697":{"nm":"刮鬍刀掛蓋","de":"為鋒利之物另外備一個小家。把刮鬍刀卡進蓋子掛好,水分與危險便一同流下。小心對待鋒利的方法,也正是珍愛自己的方法。"},"ICON-0698":{"nm":"沐浴巾環","de":"長長垂下的浴巾繞成環,把你帶到手搆不著的背後。順著泡沫滑下的那一道紋理,連獨自搓背的溫情都暖暖地溢滿整間浴室。"},"ICON-0699":{"nm":"排水口濾網包","de":"讓水流走、把渣滓留住的一張小網。在看不見的地方靜靜防止堵塞。在最低位置工作的東西,守護著整個家的流動,排水口無聲地這麼告訴你。"},"ICON-0700":{"nm":"吸盤掛鉤板","de":"不釘一根釘子,也能在牆上生出一個新位置。用力按貼上去再撕下來,連痕跡都不留。不留痕跡、暫歇片刻便離去的法子——吸盤板深諳這份輕盈的禮貌。"},"ICON-0701":{"nm":"浴室拖鞋標","de":"端正擺在門檻前的一雙。脫鞋進門的居家用心,悉心延伸到了浴室門前。把溫暖冰冷腳尖的小小款待,由名牌靜靜指定了那個位置。"},"ICON-0702":{"nm":"迷你漱口杯","de":"盛一口漱口水的小圓杯。以漱口的短短瞬間,靜靜承接一天的開始與結束。即使不華麗,卻每天都在身邊——樸素才是最長久的居家之道。"},"ICON-0703":{"nm":"撢子套","de":"像撫摸般輕輕拂去灰塵的刷子,給它的羽毛套上套子。像把翅膀妥帖收攏歇息的鳥,懂得歇息之處的工具,才能長久留在身邊。"},"ICON-0704":{"nm":"黏塵滾筒補充卷","de":"撕掉一層,底下便冒出乾爽的新面。捲收絨絮與髮絲的黏黏夾層。用完又能補上的圓圓補充卷裡,纏著勤奮反覆的美德。"},"ICON-0705":{"nm":"抹布夾","de":"代替手俐落咬住抹布的夾子。在冰冷地板與手指之間留出一掌之距。一個替你承接髒活的把手,讓辛苦的打掃輕快了許多。"},"ICON-0706":{"nm":"縫隙刷蓋","de":"瞄準狹窄縫隙鑽進去的細刷,守護它纖弱末端的小帽子。是顆連手搆不到的角落也悉心照看的心。擦拭看不見之處的人,讓家的胸懷寬了一掌。"},"ICON-0707":{"nm":"噴霧瓶標籤環","de":"輕輕貼在噴霧瓶肩上的小名牌。裡頭裝的是清水還是清潔劑,僅憑一行字便清楚告知。預先消除混淆的標籤,是手腳俐落的居家高手的老習慣。"},"ICON-0708":{"nm":"衛生紙補充帶","de":"在用完之處卡上新一捲、俐落綁好的帶子。是把斷開之物重新接續的最簡單手勢。在用完之前就預先補上的某人心意,圓圓地繞在這小環上。"},"ICON-0709":{"nm":"清潔手套掛環","de":"把剛做完水活的濕手套掛起晾乾的掛環。給辛苦的手讓出一處暫歇之地。水分緩緩晾乾的同時,為了下一件活兒靜靜調息的短暫休息。"},"ICON-0710":{"nm":"掃帚掛釘","de":"把掃帚倒過來掛好,刷毛便不會彎曲、筆直挺立。倒掛著等待下一片庭院的姿態。是個雖小卻俐落、幫它在用完後仍保持原樣的位置。"},"ICON-0711":{"nm":"垃圾袋夾","de":"俐落咬住袋口,不讓一點東西外漏地牢牢封住。用收緊末端的一個手勢,收尾便清爽許多。所謂收尾,終究是從好好封住開始的。"},"ICON-0712":{"nm":"曬衣夾收納筒","de":"散落便容易遺失的曬衣夾,聚在一起共同生活的筒子。給小東西們讓出一個同住的家。把指尖的小兵們收攏一處,需要時便能一眼找到。"},"ICON-0713":{"nm":"襪子分類環","de":"落單的襪子總是悄悄消失到哪裡去。洗之前用環一雙雙綁好,蓬鬆晾乾後兩隻也不會分離。所謂分類,是預先防止消失的小小約定。"},"ICON-0714":{"nm":"洗衣球收納袋","de":"在洗衣機裡咕嚕咕嚕滾動,把沾在衣服上的汙垢咚咚敲醒。以圓圓的身軀撫摸衣物的節奏。在洶湧水流間,把敲打這份洗衣的古老本能裝進袋裡滾動。"},"ICON-0715":{"nm":"羊毛精量杯","de":"對細緻的衣物用細緻份量的洗劑。把羊毛洗劑恰好量出一蓋份量、細細遞上的量杯。一個小刻度裡,裝著對待毛料的謹慎手勢。減去過量也是一份用心。"},"ICON-0716":{"nm":"布料保護貼","de":"在磨破之處輕輕補上的小貼片。不隨意丟棄磨損之處、靜靜照料的指尖心意。每道縫補的痕跡,都與那件衣服一同走過的歲月紋路,優美地留存著。"},"ICON-0717":{"nm":"曬衣架固定釘","de":"為了不讓曬衣架被風一吹就飛走、靜靜按住它的釘子。即使在衣物隨陽光起伏的日子,也幫它在搖晃中守住原位。是個雖小卻可靠的配重之責。"},"ICON-0718":{"nm":"內衣洗衣袋標","de":"纖弱的內衣放進網裡單獨洗。把柔嫩之物從洶湧水流中緊緊包裹懷抱的網。一個貼著名牌的小袋子告訴你,小心守護脆弱之物也是居家。"},"ICON-0719":{"nm":"洗劑勺掛架","de":"把舀粉狀洗劑的勺子整齊掛在牆上。不必再掉進桶裡弄濕手的麻煩。總把同樣的工具放在同樣位置的端正習慣,俐落地裝在這個小掛架上。"},"ICON-0720":{"nm":"曬衣繩制止器","de":"緊緊咬住曬衣繩末端,即使載滿沉甸甸的衣物也不會滑脫地牢牢固定。為了不讓繃緊的一條線下垂、撐到最後的最後一個結。俐落的收尾就懸在這上頭。"},"ICON-0721":{"nm":"枕套標籤","de":"每晚臉頰最先觸碰的位置,其內側縫著一片指甲般大的標籤。記著洗滌溫度的蠅頭小字,有誰會全讀呢。即便如此,它仍是守在睡顏旁、最貼近的一張說明。"},"ICON-0722":{"nm":"棉被夾","de":"開著窗的夜晚,即使風吹進來,棉被也不會逃走。因為咬緊雙口的夾子正叼著被角。是代替熟睡之人抓住末端的、無聲的一隻手。"},"ICON-0723":{"nm":"睡眠燈遮光板","de":"「燈光碰到眼睛,睡意就遠了。」有人悄悄立起的一片遮光板,讓光退到後頭,只隱約浸潤腳邊。是一片借出一掌黑暗的小隔板。"},"ICON-0724":{"nm":"床縫口袋","de":"想想床墊與牆壁之間,那道手搆不著的縫隙吧。滾落的遙控器、眼鏡如今都聚到這裡。是床悄悄張開、承接那些差點遺失之物的口袋。"},"ICON-0725":{"nm":"眼鏡收納盤","de":"摘下鏡片,世界便柔柔暈開,那短暫的毫無防備被一只淺盤接住。到了早晨,即使指尖不必摸索,眼鏡也總在同一位置等候著。"},"ICON-0726":{"nm":"鬧鐘底座","de":"清晨六點,最惹人厭的聲音響起的堅實踏板之上。穩穩托住時鐘,終究開啟了某人的一天。它默默撐起甦醒這個冷淡的約定。"},"ICON-0727":{"nm":"床頭線材托夾","de":"滑向床頭的充電線再也不會掉到地上。因為小托夾靜靜抓住了線的末端。是個手一伸便能搆到的距離,理順了夜晚動線的手。"},"ICON-0728":{"nm":"睡衣收納帶","de":"把疊好的睡衣繞一圈綁起的帶子。連易散的柔軟也需要儀容。是今日的我為明晚的我,端正捲好的小小準備。"},"ICON-0729":{"nm":"香氛卡夾","de":"把沾了香氣的卡片斜斜立著,便像翻書頁般用鼻尖翻過季節。從薰衣草到柑橘——成了用氣味寫下的那天的日記本。"},"ICON-0730":{"nm":"鑰匙盤墊","de":"玄關一隅,鑰匙鏗鏘落下的地方。鋪了柔軟墊子的盤子吞下那刺耳的聲響。歸來之人的第一個動作,由小小的托盤靜靜接住。"},"ICON-0731":{"nm":"雨傘接水蓋","de":"拿進門的雨傘尖端,雨水滴滴答答落下。一個蓋子俐落接住那滴水,等於有人預先體貼地擋住了那悄悄在地板上暈開的小水窪。"},"ICON-0732":{"nm":"口罩掛片","de":"貼在玄關旁牆上、指甲般大的片子。像出門的最後儀式,口罩掛在這裡。為了不忘記該帶的東西,在門前守著視線高度的小小記憶裝置。"},"ICON-0733":{"nm":"快遞刀刀鞘","de":"套在劃開快遞箱的刀刃上的保護蓋。把藏在拆封雀躍背後的割傷風險靜靜蓋住。是個讓等待的終點安全開啟、不顯眼的體貼。"},"ICON-0734":{"nm":"鞋刷托架","de":"刷完鞋的鞋刷濕著被放下的位置。即使含著水分,底面也乾爽地晾乾。創造潔淨的工具也需要歇息之處,小小的托架這麼告訴你。"},"ICON-0735":{"nm":"訪客留言板","de":"「順道來看看就走囉。」留在玄關留言板上的一行短字。是錯身而過的人們跨越時間分享的小廣場。一格紙上,問候、託付與一顆愛心重疊堆積。"},"ICON-0736":{"nm":"門縫擋條卷","de":"從門下手指般的空隙滲進來的穿堂風。捲成一圈的擋條靜靜攔住那個路口。把看不見地溜走的暖意,在房內多留住一層。"},"ICON-0737":{"nm":"門擋吊飾","de":"為了不讓敞開的門再度闔上、撐住其腳邊的小吊飾。為了進出的風與腳步聲沉甸甸地守著崗位。是個讓敞開得以持續的、溫柔的固執。"},"ICON-0738":{"nm":"玄關照明開關蓋","de":"深夜摸索著找尋的玄關開關。夜光蓋在黑暗中柔柔示出它的位置。為了不讓手徬徨,在燈亮之前先一步發光的小小指引者。"},"ICON-0739":{"nm":"杯墊","de":"放在餐桌上的杯子正要滑開的瞬間,一片墊子靜靜按住它的腳。即使凝結了水珠也不留一絲痕跡,沉穩守著崗位的托墊。"},"ICON-0740":{"nm":"車用香氛夾","de":"掛在車裡的小香氛夾。隨著出風口的風,淡雅的氣味緩緩填滿狹小空間。連等紅燈的無聊都用香氣暖熱起來,是駕駛座溫柔的慰藉。"},"ICON-0741":{"nm":"安全帶套","de":"套在橫過肩膀的安全帶上的柔軟套子。碰到後頸的粗糙感悄然消失。為安全用的帶子也能添一份溫柔,一掌寬的布這麼說。"},"ICON-0742":{"nm":"停車號碼遮蔽板","de":"在拍照前悄悄遮住地下停車場告訴你我位置的號碼板。誰都有不想留下的資訊。在日常的一個畫面裡,謹慎抹去的一層。"},"ICON-0743":{"nm":"腳踏車鈴蓋","de":"叮鈴鈴。在巷子轉角自行車遞來的清脆問候。套在鈴上的蓋子,即使下雨也守住那聲音。一聲小小的鈴響,人們便笑著讓開一步。"},"ICON-0744":{"nm":"握把套環","de":"把碰觸手掌的握把觸感柔柔包裹的環。即使久握奔馳,手也不發麻。愈是遠路,握持之處的舒適愈能縮短那段距離。"},"ICON-0745":{"nm":"安全帽標籤貼","de":"貼在安全帽內側的名字貼紙。在一模一樣的安全帽之間小聲喊著「這是我的」。是刻在守護頭部的堅固之上、最私密的一個標記。"},"ICON-0746":{"nm":"輪子反光蓋","de":"太陽下山才終於開始工作的蓋子。承接經過的燈光,把車輪清晰地反射出來。在黑暗中以光遞出「這裡有人喔」的小小信號。"},"ICON-0747":{"nm":"車鑰匙保護袋","de":"在口袋裡與其他鑰匙碰撞而被刮花的車鑰匙。柔軟的袋子把它的表面整個包裹。愈是每天握的東西,愈盼它無傷地長久,那份心意都裝在那裡。"},"ICON-0748":{"nm":"吸盤層架釘","de":"不釘一根釘子,輕輕一按就貼上牆的吸盤層架釘。連不想留痕跡的牆上也生出一格收納。在暫住的房間掛上居家用品的、不留痕跡的本事。"},"ICON-0749":{"nm":"免打孔掛鉤板","de":"不打穿牆壁也能掛東西,竟有這種事。免打孔掛鉤板悄悄擔起輕巧的行李。不願弄壞租來的空間的心意,優美地裝在一個小掛鉤裡。"},"ICON-0750":{"nm":"磁吸整理條","de":"鐵製品咚一聲、貼回原位的聲音。用磁鐵把四散的瑣碎工具唰地聚攏,原本一團亂的工作檯便排成整齊的一列,隨之而來一份小小的暢快。"},"ICON-0751":{"nm":"縫隙收納桿","de":"想像一下冰箱與牆壁之間那道被遺忘的狹小縫隙。細細的桿子把那道空隙填滿成生活的一隅。在被視為無用的空間裡撈起收納，是何等精打細算的巧思。"},"ICON-0752":{"nm":"黏貼墊片","de":"一旦貼上，再沉的東西也能輕鬆撐住的黏貼墊片。撕下時神奇地不留半點痕跡。在看不見的角落默默承重，安靜而堅韌的力量。"},"ICON-0753":{"nm":"門掛掛鉤蓋","de":"只要往門板上輕輕一掛即可的掛鉤蓋。包包也好毛巾也好，都懸在伸手可及的高度。不必釘一根釘子就生出的掛架，為狹小的房間多添一格餘裕。"},"ICON-0754":{"nm":"牆面理線夾","de":"把沿牆垂落的電線整理成一條的夾子。桌後糾結的線團被理成俐落的一道線。看不見的整理，連房間的空氣都變得輕盈幾分。"},"ICON-0755":{"nm":"立燈底座墊","de":"悄悄墊在立燈腳下的墊片。不在桌面留下刮痕，連細微的晃動都一併安撫。撐起光亮這件事，也得先有一塊不動搖的底。"},"ICON-0756":{"nm":"防滑黏貼板","de":"腳下總是悄悄打滑的地墊，終於穩穩停在原位。因為黏貼板緊緊咬住了地面。把險些跌倒的瞬間提前收走，是不顯眼的安全網。"},"ICON-0757":{"nm":"精密螺絲起子蓋","de":"「這顆小螺絲怎麼鬆不開呢。」套在精密螺絲起子尖端的蓋子守護著刀刃。開啟那巴掌大機械裡的世界，是最纖細的指尖之器。"},"ICON-0758":{"nm":"六角扳手環","de":"把好幾支六角扳手串在同一個環上的環圈。依大小排成一列的金屬像扇子般嘩啦展開。一把就挑出所需的那支，是井然有序的手部節奏。"},"ICON-0759":{"nm":"迷你捲尺扣","de":"掛在巴掌大迷你捲尺上的小扣環。掛在鑰匙圈上隨你走到哪都跟著。把突然好奇的長度，當場量給你答案的小夥伴。"},"ICON-0760":{"nm":"螺絲分類盒","de":"各式各樣的螺絲一格一格找到自己位置的分類盒。原本混雜亂滾的小零件也生出了秩序。在修理什麼之前，先學會整理的手。"},"ICON-0761":{"nm":"膠水噴嘴蓋","de":"蓋著就不會硬掉，開著卻會乾涸——我活在那兩者之間。每滴落下時，某處破碎的東西正在重新接合。一個小蓋子，靜靜守護著停滯與流動的界線。"},"ICON-0762":{"nm":"水平儀鑰匙圈","de":"在鑰匙串末端晃蕩的、巴掌大的誠實。最先察覺架子歪斜的，總是這顆小小的氣泡。把這位悄悄提醒「世界微微傾斜了」的朋友裝進口袋帶著走。"},"ICON-0763":{"nm":"鑷子保護蓋","de":"越是尖銳的東西，越需要一件安撫它的衣裳。輕輕包住尖端，手與零件都不會受傷。處理鋒利之物的第一份禮貌，就是靜靜蓋住那尖端——小蓋子擔起這份溫柔。"},"ICON-0764":{"nm":"小型切割墊","de":"刀刃劃過數千次，傷痕仍會自行癒合的板。割開的地方又疊上下一次作業，又癒合。以自身為祭，讓別的東西被細細切下，是默默無聲的底板的一天。"},"ICON-0765":{"nm":"維修零件袋","de":"為了不讓一顆螺絲、一根彈簧永遠消失而收緊袋口。修好之後剩下的小東西，在這裡靜靜等候下一次出場。防止遺失的，總是這樣不起眼的一格。"},"ICON-0766":{"nm":"零食袋夾","de":"守住開封袋子酥脆的，終究是那一次果斷的夾合。一個「絕不給受潮留縫隙」的小小約定。把袋口俐落咬緊的手部習慣，拯救了明天的點心。"},"ICON-0767":{"nm":"軟糖分裝杯","de":"要把一袋分給好幾人，得先公平地分開。在每個小杯裡舀進同樣份量的心意。所謂分享，相信總是從「不讓任何人覺得委屈」的同等份量開始。"},"ICON-0768":{"nm":"巧克力錫箔片","de":"曾包裹甜蜜的銀光，在指尖輕易就皺起。攤開時短暫閃爍，摺起時便成回憶。吃完之後才最美的一片光——丟棄之前再多看它一眼。"},"ICON-0769":{"nm":"零食標籤帶","de":"裝了什麼、何時前最佳——我替沉默的袋子說出口。一條帶子貼上的瞬間，連點心也有了名字與約定。分類其實是最溫柔的記憶法。"},"ICON-0770":{"nm":"糖果分類盒","de":"酸的和甜的不放進同一格。為了讓手不再猶豫，事先就分好。當小盒子們排成一列站好，挑選的樂趣便悄悄翻了一倍。"},"ICON-0771":{"nm":"餅乾緩衝紙","de":"為了不讓餅乾在路上碰傷，一片片夾進中間的薄紙。越易碎的東西，越需要更柔軟的同行。比起堅硬，柔暖有時反而守護得更好。"},"ICON-0772":{"nm":"甜甜圈盒繩","de":"十字綁起的一個結，扛起盒中蛋糕的平安。它成了提把，成了封印，成了令人雀躍的等待記號。這條繩被解開的瞬間，就是某人的生日。"},"ICON-0773":{"nm":"麵包袋夾","de":"扭轉一圈摺好再夾上我，麵包的濕潤便封存到明天早晨。是擋住空氣的、小而固執的堅持。長久守護柔軟之物，總是某個堅硬之物的職責。"},"ICON-0774":{"nm":"零食交換牌","de":"你的份給我，我的份給你。在小牌子上寫下名字、互換零食的那天的雀躍，還記得嗎？貼在分食心意上的紙片，總是工整地寫著朋友的名字。"},"ICON-0775":{"nm":"吸管封口蓋","de":"喝口稍歇時就把我蓋上。不讓灑出、不讓變涼，就在原地靜靜等候。為了再次湊上唇的那一刻，守住入口，是小封蓋的工作。"},"ICON-0776":{"nm":"隨行杯名字環","de":"在一字排開的眾多隨行杯之間，告訴你「這是我的」的小環。光憑一種顏色，混淆便緩緩解開。「是我的」這個標記，有這一只環就足夠清晰。"},"ICON-0777":{"nm":"杯套","de":"悄悄擠進燙杯與手掌之間的一層瓦楞紙。為了不燙傷、不滑落而墊上的體貼。守住兩者之間的距離，便成就一杯平安無事。"},"ICON-0778":{"nm":"製冰盒標籤","de":"有人會在每塊冰上寫下製作的日期。憑著「連冰冷也有順序」的信念。一張小標籤，讓冷凍庫的時間誠實地、依序流淌。"},"ICON-0779":{"nm":"茶包夾","de":"守望浸泡的時間，在恰好的瞬間撈起。懂得在太濃之前喊停的好手藝。茶的深度，由抽出的時機決定，而非浸泡的時間。"},"ICON-0780":{"nm":"濾杯架","de":"為了讓熱水緩緩滴落而托起濾紙，默默佇立。它深知急了，香氣就會變淺。承托等待這件事，也需要不動搖的姿態。"},"ICON-0781":{"nm":"水壺背帶","de":"把水壺掛在手腕、肩上一同走路的帶子。不必刻意拿取，也總讓它在身旁的同行方式。為了不忘，輕輕繫上一條，有時是最溫柔的方法。"},"ICON-0782":{"nm":"罐蓋蓋","de":"蓋住喝了一半的罐口，擋住灰塵與氣泡逸散。負責守住下一口新鮮的小帽子。把暫時開啟之物靜靜蓋好，這件事也藏著一份用心。"},"ICON-0783":{"nm":"飲料集點卡夾","de":"第十杯的那杯免費——為了不弄丟那個約定而懷抱集章卡。讓一格格累積而來的日子不被揉皺。這個夾子裡，堆著常客勤快往返的足跡。"},"ICON-0784":{"nm":"便當束帶","de":"為了不讓蓋子打開，把便當緊緊環抱一圈的帶子。是「在包包裡湯汁不會漏」的小小安心。負責守護到午餐前平安無事的，正是這俐落的一圈。"},"ICON-0785":{"nm":"配菜杯組","de":"給每樣配菜一個位置，味道便不會互相混雜。泡菜歸泡菜，涼拌菜歸涼拌菜，清清楚楚。小杯子們分出的格子，是便當的秩序，也是手藝之上的溫柔。"},"ICON-0786":{"nm":"筷子收納盒","de":"把陪伴一日三餐的筷子乾淨收好隨身帶著的小屋。在書包裡也守著整潔的安靜同行。隨身帶著的那份心，終究成就了一頓乾淨的餐。"},"ICON-0787":{"nm":"醬料瓶標籤","de":"是醬油還是醋，為易混淆的瓶子披上清晰。一行字貼上的瞬間，指尖的猶豫便消失了。忙碌廚房的速度，正是由這些小小標記悄悄造就。"},"ICON-0788":{"nm":"海苔飯捲片","de":"把飯與餡捲成一體的薄薄一張海苔。要捲得緊實，切時才不會散。郊遊日早晨的雀躍，正是從這一層裡圓圓捲出的。"},"ICON-0789":{"nm":"竹籤收納盒","de":"把串籤與牙籤立在一處，需要時手便不會亂找。連尖銳之物也給它一個固定的家。整理，終究是為下一隻手伸來而準備的小善意。"},"ICON-0790":{"nm":"保冷袋套","de":"為了多留住一點冰涼，給保冷袋再裹上一層。也一併擋住凝結的水珠弄濕包包。把清涼守到最後的，總是這厚實的一層。"},"ICON-0791":{"nm":"便當隔板","de":"為了不讓飯與配菜侵犯彼此的位置而立起的小矮牆。是湯汁不越界的一格和平。一格格分開的便當，原原本本盛著做菜人的細膩之心。"},"ICON-0792":{"nm":"用餐順序卡","de":"是先喝湯還是先吃飯，悄悄告訴你今天順序的卡片。是「照順序吃更美味」的溫柔指引。它靜靜告訴你，連一頓飯也像故事般有著流動。"},"ICON-0793":{"nm":"量杯貼紙","de":"貼在刻度旁的小貼紙，明確點出「到這裡」。把每次都搞混的份量一次校準的標記。所謂準確，正源於這樣一條小小的指引線。"},"ICON-0794":{"nm":"矽膠鍋蓋把手","de":"讓你不燙到手指就能掀起燙鍋蓋的小把手。悄悄借給你打開冒著蒸氣的鍋的勇氣。安全，總是來自事先備好一個可抓之處。"},"ICON-0795":{"nm":"迷你夾掛架","de":"抹布也好袋子也好，為那些無處可掛之物騰出位置的小夾子。把雜亂的一面牆變成井然有序的風景。一個掛起的習慣，便讓廚房輕盈不少。"},"ICON-0796":{"nm":"油刷蓋","de":"蓋住塗油刷子的尖端，灰塵與硬化都會避開。守護那份柔軟到下次料理的帽子。愛惜工具的小小心意，終究長久守住了味道。"},"ICON-0797":{"nm":"鹽匙罐","de":"牢牢插在鹽罐裡棲身的小匙。每次都用心舀起一撮的精準。所謂調味的手藝，就是這把小匙所記得的那份心意。"},"ICON-0798":{"nm":"計時器磁鐵板","de":"貼在冰箱門上，數著泡麵的3分鐘、量著運動的30秒。憑一張磁鐵，讓本要流逝的時間停留眼前。把流逝之物暫時釘在牆上的，勤快的小圓圈。"},"ICON-0799":{"nm":"鍋柄套","de":"包住燒燙的把手，讓你不必空手去抓的一層。是擋在燙與手掌之間的小盾牌。平安搬運這件事，總是從這柔軟的包覆開始。"},"ICON-0800":{"nm":"砧板防滑膠","de":"我鋪在底下，砧板便不再打滑。每當切菜晃動，就在下方撐住的一塊橡膠。所謂穩定，就是在看不見的地方牢牢咬住。"},"ICON-0801":{"nm":"廚房手套夾","de":"在爐火前不停忙碌的手暫歇之處。把飄動的一隻手套固定在牆上，到下一餐前的短暫喘息便開始了。整理，終究是溫柔的另一個名字。"},"ICON-0802":{"nm":"咖啡攪拌棒架","de":"櫃檯旁，細細的棒子們肩並肩層層倚立的位置。準備好為某人的晨杯畫上圓圈，排隊站好的模樣，恰似就要齊聲開口前的合唱團。"},"ICON-0803":{"nm":"杯墊組束帶","de":"輕輕咬住杯子觸到餐桌那聲小小叩響的束帶。把圓圓的杯墊綁在一起，迎客的準備就完成了。款待，總是從這樣不起眼的角落率先開始。"},"ICON-0804":{"nm":"糖漿標籤片","de":"貼在瓶上的一行名字。甜、濃——那短短一個詞，便把忙碌的早晨安撫得井然許多。標籤是預先寫下小小約定的紙。"},"ICON-0805":{"nm":"甜點叉收納盒","de":"戳起一塊水果的尖棒們聚居的盒子。在像旗子般插上甜點盤之前，它們在這裡安靜等候自己的順序。甜味也是有順序的。"},"ICON-0806":{"nm":"攪拌棒套","de":"把一把攪拌棒緊緊包住的紙衣。替握杯的指尖吸去冷飲滴落的水氣，讓它保持乾爽。看不見的體貼，總是來自邊緣。"},"ICON-0807":{"nm":"外帶提袋牌","de":"雙手不夠用的瞬間，替你提杯的小提把。緊緊抓住打包的暖意一滴不漏，把那份溫暖送到某人的巷口。"},"ICON-0808":{"nm":"咖啡店取餐鈴套","de":"靜靜包住「等到震動響起前」那段等待的衣裳。守著咖啡店一角閃爍的號碼牌，連「就快輪到我了」的那份雀躍也一併懷抱著。"},"ICON-0809":{"nm":"集章卡環","de":"集滿十格就多送一杯的紙。每多蓋一個章，「常客」這名字也一點點長大。串在小環上的，是再樸實不過的快樂。"},"ICON-0810":{"nm":"咖啡豆樣品袋","de":"裝一把咖啡豆、先以香氣相迎的袋子。掠過鼻尖的酸味與甜香，那第一印象決定了一杯的命運。香氣比任何說明都更快抵達。"},"ICON-0811":{"nm":"冷藏標籤磁鐵","de":"啪一下貼上冰箱門的小磁鐵名牌。寫下什麼在何時放進來，差點被遺忘的配菜也找回自己的順序。所謂持家，就是把流逝的記憶繫住。"},"ICON-0812":{"nm":"保存日期片","de":"把裝入的日子清楚刻下的一片。過了幾天也悄悄告訴你「這個還沒壞」的小證人。新鮮，由記住日期的指尖守護。"},"ICON-0813":{"nm":"分裝盒束帶","de":"繞著分裝盒的腰身環抱一圈的束帶。把躍動的蓋子緊緊摟住，守住冰箱裡的小秩序。綁住某物這件事，與整理心情十分相像。"},"ICON-0814":{"nm":"密封夾色帶","de":"俐落咬緊袋口、色彩繽紛的夾子。紅色是辣的，黃色是甜的——光看顏色，手便先知道。廚房的紅綠燈就這樣無言地指引方向。"},"ICON-0815":{"nm":"冷凍包名牌","de":"輕輕擱在冷凍物上的名牌。在結霜的袋子裡也不忘自己曾是什麼，這樣安撫它。是向陷入冬眠的食材捎去的小小問候。"},"ICON-0816":{"nm":"蔬菜保存網","de":"寬容地接住沾土蔬菜的疏鬆網袋。「要留出呼吸的縫隙才能久放」，奶奶的廚房老早就知道。通風，是給蔬菜的溫柔留白。"},"ICON-0817":{"nm":"瓶蓋分類蓋","de":"把不同大小的瓶蓋一一配對的分類蓋。替它們找回失散的另一半，比想像中更溫柔。湊好相配的一對，廚房也整齊不少。"},"ICON-0818":{"nm":"蛋盒標籤","de":"在十個小巢上工整標記的記號。提醒你先用放了幾天的蛋，這是持家的智慧。連一片早晨煎蛋裡，也藏著張羅順序的心。"},"ICON-0819":{"nm":"剩菜貼紙","de":"「這是我的！」寫上一行貼好，冰箱裡也暫得安寧。預先定下宵夜主人的可愛宣戰。所謂家人，就靠這種瑣碎的協定，今天也照樣運轉。"},"ICON-0820":{"nm":"筷架小片","de":"讓湯匙和筷子不直接觸到餐桌、輕輕托住的一片。這份小小的整潔，悄悄抬升了一餐的格調。餐桌禮儀，就在這樣的角落靜靜長成。"},"ICON-0821":{"nm":"餐巾固定環","de":"把要被風吹散的餐巾靜靜夾住的環。將等待展開的白紙整齊攏起，在餐桌上工整地刻下一份小秩序。"},"ICON-0822":{"nm":"桌墊壓角","de":"輕輕按撫桌墊翹起一角的小物。「一端被壓住，整體才終於平整」，餐桌每天這樣教導。連邊角也有屬於自己那份的責任。"},"ICON-0823":{"nm":"小調味盤","de":"把一碟醬油、一撮鹽並排托住的小托盤。連一道佐料也騰出位置的餐桌寬厚胸懷。韓式料理，因張羅佐料的心而更顯深厚。"},"ICON-0824":{"nm":"餐桌號碼片","de":"在忙碌餐廳裡被喊「幾號客人！」的那個數字。替等待標上順序，為所有人守住公平。一枚片子裡裝著的，是小小約定，與即將端出的一碗熱食。"},"ICON-0825":{"nm":"水杯標示帶","de":"繞在水杯上、悄悄告訴你是誰的帶子。在相似的杯子間標出我的位置的小旗。圍坐共桌時，這樣的體貼能擋住無謂的誤會。"},"ICON-0826":{"nm":"分食碟分類別針","de":"用顏色區分各人分食小碟的別針。溫柔地劃出我的與你的界線，讓分食的樂趣更顯清爽。情誼照分，但衛生俐落守住。"},"ICON-0827":{"nm":"菜單遮板","de":"攤開的菜單背後，悄悄遮去的猶豫時光。選什麼吃的那短短遲疑，其實也是用餐的一部分。今天吃什麼呢——它靜靜遮住那份雀躍。"},"ICON-0828":{"nm":"座位牌架","de":"把名牌筆直立好的小底座。無論宴會場座位還是喜宴桌，都清楚告知「這裡有您的位置」。款待，在喚出名字的那一刻才終於完成。"},"ICON-0829":{"nm":"瑪芬杯套","de":"把剛烤好的瑪芬豐潤腰身緊緊包住的紙衣。托住溫熱的身軀不讓它從手中滑落，把溫度好好守到咬下一口的那刻。甜點也需要衣裳。"},"ICON-0830":{"nm":"擠花袋蓋","de":"讓擠奶油的袋口緊緊閉合的封蓋。休息時連一滴都不外漏地俐落封住袋口。蛋糕上一朵小花，正是從這份節制中綻放。"},"ICON-0831":{"nm":"餅乾模環","de":"把麵團切成星形、熊形的圓模。同樣的麵粉經指尖一過，便化出數十種表情甦醒。無論烤什麼，最先觸到麵團的，永遠是用心。"},"ICON-0832":{"nm":"麵團刮刀吊飾","de":"把麵團細心刮聚、俐落切開的扁平的手。連黏在盆上的一把都不放過的那份勤快，決定了一塊麵包的份量。烘焙是惜物之手的活兒。"},"ICON-0833":{"nm":"量匙板","de":"一小匙、半大匙——讓量匙穩穩平放、整齊排列的板。精準的一匙，把味道的平衡立得端正。「手藝」一詞背後，其實藏著仔細的計量。"},"ICON-0834":{"nm":"烤箱手套鉤","de":"把守在燙烤箱前的手套掛起來的鉤。替你擋過燙傷的厚實之手，歇息時也靜靜停在伸手可及之處。安全，總是始於那永遠在原位的東西。"},"ICON-0835":{"nm":"冷卻網夾","de":"整齊咬住剛烤好點心冷卻網的夾子。在蒸氣散去時固定住不讓它走位，陪你一起等待酥脆的完成。冷卻，也需要一把耐心。"},"ICON-0836":{"nm":"蛋糕插牌","de":"把「生日快樂」幾個字輕輕插立在蛋糕上的插牌。在燭火熄滅前一刻，這面小旗把一個人的一天照得最明亮。祝賀，要立得高才看得見。"},"ICON-0837":{"nm":"糖粉罐","de":"盛著最後一次輕盈撒落的罐。如白雪般紛紛落在剛烤好的甜點上，把平凡的一塊化成小小禮物。收尾，來自最輕的手勢。"},"ICON-0838":{"nm":"三角飯糰標籤","de":"把塑膠膜按1、2、3順序撕開，海苔就酥脆復甦的那個三角形。讓你一眼認出便利商店深夜可靠夥伴的一行字。晚自習後嘴饞的夜晚，就貼在這裡。"},"ICON-0839":{"nm":"杯麵蓋固定夾","de":"在3分鐘的等待裡，靜靜壓住蓋子不讓它掀起的托架。代替從前壓在上頭、怕蒸氣跑掉的那雙筷子的位置。麵泡熟的那短短時間，是宵夜最雀躍的瞬間。"},"ICON-0840":{"nm":"熱狗串蓋","de":"俐落包住串籤尖端的小蓋。讓你方便咬下，手上不沾一滴醬料地守護著你。小吃店前零嘴的樂趣，總在這樣的瑣碎裡完成。"},"ICON-0841":{"nm":"塑膠袋提把","de":"勾在手指上，塑膠便沙沙地輕輕作響。買來的重量偏向一邊，走回家的路在手掌留下紅紅的勒痕。輕響之中，今日這一份的生計沉甸甸地盛著搖晃。"},"ICON-0842":{"nm":"收據摺疊夾","de":"把長長吐出的收據對摺一夾，今天花的錢便成乖巧的一疊。沾著油墨味的紙層層堆疊間，瑣碎的生計記憶也漸漸整理得井然。"},"ICON-0843":{"nm":"微波爐標籤","de":"在叮一聲響起之前，標籤靜靜估算加熱的時間。幾分幾秒，寫下要加熱之物名字的小指示牌。等待變暖的心情裡，也有這樣的刻度。"},"ICON-0844":{"nm":"折扣貼紙卷","de":"每撕下一格，黏黏的聲響便搔著指尖。紅色數字成排捲出時，某人的購物籃便輕了幾分。圓圓捲起、靜靜等候的一卷小善意。"},"ICON-0845":{"nm":"醬料袋環","de":"酸酸的一下在嘴角漾開，平凡的一天也微微甜了起來。掛在圓環上的醬料袋隨步伐晃動時，一小份甜味便在口袋裡整日跟著我。"},"ICON-0846":{"nm":"便利商店籃片","de":"握在手裡，塑膠輕巧地晃悠。燈火通明的深夜小店，剛好裝得下兩三個三角飯糰和一瓶飲料的深度。獨自一人也不孤單、恰好一餐份的溫暖容器。"},"ICON-0847":{"nm":"馬卡龍盒帶","de":"為了不讓繽紛的馬卡龍走位，一條帶子靜靜環抱住盒子。解開緞帶前那份雀躍，其實才最甜——收過禮物的人，用指尖就懂。"},"ICON-0848":{"nm":"水果網夾","de":"把網口攏起一夾，蘋果香便從網眼間悄悄逸出。一隻不讓它滾落的小手。「趁還沒軟掉快吃吧」，是無聲而溫柔的叮嚀。"},"ICON-0849":{"nm":"果醬瓶蓋布","de":"想起外婆把圓布罩上瓶蓋、用橡皮筋綁緊的夏日廚房。一張格紋布裡，封進果醬熟成的甜蜜時光與用心。手藝，就這樣被覆蓋著保存。"},"ICON-0850":{"nm":"餅乾束帶緞帶","de":"把剛烤好的餅乾裝進玻璃紙、扭緊束帶綁好，奶油香便滲到緞帶末端。把親手做的東西遞給某人的手，總會微微發顫。是連心意也一起綁進去的結。"},"ICON-0851":{"nm":"巧克力隔板","de":"一格一格，讓巧克力彼此不相觸地定好位置。怕它融化，怕它碎裂。小小隔板守到最後的，終究是要遞給某人的、完好的一顆心意。"},"ICON-0852":{"nm":"茶禮標籤","de":"繞在茶包上的標籤上，工整寫著手寫的名字。小紙片預先悄聲告知：沖泡時草葉香會隨蒸氣升起。還沒喝，手便先暖起來的一杯。"},"ICON-0853":{"nm":"糖果瓶項鍊","de":"在裝著繽紛糖果的瓶頸繞上繩子做成的項鍊。每走一步，裡頭便嘩啦滾出小珠子般的聲音。把甜蜜掛在脖子上的、童年引以為傲的寶物。"},"ICON-0854":{"nm":"禮物湯匙吊飾","de":"靠著掛在柄端的一個小吊飾，平凡的湯匙不知不覺成了禮物。每次舀取時，便叮噹輕碰出清亮的聲響。為遞出的心意添一抹小巧雅致的裝飾。"},"ICON-0855":{"nm":"零食回禮牌","de":"想把收到的多少也回贈一些的心。輕輕掛在零食袋上的回禮牌一張。代替還沒說盡的「謝謝」，一句小小的問候從手到手靜靜遞了過去。"},"ICON-0856":{"nm":"紙膠帶樣品環","de":"一寸寸剪下貼好的花紋排成小小的帶子。用指尖慢慢挑選哪個顏色好的同時，光是想著裝飾，一天就染上了繽紛。連煩惱都愉快的一列樣本。"},"ICON-0857":{"nm":"貼紙鑷子蓋","de":"在尖尖的鑷子尖端套上蓋子，指甲大的貼紙也不會受傷。把手指碰不到的邊角輕輕夾起的精準之手。對待心愛之物，總伴著一份小心。"},"ICON-0858":{"nm":"手帳角貼","de":"在手帳四個角貼上角貼，飄動的書頁便像撒了謊般乖巧。紙張微微被壓的觸感，是把今天這一日好好封存的小儀式。記錄，從邊角開始變得牢固。"},"ICON-0859":{"nm":"打孔導引板","de":"預先告知打孔位置的板。沿著虛線靜靜對齊便不會歪。不急著、再多估量一次的心——準確，總是悄悄來自那一拍的小小餘裕。"},"ICON-0860":{"nm":"紙屑托盤","de":"剪裁後剩下的紙屑沙沙地聚進托盤裡。為了不讓桌面凌亂，是小碎片暫歇的居所。手作的收尾，就這樣無聲地整頓妥當。"},"ICON-0861":{"nm":"彩色印台","de":"輕按印台再抬起，指尖便濕潤地暈開色彩。紅黃藍，一枚印章便沾起一道小小的彩虹。在白紙上輕輕拍下、種入色彩的軟軟一格。"},"ICON-0862":{"nm":"裝飾膠帶卷","de":"咕嚕咕嚕——捲出的花紋無盡地延續。撕一格貼上，原本單調的地方便開了花。隨手一弄就越來越美的、圓圓捲起等候的一卷小魔法。"},"ICON-0863":{"nm":"主題印章蓋","de":"為了不讓墨水乾掉而把印章頭緊緊包住的小帽。靜靜守護著讓下次蓋的花紋清晰留下。好好保存的顏色，在下一張紙上也一樣鮮明地綻放。"},"ICON-0864":{"nm":"造型打孔碎片","de":"打孔器啪一聲掉落的小碎片。被剪成星星、愛心與花瓣的色紙屑，在掌心滿滿聚起。美得捨不得丟、忍不住又貼到某處去的小寶石。"},"ICON-0865":{"nm":"線軸標籤環","de":"在每個線軸上寫貼色線名字的小標籤一張。是在凌亂之前就先告知位置的溫柔標記。再纏亂的線、再亂的心，有了名牌，理起來也順手許多。"},"ICON-0866":{"nm":"針本封套","de":"蓋住密密插著針的不織布書頁的柔軟封套。攤開時，縫紉工具整齊躺著迎接我。為了不讓指尖受傷，把尖銳之物溫柔哄睡的小小一本。"},"ICON-0867":{"nm":"布料樣品環","de":"粗糙的或柔軟的，用指尖一一摩挲布紋來挑選的緩慢時光。在按色彩層層聚起的布片中，化為一件衣裳之前，布先靜靜等著被觸摸。"},"ICON-0868":{"nm":"刺繡繃環","de":"把布夾進圓繃裡一旋緊，便像鼓面般繃得緊實。是「一針一針刺繡的準備已就緒」的小小信號。繃緊緊抓住的不是布，而是專注的心。"},"ICON-0869":{"nm":"鈕扣分類膠囊","de":"四處咕嚕亂滾的鈕扣，按色彩乖乖坐進膠囊每一格。為了不弄丟而細細分裝的持家智慧。把散落之物聚攏，也需要這樣的用心。"},"ICON-0870":{"nm":"縫紉粉土筆架","de":"把在布上劃線的粉土筆撐成好握姿勢的架。穩穩托住易折之物。第一道線要劃直，衣服才會直——是拿起剪刀前那份沉穩的初心。"},"ICON-0871":{"nm":"珠針瓶","de":"透明瓶裡，珠針相互碰撞咯吱作響。對著陽光一照，每根針尖都凝著一點小小的光。把散開便危險之物聚於一處、好好哄睡的、俐落的一只容器。"},"ICON-0872":{"nm":"修補膠帶卷","de":"貼在撕裂處上一熨燙便悄悄黏合的魔法帶。連一針都不必，磨破的衣服便靜靜癒合。不丟棄、縫補著穿的那份心，層層捲在圓圓的卷裡。"},"ICON-0873":{"nm":"貼布圖樣紙","de":"預先畫好貼布形狀的圖樣紙一張。虛線溫柔地指引剪刀將經過的路。先描出想做之物的輪廓，雀躍總是從這道淡淡的草稿開始。"},"ICON-0874":{"nm":"水彩筆洗杯蓋","de":"套在筆洗杯口上，色水再怎麼搖晃也一滴不漏。連洗筆後的混濁水會暈到桌上的擔憂都一併蓋住。默默守護畫畫位置的、安靜的一個封蓋。"},"ICON-0875":{"nm":"粉彩保護帶","de":"在會白白沾手的粉彩上繞一圈帶子，手指便不那麼髒。靜靜包住嬌嫩色彩、不讓它碎裂的紙。越軟越要溫柔地拿，在紙上才塗得勻美。"},"ICON-0876":{"nm":"色鉛筆延長蓋","de":"在用短的色鉛筆尖插上蓋子，一支便又變長了。不因短了就輕易丟棄的心。在用到最後的指尖下，畫的顏色直到最後一格都更加濃郁地完成。"},"ICON-0877":{"nm":"洗筆杯鉤","de":"把洗筆杯掛在鉤上，從筆上滴落的水珠便咕嚕滑下。塗下一個顏色之前，洗筆那段短而清澈的靜默。連那變乾淨的聲響裡，也流著安靜的節奏。"},"ICON-0878":{"nm":"調色刀蓋","de":"套在攤開、刮取顏料的調色刀刃上的小蓋。靜靜守護尖端不被磨鈍。厚厚塗上的色彩質感，正誕生於這把被悉心照料的刀刃。"},"ICON-0879":{"nm":"畫布夾","de":"把畫布用力拉緊固定在框上的俐落夾子。緊緊一咬，作畫的面便繃得平展。要有不動搖的底，奔馳其上的筆觸才能盡情自由。"},"ICON-0880":{"nm":"畫板背帶","de":"把帶子往肩上一掛，畫板便跟到背後。隨處坐下，那裡便成了我專屬的工作室。為尋找想畫的風景而輕裝出發的、背在背上的小畫室。"},"ICON-0881":{"nm":"壓克力顏料鑰匙","de":"多加一滴水便是黎明，少一點便成午夜。同樣的藍，在指尖每次都展開不同的天空。擠出一管的瞬間，今日心情的色澤便在紙上暈染開來。"},"ICON-0882":{"nm":"漸層樣本紙","de":"「晚霞不會一下子就紅起來」，這張紙最先知道。從淺處跨向深處的小小階梯。眼睛在其間緩緩漫步，靜靜追隨色彩熟成的時間。"},"ICON-0883":{"nm":"鉤針蓋","de":"在線陷進手指之前套上的、像頂針般小小的護罩。織得越久的手越明白：唯有不受傷，才能溫柔地把每一針帶到最後。"},"ICON-0884":{"nm":"編織記號環","de":"織到哪裡了，有一個標記便又清晰起來。同一針不必數第二次的那份安心。心也是如此，唯有輕輕點過走過的地方，才終於不迷路。"},"ICON-0885":{"nm":"段數計數吊飾","de":"「織完一段」的安靜證據一格格累積。看似無盡的活兒，一個個數下來，不知不覺已過半。小小的計數，讓今天的心撐到最後。"},"ICON-0886":{"nm":"線尾整理針","de":"鬆開的線頭若就那麼擱著，誰知道下一個結會在哪裡纏住。預先整頓看不見之處的手。溫柔大抵就是這樣，先在不顯眼的角落動起來。"},"ICON-0887":{"nm":"打結練習繩","de":"死結、蝴蝶結、戒指結。直到手記住形狀為止，把同一條繩綁了又解。當生疏的指尖在某個夜晚忽然順滑起來，那一條繩最先知道。"},"ICON-0888":{"nm":"毛線標籤帶","de":"在每個線團上寫下粗細與顏色的小帶子。是用完才為找不到同款線而徬徨的那些夜晚，養成的習慣。記錄，是寫給未來的我的溫柔備忘。"},"ICON-0889":{"nm":"密度尺小片","de":"10公分裡進得了幾針——那個小小的數字定了一件衣的尺寸。巴掌大的一片握著整體的尺寸，掂起來其實是頗有份量的事。"},"ICON-0890":{"nm":"釦眼標記","de":"在縫鈕扣前，先點下一個點標出要鑽的位置。多虧那個即將消失的記號，衣襟才不會歪。用心，大抵悄悄留在終究看不見的地方。"},"ICON-0891":{"nm":"小流蘇環","de":"像佩飾末端的流蘇，一個小環造出晃動。對懸著靜靜搖曳之物，人的目光總會停留。每當風經過，便靜靜活過來流動的紋理。"},"ICON-0892":{"nm":"迷你塗料瓶","de":"妥善處理塗料的方法不是省著用，而是用得精準。一滴就夠的色，放在小瓶旁仔細估量的手。節制，來自把貪念放下一回。"},"ICON-0893":{"nm":"小型砂紙棒","de":"從粗面開始，漸漸換到細面。哪裡都沒有一下子就變光滑的表面。在一級級降低紋理的指尖下，粗糙之處慢慢變得柔順。"},"ICON-0894":{"nm":"模型夾架","de":"用手握著上了膠的零件就會留下指紋。輕輕夾在夾子上，手便自由了，乾燥也自己靜靜結束。等待，有人替你撐著時也會輕鬆些。"},"ICON-0895":{"nm":"膠水墊板","de":"一滴膠水落到桌上，痕跡便久久留著。先鋪一張墊板的習慣。作業的一半，或許就始於那份「不弄髒場地」的心。"},"ICON-0896":{"nm":"零件分類格","de":"數十個同樣形狀的零件一混，組裝立刻成了迷宮。一格格分裝的手，預先省下日後徬徨的時間。整理，是遞給未來的我的善意。"},"ICON-0897":{"nm":"組裝順序片","de":"寫著從幾號零件開始裝的小片一枚。守住順序，就不易崩塌。模型也好，一步步堆起的某個日子也好，都在那安靜的約定上變得牢固。"},"ICON-0898":{"nm":"迷你筆掛","de":"用過的筆若橫放，筆毛便壓得彎曲。倒掛著瀝乾水氣的位置。把工具長久留在身旁的人，活兒結束後反而更忙碌、更溫柔。"},"ICON-0899":{"nm":"塑料碎片盒","de":"從模具上剝下的零頭靜靜聚進的盒子。看似被丟棄，總有一天會化作小小的細節歸來。「剩下的東西也有自己的順序」，盒子默默等著，懂得這道理。"},"ICON-0900":{"nm":"保護漆噴罐蓋","de":"最後一層若噴得太近，便會就那麼流下來。在一掌之距，輕輕地、輕輕地噴。上光這件事，或許也是把心裡的貪念放下一回的練習。"},"ICON-0901":{"nm":"自動鉛筆筆芯盒","de":"纖細的筆芯總在口袋裡輕易折斷。整齊地橫放在小盒裡，一根都不會白白浪費。所謂整理，終究是悄悄地疼惜明天的自己。"},"ICON-0902":{"nm":"橡皮擦套","de":"替橡皮擦穿上的小紙衣。沾染手垢越變越黑，便是越改越多的痕跡。所謂擦去，也是一種溫柔的許可——告訴你回到起點也沒關係。"},"ICON-0903":{"nm":"筆尖收納筒","de":"筆尖乾了會裂，碰撞了會彎。一個讓它單獨橫放的小筒，長久守護著字跡的紋理。被細心對待的工具，最終也會以滑順的書寫回報。"},"ICON-0904":{"nm":"鋼筆墨水試色","de":"一滴一滴試著沾上的各種墨水。以為是青綠的顏色，在紙上卻化作深邃的海。顏色總要親自相見才懂——心裡描繪的色彩，常常會落空。"},"ICON-0905":{"nm":"書籤箭旗筒","de":"在讀到一半的地方輕輕夾上的小旗子。下次翻開書，昨天的自己便揮著手等候。連停下的地方都成了約定，這是小小標記的溫柔之事。"},"ICON-0906":{"nm":"便箋小旗組","de":"撕下一張貼上，故事便從那裡重新開始。小旗子在書側排成一列，散落的思緒便一頁頁匯聚成一幅地圖。"},"ICON-0907":{"nm":"迴紋針分類磁鐵","de":"一次收攏散落迴紋針的小磁鐵。越是小東西越容易弄丟，一份聚攏的力量靜靜拯救了凌亂的書桌。連吸引裡，也藏著溫柔。"},"ICON-0908":{"nm":"鉛筆帽組","de":"包覆鉛筆尖、守護書包內部的小帽子。尖銳之物總會刺傷什麼，所以需要一隻靜靜覆蓋它的手。讓它不變鈍，卻也不傷人。"},"ICON-0909":{"nm":"桌面名牌貼紙","de":"寫上名字貼在桌前的瞬間，那個位置才真正屬於某個人。即使只是一掌大的空間，一旦有了主人，連安放心情的姿態都截然不同。"},"ICON-0910":{"nm":"跳繩握把帽","de":"在握把末端磨損裂開前先套上的帽子。揮過上千次的繩子節奏，手掌比腦袋更早記住。銘刻在身體裡的拍子，很難被遺忘。"},"ICON-0911":{"nm":"瑜伽環拉帶","de":"握著環，緩緩打開身體。帶子越是繃緊，僵硬的肩膀便一層層鬆開。所謂伸展，不是強行拉扯，而更像靜靜等待身體自己舒展開來。"},"ICON-0912":{"nm":"桌球盒","de":"輕得會滾遠，踩到便立刻凹陷的白色小球。一個小盒子，守護著這最脆弱的球直到下一場比賽。堅固，往往來自柔軟的包覆。"},"ICON-0913":{"nm":"羽球握把布","de":"替被汗水打滑的握把細細纏上一層。在纏得好的握把上，球拍便成了手的一部分。靠的不是力量而是手感——這訣竅，就藏在這薄薄一層裡。"},"ICON-0914":{"nm":"迷你計分籌碼","de":"一分，又一分。移動小籌碼，把分數一點點堆疊起來。計分看得見，比賽便更清晰，連追上一分之差的勇氣也悄悄湧上來。"},"ICON-0915":{"nm":"運動鞋朝向夾","de":"整齊擺放的鞋尖總朝著同一個方向。脫鞋時輕輕轉一下的那份用心。一個微小的整理，便讓明早的腳步輕快許多。"},"ICON-0916":{"nm":"哨子掛繩","de":"把哨子掛在脖子上，便有了喊停的權限。短短一聲，整片操場齊齊停下的光景。信任那一小聲的心意聚在一起，便成了約定。"},"ICON-0917":{"nm":"打氣針收納筒","de":"洩了氣的球，一根細針便能重新飽滿。細心收在小筒裡的那根針，一旦弄丟，整個打氣筒便成了廢物。最小的東西，有時最重要。"},"ICON-0918":{"nm":"迷你三角錐標記","de":"從這裡到那裡，小三角錐畫出了看不見的界線。即使沒有線，人們也會自然地循著標記排起隊。秩序，就在這樣的小信號裡靜靜生長。"},"ICON-0919":{"nm":"代幣小袋","de":"把叮噹作響的代幣聚在一起的小袋。束緊袋口便不會散落。再小再不起眼的東西，也要有個容身之處才能各司其職——小袋默默地證明了這點。"},"ICON-0920":{"nm":"洗牌墊","de":"在光滑的桌上，紙牌不太好拿。鋪上一張墊子，洗牌也好、拿牌也好，都柔順許多。連好好玩耍，也有先鋪好底面的溫柔準備。"},"ICON-0921":{"nm":"棋盤護角","de":"桌遊之夜結束時，總有人默默地先收起棋盤的四個角。因為知道摺痕一深，下一局便會歪斜。把邊角撫平的指尖裡，藏著明天也一起玩吧的心意。"},"ICON-0922":{"nm":"骰盅蓋","de":"搖動、傾倒，大家一起屏息的那短短一瞬。它是不讓骰子蹦出去而覆上的小小天頂。在蓋子裡，今天的運氣稍稍喘口氣後，才喀啦滾出來。"},"ICON-0923":{"nm":"牌片對齊板","de":"越是玩得起勁的人，排得越歪。當牌片傾斜時，悄悄推一推使它對齊。所謂對齊，是一隻溫柔接住某人雀躍急切的手。"},"ICON-0924":{"nm":"計分籌碼筒","de":"籌碼在筒裡堆得越滿，牌局也越發火熱。圓圓的分數在掌心喀啦相碰時，比起輸贏，那聲響先讓人歡喜起來。"},"ICON-0925":{"nm":"回合標記環","de":"告訴你輪到你了的小戒指。挪一格套上的那一刻，所有人的目光都靜靜地匯聚到我身上。它是在等待與雀躍之間緩緩轉動的環。"},"ICON-0926":{"nm":"棋子底座","de":"越是容易倒的棋子，腳下越要穩固。一個底座，在微微晃動的牌局上也能抓牢自己的位置。小的撐住了，上面大的才能挺立。"},"ICON-0927":{"nm":"說明書夾","de":"說明書總是攤開著，卻又悄悄翻了過去。在書頁被風吹跑之前，靜靜咬住一頁的夾子。把規則抓牢，遊戲才能玩到最後。"},"ICON-0928":{"nm":"吉他撥片盒繩","de":"吉他撥片總在最起勁的段落從指間溜走。盒上繫的一根繩，攔住了那場小小的離家出走。只有經歷過音樂中斷之夜的人，才會感激這根繩。"},"ICON-0929":{"nm":"簧片保存筒","de":"簧片一乾便失了聲音。在濕潤的筒裡，一小片細蘆葦等待著下一次演奏。這是在吹入氣息之前，先讓氣息安睡的地方。"},"ICON-0930":{"nm":"換弦上弦器","de":"弦一鬆，音也悄悄垮下。緩緩轉動手柄找回緊繃——用心，總是從手腕末端而來。端正的聲音，便從這樣微小的整理開始。"},"ICON-0931":{"nm":"樂器擦拭布","de":"演奏結束後，樂器上也會留下淡淡的汗。用柔軟的布輕拭一遍，光澤回來，今天的音符也隨之沉澱。珍惜的心意，總在收尾時顯露。"},"ICON-0932":{"nm":"調音栓罩","de":"調音栓若裸露著放，不知不覺便會生鏽。一個小罩子，讓金屬的季節慢上一拍。先照顧看不見角落的人，才能演奏得長久。"},"ICON-0933":{"nm":"譜架夾燈","de":"在昏暗的後台，有些時刻只需照亮樂譜。它是夾在譜架上、輕輕灑下光的小燈。為了不讓音符迷路而照亮腳邊的一捧燈光。"},"ICON-0934":{"nm":"練習弱音帽","de":"清晨的練習，總與鄰人的睡眠悄悄爭執。套上一個帽子，宏亮的聲音便縮成了低語。也有守護著某人安眠而生長的音樂。"},"ICON-0935":{"nm":"鼓墊貼紙","de":"貼在鼓墊上的小標記。敲哪裡會發出什麼聲音，在手記住之前，眼睛先認熟了路。拍子，便這樣慢慢銘刻進身體。"},"ICON-0936":{"nm":"旋律便箋籌碼","de":"哼著的旋律若不抓住，轉眼便消失。匆匆寫在籌碼上的幾小節，日後也可能長成一首歌。靈感，總會再回來找那雙勤於記錄的手。"},"ICON-0937":{"nm":"書套束帶","de":"讀到一半的書在書包裡隨意攤開可不行。一條束帶輕輕綁住書頁，書便乖巧起來。這是為了下一頁而端正摺好的約定。"},"ICON-0938":{"nm":"翻頁固定環","de":"想單手攤開書、一邊喝著溫熱咖啡的日子。套在手指上的環替你抓住書頁。小小的從容，便從這樣不起眼的發明開始。"},"ICON-0939":{"nm":"閱讀計時籌碼","de":"想著就讀一章，坐下卻不知不覺夜已深。按下籌碼定好時間，閱讀也有了逗點。越是喜歡的事，越需要懂得停下的溫柔勇氣。"},"ICON-0940":{"nm":"書角保護帽","de":"越珍惜的書，越是從邊角悄悄磨損。套上一個帽子，封面的角便被圓圓地保護起來。這是想長久相伴的心意，悄悄套上的一副小盔甲。"},"ICON-0941":{"nm":"心得書腰","de":"有些瞬間，一行句子讓胸口怦然一沉。抄寫在書腰上的心得，像書籤般停留在那一頁。那是只有讀過的人才懂的、底線的溫度。"},"ICON-0942":{"nm":"圖書館還書標","de":"還書日總是早上一天到來。標籤上的日期靜靜推著背，借來的書也有了收尾的禮數。為了下一個人的手，圖書館便這樣等候著。"},"ICON-0943":{"nm":"閱讀燈夾","de":"在熟睡的家人身旁獨自醒著閱讀的夜。書頁邊用夾子咬著的一盞小光便已足夠。不必驅散全部黑暗，一頁亮著就夠了的寧靜時光。"},"ICON-0944":{"nm":"書香卡","de":"老書會散發陽光與紙張交織的氣味。據說把那香氣裝進一張卡片，翻開時舊書店的巷弄便在鼻尖短暫復活。記憶，也會以氣味夾上書籤。"},"ICON-0945":{"nm":"讀至此頁標記針","de":"讀到哪了呢，這茫然的疑問被一根小針抹去。夾在最後一句上，明天的我便不再迷路。這是替你記住停下之處的溫柔標記。"},"ICON-0946":{"nm":"手機吊飾環","de":"手機繩上掛的一個環，人便看起來有些不同。喜歡的顏色、喜歡的形狀。握在手裡的小小喜好，悄悄撥動了那天的心情。"},"ICON-0947":{"nm":"相機鏡頭保護蓋","de":"旅行照片的命運，繫於一片鏡頭。揭開保護蓋的那一刻，便是按下快門的心理準備。在收進風景之前，最先睜眼的小小儀式。"},"ICON-0948":{"nm":"充電孔塞","de":"書包裡的灰塵總先盯上充電孔。一個塞子堵住小小入口，接孔便能長久乾淨。連看不見的縫隙都照顧到的勤快，就在這裡。"},"ICON-0949":{"nm":"手機支架彈出環","de":"為了舒服看部影片而把手機斜立起來。展開背後的彈出環，手與螢幕都從容許多。小小凸起的一個支撐，把傍晚的片刻悠然地延展開來。"},"ICON-0950":{"nm":"螢幕擦拭貼","de":"滿是指紋的螢幕，連心情都不知怎地變得模糊。用擦拭貼一抹，世界又重新清晰。所謂潔淨，有時只是手指一抹的短短一事。"},"ICON-0951":{"nm":"SIM卡針盒","de":"SIM卡針是個只在最需要的瞬間消失蹤影的精靈。放進盒子的一格，便不必再找著髮夾翻遍整個家。小小的整理，悄悄拯救了著急的瞬間。"},"ICON-0952":{"nm":"無線充電板貼紙","de":"靜靜放上去便自行充滿的夜晚。貼著的貼紙，輕輕標出手機該躺下的位置。看不見的電流無聲地補滿一天份的能量。"},"ICON-0953":{"nm":"通知遮蔽貼","de":"不想看的通知，遮起來反而心安。一張貼紙便讓清晨的小光熄滅。有時候，不看也是守護自己的一種溫柔方式。"},"ICON-0954":{"nm":"鏡頭保護環","de":"相機鏡頭觸到地面的那一剎那，心臟猛地一沉。圍上的一個環，悄悄擋下了那場小小的墜落。它是最先包覆住收藏回憶之眼的邊框。"},"ICON-0955":{"nm":"線材尾標","de":"在糾纏成團的線堆裡，硬是要認出自己那條的工作。一個尾標，充電線也終於有了自己的名字。它是在凌亂的線間指路的小旗子。"},"ICON-0956":{"nm":"充電器收納袋","de":"旅行包裡的充電器總是彼此糾纏爭吵。整齊聚在收納袋的一格裡，才終於和解。打理的技術，在於把散落之物溫柔地喚到一處。"},"ICON-0957":{"nm":"多孔插座標籤","de":"排插的孔個個長得一樣，每次都搞混。貼上標籤定下誰的位置，忙碌的早晨便順手許多。一個小名牌，減少了日常裡的瑣碎爭執。"},"ICON-0958":{"nm":"捲線輪","de":"解開來用、再捲回去，線材端正的一天。一個一個地捲進輪裡，糾纏便乾淨消失。用完歸位的手，讓明天變得輕盈。"},"ICON-0959":{"nm":"磁吸接頭帽","de":"磁吸接頭不知不覺便吸來細微的鐵屑。用帽子蓋住，黏膩的灰塵便不會附著。多照顧一次的手所觸及的設備，會更長久地相伴左右。"},"ICON-0960":{"nm":"行動電源束帶","de":"行動電源和線材分開放，總有一邊會不見。用束帶綁在一起，兩者才終於成了一對。出門前，輕輕繫上叫它們同行的小小結。"},"ICON-0961":{"nm":"插頭防塵帽","de":"空著的插座孔，沒幾天灰塵便悄悄安了家。這個小帽子替它守著位置，下次插上的充電器便能吸入乾淨的第一口氣。是替空閒時光細心看守的門衛。"},"ICON-0962":{"nm":"線材色環","de":"在糾纏的線裡摸索著找自己那條的夜晚，是誰說來上個色吧。藍色是你，黃色是我。一個小環，我們便不再彼此弄混。是合奏室一角留下的、溫柔約定的痕跡。"},"ICON-0963":{"nm":"轉接頭分類籌碼","de":"圓腳與扁腳，110與220。靜靜記下各國不同插座面孔的籌碼。第一次跨海赴舞台時的行李一角，總會夾著這張小小的分類表。"},"ICON-0964":{"nm":"耳塞分類板","de":"據說每個人的耳道深淺寬窄都不同。把大中小三副並排橫放，挑出最合自己耳朵的一對。在聽聲音之前，先讓身體合上的溫柔程序。"},"ICON-0965":{"nm":"保護殼矽膠環","de":"舞台服連一針一線都費盡心思，殼的邊角卻總是裸著相撞。這層薄薄的矽膠環輕輕環住四周，即使在從手中滑落的清晨，螢幕也能安然迎來早晨。"},"ICON-0966":{"nm":"降噪貼紙","de":"有些日子想暫時關掉世界的聲音。貼在耳機耳罩上的這張小貼紙，是開啟寂靜的標記。把觀眾席的歡呼與地鐵的噪音，在一首歌結束前遠遠帶開的護身符。"},"ICON-0967":{"nm":"耳掛組","de":"跳起舞來，耳機總有一邊先逃走。掛上這個輕輕擁住耳廓的鉤，激烈的編舞中音樂也能留在耳邊到最後。這是練習室的人們互相分享的小小發現。"},"ICON-0968":{"nm":"清潔刷帽","de":"為了不讓刷尖沾的灰塵再次飛揚而套上的小帽子。清潔的工具也需要清潔——掃地後把掃帚倒立著放的那雙手，早就懂得這個道理。"},"ICON-0969":{"nm":"充電座底墊","de":"充電座在桌上老是打滑，是因為沒有腳。鋪在底下的這張薄墊代替了腳，設備便靜靜留在原位，整夜安靜地補滿能量。"},"ICON-0970":{"nm":"左右區分標記","de":"左邊L，右邊R。為了在黑暗中摸索也能辨認，多點一個點。想讓舞台上的左腳與右腳一次都不出錯的心意，原原本本嵌在這小小的標記上。"},"ICON-0971":{"nm":"音訊分配孔帽","de":"那個讓眾人分享一條聲音的接孔，休息時要把末端堵起來，不讓灰塵滲進電路。是想讓一起聽過的歌，下次也能清澈流淌的、小心翼翼的一份用心。"},"ICON-0972":{"nm":"耳機線捲收器","de":"像從前捲線團的手法那樣，耳機線在這裡圓圓地捲起便端正了。曾在書包裡糾纏打滾的音樂，整齊收拾妥當的瞬間。明天解開時也會輕鬆許多。"},"ICON-0973":{"nm":"鏡頭蓋固定繩","de":"每次開鏡頭，蓋子總是無處安放。繫上繩綁在相機旁，便不必再徒勞地翻口袋。想不弄丟就綁在身邊——手比腦袋更早學會了這道理。"},"ICON-0974":{"nm":"熱靴蓋吊飾","de":"在相機上空著的熱靴座，悄悄插上一個小裝飾。那毫無功能的吊飾，竟讓沉重又木訥的器材，不知不覺看起來像是自己的物件般親切。是給工具注入情感的事。"},"ICON-0975":{"nm":"背帶調節釦","de":"每當包帶勒進肩膀，便一點點鬆開又收緊這個釦子。順著身體挑選長度的手指一動。背負行李終究也是照顧自己——釦子靜靜這樣告訴你。"},"ICON-0976":{"nm":"濾鏡收納盒","de":"把分割光線的玻璃片一一橫放的小屋。陰與晴，晚霞與夜。像是預先選好天氣裝進的抽屜，攝影師啟程前總會先打開這個盒子看看。"},"ICON-0977":{"nm":"吹球防塵帽","de":"噴風驅塵的橡膠球，它的入口對灰塵同樣脆弱。休息時便套上這個帽子。替別人除塵的工具先把自己的口靜靜堵起，這模樣不知怎地很是溫柔。"},"ICON-0978":{"nm":"快門鈕護蓋","de":"在書包裡快門被胡亂按下、拍了上百張空蕩天空的事，大家都遇過一兩回。蓋在按鈕上的這個小護蓋阻止了那場徒勞。是只留下真正想留住瞬間的、微小的鎖。"},"ICON-0979":{"nm":"電池區分貼紙","de":"用完的和充滿的在同一個袋裡混在一起，總是狼狽。貼在每顆電池上的色貼紙，悄悄理清了那份混亂。紅色是空的，綠色是飽滿的。是片場亮著的無聲紅綠燈。"},"ICON-0980":{"nm":"相機包隔板","de":"為了讓鏡頭、機身與備用電池彼此不相碰，在包裡分出隔間。在一份行李中設下數個小房間。每個位置都有了主人，即使搖晃也不會丟失原位。"},"ICON-0981":{"nm":"攝影手套墊","de":"冬季的戶外拍攝，唯獨按快門的指尖不能凍著。掌心墊上厚實的墊，指尖留出感覺的手套。想把溫暖與精準同握一手的、現場溫柔的折衷方案。"},"ICON-0982":{"nm":"平板筆尖筒","de":"筆尖也像鉛筆芯一樣會磨損，長久握著平板的人都懂。把備用筆尖咕嚕嚕聚在一起的這個小筒，是替不能中斷的線條預先備好的、指尖的應急金。"},"ICON-0983":{"nm":"鍵盤鍵帽托盤","de":"一個一個拔下鍵帽清洗再裝回的那天，這托盤成了一片小小灘塗。子音與母音格格分躺著晾乾的光景。有些用心，要拆解過一次才終於看得見。"},"ICON-0984":{"nm":"滑鼠腳貼組","de":"滑鼠在桌上滑行如奔的祕訣，就在黏在底部的這些小腳上。磨損了便換上一組。在看不見的地方默默撐起順滑的，這些事物的辛勞。"},"ICON-0985":{"nm":"筆電墊高膠","de":"雖像筆記本，其實是撐起筆電的橡膠墊。把螢幕稍稍抬到眼睛高度，舒展彎曲的脖頸。是為了長久書寫、長久凝視的人，端正姿勢的一份體貼。"},"ICON-0986":{"nm":"視訊鏡頭遮蔽滑蓋","de":"用手指推上去遮住鏡頭，再推開。只在想被看見時才被看見的心情。這小小一個滑蓋裡，棲息著名為隱私的莫大安心。闔上的聲音不知怎地很可靠。"},"ICON-0987":{"nm":"USB分類標籤","de":"五根相似的黑色小棒，哪根裝了什麼根本無從得知。貼上小標籤替它取名，這才成了自家人。有名字可叫，找起來也容易了。"},"ICON-0988":{"nm":"桌墊壓角","de":"桌墊邊角老是捲起，連手寫字都跟著歪斜。輕輕壓住四個角的這個小零件，守護桌上平整的安寧。底面安靜，指尖才能沉穩。"},"ICON-0989":{"nm":"集線器立架夾","de":"把多條線匯聚的集線器斜立在桌緣的夾子。凌亂的線匯聚於一點而整頓的模樣。把糾結之物理成一股的手感，在這裡也活著。"},"ICON-0990":{"nm":"螢幕清潔噴霧帽","de":"擦去螢幕上手印的噴霧，堵住它口的小蓋。為了不讓液體外漏或乾掉，總是緊緊蓋好。想看得清澈，得先疼惜擦拭的工夫——這是過日子樸素的順序。"},"ICON-0991":{"nm":"記憶卡夾","de":"好幾天份的舞台影像，靜靜沉睡在指甲般大的一張卡片裡。一旦弄丟，那天便整個消失，於是珍重地聚在小夾裡懷抱著。是裝著最小卻也最大記憶的家。"},"ICON-0992":{"nm":"外接硬碟標籤環","de":"五個黑色外接硬碟在抽屜裡以相同的面孔沉睡。貼上標籤，替它們取名「那年夏天」「未公開片段」的工作。是給模糊的記憶，掛上清晰索引的作業。"},"ICON-0993":{"nm":"備份確認籌碼","de":"備份完成了沒有，那一線之差讓人心慌。在做完的位置輕輕夾上的這個小籌碼，告訴你「到這裡為止是安全的」。安心，來自留下標記。"},"ICON-0994":{"nm":"雲端備忘代幣","de":"把一行備忘飄送到天空某處儲存庫的代幣。無論在哪裡開啟，那段文字都來迎接的小小魔法。曾在夜空放天燈寫下心願的夜，如今彷彿輕輕降到了掌心。"},"ICON-0995":{"nm":"USB保護帽組","de":"接頭裸露著在書包裡滾來滾去，接點難免受損。每個末端套上小帽子，整成一組收好。把不用的時光細心哄睡。是為下一次連接所做的、最安靜的準備。"},"ICON-0996":{"nm":"資料盒束帶","de":"把裝著珍貴資料的設備緊緊包裹束起的束帶。為了在搖晃的包裡不相碰撞，繞一圈牢牢綁住。曾用心打結包袱的那雙手，在數位裡也原原本本地活著。"},"ICON-0997":{"nm":"檔案整理標籤","de":"數百個檔案無名地堆積，找尋便成了迷路。貼上五彩標籤分出脈絡的瞬間，凌亂的堆裡便闢出一條路。所謂整理，終究是闢路之事。"},"ICON-0998":{"nm":"密碼提示卡","de":"把密碼整個寫下來很危險，乾脆不寫又會忘。於是只悄悄留下只有自己懂的線索。像是「初次登台的那座城市」。不寫答案而寫下路徑的、聰明又溫柔的記憶法。"},"ICON-0999":{"nm":"存放日期貼紙","de":"不記下存放的日子，保管便成了遺忘。貼在每個箱子上的日期貼紙，清晰刻下「從何時起」。曾在醃醬那天記下日期的舊倉房心意，延續到了這張小紙上。"},"ICON-1000":{"nm":"迷你環形燈帽","de":"發出圓形光的小燈，覆蓋它光孔的帽子。為了不讓鏡片在書包裡刮傷，暫且讓光安睡。細心珍藏點亮前的黑暗，也是疼惜光明的一種方式。"},"ICON-1001":{"nm":"支架鎖緊螺絲","de":"再轉一圈。鬆動的縫隙消失，掌下沉沉降下一份安心。不晃動的舞台背後，總藏著某人俐落的一扭手腕。小小螺絲所撐起的，是看不見的穩固。"},"ICON-1002":{"nm":"直播中標記籌碼","de":"紅燈亮起的瞬間，走廊的腳步聲悄悄踮起了腳尖。「直播中」——這一句話前所有人都屏住了呼吸。連門外的寂靜都是朝向某人的心意，這小小籌碼正靜靜地宣告著。"},"ICON-1003":{"nm":"聊天備忘墊","de":"用指尖抓住即將掠過螢幕的應援。會流逝而去的一句一句，端端正正停留在紙上的時光。所謂記錄，是再晚也想觸及的溫柔停駐之處。"},"ICON-1004":{"nm":"靜音鍵盤膜","de":"凌晨兩點，敲鍵盤的聲音像謊言般消失了。為了不吵醒熟睡室友的呼吸而蓋上的一層薄膜。最安靜的體貼，總在無聲處開始。"},"ICON-1005":{"nm":"麥克風臂夾","de":"唇與麥克風之間，歌聲不會晃動的恰好那段距離。這個小夾子替你守住那份約定。舞台後方，總有這樣牢牢撐住的手先一步來到。"},"ICON-1006":{"nm":"背景布夾","de":"即使起風，背景布也紋絲不動。因為緊咬著邊角的小小一顆夾子，撐住了整個場景。不晃動的風景背後，總有人在看不見的地方咬緊牙關。"},"ICON-1007":{"nm":"串流控制台標籤","de":"數十個按鈕上，多虧小小名牌，手才不會迷路。一行標籤，預先抹去了直播裡的一個失誤。所謂沉著，來自顫抖前先寫下的文字。"},"ICON-1008":{"nm":"時間戳記鈕","de":"一按下去，便在流逝的時間上插下一面小旗。給再也不會回來的此刻蓋下印章的事。許久之後回望，那標記便成了通往回憶的門。"},"ICON-1009":{"nm":"感應讀取鑰匙圈","de":"湊上去嗶一聲，資訊便甦醒。掛在鑰匙圈上、在口袋裡叮噹作響的小小同伴。平凡的一天，便靠這樣微小的信號音平安地延續下去。"},"ICON-1010":{"nm":"智慧插座標籤","de":"替每個插座貼上名字，便不再搞混哪條線是什麼。連看不見的電都遞上名字的心意。所謂整頓，是溫柔暫且換上的另一張臉。"},"ICON-1011":{"nm":"溫濕度感測立座","de":"默默守望著房裡溫度與濕氣的、巴掌大的哨兵。舒適不開口，但這座立座每一刻都靜靜照看著你的狀態。安好，便這樣靜靜地被守護著。"},"ICON-1012":{"nm":"門開感測帽","de":"不錯過門悄悄開啟那一剎那的小眼睛。無聲地傳遞某人回來了的信號。守護空屋的，總是這樣不言不語的東西。"},"ICON-1013":{"nm":"遙控器收納座","de":"四處亂滾的遙控器們，終於各自找到了歸位。靜靜抓住那些差點弄丟之物的小小位置，是預先刻下再相見約定的手。"},"ICON-1014":{"nm":"睡眠App代幣","de":"每個睡得香甜的夜，便咕嚕嚕堆起一份圓圓的成就。App溫柔地告訴你，睡眠也像練習一樣一點點累積。是獻給好好休息的你、世上最小的獎。"},"ICON-1015":{"nm":"計時方塊底座","de":"三分鐘端端正正流逝之間，方塊毫不晃動地數著自己的時間。靜靜撐在它底下的、巴掌大的一個位置。連等待，也需要一塊能安心踏上的地面。"},"ICON-1016":{"nm":"通知燈罩","de":"為了不太刺眼，把光柔柔地裹上一層。願通知再急，眼睛也能安然。所謂體貼，是連光的強弱都靜靜為你斟酌的心意。"},"ICON-1017":{"nm":"電池更換卡","de":"看到這張卡，便表示該替設備裡的小小心臟換新了。在停下之前先準備好的溫柔提醒。長久相伴的祕訣，總在於快一拍的照看。"},"ICON-1018":{"nm":"搖桿帽組","de":"為了不讓拇指打滑而輕輕套上的小帽子。指尖的感覺更加清晰。這小小一個帽子，有時還決定了手心冒汗那一局的勝負。"},"ICON-1019":{"nm":"底座防塵罩","de":"替主機休息的位置，輕輕擋住灰塵。即使是暫時沉睡的設備，也需要一床被子。珍惜的心意，恰恰在不用的時候更清晰地顯露。"},"ICON-1020":{"nm":"掌機收納袋","de":"移動時一律放進這裡。蓬鬆地擁住掌機的小袋。為了在書包裡四處碰撞也安然無恙，珍貴的東西最好多包一層。"},"ICON-1021":{"nm":"按鈕貼紙環","de":"在平淡的按鈕上只要疊上一個小圖案，那一刻它便完完全全成了我的。在相同的設備上留下只屬於我的標記。個性，總在這樣不起眼的地方靜靜綻放。"},"ICON-1022":{"nm":"遊戲卡盒","de":"通宵沉迷的那一局遊戲，在這小小盒子裡香甜地沉睡。再次掀開蓋子，那一夜便原原本本地甦醒。回憶，意外地常裝在巴掌大的盒子裡。"},"ICON-1023":{"nm":"散熱風扇底座","de":"風散去熱氣的同時，稍稍傾斜著撐住設備的位置。讓發燙的身軀有個喘息的空檔。想跑得遠，也得懂得偶爾停下散熱。"},"ICON-1024":{"nm":"手腕帶針","de":"繞在手腕上扣好針，再激烈的動作裡控制器也不會離身。看似累贅的這條帶子，其實是讓人安心盡情玩耍的一份安心。"},"ICON-1025":{"nm":"類比握把帽","de":"在久握而變得光滑的握把上穿件新衣。熟悉的手感原樣保留，只讓表面如新。熟稔與雀躍並肩棲於一手之中的瞬間。"},"ICON-1026":{"nm":"存檔欄標籤","de":"在每個存檔格上端端正正寫下這是誰的冒險。一行標籤，默默守護著過去幾天的旅程。珍貴的記憶，最好刻上名字以免被覆寫。"},"ICON-1027":{"nm":"錄音機收納袋","de":"收音的機器，因裡頭裝的東西而更顯珍貴。放進能在衝撞中守護它的蓬鬆小袋裡細心攜帶。也許某人的聲音正沉睡其中，所以更小心翼翼。"},"ICON-1028":{"nm":"防風罩帽","de":"拂去風聲，只留下聲音。戶外錄音時靜靜套在麥克風上的蓬鬆罩。在紛亂的雜音間只篩選出真心的小小濾網。"},"ICON-1029":{"nm":"語音備忘標籤","de":"這是想到的歌詞，這是哼出的旋律。替每段語音備忘貼上五彩名牌。散落四處的靈感碎片，這才各歸其位排起隊來。"},"ICON-1030":{"nm":"取樣鈕籌碼","de":"一按下去，預先存好的一片聲音便砰地跳出。雨滴、掌聲、某人的笑——世界的片段在指尖甦醒。音樂，是這些小小籌碼溫柔的合唱。"},"ICON-1031":{"nm":"聲音採集信封","de":"走在路上偶然拾起的聲音，輕輕裝進這個信封。風的紋理，連清晨巷弄的寂靜也一併。終將成為歌曲的素材，總這樣樸素地聚攏而來。"},"ICON-1032":{"nm":"迷你三腳架腳","de":"三條腿在桌上展開一座小小舞台。代替晃動的手，穩穩站著撐住場景。清晰的一格畫面，便從默默佇立的三條腿中誕生。"},"ICON-1033":{"nm":"錄音檔案標籤","de":"替數百個錄音檔案一一掛上短短的標籤。讓人一眼就認出哪天是首次流出的第一句。是替散落的聲音重新指路的、小小的里程碑。"},"ICON-1034":{"nm":"波形貼紙帶","de":"原樣摹寫聲音形狀的波紋帶。繞在筆記本或盒子上，彷彿音樂就在眼前可見。是把聽見之物化作看見之物的、溫柔的障眼法。"},"ICON-1035":{"nm":"耳機掛鉤針","de":"練習結束後，靜靜替疲憊的耳機備好歇息之處。釘在桌角的小小一個掛鉤。整潔的書桌，是預先掛起明天幹勁的地方。"},"ICON-1036":{"nm":"迷你禮盒帶","de":"繞在禮盒腰上的最後一圈。靠這一條帶子，心意才終於完成。用心，往往不在裡頭裝的東西，而先從撫過其上的手中傳達。"},"ICON-1037":{"nm":"緞帶尾帽","de":"為了不讓緞帶末端散開而輕輕包覆收尾。一個不太顯眼的小細節，靜靜改變了禮物的第一印象。收尾若美，心意也會美美地送達。"},"ICON-1038":{"nm":"封裝火漆","de":"滴上熱熱的一滴，封住信封。像舊時的信件，是別隨意拆開的一份沉甸甸的約定。格調，有時便這樣懷著溫暖的重量。"},"ICON-1039":{"nm":"感謝卡座","de":"為了不讓裝著謝意的卡片皺掉，端正地撐住它。讓心意端端正正地立著傳達。感謝，連模樣都端莊時，才更長久地留在心上。"},"ICON-1040":{"nm":"緩衝星星紙","de":"剪成星形的紙，蓬鬆地填滿盒中的空隙。是願它即使搖晃也別受傷的心意之棉。包裝裡的黑暗中，彷彿也有一顆小星升起。"},"ICON-1041":{"nm":"禮物清單標籤","de":"在收件人那一欄前，筆停了好一陣。寫下三個字名字的同時浮現的臉孔、一起度過的季節。繫上的瞬間，這張小紙便成了拆開前無人能讀的祕密。"},"ICON-1042":{"nm":"祝賀印章環","de":"一按下去，圓圓的祝賀便清晰地印出來。等待墨水乾的那一會兒，想著要遞給誰的心最是溫暖。要說缺點，就是會讓人想再蓋一次。"},"ICON-1043":{"nm":"包裝繩線軸","de":"原本細心捲著，又在某人雀躍的指尖下歡快地解開。在捲與解的那一瞬間，被線繫著的一份心意，才終於成了禮物。"},"ICON-1044":{"nm":"非花結扣吊飾","de":"不是模仿花，而是一縷線多次擁抱自己、自行綻放的模樣。徹夜挑揀繩結的指尖的耐心，便如此化作這小小一朵花苞留了下來。"},"ICON-1045":{"nm":"幸運錢幣袋","de":"在遠行之人的口袋裡悄悄塞幾枚錢幣的心意。填的不是重量，而是溫柔。每一步叮噹的聲響，代替著一路平安的問候。"},"ICON-1046":{"nm":"願望膠囊吊飾","de":"圓圓的殼裡，一個摺好的願望安穩地沉睡著。說打開便會實現是假的，但不打開地懷抱著，那份心願便永遠活著，這是真的。"},"ICON-1047":{"nm":"護身結繩","de":"用五方色絲線牢牢編成，把壞氣息調往身後的繩。像兒時替手腕繫上結的奶奶的手，每個繫住之處，都美美地嵌著某人的祈禱。"},"ICON-1048":{"nm":"迷你紙鶴盒","de":"據說要摺一千次才能成為心願的紙鶴，唯獨這一隻細心供奉著不讓它受傷的小屋。因為哪怕一邊翅膀皺了，那夜投入的心意也會悄悄散開。"},"ICON-1049":{"nm":"亮片小袋","de":"從舞台服上掉落的小小光粒，捨不得丟而掃攏起來的地方。一旦沾上便會跟著一週的亮片，在這裡也像在掌心般乖乖沉睡。"},"ICON-1050":{"nm":"吉兆印章籌碼","de":"挑選好日子時悄悄添上的小小牌。不在算命館的門檻，而在我的書桌上，願今天這一天只發生好事而輕輕蓋下的、一片溫柔的迷信。"},"ICON-1051":{"nm":"祈願手環卡","de":"印成手環模樣的一張紙，承載著某人靜靜的祈願。雖戴不上手腕，但放進錢包深處，那份心意便始終繫在身旁，與你同行。"},"ICON-1052":{"nm":"門前鹽瓶","de":"把粗鹽裝進小瓶，靜靜擺在門前。把壞氣息送走，只迎進可喜的客人，這是古早的算盤。每一粒鹹鹽，都是守護我們家的小門衛。"},"ICON-1053":{"nm":"幸運號碼遮蓋籤","de":"刮開前的那一刻，人人都暫時是頭獎。這張輕輕遮住幸運數字的籤，守護著期待最為膨脹的最後1秒。即使刮的指尖在顫抖，它也會裝作不知地替你閉上眼。"},"ICON-1054":{"nm":"生日蠟燭保存蓋","de":"連點過一次的蠟燭也要好好供著，留到下個生日的細心之意。若去年許下的願望還沒實現，今年就在原處接著許願便好——這是個溫柔的算法。"},"ICON-1055":{"nm":"紀念日倒數環","de":"把倒數日數套在手指上的調皮玩意。每當剩餘天數轉過一格，心跳也就往前提了那麼一些。它一個人硬說，歸零那天它會自己發光。"},"ICON-1056":{"nm":"派對尖帽繩","de":"把尖帽輕輕固定在頭上的細繩。雖然主角嫌悶很快就摘了下來，但照片裡那一格卻永遠戴著。任務有那一刻就足夠了。"},"ICON-1057":{"nm":"小蛋糕插籤","de":"插在只有兩指節大小的蛋糕上的小標記。即使在一口就消失的甜味之上，祝賀也挺直了腰桿。再小，生日也是生日，而今天的主角是你。"},"ICON-1058":{"nm":"慶賀煙火貼標","de":"雖沒有砰的響聲，但看起來最華麗的紙煙火。貼上信封的瞬間，平凡的郵件就變成了從喜宴寄來的信。捨不得撕下而留著的人很多。"},"ICON-1059":{"nm":"照片晾掛夾","de":"怕掛在繩上的回憶會掉，我總是緊緊抿著嘴。只要還咬著一張張照片，即使窗縫吹進風，那些日子也不會落下。"},"ICON-1060":{"nm":"日期氣球貼布","de":"寫著數字的氣球形貼布。貼在衣服上，整個街坊就都知道今天是第幾天的特別日子。撕下會留下痕跡，但連那道淡淡的印子也成了又一個紀念。"},"ICON-1061":{"nm":"禮物交換標記","de":"讓收的手和遞的手稍微分不清的調皮標記。比起是誰送的，更要記住交換了什麼——這是收送禮物場合中，小小而溫柔的規矩。"},"ICON-1062":{"nm":"紀念桌號牌","de":"每張喜宴桌上小小立著的一格號碼。預先定好誰坐哪個位子，就不會彼此尷尬——這蘊含著辦過多次喜宴的人，溫柔的智慧。"},"ICON-1063":{"nm":"門把禮物袋","de":"不按門鈴也能傳遞心意的方法。悄悄掛在門把上、像逃跑般消失後，發現它的人那張驚訝的臉，就成了回贈給送禮人最大的禮物。"},"ICON-1064":{"nm":"祕密配送貼標","de":"外面什麼都沒寫。把是誰寄的藏到最後，是這張貼標小小的自尊。收件人歪著頭笑得越久，那神祕的任務就越完美。"},"ICON-1065":{"nm":"門鈴留言貼","de":"鼓不起勇氣敲門時，代為貼上的小紙條。「順道來坐了一下喔」這樣短短一行，比門鈴聲留得更久。因為歪歪扭扭的手寫字裡是有表情的。"},"ICON-1066":{"nm":"拆箱刀安全蓋","de":"當拆箱刀刃不經意瞄準手指時，悄悄擋在前頭的小英雄。它把因為對新東西的雀躍而變急的指尖，安然守護到最後一格。"},"ICON-1067":{"nm":"緩衝氣泡膜片","de":"我天生就是用來捏的。隨著啵的一聲爆開，一天的緊張不知怎地就慢慢鬆開了。比起我曾包著的東西，我反而更被長久寵愛的日子，也常常有。"},"ICON-1068":{"nm":"收件時間別針","de":"明確標出幾點送達、釘好的別針。原本茫然的等待，只要有了一個座標，就變得好捱多了。在那個時刻之前要往玄關張望幾次，就全憑本人了。"},"ICON-1069":{"nm":"無人保管箱鑰匙圈","de":"為老是忘記快遞箱密碼的人準備的小夥伴。掛在鑰匙圈上晃啊晃，在關鍵時刻引出一句「啊對了」，是這位朋友不著痕跡的拿手好戲。"},"ICON-1070":{"nm":"玄關籃標牌","de":"貼在玄關角落籃子上的名牌。寫著「放這裡就走吧」這無言的約定。即使空空如也，等待著某人心意的位子，也絕不孤單。"},"ICON-1071":{"nm":"地址遮蓋貼","de":"在要丟棄的箱子上，留下名字、只把地址刷地抹去。就算全被知道也沒關係的只到名字，住在哪裡是只屬於我的祕密。撕下貼上的瞬間，便生出一份小小的安心。"},"ICON-1072":{"nm":"零食罐貼標","de":"一眼告訴你罐裡裝了什麼的貼標。可是寫上「零食」，就算不打開蓋子，不知怎地也覺得心裡踏實——這就是陷阱。貼標可不負責食慾喔。"},"ICON-1073":{"nm":"小項鍊墜飾","de":"在衣服裡靜靜分享體溫的一顆小東西。它總是貼在誰的眼睛都看不到的地方，反而更教人疼惜。是貼著胸口一同行走、最親近的伴。"},"ICON-1074":{"nm":"腳印印章墊","de":"在腳掌上輕輕一蓋，小小的腳印就成排留下。誰往哪兒走了，工工整整記在紙上、一天份的散步日記。沾了墨的第一步，總是最清晰。"},"ICON-1075":{"nm":"理毛刷蓋","de":"把卡在梳子上的毛俐落收拾乾淨的小蓋子。換季時一梳就聚成一把，沒有這蓋子，整間屋就要變成蓬鬆的雪地了。是不著痕跡卻勤快的清潔工。"},"ICON-1076":{"nm":"散步便袋盒","de":"把散步路上要帶的袋子整齊收著、隨身攜帶的小家。只有事先準備的人才能從容地走，這個盒子每天默默證明這件事。是忘了就要犯難的那一張。"},"ICON-1077":{"nm":"名字遮蓋吊牌","de":"把真名悄悄遮住、只留下暱稱的吊牌。世上也有不想隨便給誰都看的溫柔。只有知道的人才知道的那聲呼喚，就輕輕藏在這裡。"},"ICON-1078":{"nm":"水碗墊片","de":"墊在水碗底下的我總是濕答答的。代為接住四處啵啵濺開的水珠，守護地板乾爽。沒有人稱讚，但我也沒有怨言。"},"ICON-1079":{"nm":"玩具修補線","de":"縫線爆開的玩偶不是用來丟的，是用來重新縫補的。一針針填補的每一處，與那孩子共度的時光就再次變得堅實。所謂修補，終究是靜靜延後告別這件事。"},"ICON-1080":{"nm":"紀念照項鍊","de":"把笑得最燦爛的那一格掛在脖子上的心意。照片裡的那一天沒有被製成標本，而是隨著每一步一同搖晃，延續到今天。那段美好的瞬間，不曾停下。"},"ICON-1081":{"nm":"心情色彩片","de":"如果心也有顏色，今天你的色彩是什麼呢。挑一片放在書桌上的瞬間，說不盡的心情便靜靜暈染開來。晚霞色也好、破曉色也好——因為它是靜靜映照那天的我、一面小小的鏡子。"},"ICON-1082":{"nm":"今日紀錄珠","de":"一天落幕時，今天就在珠裡圓圓地凝結。做得好的事、笨拙的事，都咕嚕咕嚕收攏滾去。捧在掌心，昨天的我微微溫熱，輕拍著背說：今天也好好活過了。"},"ICON-1083":{"nm":"讚美紙條瓶","de":"好話太容易飄散，所以一張張摺好裝進這瓶裡。當讚美如香氣般積聚，便在心裡空蕩的夜晚打開蓋子。重新取出誰遞來的一句溫柔讀一讀，那天的暖意就復甦了。"},"ICON-1084":{"nm":"和解緞帶繩","de":"糾結的心像極了繩結，解開時也得費上心思。兩人各執繩的兩端慢慢一拉，不知不覺就成了一個漂亮的緞帶。所謂和解不是切斷，而是重新繫上——這條繩靜靜地告訴你。"},"ICON-1085":{"nm":"感謝代幣","de":"謝謝這話怎麼也說不出口的日子，便代為悄悄遞上一枚代幣。接過的手憑那小小的重量，就讀懂了所有心意。比話語更先抵達的真心——情意盛在圓圓的一顆裡，渡了過去。"},"ICON-1086":{"nm":"休息時間標記","de":"整天奔忙的練習室，也需要一拍喘息。把這標記掛在門上，時間就暫且慢了下來。有了休止符，歌才能呼吸——活過匆忙一天的人都懂得這道理。"},"ICON-1087":{"nm":"祕密情感抽屜","de":"總有些日子，無法把心事全掏出來給人看。那時就在心裡的一個小抽屜，把悲傷也好雀躍也好都靜靜放進、闔上。現在先擱著也沒關係——總有一天會慢慢打開、整理的日子到來。"},"ICON-1088":{"nm":"笑臉貼紙捲","de":"一格格撕下，一個笑臉就沾上指尖。在筆記角落、在朋友的置物櫃上悄悄貼下的小小開朗。當紙上升起一輪小太陽，發現它的某人那一天就明亮了一些。"},"ICON-1089":{"nm":"問候鈴鐺吊飾","de":"想觸及遠方的你，那份心意凝成了一顆鈴鐺。一搖，清脆的聲響便代為傳達問候。終究沒能說出「過得好嗎」的那天——這小小的鳴響乘著風，先一步抵達。"},"ICON-1090":{"nm":"春雨護封別針","de":"下春雨的日子，越是珍惜的東西越容易濕。用這別針把書封掩好，雨珠便側著流開。把珍貴的一本書摟進懷裡的心意——一枚小別針，代為完成那份溫柔。"},"ICON-1091":{"nm":"夏日清涼貼","de":"在被盛夏暑氣折騰的手背上輕輕一貼。沁涼如薄荷般擴散，汗便消退了一分。躺在敞亮的木地板上搖扇的那份清涼，巴掌大的一張紙細心地模仿了出來。"},"ICON-1092":{"nm":"秋日格紋布片","de":"一片像極了秋日田野的格紋布。是有人細心補綴破損處的痕跡。不丟棄、縫補著用的心意——小小的布片聚在一起，把磨損的東西重新溫暖地救活。"},"ICON-1093":{"nm":"冬日手套夾","de":"冬天的手套不知怎地老是一隻隻逃走。用這個夾子把兩隻連在一起，發冷的手就不會迷路。不想弄丟的心意寄宿在小小的鐵件上，把一雙並肩守護。"},"ICON-1094":{"nm":"梅雨防水籤","de":"梅雨季節連名牌都被雨水暈開。鍍上防水的這張籤，在傾盆大雨中也守住了字跡。雨停後依然清晰留下的一行——是為了到最後都不忘，這是誰的東西。"},"ICON-1095":{"nm":"初雪保存瓶","de":"初雪一觸到手就消失，所以至少把那份雀躍裝進了瓶裡。被關進玻璃裡的不是雪，而是那天怦然的心。一搖，一個冬天便再次紛飛，把你帶回那個早晨。"},"ICON-1096":{"nm":"節慶紅包帶","de":"圍著節慶紅包的一道紅帶。比起裡頭裝的，遞出之手的情意更大——這人人都懂。把保重的話與福氣一同包進去的心意，就好好繫在這細細的帶子裡。"},"ICON-1097":{"nm":"野餐餐具束帶","de":"鋪開野餐墊、解開便當，風老是掀起蓋子。用這束帶把餐具俐落地紮好，野餐就不會亂了套。想把帶來的一餐守護到最後的心意，盛在小小一條帶子裡。"},"ICON-1098":{"nm":"季節香氣樣品卡","de":"為了不打開也能知道季節，把那個時節的香氣裝進了一張卡裡。春天是花，秋天是乾葉的氣味。拂過鼻尖的瞬間，那個季節便整個浮現——「這就是四月的空氣」。"},"ICON-1099":{"nm":"價格牌寫字板","de":"價格牌老是飛走的攤位煩惱，被這一塊寫字板給平息了。緊緊咬住數字，挺直地遞到客人面前。做生意的第一聲問候，始於不亂套、正直的那一行。"},"ICON-1100":{"nm":"營業中翻面牌","de":"在門前把這牌子翻面掛上，店就終於甦醒了。從「準備中」到「歡迎光臨」。宣告一天開始的小信號——是主人的手每天早上最先觸及的地方。"},"ICON-1101":{"nm":"集點印章墊","de":"集滿十格，不知怎地就會有好事發生。每一個印章都是常客的腳步，是累積下來的情意。隨著墊上的墨水乾去而蓋下的每道痕跡，都活著一個「會再來」的小約定。"},"ICON-1102":{"nm":"紙袋提把蓋","de":"紙袋的提把在重量面前總是脆弱。套上這蓋子，眼看要斷的繩就變得結實了。想把裝著的東西安然帶回家的心意——一個小零件，把那條路撐持到底。"},"ICON-1103":{"nm":"收銀台零錢碟","de":"把零錢從手交到手時的那份遲疑，這碟子靜靜替你化解。硬幣叮噹找到自己位置的聲音。收送這件事變得更溫暖，正是多虧了這樣圓圓的體貼。"},"ICON-1104":{"nm":"點數累積片","de":"今天踏出的腳步，化作一片片地累積起來。越聚集心越輕盈的奇妙算法。一點一點填滿的樂趣，就像看著空甕子不知不覺裝滿的喜悅。"},"ICON-1105":{"nm":"陳列架號碼針","de":"每個陳列架上都親切地釘著一個小號碼。告訴你哪裡有什麼的安靜嚮導。為了不讓人迷路而預先指明位置的心意——連秩序裡也這樣寄宿著溫暖。"},"ICON-1106":{"nm":"試吃串杯","de":"插著一口試吃遞出的小杯子。猶豫不決的客人，也因這一塊而悄悄敞開了心。「拿一個嚐嚐吧」這份人情掛在竹籤尖上，留住了初次到訪者的腳步。"},"ICON-1107":{"nm":"預約名單夾","de":"今天要來的客人們的名字，在這個夾子裡整齊地站著。連等待也有順序的溫柔約定。把一張紙端正立著這件事，成了精心迎接某人一天的第一步準備。"},"ICON-1108":{"nm":"牆面照片繩夾","de":"在牆上拉一條繩，用夾子把照片一張張掛上。歡笑的瞬間像曬衣物般並排晾著風乾。把回憶晾在灑進陽光的地方，每次經過，那天的笑容就再次翻飛。"},"ICON-1109":{"nm":"迷你地毯角墊","de":"鋪在房間邊角的一張小地毯。是率先在冰冷地板上鋪展暖意的位置。赤腳最先觸及的一掌之地——回到家的腳尖在這裡才終於安心地慵懶下來。"},"ICON-1110":{"nm":"門牌遮簾布","de":"輕輕遮住門牌的一幅布。把名字暫且藏起，也是過日子的雅趣。把內與外的界線優雅垂下的一襲——今天想靜靜歇息的心意，柔柔地掛起。"},"ICON-1111":{"nm":"燈線夾","de":"鬆垂的燈線，這夾子端正地把它抓好。讓光不致散亂、把路理直的手。傍晚將臨時，把雜亂的一條線理一理，房裡的光與心也都從容了幾分。"},"ICON-1112":{"nm":"海報磁鐵蓋","de":"把海報貼上牆的小磁鐵蓋。不用戳一個圖釘孔，紙就守住了原位。對待珍惜之物的手總是輕柔的——不讓它受損的心意，盛在這裡。"},"ICON-1113":{"nm":"窗簾流蘇繩","de":"把窗簾的一幅往一邊綁起的流蘇繩。優雅地為晨光打開進來的路。垂著穗子的繩一拉，明亮的一天便大步湧進房裡停駐。"},"ICON-1114":{"nm":"香氛蠟燭墊貼標","de":"貼在香氛蠟燭墊上的一張小貼標。燃著什麼香、何時初次點上，工工整整地記下。為喜歡的氣味取上名字這件事——那份整潔，讓房裡的空氣更顯溫柔。"},"ICON-1115":{"nm":"裝飾層架橡膠腳","de":"撐著層架不晃動的四隻橡膠腳。在看不見的地方默默承受重量。又小又低不顯眼，但在最底下撐持的，終究撐得最久。"},"ICON-1116":{"nm":"方向標箭頭吊飾","de":"為猶豫該往哪兒走的人，一支箭靜靜指明方向。是叮囑你別迷路的溫柔手勢。多虧每個岔路口都有人先立好的心意，今天也不迷惘地往前走。"},"ICON-1117":{"nm":"島嶼邀請鑰匙繩","de":"交到邀你上島之人手中的鑰匙繩。收下這個，從此你也是這裡的家人了。把陌生的客人迎進溫暖之內的款待，就牢牢盛在繩尾那個小小的約定裡。"},"ICON-1118":{"nm":"關係溫度片","de":"兩人之間的溫度，一片小片悄悄替你說明。是還生疏的藍光，還是不知不覺已暖成的橙紅。情意加深的速度難以丈量，但掌心會先一步察覺那暖意。"},"ICON-1119":{"nm":"喜好樣品盒","de":"還不知道喜歡什麼時，就把小小的樣本裝進一個盒裡遞上。在挑選的樂趣中，喜好慢慢長大。哪一個會成為你的呢——盒裡滿是令人雀躍的可能。"},"ICON-1120":{"nm":"照護預約針","de":"要照顧某人的約定，清清楚楚釘在這一枚針上。寫下名字與時間，心就不會迷路。輪流替彼此照看孩子的那份溫柔互助，在這裡活著呼吸。"},"ICON-1121":{"nm":"成長紀錄膠囊","de":"就像門框上量身高的刻痕一行行累積，這膠囊靜靜封存昨天的你。遙遠的某天打開蓋子你就會明白，那曾小小的腳步，走了多麼遠的路。"},"ICON-1122":{"nm":"初遇保存帶","de":"把初次相握時的那份悸動，輕輕繫進一條帶子裡。打結不是為了解開，而是為了讓那天的暖意繼續活在手腕上，才停駐在那兒。"},"ICON-1123":{"nm":"我的房間小物貼標","de":"「這裡是我的位子。」一張小貼標貼上書桌角的瞬間，原本陌生的房間才終於透了口氣，成了我的房間。名牌，是心最初落腳的地方。"},"ICON-1124":{"nm":"親密度珠罐","de":"一搖咕嚕嚕，兩人之間靠近一格的聲音滾了過去。等到罐子裝滿時，光是喊個名字，笑就已經先一步出來迎接了吧。"},"ICON-1125":{"nm":"出道準備封緘","de":"封住信封的最後一張。到這裡是準備，翻過下一頁就是舞台。用指尖用力按下，練習生調勻了呼吸。終於，要開始了啊。"},"ICON-1126":{"nm":"水","de":"最常見，所以最珍貴。燈火熄滅的凌晨練習室，僅僅一口，就把癱坐的人重新扶起。自己沒有形狀，卻能滲進任何容器的溫柔。"},"ICON-1127":{"nm":"清水","de":"連水底的卵石都映得透亮的澄澈。山谷的小泉從不曾自誇它的清。無所隱藏的心，總是這樣連底都看得分明。"},"ICON-1128":{"nm":"海水","de":"觸到舌尖的瞬間，遠方的浪便湧了過來。一口鹹味裡，水平線與海鷗、離別的港口，整個融化其中。海，總是鹹鹹地留在記憶裡。"},"ICON-1129":{"nm":"冰","de":"在掌心上慢慢變小，握多少就消失多少。看似堅硬，終究懂得回歸為水。冰，是暫時屏住呼吸的河。"},"ICON-1130":{"nm":"雪球","de":"緊緊揉成的一團劃過巷子，雪白地飛去。咯咯的笑與凍得通紅的臉頰。是冬天悄悄塞給孩子們、最最雪白的玩具。"},"ICON-1131":{"nm":"土","de":"懷抱種子、飲下雨水、無言地承接路過的腳印。把一切都摟進懷裡的黑色肌膚。所有生長之物的最初位置，都有這一把。"},"ICON-1132":{"nm":"肥沃的土","de":"手指深深插進去，便鬆軟纏上來的黑色油潤。奶奶的菜園年年青翠的祕密就在這裡。養得好的土，用堆肥的氣味低語著豐年。"},"ICON-1133":{"nm":"黏土","de":"含進水氣的瞬間，任何形狀都乖乖接受。隨手成鳥、成器的溫柔之肌。轆轤旋轉之間，一把泥土才終於做起了夢。"},"ICON-1134":{"nm":"沙","de":"從指縫間溜溜滑落的細碎顆粒。越想抓住流得越快，總是越來越像時間。海灘的一把裡，沉睡著無數個昨天。"},"ICON-1135":{"nm":"礫石","de":"在溪邊磨得圓圓的石頭。是水長年累月撫摸、直到稜角消失的痕跡。越是滾得遠的，越是乖巧地落進手裡。"},"ICON-1136":{"nm":"石頭","de":"路邊隨意擱著的一塊。有人一腳踢開就走，有人靜靜撿起堆成塔。同一塊石頭，隨著心境既能成負擔，也能成願望。"},"ICON-1137":{"nm":"石板","de":"橫越古宮庭院的扁平石頭。被數百年的鞋履踩踏而過，中央凹陷了下去。每一個一步步踏上的人，都在那裡多疊了一層時間。"},"ICON-1138":{"nm":"石灰石","de":"曾是海洋時代的貝殼層層凝固，成了白石。入了窯便化為灰，把牆垣刷得雪白。看似靜謐，卻是整整懷著一個時代的石頭。"},"ICON-1139":{"nm":"煤","de":"黑黑地沉睡下去的古老森林。是數億年前的蕨類在地下深深凝結而成。一點上火，埋藏已久的陽光便熊熊地再次甦醒。"},"ICON-1140":{"nm":"炭","de":"含住火，卻靜靜吞下煙。在窯中被黑黑壓實的木頭，在火爐上無言地紅紅綻放。越是默默的，越是長久溫暖。"},"ICON-1141":{"nm":"樹枝","de":"為了不折斷而默默彎曲過來的枝，懂得彎折之道。在熬過狂風的每一處長出節瘤，所謂真正的堅韌，終究是好好彎過的痕跡。"},"ICON-1142":{"nm":"原木","de":"切開的年輪裡，一百個春與冬圓圓地疊著。一棵樹活過的歲月整個躺下，如今靜靜等著，輪到自己成為房子的樑柱。"},"ICON-1143":{"nm":"木材","de":"每當刨子掠過，便露出一層芬芳的木紋。粗糙的木頭變得光滑之際，木屑如黃雪般堆在地上。修整的手，喚醒了用處。"},"ICON-1144":{"nm":"木板","de":"鋪地板、做矮榻、圍籬笆。把方正鋸出的一張張聚在一起，住人的地方才終於立起。平凡的東西堆疊起來，便成了安身之所。"},"ICON-1145":{"nm":"竹","de":"心裡雖空蕩，在風前卻挺直。每一節都斷了又重新冒出的那股氣節，古時的士子曾想效法。空著反而更挺拔的東西，就在這裡。"},"ICON-1146":{"nm":"軟木","de":"用力一壓再放開，便又脹回原本的厚度。看著這既輕又韌的紋理，便明白柔軟絕非脆弱。從瓶塞到布告欄，靜靜地撐托著。"},"ICON-1147":{"nm":"草","de":"被踩了，下一場雨來時又站起來。連一個名字都沒有，卻把田野整個覆蓋過去的綠的韌性。別小看它小，最先報春的，總是這低矮的角落。"},"ICON-1148":{"nm":"稻草","de":"秋收後黃黃留在田裡的東西。編起來成了屋頂，鋪上便成了溫暖的睡處。把穀粒全部讓出後，仍到最後都還替人遮蓋的心意。"},"ICON-1149":{"nm":"蘆葦","de":"風一拂過，沙啦沙啦，整條河岸都歌唱起來。因心是空的而哭得更遠的莖。搖曳的那副模樣本身就是自己的歌，蘆葦一點也不覺羞愧。"},"ICON-1150":{"nm":"棉花","de":"成熟的莢啵地一裂，一朵小雲便綻放開來。又輕又柔的這團棉成了線、成了衣，在冰冷的冬夜，靜靜暖了某人的肩。"},"ICON-1151":{"nm":"羊毛","de":"沾到手上便泛起油氣，靜靜留下暖意。是羊為了熬過寒山而裹在自己身上的外套。剪下的那份溫暖，如今移到了人的冬天。"},"ICON-1152":{"nm":"線","de":"細得若隱若現，可重新接起散落的兩端的，總是這個。一縷雖弱，編在一起便成一幅布。在連結這件事上，粗細並不重要。"},"ICON-1153":{"nm":"布","de":"緯線與經線無數次交錯，織成一幅。是獨自就會散開的線們彼此緊緊抓牢的結果。越緻密越溫暖這件事，人與人之間也是一樣。"},"ICON-1154":{"nm":"皮革","de":"越用越染上手澤，一點點地像起自己的主人。在最初的硬挺被馴順的過程裡，色澤變深、紋理變柔。時間刻下的那份光潤，無物能夠模仿。"},"ICON-1155":{"nm":"羽毛","de":"放在掌心也輕得感覺不到重量。曾在天空飛翔的記憶，原封不動寄宿的一縷。最輕的曾飛得最高——請千萬別忘了。"},"ICON-1156":{"nm":"貝殼","de":"奶奶說過貼到耳邊聽聽看，那句話忽然浮上心頭。內側的虹彩裡，整片離別的海被刻了進去，所以即使是空殼，也能聽見一個時代的盪漾。"},"ICON-1157":{"nm":"珊瑚","de":"雖如石頭般凝固，但曾是分明呼吸過的群落。在緩慢的海中，耗上數百年伸展枝椏。最堅硬的枝，要等到最久之後才長得出來。"},"ICON-1158":{"nm":"珍珠","de":"受不了一粒沙的硌人，貝便把它靜靜以光裹了起來。若把痛圓圓地懷抱，就會如此晶瑩——這是海遞來的小小慰藉。"},"ICON-1159":{"nm":"海藻","de":"退潮的礁岩上滑溜垂掛的綠帶。握在手裡，腥腥的海味便撲面而來。沒有根、把身子交給水流，海靜靜地耕著自己的庭園。"},"ICON-1160":{"nm":"海苔","de":"把黑黑的一張稍微在火上烤一烤，便轉青、散出香氣。捲在剛煮好的飯上的那個早晨。薄薄的，卻足以把一餐的幸福整個摟進懷裡。"},"ICON-1161":{"nm":"鹽","de":"我是海留在陽光下的白色結晶。一撮，淡薄的湯便深邃起來；手一滑，便蓋過所有味道。只有懂得適量的指尖，才能好好使喚我。"},"ICON-1162":{"nm":"玻璃碎片","de":"正是在破碎之處，才終於折出光、開出彩虹。完好時不曾知道的本事呢。連碎掉的東西也還留著一份替陽光分享的責任——躺在窗邊的碎片靜靜告訴你。"},"ICON-1163":{"nm":"玻璃","de":"透明不只意味著無所隱藏。是為了讓光完整穿過，而抹去了自己的模樣。在不被看見地停駐於那裡這件事上，手一觸及也自有一份清涼的端正。"},"ICON-1164":{"nm":"玻璃瓶","de":"得空了才能裝些什麼。果醬也好、一把野花也好、摺進去的信也好，隨著進來的東西改變名字。不畏懼空的容器，最是寬厚。"},"ICON-1165":{"nm":"空瓶","de":"我喜歡喝完之後到訪的寂靜。有人把我丟棄，有人沖洗後擱上窗台、盛滿陽光。在結束之處再次獲得用處，這就是空了之物的第二段人生。"},"ICON-1166":{"nm":"紙","de":"備好接納任何書寫，白白地攤展著。最久凝望著躊躇第一行之人那顆心的，總是我。白紙的忍耐，比墨水還深上一掌。"},"ICON-1167":{"nm":"舊紙","de":"泛黃不是衰老，而是熬過。每一道摺痕裡，都浸著攤開閱讀之手的暖意。老舊的紙為了不被遺忘，用自己的顏色寫下流逝的時間。"},"ICON-1168":{"nm":"墨水","de":"從一滴開始成句，乾了便如約定般留下。暈開就照暈開的樣子，是那天的痕跡。讓事情無法挽回是我的工作，所以人們會再慎重一次，才把我落下。"},"ICON-1169":{"nm":"鐵礦石","de":"是在地下做著紅色之夢的石頭。得穿過火一回，才終於交出體內的鐵。堅硬不是一開始就堅硬，而是通過熾熱之後才得到的名字。"},"ICON-1170":{"nm":"鐵錠","de":"礦石熬過火後才凝成一塊冷卻下來。又冷又沉重的這模樣，能成橋、成刀、成鋤。正因用途還沒定下，我才能成為任何東西。"},"ICON-1171":{"nm":"銅礦石","de":"裹著青蘋果色的鏽，從泥土裡鑽了出來。熔了便響起鐘聲、立起銅像、流過電線。即使在漆黑的地下沉睡時，我也總在等著被喚作什麼的那一刻。"},"ICON-1172":{"nm":"銅錠","de":"在身旁擺得久了，便親手替自己縫起一身青衣。有人把那光稱作瑕疵，也有人把它當歲月的紋路而撫摸。不為自己變化的色澤羞愧的金屬，最是長久被愛。"},"ICON-1173":{"nm":"金礦石","de":"是淘了又淘江沙才遇見的一點。並非因稀少而珍貴，而是因不變而珍貴。古人叮囑要像不生鏽的心，便把它握在手裡當作信物遞出。"},"ICON-1174":{"nm":"金錠","de":"不褪色也不生鏽地化為一塊躺著。聽過最多人們的貪欲，自己卻什麼也不貪。只是忠於發光這一件事的、沉重的沉默。"},"ICON-1175":{"nm":"廢鐵","de":"不是用盡了用處，而是正等著下一個用處。斷掉的釘與壓扁的罐聚在一處，再次遇上熾熱的火。被丟棄這句話對我而言，是暫時歇息的意思。"},"ICON-1176":{"nm":"螺絲","de":"獨自什麼也辦不到。要旋轉鑽入、把兩塊板緊緊咬合時，才終於盡了本分。以小小的身子抓牢大東西的本事，在那擰緊的力道裡也寄宿著用心。"},"ICON-1177":{"nm":"釘子","de":"一旦釘入便輕易不退讓。每當鎚子敲下，加深的不是傷口而是約定。若是把什麼緊緊接起的事，我願意把頭交出去。"},"ICON-1178":{"nm":"齒輪","de":"推著旁邊鄰居的齒，一同轉動。不獨自圖快，而懂得配合身旁的速度。就像非得咬合時間才流動的時鐘，我相信和諧便是運轉。"},"ICON-1179":{"nm":"彈簧","de":"越被壓，越把回彈的力往內聚攏。彎曲不是放棄，而是為了重新伸展的準備。承接了多少衝擊就彈回多少，柔軟即堅韌的一條小螺旋。"},"ICON-1180":{"nm":"電線","de":"外是溫順的外皮，內是不停流動的路。在看不見的地方載運著光與聲。就像默默接連舞台後方的手，正因不外顯，才更教人信賴的通道。"},"ICON-1181":{"nm":"電池","de":"把半天份的明亮光，在小小身軀裡一點點收攏。用完了再充滿就好，從不把空蕩當作終結。懷著要照亮某人漫漫長夜的、一個小小的傍晚。"},"ICON-1182":{"nm":"燈泡","de":"一根細細的絲紅紅燒起，推開黑暗。不是燒著自己去暖房，而是去照亮。亮起時最熾熱，因而最明亮的、一瞬間的小太陽。"},"ICON-1183":{"nm":"鏡片","de":"把散開的光聚起，在一點上清晰立定。遠處的星，掌上的小字，都靜靜喚來。為了幫人看見，反倒藏起自己模樣的、清澈圓潤的媒人。"},"ICON-1184":{"nm":"橡膠","de":"壓也好拉也好，終究回到原位。嫌它軟的人，下雨天也挑我來穿。把猛烈的衝擊柔柔接下這件事，這份軟綿裡也住著韌性。"},"ICON-1185":{"nm":"塑膠碎片","de":"是從本體脫落的小碎片。差點就要被丟棄，但聚在一起便又成了新東西。不是因為小而輕，而是因為輕才能走得遠的、某物的一部分。"},"ICON-1186":{"nm":"繩索","de":"得把好幾股絞在一起，才終於成為一條。獨自容易鬆開，編在一起便能拉船、捆貨。一同扭絞多少就有多韌，是掌心粗糙的、協力的古老繩結。"},"ICON-1187":{"nm":"帆布","de":"不憎恨風，而把它滿懷擁進胸口。鼓得緊繃才能把船送遠，所以連逆風對我也成了力量。不違逆狂烈而摟進懷裡前行的方法，是向海學來的。"},"ICON-1188":{"nm":"錨片","de":"雖是錨的一角，卻完整記著那份重量。記著沉沉抓住海底、把船停下的那段歲月。即使如今脫落，仍是懂得停駐之重的、沉甸甸的一片。"},"ICON-1189":{"nm":"船釘","de":"是把隨浪起伏的甲板一點一點釘牢的釘子。即使被鹽分鏽得通紅，也到最後都不放開自己的位置。把漂浮之物緊緊抓牢，也需要一股拗勁。"},"ICON-1190":{"nm":"防水布","de":"在擋雨這件事上沒有怨言。默默承接上頭傾瀉而下的，守護下方之物乾爽。即使不華麗，也是替某人的行李遮著不被淋濕的、可靠的一層。"},"ICON-1191":{"nm":"染料","de":"靜靜滲進白布裡，才終於成為色彩。靛藍也好茜紅也好，從前的母親們染著指尖，替布上了色。在沉下、滲入這件事上，也有一份輕易褪不去的深度。"},"ICON-1192":{"nm":"香料油","de":"僅僅一滴，房裡就大步鋪展開一片遼闊的原野。雖看不見，卻是最先抵達的客人。悄悄牽起沉睡記憶衣襟的、先一步觸及鼻尖的風景。"},"ICON-1193":{"nm":"蠟","de":"受熱便流，冷卻便凝固守住那形狀。在柔軟與堅硬之間來回，把什麼都靜靜拓印下來。封、緘、上光，隨溫度改變表情的、溫柔的材料。"},"ICON-1194":{"nm":"蠟燭","de":"慢慢融去自己的身子，照亮一格黑暗。燒盡後只剩變短的個頭，但暖過某人夜晚的那段時間不會消失。是懂得在變小中發光的、筆直的燭芯。"},"ICON-1195":{"nm":"堆肥","de":"腐朽之物聚在一處，成了最肥沃的土。被丟棄的果皮與枯萎的落葉，成了春日新芽的飯。在以為結束的那個位置，下一個生命靜靜調起最初的呼吸。"},"ICON-1196":{"nm":"米","de":"把一粒握進手裡，要經八十八道手。從插秧到打穀，農夫的一整年原封不動盛在這小小的顆粒裡。一碗冒著熱氣的飯，便是某人的四季。"},"ICON-1197":{"nm":"糙米","de":"只稍稍褪去外殼，原原本本守著本來的顏色。越嚼越香，是不急不躁的正直之味。不肯被細細削去、留下粗糙紋理的、穀粒堅硬的執拗。"},"ICON-1198":{"nm":"小麥","de":"記得在風中一齊低頭的金黃田野。成了麵包、成了麵條、成了麵疙瘩，暖著世界各處的餐桌。正因常見，反而更深地滲進人間生活的穀物。"},"ICON-1199":{"nm":"麵粉","de":"成了細細的白粉後，才終於備好成為任何東西。遇水便脹，遇火便熟。正因沒有固定的形體，才能隨手揉捏成形的、溫順的底子。"},"ICON-1200":{"nm":"麵團","de":"粉與水在掌心下融成一塊。揉多少就有多Q彈，等多少就脹得多飽滿。一急就變韌，唯有發酵的時間催促不得——老麵包坊這麼說。"},"ICON-1201":{"nm":"麵包粉","de":"撥落指尖沾上的白粉，不知不覺連衣袖都白了。裹成炸衣是酥脆，輕輕堆起像初雪。它是一塊麵包烤完後留下最輕盈的痕跡，但再小的東西，用途也會慢慢長大。"},"ICON-1202":{"nm":"義大利麵條","de":"把一把麵條像扇子般撒進滾水的那一刻，遠方的陽光便越過廚房灑了進來。長長的麵條是手腕的活兒，彈牙則是懂得稍微留一分生、耐心等待的心。看那纏在叉子上一圈圈的光澤吧。"},"ICON-1203":{"nm":"泡麵","de":"卸下舞台妝的凌晨，偷偷下的那一包。麵條泡開的三分鐘，是一天裡最私密的時光。呼呼吹著的氣息把緊張一同吹涼，霧濛濛的眼鏡後，今天靜靜落幕。"},"ICON-1204":{"nm":"年糕","de":"稻米熬過石臼的捶打，才終於成為年糕。打糕、黃豆糕、松糕——同樣的穀物，隨手藝得來上百個名字。一上喜宴的桌，比起嘴，情誼先被喚起，是要分著吃才夠味的食物。"},"ICON-1205":{"nm":"年糕湯片","de":"把長條年糕斜斜切開，圓圓的像枚小銅錢。漂在白湯裡的，是年糕呢，還是圓圓的心願？新年第一個早晨喝完一碗，便又添上一歲——這多麼溫柔，也是這個國家的算法。"},"ICON-1206":{"nm":"馬鈴薯","de":"把泥土啪啪拍落，圓圓的臉龐便露了出來。在江原道坡地的風裡也默默長胖的塊根，蒸了鬆軟，煎了噴香。即使口袋空空的日子，也踏實填飽一家人肚子的誠實根莖。"},"ICON-1207":{"nm":"地瓜","de":"巷口一支起烤地瓜爐，那便是冬天的開始。撕開錫箔，黃黃的熱氣先從指尖暖起，那份甜是熬過寒冷的根所給的回報。呵呵吹著，掰成兩半分著吃，正好的暖意。"},"ICON-1208":{"nm":"胡蘿蔔","de":"在泥土中筆直向下伸展的一支橙色。本以為只有兔子喜歡，炒過卻喚醒了藏著的甜，入湯還添上色澤。老一輩說它對眼睛好的話，大抵是對的。"},"ICON-1209":{"nm":"白蘿蔔","de":"有這一根又白又沉的根，冬天的餐桌就踏實了。做成水蘿蔔泡菜清冽，煮蘿蔔湯爽口，醃成蘿蔔丁脆生生。沒有一處可丟，連青青的蘿蔔纓都掛在屋簷下曬成乾菜，是一樣勤儉的蔬菜。"},"ICON-1210":{"nm":"洋蔥","de":"剝著皮，眼淚便一行行滾落。又辣又嗆的內裡，遇上燒熱的油，卻像撒謊似地變甜了。它是幾乎所有韓食頭一行寫下的名字，默默鋪墊香氣根基的安靜主角。"},"ICON-1211":{"nm":"大蔥","de":"把切碎的白色蔥根與青翠蔥葉撒在湯麵上，那一碗才彷彿終於完成。吃剩的蔥根插進水杯，又會嗖嗖長起來，是持家人窗邊的小小菜園。"},"ICON-1212":{"nm":"蒜頭","de":"六瓣圓圓聚成一顆。據說它就是把熊變成人的那辣根。用刀背咚咚拍碎，香氣便轟地醒來，泡菜也好燉鍋也好，少了這一把，怎麼都說不過去。"},"ICON-1213":{"nm":"生薑","de":"長得疙疙瘩瘩像個結的小根。只放一片，就能壓下腥味，從體內暖起發冷的身子。被感冒折騰得呻吟的夜裡，配著蜂蜜沖來喝的那杯暖飲，正是從這份辛辣開始的。"},"ICON-1214":{"nm":"大白菜","de":"把結實飽滿的葉子用鹽醃軟，泡菜的第一頁才算翻開。深秋每家院子裡堆得像山一樣的那東西。一家人圍坐著醃上一整顆，是相約共度漫長冬天的約定。"},"ICON-1215":{"nm":"高麗菜","de":"把層層捲起的圓葉一片片剝下，剝著剝著沒個盡頭，不知不覺心也悠閒了起來。汆燙後軟軟嫩嫩，下鍋炒則甜絲絲。粗樸的外表下，藏著意想不到的溫柔的蔬菜。"},"ICON-1216":{"nm":"結球萵苣","de":"在凹凹的葉子上擱一片肉，再抹上包飯醬，滿口塞進去。圍坐成一圈包著吃的場合，誰都會悄悄放下拘謹，所以這正是綠色的款待。"},"ICON-1217":{"nm":"萵苣","de":"菜園一角最早冒出頭的葉子。摘了又長，整個夏天填滿餐桌。用冷水沖過、用手隨意一包就吃下的那股清新草香，對某些人來說，整個就是故鄉的味道。"},"ICON-1218":{"nm":"菠菜","de":"卡通裡吃完罐頭就力氣大增的那抹綠。汆燙後縮成小小一把，香氣與精神卻一點不減。隨手拌一拌，或放一把進大醬湯都好——可絕不是因為常見就能小看的蔬菜。"},"ICON-1219":{"nm":"蕨菜","de":"折下春山獻出的嫩芽，煮過又曬乾。歷經這漫長的功夫，才終於擺上祭桌、拌進拌飯。費工夫越多，誠意便層層浸染其中，是山養了一季的珍貴山菜。"},"ICON-1220":{"nm":"山野菜","de":"看似無名，卻各懷不同香氣的春之禮物。奶奶的手在山路上一眼就認出哪片葉子能吃。一籃野菜裡，連著那個季節整個，帶著香氣一同跟了來。"},"ICON-1221":{"nm":"艾草","de":"最早衝破凍土冒出來的、帶點苦卻清香的草。揉進年糕，春光便原原本本入了口。正月時用它煮湯，相信能擋住一年的厄運，所以春天總是從這股香裡來。"},"ICON-1222":{"nm":"芝麻葉","de":"僅僅一片，就能把滿口濃濃染上香氣。配著焦黃的五花肉，或一層層醃進醬油裡，一碗白飯轉眼就空了。這獨特的香味，唯有在這片土地的餐桌上才這般親切。"},"ICON-1223":{"nm":"青椒","de":"中空卻脆生生碎開的綠色果實。微微帶著的苦味喚醒遲鈍的胃口，下油一炒，色澤更加鮮明。只是切碎撒上，任何料理都能瞬間變得清爽。"},"ICON-1224":{"nm":"甜椒","de":"紅黃橙，像紅綠燈般的色彩裝滿一籮筐。生著咬一口，甜汁便汩汩流出，光憑顏色就把餐桌照得明亮。好看的蔬菜也能勾起食慾，這話在它身上正好應驗。"},"ICON-1225":{"nm":"番茄","de":"總爭論不休究竟是水果還是蔬菜的圓圓的紅。慢慢熬煮味道更深，生著吃則無比清爽。它是最誠實地把盛夏陽光收攏起來的果實，咬一口，整個正午便轟然迸開。"},"ICON-1226":{"nm":"小黃瓜","de":"把夏日暑氣消解得最清涼的綠。漂進冷湯裡，滿口生涼；醃成釀黃瓜，脆勁便活了起來。酷熱的日子，薄薄切片擱在眼上也好，是裡外都清涼的蔬菜。"},"ICON-1227":{"nm":"南瓜","de":"圓圓地掛在藤蔓末梢，一路到深秋慢慢蓄滿甜味。熬爛成黃黃的粥，撫慰腸胃；煎成焦黃的煎餅。掛在屋簷下，整個冬天便擔起糧倉的角色。"},"ICON-1228":{"nm":"嫩南瓜","de":"夏日菜園裡一天比一天長胖的嫩綠。切大塊丟進大醬湯，煎成金黃煎餅——軟嫩得連小孩的嘴也順口。正因常見而更教人感激，是盛夏餐桌的常客。"},"ICON-1229":{"nm":"茄子","de":"泛著紫光油亮的長條果實。吸飽了油便無比柔軟，蒸得透了，紋理細緻如綢。看似平淡，卻與什麼搭配都合得來，是餐桌上溫柔的配角。"},"ICON-1230":{"nm":"玉米","de":"一粒粒整整齊齊排成行的黃色顆粒。在鍋裡蒸熟、呵呵吹著咬下的夏日點心，也是田野熟透了的可喜信號。一束毛茸茸的鬚裡，滿滿裝著甜味。"},"ICON-1231":{"nm":"黃豆","de":"又小又硬的顆粒泡了一整夜的水，飽脹起來。細磨成豆漿，發酵成醬——這片土地餐桌上的蛋白質，大多從這裡開始。在土裡埋下一粒，又會化作一株回來。"},"ICON-1232":{"nm":"豆腐","de":"黃豆吸飽水、磨碎、凝固，便成了稜角方正的白塊。柔軟而平和，無論入哪種湯，都不固執己色。用湯匙一舀便酥酥碎開，淡然恬靜正是它的美德。"},"ICON-1233":{"nm":"紅豆","de":"把又紅又小的顆粒煮得透爛，深紅的甜味便濃濃滲出。最長的那一夜，一碗熱騰騰的紅豆粥把寒冷與邪祟一同驅走的心意，便寄寓在此。年糕一層層間那抹紅，正是誠意。"},"ICON-1234":{"nm":"紅豆沙","de":"把煮好的紅豆細細搗碎、熬了又熬而成的柔軟內餡。夾進麵包、藏在年糕裡、舀一匙擱在刨冰上——一縷甜味連舊日記憶都暖了起來。那濾過熬過的漫長時光，原原本本化成了甜。"},"ICON-1235":{"nm":"蕈菇","de":"雨停之後，在昏暗的林蔭裡悄無聲息地探出頭。不靠一絲陽光也能養出自己香氣的、土壤的手藝。入湯只放一把，不用肉也能熬出深厚鮮味，是森林藏起的祕密。"},"ICON-1236":{"nm":"香菇","de":"撐開菌傘的褐色雨傘。曬乾後香氣濃上數倍，乾乾的一朵就足以撐起一鍋湯。它是素食餐桌可靠的支柱，也是懂得深味之人多年的老主顧。"},"ICON-1237":{"nm":"松茸","de":"秋日松林深處，唯有在松樹旁悄悄抬起頭。人工養不出、只能憑著腳力一步步尋來的香氣，因而更顯珍貴。稍微烤一烤、只蘸點鹽，一片森林便入了口。"},"ICON-1238":{"nm":"杏鮑菇","de":"把厚實的菌柄順著紋理一條條撕開，那份彈勁便握在手中。四季都踏實地長著，餐桌上沒有一天遠離它。烤也好炒也好——豐厚的肉裡，滿滿盛著毫無負擔的踏實。"},"ICON-1239":{"nm":"草莓","de":"在熬過冬天的塑膠棚末梢，最早紅紅地熟了。咬一口酸酸甜甜，正像初春的第一聲問候。在蛋糕上圓圓地擱一顆，平凡的今天也立刻成了紀念日。"},"ICON-1240":{"nm":"藍莓","de":"啵一聲爆開，滿口的酸便明亮地漾開。一顆顆夾起紫色小珠，不知不覺一盒就空了；撒在白白的牛奶上，便鋪開一片小小的夜空。"},"ICON-1241":{"nm":"蘋果","de":"咬一口，喀嚓一聲，秋天便碎了開來。果園奶奶用抹布擦了遞來的那抹紅，是要久久懷抱陽光才染上的顏色。越是結實，越懂得甜到最後的道理。"},"ICON-1242":{"nm":"梨子","de":"削起皮來，指尖先涼了一截。中秋祭桌的最前排，冰涼甜汁滿口湧上的那一刻，秋夜的晚風便悄悄挨過來，在身旁坐下。"},"ICON-1243":{"nm":"水蜜桃","de":"桃花謝去的每一處，都結出絨毛細細的夏天。輕輕一按，香氣先漾開，咬下一口的瞬間，整個季節便隨之入了口。"},"ICON-1244":{"nm":"葡萄","de":"一粒粒紫色聚成一串，彼此倚著肩。啵一聲爆開，酸先到，甜慢半拍才來——像夏末喚起的一場端正合唱。"},"ICON-1245":{"nm":"青葡萄","de":"嫩綠原原本本透過陽光，每一粒都點起了燈。無籽而清爽，像剛唱出的第一句，是毫無贅餘的甜。"},"ICON-1246":{"nm":"檸檬","de":"用指甲刮一刮黃色的皮，香氣便啵地喚醒鼻尖。一滴就教嘴角不由自主皺起，可那酸味的盡頭，竟莫名有一處讓一整天豁然明亮起來。"},"ICON-1247":{"nm":"萊姆","de":"比檸檬小、更深綠的這顆果子，先以嗆鼻的香氣打了招呼。只要一片，溫吞的水也瞬間醒來——雖小卻俐落的一把清涼。"},"ICON-1248":{"nm":"柳橙","de":"剝皮的瞬間，指尖便沾上了陽光的氣味。一瓣瓣放進嘴裡，啵、啵，小小的甜汁氣球接連爆開——圓圓的東西，連心情都會被滾得圓圓的。"},"ICON-1249":{"nm":"橘子","de":"冬日暖炕邊，把腳埋進被窩裡剝著吃的那味道，還記得嗎？從指甲縫漾開的香氣，把整個房間都染成了黃色。一袋橘子，就成了一家人圍坐的藉口。"},"ICON-1250":{"nm":"香蕉","de":"飢腸轆轆的凌晨練習室角落，曾有過用包包裡滾出來的一根黃色填飽一餐的日子。又軟又甜又頂飽——是最溫柔的權宜之計。"},"ICON-1251":{"nm":"鳳梨","de":"得越過一層帶刺的外殼，黃黃的果肉才露出來。一片含進嘴裡，酸酸甜甜啵地刺著舌尖，嘴角邊不知不覺繚繞起南方海洋的氣味。"},"ICON-1252":{"nm":"芒果","de":"用手剖開熟透的果肉，黏黏的甜香便濡濕了指尖。濃濃的黃在口中酥酥融化消失時，一場像短暫夏日午睡般的甜夢拂過。"},"ICON-1253":{"nm":"椰子","de":"搖一搖堅硬的殼，裡頭便傳來嘩啦的水聲。敲開來，雪白果肉與清涼的汁——是把遙遠海洋整個盛進去、晃晃蕩蕩的小小罈子。"},"ICON-1254":{"nm":"火龍果","de":"粉紅鱗片般的外貌，起初讓人頓了一下，剖開卻見雪白的肉裡點點芝麻。味道平實、裝扮華麗，是裡外恰好相反的滑稽傢伙。"},"ICON-1255":{"nm":"奇異果","de":"把披著絨毛的褐色剖成兩半，綠色的寶石便露了出來。黑籽如星辰般嵌在斷面，舀一匙放進嘴裡，酸酸的一口便把睡意搖醒。"},"ICON-1256":{"nm":"雞肉","de":"放上抹了油的鍋，滋一聲，焦黃的聲響先熟了。清淡又柔嫩，無論誰的餐桌都能無拘地擠進去坐下——是一頓溫和餐食的常客。"},"ICON-1257":{"nm":"豬肉","de":"在烤盤上滋滋作響，油花啵啵跳濺，焦黃地熟了。在一片萵苣上點一坨包飯醬、滿口塞進去的聚餐之夜，那股噴香把整個場子都暖了起來。"},"ICON-1258":{"nm":"牛肉","de":"每一道紅色紋理間都細細嵌著油，閃閃發亮。放上燒熱的石板，香氣便先填滿座位，一片含進嘴裡的瞬間，一天的疲憊悄悄鬆開了。"},"ICON-1259":{"nm":"培根","de":"清晨的平底鍋上，酥脆作響，油花跳起了舞。光憑那股鹹香，連睡懶覺的家人都揉著眼睛聚到廚房來——是氣味先喚起的一餐。"},"ICON-1260":{"nm":"香腸","de":"劃了刀口的地方咧開大嘴，啵地迸出肉汁。曾擔起便當一格的紅色章魚造型，是兒時午餐時光所享有的小小奢侈。"},"ICON-1261":{"nm":"義式臘腸","de":"圓圓的、辣辣的一片，在滾燙的起司上從邊緣捲了起來。微微積起一汪油，那便是一整片披薩的高潮——雖小，存在感卻圓潤而濃烈。"},"ICON-1262":{"nm":"肉排","de":"厚厚地捏成形放上烤盤，便從邊緣開始褐褐地熟了。在壓著煎好的一片之間夾上蔬菜，正好一手握住的踏實便完成了。"},"ICON-1263":{"nm":"雞蛋","de":"啵地一磕，蛋黃便像圓圓的太陽般滑了出來。拌進剛煮好的飯也好，化作飯捲裡那條黃線也好——是最常見因而最溫柔的蛋白質。"},"ICON-1264":{"nm":"牛奶","de":"凌晨擱在門前冰涼的一瓶，掌心觸到的那股清涼，常為一天揭開序幕。加熱便冒起熱氣，冰鎮則噴香——是隨時守在身旁的白。"},"ICON-1265":{"nm":"起司","de":"黃黃的一片在溫熱的麵包上慢慢塌軟。等候它拉長的那一瞬的心情——越是融化，那份噴香便越深越濃。"},"ICON-1266":{"nm":"切達起司","de":"濃濃的橙色，一眼就預告了鹹香的滋味。薄薄切片夾進吐司，鮮味便滿口擴散——顏色有多分明，風味便有多分明。"},"ICON-1267":{"nm":"奶油","de":"在燒熱的鍋裡丟下一塊，便酥酥融化，升起噴香的熱氣。抹在麵包上、拌進飯裡，碰到什麼都讓它更加柔順的黃色魔法。"},"ICON-1268":{"nm":"鮮奶油","de":"打蛋器轉得越久，原本稀薄的白便漸漸膨成緊實的雲。在蛋糕上舀一匙的瞬間，平凡的午後便像個小小的生日般明亮起來。"},"ICON-1269":{"nm":"優格","de":"湯匙一探，便滑順舀起的酸酸的白。拌進一塊水果，早晨便輕盈了起來，一杯下肚，腸胃也安穩地整頓好——是柔軟開端的味道。"},"ICON-1270":{"nm":"鯖魚","de":"放上烤網，油花啵啵跳濺，又腥又香的煙塞滿了廚房。挑去魚刺擱在飯上的那雙手——是尋常餐桌裡寄寓的最深的誠意。"},"ICON-1271":{"nm":"鮭魚","de":"粉紅色的紋理一層層疊著躺臥。冰涼地切來吃，在口中柔軟化開；烤了，油便滲出而噴香——是逆著遙遠海洋而來的結實滋味。"},"ICON-1272":{"nm":"鮪魚","de":"一掀開罐頭蓋，鹹香便呼地竄上來。拌進飯、用海苔包著吃的租屋夜晚，曾有一段一罐就成了踏實一餐的時光。"},"ICON-1273":{"nm":"鱈魚","de":"清淡的白肉，一煮，湯頭便先爽口地熬了出來。這熬過冬日港口刺骨寒風的白魚，一碗熱騰騰的湯，連發冷的手也慢慢暖了。"},"ICON-1274":{"nm":"蝦子","de":"把背圓圓地蜷起，一熟，灰色便染上紅暈。啵地爆開的彈勁與噴香，一隻隻剝著吃，不知不覺盤子就空了。"},"ICON-1275":{"nm":"螃蟹","de":"從堅硬的殼裡剔出雪白的肉，是一段小小的忍耐時光。那番功夫過後含進嘴裡的一口，甜絲絲的，秋天的海整個入了口。"},"ICON-1276":{"nm":"魷魚","de":"在烤盤上圓圓地蜷縮起來，升起噴香的氣味。彈牙的一片，蘸點醋辣醬放進嘴裡，鹹鹹的大海便跟了來。"},"ICON-1277":{"nm":"蛤蜊","de":"在清澈的湯裡張開嘴，悄悄獻出自己的香氣。咕嘟咕嘟滾沸的聲響裡漾開海的氣息，呼嚕一口，發冷的腸胃便暖暖鬆開。"},"ICON-1278":{"nm":"魚板","de":"連著竹籤泡進熱騰騰的湯裡，熱氣便裊裊升起。寒冷的日子在路邊攤前，用紙杯接著湯、呵呵吹著的那雙手——是巷子遞來的小小慰藉。"},"ICON-1279":{"nm":"泡菜","de":"在缸裡慢慢熟成，養出又酸又深的香氣。用手撕開擱在剛煮好的飯上就好，家家不同的味道，正是那一家的家史。"},"ICON-1280":{"nm":"醃蘿蔔","de":"黃黃的一片，喀嚓地在口中輕快碎開。守在一條飯捲、一盤麵食旁的死黨——酸酸甜甜把油膩的口腔清爽地漱淨。"},"ICON-1281":{"nm":"醃黃瓜","de":"黃瓜在鹽裡短暫斂了氣息，又在醋中睜開眼。生怕錯過脆勁回來的那一刻，玻璃瓶總不離有陽光的窗邊。慢慢醃漬的時光，把滋味帶了來。"},"ICON-1282":{"nm":"辣椒醬","de":"在缸裡熬過一年的紅。辣味的盡頭悄悄藏著黃豆的甜，化一匙進去，燉鍋才終於成了我家的面孔。是院子裡醬缸臺用陽光養出的深度。"},"ICON-1283":{"nm":"大醬","de":"豆麴擁著黴菌過了一整個冬天。那股醇香，是熟與爛之間驚險的走索——奶奶單憑指尖一嗅就辨出那條界線。等多久，便深多少的滋味。"},"ICON-1284":{"nm":"醬油","de":"黃豆越黑，內裡越深。一滴就讓野菜活了過來、讓滷味得了光澤，所以廚房所有的色彩，終究都從這溫暖的褐色開始。是鹹味之外的鮮。"},"ICON-1285":{"nm":"春醬","de":"同樣是黑，紋理卻不同。用焦糖再多炒一道的甜鹹尾韻，拌進麵裡，那烏黑的光澤便把胃口搖醒。是中華鑊氣開始的第一顆鈕扣。"},"ICON-1286":{"nm":"咖哩粉","de":"多種香料在一匙之中和睦交融的黃色粉末。化進水裡咕嘟咕嘟滾起，把整個家都暖了，便成了下雨傍晚最踏實一碗飯的預告片。"},"ICON-1287":{"nm":"胡椒","de":"整顆現磨香氣才活，預先磨好香氣便悄悄溜走。最後那一轉，總在熄火前一刻——是下廚的手珍惜地點下的小小句點。"},"ICON-1288":{"nm":"辣椒粉","de":"在秋陽下曬乾的太陽椒，這才完成那抹紅。細磨還是粗磨，泡菜的性格便由此分野，所謂手藝，終究來自挑選這粉末顆粒的功夫。"},"ICON-1289":{"nm":"鹽","de":"所謂調味，是朝著不足的那一邊一撮撮靠近。一旦放進的鹹味再也收不回，老練的手總在最後少放一點，嚐了味道再說。留下的那一分，便是餘裕。"},"ICON-1290":{"nm":"糖","de":"撫平苦味，磨圓酸味的稜角。然而甜味不該讓人察覺它的存在，所以越好的調味，糖越會在最後悄悄隱去蹤影。是懂得藏身的甜。"},"ICON-1291":{"nm":"蜂蜜","de":"蜜蜂在花田往返數千次採集而來的一瓶。凝固了就隔水溫熱回春，化進茶裡，便柔柔包覆喉嚨。是把一整季節整個熬煮起來的金黃一匙。"},"ICON-1292":{"nm":"食用油","de":"在燒熱的鍋裡繞上一圈，食材便忘了沾黏這回事。倒得太早會焦、太晚會黏，煙剛升起的那一拍，正是煎炸的正道。憑聲音掐準時機。"},"ICON-1293":{"nm":"橄欖油","de":"初榨的綠色裡，草香與一絲辛辣同住。比起上火，最後繞一圈淋上，那香氣才能撐到最後，不加熱反倒是最誠實的用法。"},"ICON-1294":{"nm":"香油","de":"最後啵地滴上一滴，野菜這才宣告完成。那股噴香有著在火上輕易溜走的性子，所以總在一切烹調結束後，悄悄添上的句點。"},"ICON-1295":{"nm":"香草莢","de":"剖開一根莢、刮下黑色的籽，甜點便以香氣換上了新衣。用完的莢也不丟，埋進糖裡——是甜點師傳承下來的古老勤儉。"},"ICON-1296":{"nm":"可可","de":"果實裡雪白的果肉與苦澀的籽。要歷經發酵與日曬風乾，才終於被翻譯成我們所知的甜美。在成為巧克力之前，它有著最接近野生的第一張臉。"},"ICON-1297":{"nm":"巧克力","de":"光憑掌心的溫度就酥酥融化的難搞性子。要在28度上下凝固，啪一聲折斷的光澤才活，所以甜美背後，意外藏著一條挑剔的溫度規則。"},"ICON-1298":{"nm":"咖啡豆","de":"研磨之前的一顆，近乎堅硬的沉默。然而一遇熱水便鼓鼓膨脹、吐出香氣，所以喚醒早晨的第一聲信號，總是從這小小一顆開始。"},"ICON-1299":{"nm":"茶葉","de":"在熱水裡待得太久會澀，太短則寡淡。靜靜揣度葉子慢慢舒展的時間——所謂泡茶，便是用指尖丈量等待這回事。"},"ICON-1300":{"nm":"薄荷","de":"一揉碎便滲出苦味，所以總得輕手呵護的嬌嫩葉子。輕輕一拍喚醒沉睡的香氣，酷熱的日子漂進玻璃杯，盛夏便清涼地沉降了一個音階。"},"ICON-1301":{"nm":"香草","de":"連莖一起放，香氣深；只用葉子，則清。曬乾了濃，生著用便清新，一束所懷的香氣有多寬，廚房的表情便跟著拓展多寬。"},"ICON-1302":{"nm":"栗子","de":"帶刺的殼裡藏著油亮的果肉。劃上刀口烤一烤，啵地裂開散出甜香，寒風吹過的巷裡，那袋糖炒栗子的暖意彷彿握得到。"},"ICON-1303":{"nm":"花生","de":"噴香要在炒的火上完成。一顆顆剝著吃，會讓人忘了時間流逝的小小果仁——圍坐在木地板上分著吃，連故事也悄悄一同剝了出來。"},"ICON-1304":{"nm":"杏仁","de":"稍微汆燙剝去皮，內裡便更白更柔。搗碎磨開像牛奶，整顆烤過則酥脆——一顆所懷的變身幅度，把糕點師的想像盡情拓寬。"},"ICON-1305":{"nm":"芝麻","de":"在小火上輕輕晃著，某一刻便啵啵跳了起來。那聲響快停的前一刻最是噴香——炒芝麻這件事，終究成了用耳朵聽的活兒。"},"ICON-1306":{"nm":"甘蔗","de":"咬一節，草香與甜汁一同滲出。要熬了又熬才成為我們所知的甜的莖——糖的開端，意外地竟是這般青翠而高挑。"},"ICON-1307":{"nm":"原蔗糖","de":"少經提煉、原原本本保留自身色澤的粗獷甜味。隱隱殘留著一抹土香的深度，所以喜歡那份未經細修之坦率的手，會特意去尋它。"},"ICON-1308":{"nm":"可可豆","de":"剛從豆莢取出的籽又苦又澀。要默默熬過發酵的幾天，香氣才綻放，所以甜美，是這顆豆久久忍耐之後接過的一份小小獎賞。"},"ICON-1309":{"nm":"可可碎粒","de":"把炒過的豆細細搗碎的碎塊，連一粒糖也沒有。放進嘴裡，苦味先到，噴香遲遲跟上，所以這是最誠實地遇見甜味之前的可可。"},"ICON-1310":{"nm":"咖啡生豆","de":"還泛著青澀的綠色顆粒。就這樣，香氣仍熟睡著，在接受火的洗禮之前，它靜靜留作一份連自己會成為什麼都未知的可能。"},"ICON-1311":{"nm":"烘焙咖啡豆","de":"微微滲出油的褐色表面，蓄滿了香氣。要趁未涼前研磨，那香氣才完整，所以一杯的命運，在烘焙之後的幾天內悄悄定下。"},"ICON-1312":{"nm":"香草莢","de":"一根香莢便把整鍋牛奶通通染上香氣。連用完的莢插進糖罐，幾天後整罐糖都芬芳了起來，是連一處可丟之地都沒有的奢侈。"},"ICON-1313":{"nm":"胡椒","de":"一顆整粒胡椒的香氣，從研磨的瞬間起便開始減損。所以才整顆擱在餐桌上、隨吃隨磨——所謂新鮮，是從不拖延的心裡綻放出來的。"},"ICON-1314":{"nm":"白胡椒","de":"剝去皮、變得更光滑的顆粒，比起辣，更顯隱約。它生於不願在白醬上留下一個黑點的體貼，是隱於不顯眼之處的細膩。"},"ICON-1315":{"nm":"肉桂","de":"沖泡一片，茶裡便慢慢漾開溫暖的辛辣。比起磨粉，整片放入香氣才持久，所以冬日飲品的深度，來自這曬乾樹皮的韌性。"},"ICON-1316":{"nm":"丁香","de":"長得像顆小釘子的花苞，凝縮著滿滿香氣。放太多會把整道菜整個吞沒，所以僅僅一顆的節制，靜靜守住風味的平衡。"},"ICON-1317":{"nm":"肉荳蔻","de":"把整顆籽留著、隨吃隨磨一點來用。預先磨好香氣便很快散去的性子，所以最後刮一下的那道手勢，讓牛奶的香氣更深一層。"},"ICON-1318":{"nm":"小荳蔻","de":"啵地捏破綠色的莢，裡頭便傾瀉出清涼的香氣。只往茶裡搗進一兩顆，平凡的一杯便忽然得了遙遠國度的芬芳。"},"ICON-1319":{"nm":"番紅花","de":"一朵花才收得三根的紅絲。化進溫水，黃色的光便慢慢漾開，所以珍貴，也是用手一根根挑出之時光的重量。"},"ICON-1320":{"nm":"薑黃","de":"把土裡的根一磨，連指尖都染成了黃。要下油稍微炒過香氣才醒的性子，所以咖哩的金黃，是這小小的根在火上綻出的色彩。"},"ICON-1321":{"nm":"月桂葉","de":"據說曾擱在勝者額頭上的葉子。往滾水裡漂一片，熱氣間便短暫升起昔日競技場的吶喊。即使未曾贏得的日子，吸一口那香氣，也成了靜靜擁抱今日之你的青翠慰藉。"},"ICON-1322":{"nm":"椰奶","de":"要敲破堅硬的殼才終於流出的白色汁液。在炎熱國度的市場一角，插一根吸管啜一口，正午的乾渴便整個消解。滿口擴散的清涼甜香，帶來了熱帶的綠蔭。"},"ICON-1323":{"nm":"椰子油","de":"凝固了像初雪般白，在掌心一暖香氣便緩緩漾開。說一罐就足以從頭到腳，島上奶奶遞來的那份溫柔持家智慧，原原本本盛在圓圓的罐裡。"},"ICON-1324":{"nm":"香蕉乾","de":"在陽光下晾上幾天，黃黃的果肉便Q軟了起來。一片片省著咬，那下雨收穫季黏黏的甜香，便在口中悄悄復甦。慢慢熟成的甜味，就這樣懷抱起季節。"},"ICON-1325":{"nm":"芒果乾","de":"軟嫩的果肉在陽光下濃縮，重生為琥珀色的果凍。酸、甜、Q彈三種滋味全在一片裡，含在口中慢慢打轉，一袋便把午後拉長了。"},"ICON-1326":{"nm":"鳳梨乾","de":"與帶刺的外貌不同，內裡的果肉黃得無比明亮。曬乾後酸味濃縮，只咬一片，嘴角便不由自主揚起。一片過後殘留的清爽餘韻，久久不散。"},"ICON-1327":{"nm":"熱帶水果籃","de":"剛採來的各種色彩在一籃裡交融。芒果的橙、香蕉的黃、鳳梨的金黃——還沒伸手挑選，夏天便先從鼻尖湧了上來。光是看著心情就明亮起來的一大抱。"},"ICON-1328":{"nm":"海藻包","de":"從退潮岩礁上採來的、海的頭髮。鹹鹹的潮味裡纏著浪聲，靜靜泡進冷水，腥腥的海香便慢慢湧進廚房。一把便在餐桌上鋪開一小片灘塗。"},"ICON-1329":{"nm":"海產乾貨","de":"一把曬得乾硬的大海。用手順著紋理撕開，鹹味便連同昔日港口鹹鹹的風一同鬆了開來。是會教人不由自主想起一碗馬格利酒、情誼深厚的餐桌旁的老友。"},"ICON-1330":{"nm":"魷魚乾","de":"把十條腿整整齊齊攤開曬乾。在火上稍微一烤、噴香一升，便順著紋理撕開。憑那彈牙的滋味，深夜一盤宵夜的格調便上了一個檔次。"},"ICON-1331":{"nm":"鹽漬魚","de":"埋進粗鹽裡，魚便學會了熬過時間的方法。一片鹹味深厚的肉，便讓一碗飯轉眼見了底，是海邊奶奶用指尖傳下的溫柔祕方。"},"ICON-1332":{"nm":"蝦醬","de":"小小的蝦在鹽中慢慢熟成，重生為鮮味。醃泡菜時往白菜餡裡放一匙的瞬間，那漾遍整個院子的鹹香。那一匙，分出了一年泡菜的味道。"},"ICON-1333":{"nm":"鯷魚","de":"手指般大的身軀，擔起一鍋湯頭的深度。摘著頭與內臟、絮絮叨叨聊天的兒時廚房，雖小卻穩穩站在持家正中央的、教人感激的魚。"},"ICON-1334":{"nm":"昆布","de":"在海底長長生長的黑色帶子。放進冷水、在快沸騰前輕輕撈起，是熬湯的手代代相傳的約定。深厚的鮮味，從不懂得急躁。"},"ICON-1335":{"nm":"羊栖菜","de":"凹凸的口感在嘴裡啵啵爆開。春天時把岩礁染成一片綠的海藻，隨手一拌，餐桌一角便鋪開一小片清新的海。是咀嚼春天的滋味。"},"ICON-1336":{"nm":"珍珠貝","de":"在堅硬的兩瓣之間久久懷抱、孕育出的圓圓的光。把一粒沙的不適化作寶石，這一路上，大海從未催促過一次。擱在掌心，那漫長忍耐的重量便一同擱了上來。"},"ICON-1337":{"nm":"珊瑚擺飾","de":"浪花打磨了數百年的、大海的樹枝。陽光一觸便漾成粉紅與橙，只是靜靜擱在架上，一整個房間便染成了溫暖的島。連觸到指尖的粗糙紋理都教人親切。"},"ICON-1338":{"nm":"貝殼鈕扣","de":"貝肉離去之處，把晶瑩的內裡圓圓地剜了下來。綴在衣襟上，每次扣起，指尖便閃起一道小小的彩虹。是傾盡所有獻出、離去之時大海留下的、最後一份溫柔禮物。"},"ICON-1339":{"nm":"玻璃珠","de":"在掌心一滾，囚於其中的光便骨碌骨碌跟著滾來。在巷裡蹲著、忘了日頭西沉玩著彈珠的那個年代，多贏一顆的孩子，口袋格外沉甸甸而得意。"},"ICON-1340":{"nm":"香木片","de":"削下的每一道紋理間都滲出隱隱的香。古人焚燒這木頭，整頓散亂的心。靜靜握著一片，平靜便從指尖開始慢慢漲了起來。"},"ICON-1341":{"nm":"香","de":"細細的一柱緩緩燃起，向上闢出一條路。用眼追著煙描畫的曲線，整日匆忙的心也不知不覺放慢腳步，靜靜停在那裡。"},"ICON-1342":{"nm":"染料花","de":"把藏在花瓣裡的色彩化進滾鍋，潔淨的布便漸漸染上那色。是暫時借來自然預先塗好的光——所謂染色，本是向花獻上的一聲溫柔問候。"},"ICON-1343":{"nm":"靛藍染料","de":"把藍草發酵了又發酵而得的、深邃幽遠的藍。每浸一次再取出，布便從天空色慢慢挪向海洋色。是要放下急躁，才終於綻放的、等待的顏色。"},"ICON-1344":{"nm":"赤紅染料","de":"把茜草根熬出來，沉睡在土裡的晚霞便在鍋中甦醒。曾把喜宴日新娘裙襬秀美染上的、村裡最喜慶最明亮的色彩。"},"ICON-1345":{"nm":"金線","de":"把比髮絲還細的金抽出來，一縷一縷用心紡成。刺繡之處都含著光，連熄了燈的暗房裡，唯有那紋樣兀自隱隱明亮地浮現。"},"ICON-1346":{"nm":"綢緞","de":"把蠶吐出的絲織了又織，才勉強成為一幅。拂過手背像春水般滑溜的觸感，是古人把一整個季節整個懷抱、慢慢養出的細緻的布。"},"ICON-1347":{"nm":"珍珠鈕扣","de":"只挑珍珠的內裡光澤，圓圓地修整而成。在上衣衣襟一顆顆扣起時，指尖便短暫優雅了起來。雖小，卻悄悄抬起衣著格調的、端正的一顆。"},"ICON-1348":{"nm":"航海圖殘片","de":"撕裂的邊緣之外，未知的海岸線戛然中斷。據說唯有湊齊其餘殘片的人才能觸及寶藏旁——或許隨風尋它而漂泊的旅程本身，早已是寶藏了也說不定。"},"ICON-1349":{"nm":"陳舊海圖","de":"被海水暈開的航路與褪色的羅盤圖。用指尖追著某個船員在漆黑夜裡只憑星辰劃下的線，一座早已消失的島，便在陳舊的紙上再次慢慢浮現。"},"ICON-1350":{"nm":"瓶中信","de":"被浪推送而來的玻璃瓶裡，捲成一捲的一張紙。不知是誰、何時放流的問候，終於觸到了某人的手。大海只要有心，也能成為這般緩慢的郵差。"},"ICON-1351":{"nm":"漂流寶箱","de":"在鹹水中泡得發脹、難以開啟的箱蓋，掀開的那一刻之前都還算是冒險。無論裡頭裝的是寶物還是空沙，遠道漂來的箱子總會連同某個素未謀面之人的故事，一起被浪沖到岸邊。"},"ICON-1352":{"nm":"小鑰匙","de":"正好能握進手心的一小片舊鐵。即使早已忘了它能開哪扇門，那份沉甸甸的溫柔重量仍留在指尖，讓人先想起如何打開，而非如何上鎖。"},"ICON-1353":{"nm":"銀幣","de":"被手摩挲得花紋已模糊的圓銀。這一枚曾是某人的船資，也曾換來一夜疲憊的安眠。撫過那冰冷的表面，許久以前一場交易的餘溫，便隱約在指尖復甦。"},"ICON-1354":{"nm":"金幣","de":"放在掌心，那沉甸甸的重量便先撼動了心。映著陽光泛出金黃的一枚，彷彿擁有它便能成為富翁——但其實最耀眼的，是握進手中前的那陣心跳。"},"ICON-1355":{"nm":"船長印章","de":"曾用力按壓在紅蠟上的船長之約。一枚印記便立下命令、定下險惡的航線。所謂權威，終究是同船之人一起選擇相信的，那一枚小而堅實的印章。"},"ICON-1356":{"nm":"手握麥克風","de":"握進手中的瞬間，一股莫名踏實的重量便填滿了掌心。無論是顫抖著道出第一聲問候時，還是終於飆上高音的那一刻——這根小小的棒子，都會悄悄為你的嗓音添上翅膀。"},"ICON-1357":{"nm":"無線麥克風","de":"少了那條線，整個舞台便豁然開闊。即使奔到觀眾席的最末端，嗓音也一次都不曾中斷，彷彿有人正悄悄推著你的背，要你盡情奔跑歌唱。"},"ICON-1358":{"nm":"立式麥克風","de":"牢牢立在腳邊，默默等候歌者。當雙手得以自由，歌聲便不再只由指尖、而是以整個身體蔓延開來。這根棒子靜靜訴說著——堅守一處到底，也自有一番風采。"},"ICON-1359":{"nm":"防噴罩","de":"在麥克風前圓圓擋住的一層薄布。將粗重的氣息柔柔濾去，只讓清亮的嗓音通過。所謂讓人聽得清楚，便是在始終看不見的位置默默替人遮擋。"},"ICON-1360":{"nm":"入耳式監聽","de":"塞進耳中，自己的歌聲便在數萬人的吶喊之上重新變得清晰。在光與聲都傾瀉而下的舞台上，緊緊抓住節拍不讓你漏掉——那是最小、也最隱密的同行者。"},"ICON-1361":{"nm":"耳機","de":"覆上雙耳的瞬間，世界縮小了一寸，唯有歌聲被放得很大。一間誰也無法闖入的圓形房間。在獨自戴上的耳機裡，奇妙的是，你並不孤單。"},"ICON-1362":{"nm":"樂譜","de":"當黑色的小點靜靜落在線上，原本沉默的紙便含住了聲音。這是用來聽、而非用來讀的文字。攤開的那一刻，停駐的歌便又重新呼吸起來。"},"ICON-1363":{"nm":"聲樂譜","de":"在每個該換氣的地方畫上小小的圓圈。在這裡吸氣，在那裡靜靜放開。這是一張溫柔的地圖，替你開出一條不讓嗓子受傷的路。"},"ICON-1364":{"nm":"鋼琴譜","de":"十根手指同時在這一頁問路。左手按住根基，右手描繪旋律。原本各說各話的兩隻手，終於在最後一小節合而為一。"},"ICON-1365":{"nm":"吉他和弦表","de":"手指最初學的外語，那第一個單字就寫在這裡。六個點聚成一個圓，一個音才終於鳴響。在一夜又一夜的反覆按壓中，指尖長出了厚繭。"},"ICON-1366":{"nm":"節拍器","de":"嗒、嗒——一道毫不動搖的腳步在身旁敲響。當心急著往前衝時，它便在背後慢慢地、慢慢地拉住你。因為所謂節拍，終究是一句「一起走吧」的約定。"},"ICON-1367":{"nm":"調音器","de":"當指針滑向正中央，音才終於找回自己的位置。不高也不低的那一點。原來所謂準確，便是這樣不再顫抖、靜靜停下。"},"ICON-1368":{"nm":"鋼琴鍵盤卡","de":"每翻過一張，琴鍵便走進掌心。從Do到Si，七格的小宇宙。即使在沒有真鋼琴的夜裡，歌也能在這裡靜靜生長。"},"ICON-1369":{"nm":"吉他撥片","de":"夾在拇指與食指間的、小而堅硬的一片。一旦掉落便會在椅子底下永遠消失蹤影，但握在手中的瞬間，六根弦便一齊鳴響開來。"},"ICON-1370":{"nm":"鼓棒","de":"兩根在空中相碰，信號便落在那一處。一、二、三、四。原本各自散落的眾人心跳，便隨著那四拍開始以相同的速度跳動。"},"ICON-1371":{"nm":"鈴鼓","de":"敲一下，清亮的聲音便如陽光細碎四散。看似輕巧，卻是興致漸冷時最先想伸手去拿的那一拍。誰也不敢因它小巧而輕視它。"},"ICON-1372":{"nm":"舞蹈運動鞋","de":"對於如滑行般旋轉的雙腳而言，摩擦力便是武器。每一道磨損的鞋底，都刻著一圈又一圈的旋轉。最帥氣的動作，總是始於一雙堅實的鞋。"},"ICON-1373":{"nm":"護膝","de":"唯有無數次跪下又重新站起的人才懂得，這一層薄布的可貴。讓地板不再令人畏懼——勇氣有時就這樣，纏繞在膝蓋上。"},"ICON-1374":{"nm":"護腕","de":"預先護住容易彎折的部位，再勉強的動作也會變得寬容些。手腕無言，總是默默忍到痛了才作聲。那長久的沉默，由這一層替它擋下。"},"ICON-1375":{"nm":"護踝","de":"高高躍起的盡頭是落地，而落地的盡頭是腳踝。在最低的位置承接全身重量之處。這條小小的帶子，靜靜守護著明天的練習。"},"ICON-1376":{"nm":"伸展彈力帶","de":"拉多遠，它便用多大的力氣想彈回原位。在承受那份阻力的同時，身體也在不知不覺間一點點變長。所謂伸展，終究是堅持過的時間留下的痕跡。"},"ICON-1377":{"nm":"瑜珈墊","de":"攤開的瞬間，地板上便有了屬於我一人份的土地。一塊可以趴下、躺臥、調勻呼吸的小小領土。一天的開始與結束，都在這一張墊子上靜靜收尾。"},"ICON-1378":{"nm":"滾筒","de":"輕輕按壓糾結的部位，起先會痛，隨即便覺舒暢。鬆開僵硬之物的過程，總得伴隨些許疼痛。畢竟無論身體還是心，想要鬆開，都得先按壓一回。"},"ICON-1379":{"nm":"啞鈴","de":"舉起同樣的重量，一次又一次。只比昨天多舉一下，如此而已。在毫無花俏的反覆之中，手臂默默變得粗壯。一塊只懂得誠實的鐵。"},"ICON-1380":{"nm":"壺鈴","de":"一個握把，便牽動整個身體。當圓潤的重量畫圓旋轉時，撐持者的平衡便被擺上考驗台。想要不晃動，得先認清自己的重心。"},"ICON-1381":{"nm":"跳繩","de":"越過從腳下嗖地掠過的一條繩，再越過一次。就像在院子裡與玩伴一起數著數的那個遊戲，數字越堆越高，氣息越喘，笑聲也越多。"},"ICON-1382":{"nm":"跑鞋","de":"唯有踏上路面，才懂得這雙鞋的真正價值。劃破清晨的空氣，又一次跑過同一條路，昨日還遠的那個轉角，今天已近在眼前。距離，由雙腳記住。"},"ICON-1383":{"nm":"運動毛巾","de":"擦去額上的汗水後，那裡便沁著今日努力的一道痕跡。洗過後痕跡雖會消失，但流過多少汗，便會在某處一點一點累積。最誠實的應援，總在身旁晾乾。"},"ICON-1384":{"nm":"水瓶","de":"空了便添滿，渴了便喝一口。那單純的往返默默撐起一整天。就像井邊的吊桶上上下下，新的一天又從「裝滿」這件事開始。"},"ICON-1385":{"nm":"蛋白飲","de":"搖勻後嚥下一口，今日耗損的肌肉便在明天重新充盈。雖不是什麼華麗的滋味，身體卻明白，這是恢復的語言。成長，總是被靜靜喝下。"},"ICON-1386":{"nm":"能量棒","de":"在口袋裡被壓得扁扁的一條。在這一餐與下一餐之間，填補空白時間的應急糧。雖不算氣派，這小小的一口卻能讓你在午後多撐住一個動作。"},"ICON-1387":{"nm":"潤喉糖","de":"含在口中滾動，沁涼的薄荷便悄悄撫過粗啞的喉嚨。在說了許多話的日子、唱了許多歌的夜晚——一顆小小的糖球，安撫著那條乾澀的路。原來甜，也自有其用處。"},"ICON-1388":{"nm":"護嗓茶","de":"暖暖的蒸氣熱了喉嚨，一口下肚，肩頭的緊張便緩緩鬆開。如同奶奶煮的那碗薑茶，是一帖古老的藥方。是歌唱之前，向嗓音道的一聲溫柔問候。"},"ICON-1389":{"nm":"蜂蜜水","de":"在微溫的水裡慢慢化開一匙蜂蜜。每當喉嚨乾啞時，長輩們總會替你沖上的那一杯。不是藥也不是飲料，只是一份從體內靜靜撫慰著身體的甜。"},"ICON-1390":{"nm":"加濕器水箱","de":"在房裡釋放出小小薄霧的容器。在乾燥空氣抓傷喉嚨的冬夜，悄無聲息地分送濕潤。照料一個人這件事，多半就這樣無聲地流淌著。"},"ICON-1391":{"nm":"休息券","de":"一張寫著「可以休息了」的紙。接過手中的瞬間，心上的重擔便輕了一格。停下來也是一種練習——這張小小的票，替你開了這份許可。"},"ICON-1392":{"nm":"練習行程表","de":"在一格格寫著時間的欄位上，一天層層落定。早上發聲，下午編舞，晚上休息。原本茫然的明天，劃上線分一分，竟也變得可以走走看了。"},"ICON-1393":{"nm":"出席印章","de":"用力按下一個「今天也來了」的記號。隨著墨水微微暈開的圓圈在每一格裡漸漸增多，原本不算什麼的勤勉，不知不覺已成了一條路。每日的小小證據。"},"ICON-1394":{"nm":"稱讚貼紙","de":"不必說出「做得好」，只是靜靜貼上一顆星。明明只是指甲大小的閃亮，落在筆記本一角的瞬間，整個一天便明亮起來。稱讚雖小，卻奇妙地閃耀許久。"},"ICON-1395":{"nm":"心靈筆記","de":"把舞台後方那顆顫抖的心，化為文字寫下的一頁。連不順遂的日子也誠實記下，心便會在某處輕鬆許多。心，看得越深，便越堅韌。"},"ICON-1396":{"nm":"意象訓練卡","de":"閉上眼握在手中，腦海裡便靜靜展開一座舞台。在尚未真正站上的位置先繞行一圈。用想像描繪的走位，會比真正的腳尖早一步抵達。"},"ICON-1397":{"nm":"表情練習鏡","de":"在鏡前笑開又收緊，同一張臉做上百遍也不止。在這裡學會，喜悅與悲傷都需要練習。因為所謂表情，便是把心境向外謄寫出來這件事。"},"ICON-1398":{"nm":"編舞筆記","de":"把腳與手將要行經的路，以圖畫謄寫下來的一頁。每八拍身體該往哪去，箭頭都靜靜指點。再怎麼也記不住的動作，也在這頁上慢慢馴熟。"},"ICON-1399":{"nm":"編舞影片晶片","de":"一片小小的晶片，原原本本裝下了上百次的動作。入睡前再回放一次，指尖便會自然順著那條路移動。反覆，是用身體謄寫的另一種記錄。"},"ICON-1400":{"nm":"舞台走位表","de":"從高處俯瞰舞台的一張地圖。誰在哪裡會合、又往哪裡散開，都以線與點預先約定好了。眾人若要共繪一幅圖，得先把路分配清楚。"},"ICON-1401":{"nm":"彩排通行證","de":"觀眾席空蕩，燈光仍在沉睡。這一張通行證，將你放進那片靜謐之中。無人觀看時的舞台——所以最誠實的你，便從這裡開始與自己相見。"},"ICON-1402":{"nm":"穿搭手冊","de":"今天要懷著什麼心情穿衣呢。連一件襯衫也有與之相配的心境，這本書靜靜告訴你。書頁翻得越多，曾在鏡前猶豫的指尖，便一點點累積起一份小小的眼光。"},"ICON-1403":{"nm":"定型噴霧","de":"嘶地噴一下，連風也無法隨意吹亂。那是想將舞台上短短幾分鐘穩穩抓住、不留破綻的小小私心。完美的瞬間，總是建立在這般細微的固執之上。"},"ICON-1404":{"nm":"彩妝盤","de":"十二格的顏色，便是十二種心情。今天要以哪種神情歌唱，指尖先選，心隨後跟上。每一格漸漸見底，都靜靜沾著那些留在舞台上的日子。"},"ICON-1405":{"nm":"服裝別針","de":"在最華麗的瞬間，反而有一枚看不見的小別針在暗處固定著布料。不讓它滑落，不讓它凌亂。舞台上的耀眼，總是踩在某人的堅實之上。"},"ICON-1406":{"nm":"名牌板","de":"當原本空白的板子被填上名字，原本模糊的一個約定便清晰起來。誰將站上這個位置——由一行字決定。所謂名字，是最短也最堅定的誓言。"},"ICON-1407":{"nm":"粉絲服務卡","de":"收信的人只有一位，而對那一人而言便是整個世界。在短短一句問候裡，把幾夜的感謝用力按進去。心，即使在掌心大的紙上，也能這般滿溢而出。"},"ICON-1408":{"nm":"簽名練習紙","de":"起初連自己的名字都寫得生疏。在劃過上百次、修了上千遍的清晨，直到手比心更早記住那道筆勢。一個名字，就這樣終於成了簽名。"},"ICON-1409":{"nm":"訪談題卡","de":"「這個問題該怎麼答呢。」握著紙的指尖微微發顫。這不是背答案，而是把真心依序排好的時間——面試也好，告白也罷，終究都是在叩問內心的順序。"},"ICON-1410":{"nm":"外語單字本","de":"磨損得最厲害的那一角，告訴你看得最久的是哪個單字。一個陌生的發音黏上嘴所需的時間，與那個從未去過的世界之間的距離，便一寸寸拉近。"},"ICON-1411":{"nm":"發音矯正卡","de":"翻滾的「ㄹ」，漏氣的「ㅅ」。有一個個翻著卡片、馴服舌頭的清晨。話語變得越清晰，想用那句話觸及的某人的臉龐，也越清晰。"},"ICON-1412":{"nm":"現場演出檢查表","de":"麥克風開啟、入耳確認、走位檢查。每填上一格方框，胸中的不安便空出一格。登上舞台前，細心便是最安靜的勇氣。"},"ICON-1413":{"nm":"舒緩貼","de":"貼上的瞬間，便有一處溫暖地暈染開來。過度操勞的肩膀、僵硬的小腿——這是掌心大小的慰藉，靜靜回應著身體發出的小小訊號。好好休息，也是練習的一部分。"},"ICON-1414":{"nm":"冰敷袋","de":"靜靜敷在腫起的腳踝上。在冰涼緩緩滲入的過程中，才終於明白今天究竟奔跑了多少。舞台幕後的恢復，總是這樣無聲地到來。"},"ICON-1415":{"nm":"急救包","de":"OK繃、止痛藥、小手鏡。裝滿這些不起眼之物的小袋子，總會在某一刻變得最為可靠。預先備好的那份體貼，在意料之外的危機前最為耀眼。"},"ICON-1416":{"nm":"提詞卡","de":"鏡頭之外，有人悄悄將它舉起。差點忘掉的那一句話，工整地寫在上頭。在流暢無礙的進行背後，總有這樣一隻不被畫面拍進的手。"},"ICON-1417":{"nm":"任務信封","de":"撕開信封的前一刻最是心跳。無論裡頭裝著什麼，在尚未得知的那短短間隙裡盡是期待。綜藝的妙趣，便完整地活在那封緘的一瞬之中。"},"ICON-1418":{"nm":"名牌","de":"貼在胸前的一個小小名字，代替了初次的問候。在彼此還不相識的人們之間，一枚名牌「啪」地打破了尷尬的堅冰。從喚出名字的那一刻起，關係便開始了。"},"ICON-1419":{"nm":"懲罰貼紙","de":"「啪」地貼上輸家額頭的一張，引得哄堂大笑。說是懲罰卻太過親暱，連輸了也成了日後反覆回味的回憶。這是為了一起歡笑而做的、小而溫馨的記號。"},"ICON-1420":{"nm":"隨機懲罰卡","de":"抽出之前誰也不知道。是大象鼻轉十圈，還是賣萌一次。把命運整個託付給一張紙的瞬間，反倒是笑點先「噗哧」鬆了開來。"},"ICON-1421":{"nm":"提示卡","de":"像是在卡住的時候悄悄遞來的一隻手。它不會給你全部的答案，卻會指出路。所謂好的提示，不是正確答案，而是靜靜遞上「再想一次」的勇氣。"},"ICON-1422":{"nm":"機會卡","de":"能將傾斜的局面一舉翻轉的唯一一次機會。何時亮出這張卡，便決定了勝負。捨不得用而珍藏到底的幸運，唯有在最關鍵的一刻才終於發揮真正的價值。"},"ICON-1423":{"nm":"暫停卡","de":"「暫時停一下也沒關係」，這張卡替你這麼說。在需要喘口氣時堂堂正正舉起手——停頓也是一種正當的戰略，好好休息同樣是實力的一環。"},"ICON-1424":{"nm":"笑聲按鈕","de":"「啪」地一按，便傾瀉出滿滿一片咯咯的爽朗笑聲。真正好笑的場面，連這種音效也會悄悄來幫襯。一場聚會的暖意，便從這樣一個小小的玩笑裡升溫。"},"ICON-1425":{"nm":"音效遙控器","de":"一個按鈕是掌聲，另一個是噓聲。一位只憑指尖便能塑造氣氛的魔法師，靜靜坐在控制室裡。不被畫面拍進的幕後操作，讓那一幕活了過來、有了呼吸。"},"ICON-1426":{"nm":"場記板","de":"「啪」地一聲清脆，一個鏡頭便開始了。在數十次的NG與唯一一次的OK之間，這塊黑板工整地替每一個瞬間數著數。那是記錄踏出的第一拍。"},"ICON-1427":{"nm":"定位膠帶","de":"當腳尖靜靜觸到那條線的瞬間，燈光便彷彿等候已久般輕巧地落下。那是背得滾瓜爛熟的唯一一格——舞台，便由地板上劃出的一小條色帶終於成形。"},"ICON-1428":{"nm":"燈光濾片","de":"同一張臉，也會因光的顏色而徹底改變。藍色濾片裡棲著黎明，紅色濾片裡棲著晚霞。氣氛從不遙遠——它就靜靜摺疊在一張薄薄的色紙裡。"},"ICON-1429":{"nm":"相機電池","de":"紅燈一開始閃爍，心便先急了起來。因為偏偏最好的畫面總在電量剩1%時到來。口袋裡的一顆備用，便成了能鬆一口氣的安心。"},"ICON-1430":{"nm":"記憶卡","de":"一整天的笑容與汗水，密密麻麻裝進指甲大小的晶片裡。它小到容易遺失，卻也因此格外珍貴。所懷抱的回憶之重，從來無法以大小衡量。"},"ICON-1431":{"nm":"拍立得底片","de":"「喀嚓」，然後是靜靜的等待。在原本一片白的相面上，臉龐緩緩浮現的那幾秒，奇妙地令人心動。即使是握在手中的即時照片，也必定要加上一匙耐心。"},"ICON-1432":{"nm":"小卡底片","de":"這一張上會印出什麼表情，在印刷出來的前一刻都是祕密。某人的本命的臉龐，便在這裡誕生。一張小小的紙，竟能容下那般巨大的心意。"},"ICON-1433":{"nm":"小卡保護套","de":"小卡是不會徒手去碰的。畢竟邊角一旦被壓到，連那天的笑容都會跟著刺痛。用一張透明把本命好好包覆——珍惜，也得花上這般心思。"},"ICON-1434":{"nm":"硬卡夾","de":"夾進兩張硬挺之間，連時間也無法隨意將它揉皺。要它別彎，要它別摺。守護某樣珍貴之物這件事，總是要借來一層堅硬。"},"ICON-1435":{"nm":"貼紙包","de":"一張張撕下，「啪」地貼在手帳邊角、筆電背面。一個小小的圖案，便讓原本無彩的一天染上繽紛。想要妝點身旁的這份心，沒有年齡之分。"},"ICON-1436":{"nm":"簽字筆","de":"墨水沙沙拂過紙面的聲響裡，隊伍漸漸排得越來越長。在以怦然之手遞出的專輯上，短短幾秒的相遇卻長久留存。心意，順著筆尖渡了過去。"},"ICON-1437":{"nm":"簽名專輯","de":"翻開封面，那熟悉曲線的簽名便先打了聲招呼。因音樂結緣的關係，在紙上又拉近了一寸。所謂珍藏，便是把那個瞬間靜靜停駐下來。"},"ICON-1438":{"nm":"應援棒電池","de":"「快亮起來啊，拜託。」入場前換電池的手忙個不停。為了讓數萬道光中屬於我的這一道不要熄滅——一顆小小的電池，照亮了那片巨大的夜。"},"ICON-1439":{"nm":"應援棒收納袋","de":"毫無刮痕地細細收好，妥妥珍藏到下一夜的吶喊。即使那片熱烈早已冷卻，也珍而重之地裝起、帶回家。應援的道具也有它的歸處，而珍惜那歸處的，是一份心意。"},"ICON-1440":{"nm":"應援橫幅","de":"寫在長布上的句子橫越觀眾席展開。那難以說出口的應援豁然張開的瞬間，一個人的真心便成了所有人的吶喊。那塊布，原原本本成了一道嗓音。"},"ICON-1441":{"nm":"迷你旗幟","de":"正好握進掌心的小小應援。遠遠掛起的橫幅是眾人的，而這一面只在你的桌角飄揚。雖然尺寸小，心意卻絕不會小，它靜靜搖曳著證明這一點。"},"ICON-1442":{"nm":"粉絲信","de":"收信人的名字改寫了三次，第一句話塗掉了七遍。封上信封前指尖會發顫，是因為心意太過誠實。比一張郵票更沉重的真心，就摺疊在那裡頭。"},"ICON-1443":{"nm":"禮物包裝紙","de":"拆開前那一秒最是心動，這一點包裝紙比誰都明白。明知自己即將被撕開，卻仍如遞禮之人的心意一般，以最美的紋理裹住身軀。"},"ICON-1444":{"nm":"緞帶","de":"綁太緊便覺憋悶，太鬆又會散開，找到那恰好之間，便是用心。指尖選定的一個結，盛著心意的形狀。禮物的最後一行，總由緞帶替人寫就。"},"ICON-1445":{"nm":"感謝卡","de":"用口說出的謝意會隨風散去，以手寫下卻能長久停留。在收到的溫柔上再添一些回送出去。一字一字用力寫下的同時，心意也加深了兩倍。"},"ICON-1446":{"nm":"便當券","de":"這一張紙，便讓午餐的煩惱悄然化解。剛煮好的飯熱氣騰騰，一格格盛滿配菜的一餐已有了約定。是守護飢餓午後、讓人安心的小小護身符。"},"ICON-1447":{"nm":"點心券","de":"它生來就是要在下午三點、肚子悄悄發出訊號時拿出來用的。它懂得，一份小小的甜食能讓心情上揚半寸。雖不是什麼大獎賞，卻總在最需要的時刻悄悄送達。"},"ICON-1448":{"nm":"咖啡券","de":"一杯熱飲，加上一個靠窗的座位，這張券所承諾的就是這些。看似不算什麼，對某人而言卻是撐過一天的小小獎賞。是香氣先一步抵達的溫柔邀請函。"},"ICON-1449":{"nm":"宿舍打掃券","de":"敞開窗戶，把被子抖得啪啪作響，連一粒灰塵都逃之夭夭的一天。原來不必親手做這件事，竟是如此一種奢侈。房間一閃亮，連心也悄悄整頓了起來。"},"ICON-1450":{"nm":"修理工具包","de":"螺絲起子、膠帶，還有幾個來歷不明的零件。湊齊後看似沒什麼修不好，打開一看卻總是缺了一樣。即便如此，握在手中仍莫名讓人多了幾分底氣的自信之盒。"},"ICON-1451":{"nm":"幸運票","de":"一張既無座位也無號碼的空白票。今天會有什麼好事降臨，上頭並未寫明，這正是重點。填滿那片空白，是把它揣進口袋之人的責任。"},"ICON-1452":{"nm":"骰子","de":"最懂「公平」二字的朋友。不偏袒任何一方，平等地疼愛六個面。在離開掌心咕嚕嚕滾動的那一刻，無論實力還是人脈，都暫時把位置讓給了運氣。"},"ICON-1453":{"nm":"移動券","de":"從這裡到那裡，一步便足夠的約定。把遙遠的路小小摺起、放進口袋的魔法般的紙。在猶豫著該不該出發的日子裡，再沒有比這更好的藉口攔截器了。"},"ICON-1454":{"nm":"重來券","de":"與其對跌倒的人伸出手，不如靜靜推一把背、叫他再試一次的票。它最安靜地告訴你，失敗不是結束，而是短暫的逗點。再一次的勇氣，便從這裡充盈起來。"},"ICON-1455":{"nm":"快速完成券","de":"稍稍跳過等待的溫柔作弊碼。連3分鐘都等不了的心，誰又能責怪呢。用手指「啪」地撥掉沙漏裡的沙——這裡有著一份略帶犯規的快樂。"},"ICON-1456":{"nm":"生產加速器","de":"同樣的手、同樣的時間，成果卻翻倍。彷彿不准你問訣竅般，在工作檯上「嗡」地歡快旋轉。是替勤奮舞動的雙手悄悄裝上翅膀的小小裝置。"},"ICON-1457":{"nm":"親密度糖果","de":"言語難以化解的尷尬，在甜食面前也會緩緩融化。一起剝開吃下的一顆糖，讓彼此比昨天又近了一寸。甜，便是變親近的速度——這是一個可愛的小發現。"},"ICON-1458":{"nm":"心情恢復軟糖","de":"難過的日子，冰冰軟軟的東西最是見效。咬下一口，陰沉的神情便悄悄舒展開來。修復心情這件事本就珍貴，R等級可不是白給的。"},"ICON-1459":{"nm":"閃亮粉末","de":"在平凡之物上輕輕一撒，便突然變得特別。其真面目不過是閃閃發亮的粉末，沾上的瞬間世界卻顯得更雀躍些，著實神奇。它就像在日常上輕點一下的幸福調味料。"},"ICON-1460":{"nm":"舞台定位帶","de":"一站上舞台，無數燈光便一齊找到你。那個位置，由地板上的一個小小X字無言地標記著。在看不見之處最為精準的事物，終究撐起了最大的舞台。"},"ICON-1461":{"nm":"束線帶","de":"能將糾結的線材一舉理得整整齊齊的小小英雄。一旦束緊便無法回頭，這既是缺點也是魅力。是對整潔極度認真的人會悄悄備好的必需品。"},"ICON-1462":{"nm":"備用線材","de":"有它時毫無存在感，沒它時才終於令人渴求的東西。它在舞台幕後的包包深處沉睡，總在關鍵的一刻猛然甦醒。它用身體證明了「未雨綢繆」這句話。"},"ICON-1463":{"nm":"彩排檢查表","de":"走位、提示，連換裝都一格格寫得密密麻麻的紙。這上頭只要有一處沒打勾，就會有某人的心臟「咯噔」一沉。完美的舞台，唯有在這張表填滿之後，才終於拉開帷幕。"},"ICON-1464":{"nm":"佈景指示牌","de":"這裡是咖啡廳，那裡是巷弄，順著箭頭走便是截然不同的世界。明明是畫在合板上的謊言，在鏡頭前卻成了真。它是一位把畢生奉獻給「指引方向」的誠實嚮導。"},"ICON-1465":{"nm":"迷你獎盃","de":"接過手中的瞬間，便莫名覺得自己彷彿長高了一寸的一塊金光。它在桌上閃耀著，告訴你即使不是第一名也真的沒關係，今天你的努力它全都知道。是小小獎賞遞來的大大慰藉。"},"ICON-1466":{"nm":"背包","de":"背上肩的瞬間，便彷彿能去往任何地方。即使裡頭沒裝什麼，可能性卻滿滿一袋。冒險，總是始於把這肩帶牢牢繫緊這件事。"},"ICON-1467":{"nm":"羅盤","de":"即使迷了路也不慌張，是因為針尖永遠指向北方。晃了好一陣終究找回原位的模樣，恰似人心。它用顫抖的針尖告訴你，迷路也沒關係。"},"ICON-1468":{"nm":"筆記本","de":"第一頁總是空白。要寫些什麼，只有執筆之人才知道。我只是等待，等今日的思緒化為字跡，靜靜落在我身上。R等級，便是即將被填滿的可能性之重。"},"ICON-1469":{"nm":"鉛筆","de":"寫錯也沒關係，是這支工具最溫柔的一面。只要橡皮擦朋友在身旁，便能一次又一次重新開始。削得越多便越短，但短去的部分，正是被長久喜愛過的證明。"},"ICON-1470":{"nm":"底片","de":"在光通過的瞬間，那一天的色彩便原原本本地印了下來。一格過去便永遠無法挽回，這既是緊張也是魅力。是在飛快的時代裡，刻意慢上一拍去記憶的人們的選擇。"},"ICON-1471":{"nm":"即時相機","de":"「喀嚓」，然後是片刻的等待。握在手中輕輕搖晃，原本模糊的瞬間便漸漸變得清晰。是把此時此地原原本本封進一張紙裡的、稍帶些魔法的機器。"},"ICON-1472":{"nm":"老照片","de":"色彩褪得越多，便意味著流逝的時間越久。每一處磨損的邊角，都曾停駐過某人的手。最老的照片懷抱著最清晰的記憶，大概就是因為那些手的緣故吧。"},"ICON-1473":{"nm":"剪貼簿","de":"捨不得丟棄的碎片聚了又聚，便成了一本。褪色的電影票、乾掉的花瓣、短短一張便條。在別人眼中或許是雜物，對攤開它的人而言，卻是一整段時光的復甦。"},"ICON-1474":{"nm":"航海日誌","de":"今天的風與浪，還有心情的一行。連平安無事的日子也一筆一筆記下，是航海的規矩。平安抵達的證據，總寫在這本厚厚記錄裡的某一處。"},"ICON-1475":{"nm":"地圖碎片","de":"明明只是整體的一個角落，少了它卻終究找不到路。當撕裂的斷面與另一塊碎片嚴絲合縫地咬合時，那份暢快可真是無與倫比。R等級，有著如拼圖最後一格般的存在感。"},"ICON-1476":{"nm":"瓶中信","de":"在不知會被誰讀到的情況下，靜靜把自己交付給海浪。不指望回信，只盼這份心意能觸及某處。是最緩慢卻也最浪漫的郵遞方式。"},"ICON-1477":{"nm":"骰子","de":"彷彿在說「又是你啊」般圓圓而笑的六個面。明明是相同的模樣，每次滾動卻都給出不同的答案，這便是這位朋友始終如一的善變。在離手的瞬間，把選擇暫時託付給命運。"},"ICON-1478":{"nm":"風車","de":"唯有起風才終於活了過來。靜靜擱著時不過是紙做的翅膀，一旦有人呼地一吹，便歡快地轉了起來。不為受人幫助而羞赧，正是這朵小花的智慧。"},"ICON-1479":{"nm":"野餐籃","de":"掀開籃蓋，紫菜飯捲的香氣便先打了聲招呼。青翠的草坪、攤開的野餐墊，還有分享食物的一雙雙手。這只籃子裝得滿滿的日子，奇妙的是天總是很晴。"},"ICON-1480":{"nm":"花瓶","de":"只插上一朵，房裡的空氣便不一樣了。空著的時候，默默等待便是它的本分。為了讓花更加耀眼而靜靜放低自己的存在——是房裡最謙遜的舞台裝置。"},"ICON-1481":{"nm":"花瓣","de":"風帶走一片，春天便輕了那麼一分。院中的老樹年年道著相同的問候——飄落，也是綻放的一部分。飄散不是結束，而是預先寄給來年春天的一封信。"},"ICON-1482":{"nm":"玫瑰","de":"先豎起尖刺，是「別隨意觸碰」的約定。而那內裡，藏著最為赤紅的心。曾有人把一朵靜靜放在腳邊，不留下名字，只以顏色寫下心意，便轉身離去。"},"ICON-1483":{"nm":"百合","de":"潔淨的白瓷旁總擺著這朵白花。願香能飄遠，而姿態始終不亂。在以純白取代華麗的那一處，百合無言地守住了一格的端莊。"},"ICON-1484":{"nm":"鬱金香","de":"微微低著頭、成排站立的模樣，莫名顯得端正。是承包春日花壇第一排的花。一齊綻放、一齊凋謝的那份誠實，把短暫的季節染得最為濃烈。"},"ICON-1485":{"nm":"風信子","de":"一根花莖上密密掛滿小小的鈴鐺。即使搖晃也無聲，香氣卻代它響徹整個房間。在春的入口，僅憑一只花瓶便將房裡的空氣整個換新的溫柔奢侈。"},"ICON-1486":{"nm":"青蛙標本","de":"在玻璃箱裡時間靜止的小小身軀。標籤上寫著——「棲於稻田與蓄水池，雨後翌日最為活躍。」唯有在靜止之後，連一隻生物曾棲居的水邊溫度，都化為記錄留存下來。"},"ICON-1487":{"nm":"蜥蜴標本","de":"斷尾逃生的那份機靈，即使成了標本也抹不去。是喜愛陽光充足的石牆的小小訪客。一旁的便箋上工整地寫著，牠最常攀爬的那片向陽處的方向。"},"ICON-1488":{"nm":"鼴鼠記錄","de":"穿行地底者的日記，是以土的紋理寫成的。挖了哪裡、在哪裡停下，是一張看不見的路的地圖。背光而活的時光，對某人而言也成了再誠實不過的記錄。"},"ICON-1489":{"nm":"貝殼標本","de":"海浪打磨了數千次才送來的堅硬紋理。灘塗上的人，光看殼的紋路便知是哪片海的。曾經鮮活呼吸的那片海的形狀，原原本本盛在這掌心大的標本裡。"},"ICON-1490":{"nm":"珊瑚標本","de":"在大海深處費時數百年才好不容易長了一寸。看似枝椏，實則是無數微小生命共同築起的家。越緩慢的越能長存——珊瑚以沉默證明了這一點。"},"ICON-1491":{"nm":"愛動線索","de":"散落在島嶼某處的故事的一個片段。一小片紙條靜靜指向下一步該邁向何方。古老的嚮導說，所有冒險終究都始於拾起這般細微的痕跡。"},"ICON-1492":{"nm":"簽名標誌碎片","de":"散落的紋路各歸其位，一個標誌才終於完成。是刻著某人獨有紋理的碎片。在拼合之前一直藏著意義，拼合的瞬間才終於成為名字。"},"ICON-1493":{"nm":"舞台記憶碎片","de":"即使一首歌結束，觀眾席仍殘留著餘溫。把那份暖意剝下凝固，便成了這樣的小小碎片。散落的掌聲與吶喊的碎片，靜靜聚攏，那一夜便整個復甦。"},"ICON-1494":{"nm":"出道印記","de":"第一次自己的名字被唱名的那天，蓋在手背上的那道墨痕。連小心翼翼吹乾、不讓它暈開的那份心，都算在起跑線之內。一枚小小的印章，讓某一天永遠無法被抹去。"},"ICON-1495":{"nm":"頂尖偶像獎牌","de":"唯有登上最高位置之人，才獲准擁有的那份沉甸。然而這枚獎牌之所以沉重，並非因為金屬。而是因為共同填滿舞台的無數雙手的重量，原原本本匯聚於一點。"},"ICON-1496":{"nm":"小鑰匙","de":"宿舍的第一把鑰匙，總是最裡側那間房的。是在那裡，先學會了開鎖而非上鎖。離開的那天，冰冷的鐵片上，掌心留下的餘溫久久停駐。"},"ICON-1497":{"nm":"寶箱","de":"打開之前，誰也不知道裡頭裝著什麼。那份「不知道」，才正是寶箱真正的寶物。掀起箱蓋的短短瞬間，任誰都會暫時回到童年的那陣心跳。"},"ICON-1498":{"nm":"設計圖","de":"在一格格劃定的線上，住著一棟尚未建起的房子。攤開圖紙，便是預先把明天走上一遍。一條劃得好的線，撐起一個不會崩塌的明天。"},"ICON-1499":{"nm":"食譜卡","de":"在一張沾滿手澤的卡片上，奶奶的手藝以份量寫了下來。「鹽一撮」這般含糊的話，反而是最精準的祕訣。字跡越是模糊，煮著那道菜的廚房便越清晰地浮現。"},"ICON-1500":{"nm":"設施許可證","de":"一張紙，便把空地變成了「可以使用的地方」。新建築總是得先有村裡的印章。所謂許可，終究是「在這裡開始些什麼也無妨」的一枚溫暖印記。"},"ICON-1501":{"nm":"港口許可證","de":"船要下錨，得先有這麼一張才行。港邊那枚褪色的印章，是迎接遠方來客的第一聲問候。在離去與抵達之間，港口總以一紙文書敞開心扉。"},"ICON-1502":{"nm":"入島證書","de":"證明你已成為這座島一份子的小小證書。從前的村子若有新鄰搬來，便會添上名字、分送溫熱的年糕。雖只是一張紙，上頭卻寫著「從今你也是我們的人」這般明亮的款待。"},"ICON-1503":{"nm":"宿舍門牌","de":"門邊掛上一個名字，空房才終於成了某人的家。從前的廂房，也是先掛上刻有主人雅號的匾額。門牌雖小，裡頭卻滿是「這裡有人住著」的暖意。"},"ICON-1504":{"nm":"粉絲郵票","de":"沾點口水用力按貼上去的那份心意，也是一封完整書信的一部分。把喜歡的心意黏在小小紙片上，寄向遠方。即使在數位時代，仍有人偏要親手寄出自己的心意。"},"ICON-1505":{"nm":"閃亮島徽章","de":"別在衣領上，一抹微光便會一路相隨。在路上遇見別著相同徽章的人，不必開口便能心領神會。閃光不是炫耀，而是「我們愛著同一座島」的靜靜暗號。"},"ICON-1506":{"nm":"工作檯","de":"佈滿刮痕的檯面，見證著那雙做出最多東西的手。在這裡修補、接合、打磨種種物件。比起整潔的書桌，凌亂的工作檯其實藏著更多故事。"},"ICON-1507":{"nm":"收納箱","de":"越是珍貴的東西，越要先為它定好位置。從前的人也會把貴重文書另收進梧桐木匣裡。好好保管，說到底就是為了未來的某人，將今日端正地摺疊收好。"},"ICON-1508":{"nm":"資源箱","de":"有餘時收存起來，不足時再取出來用。這裡裝著倉廩充實、心也踏實那個年代的智慧。儲備，就是預先遞給未來的自己一頓溫暖的飯。"},"ICON-1509":{"nm":"冷藏箱","de":"填滿冰塊的匣子，即便盛夏也留得住清涼。彷彿是把石冰庫的古老智慧，縮成了一掌大小。守住冰涼，就是讓最新鮮的那一刻久久停留。"},"ICON-1510":{"nm":"水泵","de":"上下搖動把手，地底深處的水便會湧上來。得先倒進一瓢引水，才會嘩啦嘩啦傾洩而出的誠實機器。要先付出才能有所得的道理，井邊早早就懂了。"},"ICON-1511":{"nm":"淨水器","de":"混濁的水一層層變清流出，是個小小的奇蹟。從前的人在缸裡層層鋪上沙與炭來濾水。清澈並非平白得來，而是慢慢過濾的一份用心。"},"ICON-1512":{"nm":"灑水壺架","de":"灑水壺有了自己歇腳的位置，花圃的一天便顯得井然。為工具定下擺放之處，是熱愛勞作之人的習慣。一個位置定下，整座庭院便齊整了許多。"},"ICON-1513":{"nm":"釣竿架","de":"等到魚訊上鉤之前，人縱然離開，釣竿仍守著原位。在江邊垂釣歲月的那份等待姿態，原原本本嵌在這裡。釣竿架說到底，是暫且放下急躁的承托。"},"ICON-1514":{"nm":"採集籃","de":"盛著一把山菜、一朵野花歸來的，是母親手裡的提物。從竹篾編織的縫隙間，泥土的氣息悄悄滲出。端看盛裝什麼，空籃子既能是春天，也能是秋天。"},"ICON-1515":{"nm":"石臼","de":"咚、咚，以固定的節拍舂著穀物，村子的一天便甦醒了。逢年過節，打糕聲便會盈滿巷弄的器具。要把堅硬之物變得柔軟，需要一雙手持續不輟的律動。"},"ICON-1516":{"nm":"砧板","de":"刀刃劃過的每道痕跡，都刻著一頓飯的歷史。佈滿刮痕的木板，是廚房裡最勤勞那雙手的勳章。切割什麼，始於想用心款待它的那份心意。"},"ICON-1517":{"nm":"鍋子","de":"咕嘟咕嘟的沸騰聲，比任何音樂都來得溫柔。飢腸轆轆的凌晨，等麵煮熟的那3分鐘，是最私密的慰藉。圓圓的鍋底盛滿了想餵飽某人的暖意，正被加熱著。"},"ICON-1518":{"nm":"平底鍋","de":"在火上一瞬間煎熟的手藝，全繫於這一面鍋上。表面養得越好，越不沾黏、越是油亮。用久了的鑄鐵鍋本身，便是廚房走過歲月的證據。"},"ICON-1519":{"nm":"烤箱","de":"關上門等候的期間，裡頭正悄悄上演著魔法。麵團膨脹、色澤漸熟的時光。即便看不見，只要信任地等待，溫暖的成果便會推門而出。"},"ICON-1520":{"nm":"果汁機","de":"再堅硬的東西放進這裡，轉眼也成了柔滑的一杯。各異的食材交融，誕生出新滋味的小小漩渦。所謂融洽，說到底就是各自讓出一點稜角。"},"ICON-1521":{"nm":"打蛋器","de":"手腕一揮便鎖住空氣，攪打得越快，原本稀薄的便挺立得越堅實。在泡沫如山峰般高聳的同時，膨脹起來的不只是麵糊。今天想餵飽某人的心意，也一同膨脹起來。"},"ICON-1522":{"nm":"研磨器","de":"抓一把咖啡豆轉動把手，香氣便先在齒輪間碎裂開來。等到手臂痠了，粉末才終於細緻，那份辛勞讓第一口更加深邃。用心，總是從手腕開始的。"},"ICON-1523":{"nm":"磨粉機","de":"穀粒鑽進石縫間，化作白色粉末流出。一次磨不細也沒關係，再多磨兩回就行。把粗糙磨得細緻，也是有順序的——磨粉機默默這般告訴你。"},"ICON-1524":{"nm":"鋸木檯","de":"原木一上檯，鋸子便先讀懂它的紋理。避開節疤、只沿著筆直的路鋸，木板才不會翹曲。鋸木這件事，說到底是把一棵樹活過的時光，齊整地展開。"},"ICON-1525":{"nm":"縫紉機","de":"嗒嗒——針咬著布料奔跑的聲響，填滿了深夜。一道接縫將兩幅布拼成一體，舞台服裝裡側那些看不見的縫線中，深深嵌著某人徹夜未眠的時光。"},"ICON-1526":{"nm":"染布檯","de":"白布浸入再取出，起初是嫩綠，遇上空氣後才終於轉藍。據說那是藍草要熬上三回才能煉出的顏色。等待即化作顏色——我是在這染布檯前第一次學會的。"},"ICON-1527":{"nm":"攝影三腳架","de":"撐開三條腿踏上地面的瞬間，搖晃的世界便靜止了。若用手持便會抖動的那一格畫面，在這三點的約定之上變得清晰。要長久凝視某物，得先懂得停下腳步。"},"ICON-1528":{"nm":"照明立燈","de":"在一根柱子上載起光，房裡任何角落都成了小小舞台。角度稍一轉動，影子便拉長、神情便鮮活起來。它不是消除黑暗，而是連黑暗也溫柔地安放的工具。"},"ICON-1529":{"nm":"麥克風架","de":"調好高度的瞬間，嘴與歌聲之間的距離便定了。即使鬆開手，聲音也停留在原處。唯有在雙手獲得自由的舞台上，以全身歌唱的歌聲才終於開始。"},"ICON-1530":{"nm":"譜架","de":"攤開的紙頁斜斜倚立，音符便齊高排成隊，迎著演奏者的視線。即使手一揮、下一小節便到來，承托的架子也不會動搖。某人的演奏背後，總有一個無言的位置。"},"ICON-1531":{"nm":"菜園","de":"翻土開出田壟，地上便生出一道小小約定的線。埋下種子的那幾天看似毫無動靜，某個清晨，嫩芽卻會頂開泥土冒出來。那是只有等待過的人才看得見的風景。"},"ICON-1532":{"nm":"肥沃菜園","de":"明明是同樣的種子，在這片地裡葉子卻大了兩倍。把手指插進去，黑而柔軟的土便跟到指甲縫底下。長得好，說到底是看不見的腳下，默默成就的事。"},"ICON-1533":{"nm":"溫室","de":"在玻璃天頂之下，季節慢上半拍流轉。外頭即便落霜，裡頭仍以盛夏的濕氣潤澤著。為了那些畏寒的生命，有人把陽光悄悄關進了屋頂裡。"},"ICON-1534":{"nm":"香草花圃","de":"指尖輕拂過葉子，香氣便先打了聲招呼。羅勒、迷迭香、薄荷——每喚一個名字，指上便沾染不同的氣味。一方小小花圃，便能把整座廚房變得溫柔起來。"},"ICON-1535":{"nm":"果園","de":"春天為花蔭，秋天則因果實的重量而枝椏彎垂。爬上梯子摘下一顆咬下，一整年陽光積攢的甜味便在口中迸開。彷彿是樹給人的一封回信。"},"ICON-1536":{"nm":"香菇原木","de":"在伐下的原木上鑽孔種入菌種，枯木便又養育出了什麼。幾天後菌傘成簇冒出的清晨，在以為是終結的地方，新的生機悄然開始。"},"ICON-1537":{"nm":"蜂箱","de":"把耳朵湊近，便聽見裡頭低沉而勤勉的震動。數千次振翅匯聚，才勉強換來一匙的甜美。往返花田一整天的辛勞，黏稠而金黃地，凝聚在這裡。"},"ICON-1538":{"nm":"雞舍","de":"天亮之前，棲架上的牠們便先窸窣作響。把手伸進溫熱的稻草裡，便摸到一顆尚有餘溫的蛋。最先報曉的地方，也最先張羅起了早餐。"},"ICON-1539":{"nm":"牧場","de":"草香與陽光氣味交織的遼闊原野。圍欄裡慢吞吞反芻的脊背上，雲影緩緩掠過。在這無須匆忙的地方，連時間都像啃草般慢慢流淌。"},"ICON-1540":{"nm":"起司工坊","de":"剛擠出的乳汁經過凝固與熟成，慢慢變得堅實。在如洞窟般陰涼的架上等候數月，白色塊體便滲入深邃的風味。起司，是只賜給不曾匆忙的牛奶的名字。"},"ICON-1541":{"nm":"豆腐工坊","de":"把豆子泡發、磨碎、煮沸，腥澀的豆漿便變得香醇。一滴鹵水讓四散的東西聚成嫩豆腐，靜靜壓上一陣便成了方塊。把零散的心安撫、塑出形狀的手，就在這裡。"},"ICON-1542":{"nm":"醬缸臺","de":"陽光充足的院子一角，矮矮的缸甕擠成一團曬著太陽。揭開蓋子，陳年時光的氣味便撲面而來。奶奶醃下的醬味，其實是把歲月一匙匙舀來品嚐。"},"ICON-1543":{"nm":"碾磨坊","de":"轟隆轟隆地石磨一轉，穀物便鬆解成了粉末。白色塵粉在陽光中飄浮，想做一笸籮年糕的人們等著輪到自己。村裡的喜慶日，總是從這道門檻開始。"},"ICON-1544":{"nm":"麵包坊","de":"奶油與砂糖的香氣，從烤箱門縫間溢出。膨脹的麵團烤至金黃時，店門前路過的腳步便不自覺地慢了下來。一塊剛出爐的麵包，有著誰也抵擋不住的溫柔。"},"ICON-1545":{"nm":"小吃攤車","de":"塑膠帳篷隨風啪嗒翻飛，辣炒年糕的湯汁咕嘟咕嘟收稠。在配著一串魚板、灌下一紙杯熱湯的傍晚，是同時融化寒冷與飢餓的地方。是巷尾擺著的小小慰藉。"},"ICON-1546":{"nm":"西餐廚房","de":"鍋子燒熱，橄欖油滋滋作響。單憑火候的拿捏，醬汁能勾芡、也能燒焦。連盤上色彩的平衡都要顧及的這裡，一頓飯便成了精心打理的一齣演出。"},"ICON-1547":{"nm":"中華廚房","de":"炒鍋在猛火上如起舞般颼颼翻轉。火焰竄起的短短瞬間，食材的香氣便完整地被鎖住。又快又熱，一猶豫便會錯失的那一口氣息中，藏著中華料理的祕密。"},"ICON-1548":{"nm":"咖啡館","de":"推開門，咖啡豆香與舒緩的音樂便先來相迎。窗邊座位上，一杯漸涼的拿鐵與攤開的筆記本。為了讓人在忙碌的一天裡稍歇口氣，城市在各處藏下了這樣的小小房間。"},"ICON-1549":{"nm":"甜點店","de":"玻璃櫥窗裡，五彩的蛋糕排成隊等候客人。叉尖劃開奶油的瞬間，嘴角便先揚了起來。即便在傷心的日子，有一塊也能撐得過去——小小而甜美的處方箋。"},"ICON-1550":{"nm":"肉舖","de":"紅色燈光下，肉順著紋理排得齊整。一句「今天這個好」，刀便以精準的厚度滑開。晚餐桌的豐盛，正是從這雙日日守在同一位置的手，悄悄開始的。"},"ICON-1551":{"nm":"水產作業檯","de":"凌晨的腥味與冰塊的冰冷交織的作業檯。即使魚鱗飛濺、雙手凍僵，那雙挑出最新鮮之物的眼睛也不停歇。剛從海裡撈上來的東西，在這裡找到了通往餐桌的路。"},"ICON-1552":{"nm":"鹽田","de":"把海水圈起來，剩下的便交給陽光與風。等上幾天水乾了，地面便如星星般冒出白色結晶。一撮鹹味其實是海與天，慢慢合力做出的禮物。"},"ICON-1553":{"nm":"海藻晾架","de":"長繩上，海帶與昆布並排晾著隨風搖曳。飽含海水的它們在風乾中，染成濃郁的深綠。陽光與海風共同釀出的、大海最樸素的滋味，就懸掛在這裡。"},"ICON-1554":{"nm":"小碼頭","de":"半浸在水裡的木板，在腳下輕輕晃盪。是個正好繫上一艘小船的位置。遠行也好、平安歸來也罷，全都從這一格開始，又在這裡結束。"},"ICON-1555":{"nm":"港口倉庫","de":"推開被海風醃透的木門，漁網、木桶與纜繩堆到了天頂。即將遠航的行李與剛抵達的貨物，暫時共處一個屋簷下。是個讓離去與歸來短暫交會的轉乘站。"},"ICON-1556":{"nm":"燈塔","de":"唯有當夜海最為漆黑時，它才終於開始幹活。旋轉的光劃破濃霧，告訴人們「這裡有路」。為了某人能平安歸返，它是個始終不眠的高大守望者。"},"ICON-1557":{"nm":"造船廠","de":"立起龍骨、接上肋材，一艘船的骨架便有了模樣。在槌聲整日迴盪的場院裡，尚不識水味的船兒夢想著第一次航行。是個為了出發而先變堅實的地方。"},"ICON-1558":{"nm":"錄音室","de":"門一關上，外頭所有的聲響便瞬間消失。耳機那頭聽見的，只有自己的呼吸與節拍。在這小房間的寂靜裡，那道盡管顫抖也無妨的嗓音，才終於誕生。"},"ICON-1559":{"nm":"音樂教室","de":"從門縫溢出的和聲填滿了走廊。有人按著音階，有人數著拍子。是個生澀與純熟的聲音交織也無妨的地方，是每首歌初次邁步的溫柔教室。"},"ICON-1560":{"nm":"鋼琴室","de":"掀開琴鍵蓋，白色琴鍵上淺淺積著灰塵。手指觸上的瞬間，清澈的迴響便盈滿整個房間。若有哪個夜晚獨處也不孤單，大概就是因為這一架鋼琴。"},"ICON-1561":{"nm":"練舞室","de":"腳尖一踩，地板便回推上來。四面鏡子把同一個動作複製四遍的同時，身體比節拍早半拍記下了編舞。是汗水與氣息停留最久的房間，在此長成的動作，將走上舞台。"},"ICON-1562":{"nm":"健身室","de":"重量不會說謊。舉起多少，便精準地累積到肩上多少，正是愛這份誠實，人們每天清晨來找我。在鏡子裡慢慢刻下的不是肌肉，而是不放棄、撐住的那些時光。"},"ICON-1563":{"nm":"瑜伽室","de":"深深吸一口氣，便覺得木地板也一同膨脹起來。是個把一路疾奔而來的一天慢慢摺好的房間，在一張墊子上，誰都能回到自己呼吸的速度。再急躁的心，在這裡也暫且放下。"},"ICON-1564":{"nm":"化妝室","de":"踏上舞台前的一刻，人們在這裡暫時成為另一個人。鏡框周圍的燈泡把臉均勻地烘暖，顫抖便沾在粉撲尖上，悄悄藏到衣領後。是變身開始、又結束的地方。"},"ICON-1565":{"nm":"服裝室","de":"舞台上的一套衣裳完成之前，這裡掛著的衣服被穿上、脫下幾十回。插著珠針旋轉的人檯，粉筆劃出的縫份線。閃光的背面，總留著某人的針線痕跡。"},"ICON-1566":{"nm":"電視台佈景","de":"只要把鏡頭照到的那一面佈置得像真的就行——我早早便學會了。繞到合板後頭，只有空蕩的骨架。默默撐起正面華麗的，永遠是那些看不見的木條。"},"ICON-1567":{"nm":"攝影棚","de":"從三個方向打光消除陰影，是第一個訣竅。主光照亮臉龐，輔光提亮陰影，背光勾出髮絲末端。快門落下的剎那，一張白色背景便鎖住了今天最好的微笑。"},"ICON-1568":{"nm":"演出廳","de":"在天頂高聳的黑暗中，我總懷著同一個約定。幕一升起，連空蕩的觀眾席也會如同一人般屏住呼吸。為了第一個鼓點落下的那一瞬，我一整年靜靜地空著。"},"ICON-1569":{"nm":"粉絲見面攤位","de":"手與手之間的距離，恰好是一張桌子那麼寬。短短的問候、顫抖的簽名、終究沒能說出口的那句話，列隊掠過。在這小小一格裡，長久培養的喜歡，第一次面對面相見。"},"ICON-1570":{"nm":"床","de":"最先接住一天結尾的，向來是我。練習而沉重的雙腿、舞台後殘留的顫抖，全都沉澱下來後，早晨便又以輕盈的腳尖開始。它說著晚安，無言地擁抱你。"},"ICON-1571":{"nm":"雙層床","de":"在上層與下層之間，五階梯子連起了兩個人。熄燈後交換的細小聲音、貼在天頂的夜光星星。狹窄的宿舍之所以變得最寬廣，全靠每晚在梯子上上下下的那些故事。"},"ICON-1572":{"nm":"層架","de":"擺上什麼，便看得出那是個怎樣的人。收到的信、第一座獎盃、褪色的入場券，並排成隊。我不是炫耀擺設的家具，而是靜靜陳列著捨不得丟的記憶的位置。"},"ICON-1573":{"nm":"書桌","de":"歌詞本攤開著，擦掉的痕跡上又劃出新的一行。徹夜堆積的紙杯，與好不容易撈出的一句旋律。把心意化作文字的遲緩工作，總是在這平坦的面上悄然進行。"},"ICON-1574":{"nm":"椅子","de":"「坐一下吧」這句話，意外地溫柔。即使會議拉長、練習拖久，椅背仍默默承接著人的重量。站得越久的人越歡迎我——這點，我是知道的。"},"ICON-1575":{"nm":"沙發","de":"深夜要把宿舍變成客廳，有我一個就夠了。大家擠著坐看綜藝節目，看著看著，總有一人不知不覺靠在扶手上睡著。中間那塊深陷的位置，證明著這個家的暖意。"},"ICON-1576":{"nm":"餐桌","de":"圍坐下來，誰也不算上座。剛煮好的鍋物、湯匙碰撞的聲響，今天發生的事都聚向中央。一張圓圓的桌面攤開，四散的一天也再次圍坐到一處。"},"ICON-1577":{"nm":"衣櫃","de":"每逢季節更替，裡頭便傾瀉出陳年的故事。舞台服裝與便服肩並著肩，在緊閉的門後等著下一個輪次。唯有打開門，今天要穿的這一天才終於定下。"},"ICON-1578":{"nm":"鏡子","de":"稱讚也好、瑕疵也罷，我都以同樣的誠實回還。是踏上舞台前接受最後檢查的位置，人們在我面前整理神情、端正姿態。最坦率的朋友，總是一句話也不說。"},"ICON-1579":{"nm":"梳妝檯","de":"每個小抽屜裡都沉睡著一張不同的臉。舞台用的一盒、平日用的一盒、捨不得用的限定版一盒。坐到鏡前，便要從今天要成為怎樣的人、再出門開始慢慢決定。"},"ICON-1580":{"nm":"地毯","de":"赤腳初次觸到的觸感，定下那房間的溫度。圍坐吃零食、打滾的痕跡化作絨毛留了下來。把冰涼的地板再暖上一寸的，是在最低處工作的家具。"},"ICON-1581":{"nm":"窗簾","de":"要放多少早晨進來，由我決定。稍微拉開，陽光便長長地照進；緊緊閤上，連賴床也變得寬容。站在窗與房之間靜靜調節光量，向來是交付給我的職分。"},"ICON-1582":{"nm":"燈具","de":"同一個房間，隨著光的顏色便成了截然不同的時間。黃光把傍晚拉長，白光把清晨清晰地喚醒。憑一個開關便悄悄改變一天氛圍的，是個巴掌大的魔法師。"},"ICON-1583":{"nm":"掛鐘","de":"秒針的聲音，只在安靜的房間裡聽得見。練習越深越忘了自己，猛一抬頭，窗外不知何時已是凌晨。它從不責怪流逝的時光，只是默默指向下一格。"},"ICON-1584":{"nm":"花瓶","de":"即便花謝了，我也不會讓那位置空著。我是暫時盛裝收到心意的容器，只要有換水的那雙手，餐桌便明亮起來。即使空著時，我也以等待某人的姿態站立著。"},"ICON-1585":{"nm":"海報相框","de":"把喜歡的臉龐掛上牆，也是要下一番功夫的。陽光不直射的位置、水平剛剛好的一根釘子。好好躺在玻璃裡的一張紙，每天清晨在我踏進房間時，最先向我問好。"},"ICON-1586":{"nm":"小卡收藏板","de":"要按字母順序插，還是按發售順序插，光是這幸福的煩惱便是追星的開始。空著的一格，是還沒遇見的本命的位置。一張張被填滿，這板便成了專屬於我的小小編年史。"},"ICON-1587":{"nm":"應援棒架","de":"電池取出，握把朝上。連斜斜傾立的角度，也自有一套訣竅。等候著即將到來的下一聲歡呼，棒子便在這裡熄了光、齊整地橫躺下身。好好歇過，才能更亮地點起。"},"ICON-1588":{"nm":"獎盃架","de":"最前排擺上最古老的那座。從小型比賽的銅像到大舞台的獎盃，不是依高矮，而是依心意的順序排列。每次擦拭時，那天舞台上的顫抖便又沾上指尖。"},"ICON-1589":{"nm":"野餐籃","de":"掀開蓋子，春日陽光的氣味便先溢出。紫菜飯卷、保溫瓶與一張野餐墊層層疊好，準備往原野去。提著我的人的腳步，不知怎地總比平時輕盈了一寸。"},"ICON-1590":{"nm":"小花盆","de":"一掌寬的窗臺，對我而言便足夠。即使常忘了澆水，也寬容地撐著的小小綠意。在忙碌之人的書桌一角，我每天多展開一片葉子，靜靜送上今日的問候。"},"ICON-1591":{"nm":"大花盆","de":"在我長高的同時，人也一同成長。佔據客廳一角的寬大葉片承著陽光、垂下綠蔭，房裡也悄悄染上了季節。是只有不忘澆水的人才懂的成就感。"},"ICON-1592":{"nm":"香氛蠟燭組","de":"為燭芯點上火的瞬間，房裡的空氣便沉澱了一階。香氣緩緩瀰漫，把昨日殘留的疲憊烘暖、送走。憑一小簇火焰，將忙碌一天的結尾，如靜謐儀式般收束。"},"ICON-1593":{"nm":"迷你冰箱","de":"深夜打開門，一罐冰涼的飲料便迎接我。嗡嗡的小小震動聲，讓空蕩的宿舍不那麼孤單。大事業我做不來，但要負責飢腸轆轆的凌晨，沒有比我更行的了。"},"ICON-1594":{"nm":"捕蟲網頭飾","de":"戴上頭的瞬間，夏日原野便跟著爬上了肩頭。圓圓的網把陽光細細濾過，每走一步草香便輕輕搖曳。是頂即使一隻蜻蜓也沒抓到也無妨、把整個季節整個罩上的帽子。"},"ICON-1595":{"nm":"採集網袋","de":"掛在腰間，成了採集的同伴。把袋口稍稍束緊，抓到的東西便不會又逃走——這是在原野上學到的第一個訣竅。一只輕巧的布袋，把一天份的收穫牢牢地擁進懷裡。"},"ICON-1596":{"nm":"昆蟲觀察瓶","de":"對暫住的客人而言，透氣孔是最重要的——這點我懂。蓋上鑽出的小小氣孔、底部鋪的一片草葉。觀察結束後再送回草叢，這才算是一整套。"},"ICON-1597":{"nm":"標本針盒","de":"連斜斜插針的角度，都藏著技術。太深會碎裂、太淺會搖晃，得把指尖的力道精密地分配開。靜靜盛裝著想長久端詳一個小小生命之人那份用心的盒子。"},"ICON-1598":{"nm":"飼養箱蓋","de":"負責裡與外的界線，是我的工作。蓋得太緊會悶住、放得太鬆會迷路，所以總要留下斜線般的縫隙。守護，與關押，分明是兩回事。"},"ICON-1599":{"nm":"蝴蝶餵食盤","de":"把沾了糖水的棉花放在中央，翅膀們便聚攏過來。淺而寬，盛得讓小腳不會陷進去的深度，是訣竅。一只盤子，靜靜召來那些在陽光正好的庭院短暫停留便離去的客人。"},"ICON-1600":{"nm":"誘蟲燈","de":"在黑暗中淡淡點著，小小翅膀便循著光聚攏而來。亮度要柔和，位置要離人遠些。是個把嗡嗡作響的夏夜安撫得安靜許多、再溫柔不過的招客者。"},"ICON-1601":{"nm":"昆蟲貼紙標籤","de":"六條腿配一對觸角，指甲大的紙片裡沉睡著一段小小的生涯。輕輕貼在筆記本的一角，書頁之間便靜靜展開一方草地。"},"ICON-1602":{"nm":"採集許可吊牌","de":"拿起捕蟲網之前，大人先問的話。能抓幾隻、能抓到哪。這一張小小吊牌，在雀躍的好奇與該守的約定之間，溫柔地劃下一道線。"},"ICON-1603":{"nm":"魚餌盒","de":"掀開蓋子，腥而清涼的凌晨氣味便升了上來。召喚魚兒的或許不是魚餌，而是懂得靜靜等到浮標晃動為止的那份心。"},"ICON-1604":{"nm":"浮標收納盒","de":"五彩浮標一格格躺著沉睡的小小衣櫥。有的是平靜湖面的清晨，有的是湍急水流的正午。隨著水面每種表情，把合適的搭檔細細疊好收存。"},"ICON-1605":{"nm":"釣線捲線器","de":"鬆開的線別繞在手指上。在這圓圓的工具上一圈圈回捲，糾結也會悄悄解開。與重新整理已然散亂的一天的那雙手，很是相像。"},"ICON-1606":{"nm":"脫鉤器","de":"曾徒手取鉤而被刺痛過的人，才認得出這工具。對小小生命、對我的指尖，都少疼一些的路。體貼，總是從這些瑣碎的末梢開始。"},"ICON-1607":{"nm":"貝鏟護套","de":"包覆剛從灘塗挖完的鏟刃的一層。為了不讓泥與鹹水蝕蛀刃口，在海與工具之間，悄悄夾入一段薄而柔軟的歇息。"},"ICON-1608":{"nm":"潮汐表卡","de":"水何時漲、何時退，一張巴掌大的卡片靜靜告知。把月亮與大海立下的古老約定，由人記錄下來的一張小小日曆。"},"ICON-1609":{"nm":"魚缸清潔刷","de":"把附在玻璃壁上的綠苔輕輕刷去，水中的小小世界便又滲入了光。讓某人的一天變得清澈的事，大多便是這般靜靜流淌的。"},"ICON-1610":{"nm":"水槽溫度晶片","de":"一個數字閃爍，停在恰當的度數時，魚兒們才終於安心。不太冷也不太熱的一格暖意。照料，連看不見的地方也觸及得到。"},"ICON-1611":{"nm":"海洋生物觀察箱","de":"在透明的箱裡暫住的小小客人。靜靜數一數背鰭，再送回大海。所謂觀察，不是擁有，而是暫且借看一回。"},"ICON-1612":{"nm":"化石刷","de":"喚醒沉睡數千萬年的石頭紋理的，不是鐵錘，而是柔軟的刷尖。在一急便會碎裂的時間面前，謹慎成了最深的禮數。"},"ICON-1613":{"nm":"發掘刷帽","de":"刷尖一乾透，泥土便不會細細落下。一頂小小的帽子，潤澤地守護著刷子的氣息。愛惜工具的手，邁出了發掘的第一步。"},"ICON-1614":{"nm":"地層樣本板","de":"一掌寬的泥土裡，數百年層層疊著。靜靜舀盛到這板上，那些至今看不見的時間紋路，便劃出線條，緩緩浮現。"},"ICON-1615":{"nm":"骨片托盤","de":"把零散的碎片一格格躺好，曾隨風飄散的一段生涯，便緩緩摸索著找回原位。所謂復原，是溫柔地重新追問失去的順序。"},"ICON-1616":{"nm":"復原黏接帶","de":"接連破裂之處的纖細一道。不刻意藏起傷痕，而是溫柔地擁住、固定它。破碎過的東西也能再次完整——它靜靜地證明著。"},"ICON-1617":{"nm":"展示名牌護套","de":"為了讓玻璃那頭的名牌不褪色，輕輕覆上的一張。是誰、在何處生活過，那短短一句話，盼望直到久遠的日後仍能清晰讀出，這份心意便包含其中。"},"ICON-1618":{"nm":"庫房吊牌","de":"不曾走到燈光下的珍寶沉睡的幽深房間。其中的一切都掛著小小的名牌。即使不站在明亮之處，也絕不會被遺忘。"},"ICON-1619":{"nm":"博物館捐贈信封","de":"把某人傾盡一生收藏的東西，無言地遞了出來。這信封裡裝的不是物件，而是長久珍藏的心意。分享化作最長久留存的展覽，映照著某個人。"},"ICON-1620":{"nm":"標本編號晶片","de":"在採集到的那個地方，靜靜標上一個小小的數字。何時、在何處初次相遇。沒有記下的發現，轉眼便如晨霧般消散了。"},"ICON-1621":{"nm":"流星碎片瓶","de":"劃破夜空墜落的碎片被關進了玻璃瓶裡。來不及許願便已殞落的一道光芒，如今在手中又靜靜地重新閃爍。"},"ICON-1622":{"nm":"貝殼風鈴繩","de":"把在海邊一顆顆撿來的貝殼穿在線上，掛到屋簷。每當風經過便叮叮鈴鈴，那年夏天的大海，便靜靜地跟進了屋裡。"},"ICON-1623":{"nm":"彩虹水珠","de":"雨停後在葉尖滴溜溜凝成的一滴。那圓圓的裡頭，圓圓地盛著整片天空與七彩。有時候，最小的東西能容下最遼闊的風景。"},"ICON-1624":{"nm":"霧氣採集瓶","de":"把凌晨山腳的霧氣裝了滿滿一瓶帶回來。握在手裡，便清涼而朦朧地模糊起來。是想把抓不住的東西暫且留在身邊的、溫柔而微小的一份貪心。"},"ICON-1625":{"nm":"承露杯","de":"承接草葉徹夜一滴滴積攢的露水的小杯。雖連一口都不足，但早晨最清澈、最潔淨的那部分，便靜靜蓄在那裡。"},"ICON-1626":{"nm":"風紋緞帶髮夾","de":"依風吹過的紋路原樣仿做、綁成的緞帶。別在頭上，每走一步便有微風颯颯相隨。把春日的輕盈，靜靜繫在了一枚髮夾上。"},"ICON-1627":{"nm":"浪聲膠囊","de":"靜靜湊到耳邊，遠方大海的浪便湧了上來。彷彿有人把兒時收進海螺殼裡的那道聲音，好好地封存進了一顆小小的膠囊。"},"ICON-1628":{"nm":"沙星碎片","de":"在夜晚的海灘抓起一把沙，裡頭便混著星屑閃閃發亮。是從天上掉下來的，還是被海浪細細磨成的，誰也不刻意去問。"},"ICON-1629":{"nm":"島嶼天氣紀錄晶片","de":"島上的天空一天裡也要改幾回心意。把晴、霧、陣雨一筆筆記進小小晶片，昨天的天空，今天便能再次攤開來看。"},"ICON-1630":{"nm":"懸崖階梯套件","de":"供人在陡坡上下的一階、又一階。把零散的零件拼起，懸崖也成了悠閒的散步路。所謂開路，是為某人的下一步預先鋪好。"},"ICON-1631":{"nm":"泥土路紋路捲","de":"把柔軟泥土路的紋理原樣拓下的捲軸。咻地一攤開，一條讓人想赤腳走走的鄉間小徑，便靜靜鋪到了腳下。"},"ICON-1632":{"nm":"石板路紋路晶片","de":"鋪滿舊巷的石板花紋，完整地納進了小小晶片裡。每一踩便咔噠咔噠，古老村落的腳步聲，便在腳尖復甦。"},"ICON-1633":{"nm":"海灘圍欄段","de":"為了不讓浪越過而立在沙灘上的矮欄，那一截。在海與沙之間溫柔地劃下一線而立著，是個小小而沉默的界線守衛。"},"ICON-1634":{"nm":"草地復原貼片","de":"輕輕覆在被踩踏而光禿之處的一塊綠。不消幾天，草們便互相牽起手，把空缺填補上。大自然向來都懂得自行癒合的法子。"},"ICON-1635":{"nm":"水道標示樁","de":"預先指引水流去向的木樁。為了讓雨水不致迷失該往何處，這根插在地裡的小小路標，即使下雨天也默默佇立著。"},"ICON-1636":{"nm":"小橋零件","de":"連起溪流兩岸的小巧橋樑的一塊。在這頭與那頭之間，隨時都能跨越過去的約定，便從這一塊小小零件靜靜開始。"},"ICON-1637":{"nm":"觀景台欄杆帽","de":"島上最高之處，包覆那欄杆末端的一點收尾。為了眺望遠方而聚來的人們，那雙最常觸碰的手所及之處，靜靜地承托守護著。"},"ICON-1638":{"nm":"營火承架","de":"在堆上柴火之前，承住火星不致四散的位置。在它之上仰望星空、絮絮閒談的那些夜晚，久久溫暖地燃燒著。"},"ICON-1639":{"nm":"壁紙樣本捲","de":"房間的氛圍，從一面牆開始。攤開小小的捲軸挑選顏色，是預先靜靜描摹今後想過怎樣一天的事。"},"ICON-1640":{"nm":"地板材樣本晶片","de":"用指尖先掂量赤腳將觸到的地板觸感。是暖是涼，今後將要度過的那些日子的舒適，便靜靜繫於這一小片晶片上。"},"ICON-1641":{"nm":"天花板掛鉤組","de":"在橫梁上掛起一個鉤子的瞬間，空蕩的天花板便成了等待某物的位置。掛風鈴呢，還是掛花盆呢。承住懸掛的重量靠這小小鐵鉤，但要掛什麼，由住的人的心決定。"},"ICON-1642":{"nm":"窗戶遮光膜","de":"正午的光太過坦率，便在窗上披一層薄膜。陽光照進依舊，邊角卻柔和地化開，房裡的一切都柔順成了杏色。這不是遮擋，而是讓光溫柔地暈染開來。"},"ICON-1643":{"nm":"門鈴罩","de":"說連客人按的門鈴也需要件衣裳，有人為它套上了圓圓的罩。擋雨、擋灰，更重要的是，最先送上「這裡有人住著」這第一聲問候的，是張小小圓圓的嘴。"},"ICON-1644":{"nm":"簽到簿立架","de":"為了讓每位來客都留下名字而立起的承架。墨水乾透之前，筆尖流出一行問候。到訪的腳步一行行積累，空白的本子轉眼便成了這個家最厚的相簿。"},"ICON-1645":{"nm":"家具定位釘","de":"猶豫著該不該挪的書桌位置，一根釘子咚地釘進地板便決定了。靜靜固定家具腳尖的小小釘子。位置一旦定下便會生情——地板靜靜地點了點頭。"},"ICON-1646":{"nm":"收納標籤框","de":"什麼在哪裡，抽屜終究說不出口。所以便在方框裡嵌入名牌，代它說話。一張標籤就位的瞬間，凌亂的一格格便找回了自己的名字，沉靜下來。"},"ICON-1647":{"nm":"室內香氛擴香棒","de":"棒子末端浸潤的香氣緩緩向上瀰漫。一會兒是薰衣草，一會兒又是雨後的草地。如看不見的絲線般的氣味為房裡的空氣換新，歸來之人的肩頭，一天份的疲憊便緩緩鬆開。"},"ICON-1648":{"nm":"種子袋夾","de":"把春天買下卻沒能種完的種子，連袋用夾子牢牢夾住。哪怕漏出一粒，下個季節便少了一行。小小的扣鎖裡，沉睡著整片明年的菜園。"},"ICON-1649":{"nm":"育苗盤","de":"一格格填滿泥土，為幼苗築起第一間房。一個孔裡一個生命，並排對齊生長的新生們。探頭一看，綠意成群點名的清晨，便每天在育苗盤上重新開始。"},"ICON-1650":{"nm":"澆水標示釘","de":"「我渴了。」花盆說不出話，便有小小的牌子插在土裡代它發出信號。顏色一變，就是澆水的時候。植物與人之間最小的翻譯，全在這一掌寬的小棒裡。"},"ICON-1651":{"nm":"作物支架繩","de":"怕抽高的莖會被自身重量壓彎，便用柔軟的繩子輕輕將它繫上支架。綁太緊會喘不過氣，太鬆又會倒下，綁的那雙手需要恰到好處的溫柔。連成長都有人相伴。"},"ICON-1652":{"nm":"防蟲網","de":"細密編織的網靜靜擋住覬覦嫩葉的小嘴。它讓風與陽光穿過，只把傷害之物擋在外頭，是看不見的守門人。菜園之所以平和，全靠這密實網眼的體貼。"},"ICON-1653":{"nm":"日照測量卡","de":"把一張卡立在花壇裡，靜靜問它今天曬到多少陽光。顏色加深多少，便是今日所得的光量。這張小紙片，替愛曬太陽的孩子與愛待陰涼的孩子分好各自的位置。"},"ICON-1654":{"nm":"土壤酸度試紙","de":"把試紙貼上泥土，從粉紅到湛藍，大地便用顏色坦白自己的心事。在不太酸也不太苦的地方，根才能最安心地呼吸。看不見的泥土心意，被一格格讀了出來。"},"ICON-1655":{"nm":"收穫籃標籤","de":"今天摘的是萵苣還是小番茄，每個籃子都掛上名牌。在混著泥香與青澀的收穫清晨，貼上一張標籤的瞬間，那只籃子便成了通往餐桌之路的第一個路標。"},"ICON-1656":{"nm":"種子保存瓶","de":"把今年收成的種子裝進玻璃瓶，寄給明年的春天。蓋上蓋子，時間便暫時停下，小小的顆粒在黑暗中等候自己的順序。這是一只跨越整個季節、像信一般的瓶子。"},"ICON-1657":{"nm":"嫁接膠帶","de":"把切下的枝與新枝對齊，用膠帶繞著纏好，兩者便漸漸合為一體。斷處重新流動的汁液，慢慢癒合的傷口。所謂相接，終究是彼此接納各自的紋理。"},"ICON-1658":{"nm":"修枝剪刀套","de":"在鋒利的剪刀尖端套上一頂小帽。在修剪枝條的手歇息的時候，讓刀刃不鈍、讓手不受傷。菜園說，完工的工具也需要睡衣，便把器具悉心地哄睡了。"},"ICON-1659":{"nm":"花種分類盒","de":"鳳仙花、馬齒莧、紫茉莉——名字與顏色各異的種子，在每格都分得自己的房間。混在一起，春天就分不清誰是誰了。盒中小小的隔板，預先畫好了尚未綻放的花園藍圖。"},"ICON-1660":{"nm":"花盆托盤輪","de":"再重的花盆，裝上四個輪子也能隨著陽光出門串門子。清晨在東邊窗台，正午躲到陰涼處。被重量釘住的綠意骨碌碌地滾動，整天追著光，尋找最好的位置。"},"ICON-1661":{"nm":"藤蔓引導繩","de":"不知去處、在半空摸索的卷鬚，被繩子悄悄引上正確的路。向上，再向上。只要替它定好攀附之處，植物便神奇地握住那隻手。連成長，也需要一個引路人。"},"ICON-1662":{"nm":"花語卡夾","de":"插在花旁的卡片上，寫著那朵花要說的話。繡球是真心，雛菊是純真。為了讓走過花壇成為一場讀信的散步，小小的卡夾靜靜借出了無言之花的嘴。"},"ICON-1663":{"nm":"庭園牌套","de":"怕風雨把字跡暈開，便在庭園牌上罩一頂清透的帽子。「這裡是番茄」「這裡是羅勒」。差點模糊的名字清晰地留了下來，菜園即使過了一年，也一個家人都不忘記。"},"ICON-1664":{"nm":"肥料勺","de":"替泥土添營養時，貪心反而會燙傷根。所以一勺，就那麼一勺。小小的湯匙舀起恰當的份量，提醒著——懂得照料的心，總是來自懂得適度的指尖。"},"ICON-1665":{"nm":"水霧噴頭","de":"轉動噴頭，水流便如薄霧般灑落。被猛烈水柱沖刷過的嫩葉，在露珠般的水滴下緩緩抬起了頭。同樣的水，怎麼澆下去，竟成了截然不同的問候。"},"ICON-1666":{"nm":"餵食量杯","de":"一杯，兩杯。不靠目測，而以誠心丈量朋友的一餐。太多會剩，太少又委屈，正是要去衡量剛剛好的份量。愛，有時就這樣以計量的模樣到來。"},"ICON-1667":{"nm":"換毛梳套","de":"換毛季節，套子細心地裹住纏在刷上的柔軟絨毛。梳完毛替梳子戴上帽子，隔天又是清爽的開始。同住家人的光澤，便在這樣的小小整理中悄悄滋長。"},"ICON-1668":{"nm":"指甲剪套","de":"在鋒利的指甲剪尖端套上小蓋。讓修剪完的工具，不會抓傷抽屜裡的其他物件。照料的時光結束後，連把器具安撫著哄睡，才算照顧的一個輪迴。"},"ICON-1669":{"nm":"項圈裝飾片","de":"在項圈掛上一片閃亮的小片，平常走慣的散步路便多了一分特別。在陽光下滴溜溜閃爍的小裝飾。雖不華麗，但要表明這孩子是被某人深深疼愛的家人，已綽綽有餘。"},"ICON-1670":{"nm":"動物健康卡","de":"今天吃得好嗎，有沒有哪裡不舒服。把同住朋友的一天，一行行記在卡片上。不會說話的家人狀態化作字跡留下，照料的心也跟著細緻又安穩。"},"ICON-1671":{"nm":"睡窩墊套","de":"替睡窩墊穿上鬆軟的新衣。脫下被翻滾蹭磨而磨損的布，曬過太陽的絨毛香撲鼻而來。把躺得最頻繁的位置打理得最乾淨，是為同住家人付出的每日心意。"},"ICON-1672":{"nm":"小圍欄釘","de":"在花壇邊緣一一插下小釘，立起低矮的圍欄。這不是別越界的恐嚇，而是「到這裡就是花的位置」這般溫柔的界線。有所守的線，花才能在其中安心生長。"},"ICON-1673":{"nm":"親密零食罐","de":"再怕生的孩子，聽到搖晃這罐子的聲音也會豎起耳朵。裡頭裝著一把能打開心房的零食。要拉近距離，小小的約定比言語更快，叮噹作響的聲音便先一步走近。"},"ICON-1674":{"nm":"散步紀錄牌","de":"今天走了哪條路、走了多遠，像打結般把紀錄繫在牌子上。腳印聚起來成了地圖，地圖聚起來成了回憶。一同走過的每一天，都在這小小的標牌上一層層堆疊。"},"ICON-1675":{"nm":"鳥食碟","de":"在窗台放只碟子，擺上幾粒小米，叫不出名字的客人便依序飛來。叩叩的啄食聲，撲撲的振翅。施捨的一把，每天清晨都帶來一場小小的音樂會，是個迷你的餐桌。"},"ICON-1676":{"nm":"松鼠觀察筒","de":"在透明的筒裡，與松鼠圓圓的眼睛對上。腮幫塞滿橡實、歪著頭的模樣，真是可愛。在「看一會兒就放它走」的約定上，與小小的野性短暫地打個招呼。"},"ICON-1677":{"nm":"腳印石膏模","de":"倒入軟軟的石膏，翻印出小小的腳印。等待凝固的時候，院子裡的時間也暫時停了下來。那長大就會消失的一掌腳印，被白色的模子如永恆般拓下，輕輕放進兩手心。"},"ICON-1678":{"nm":"夜間觀察鏡頭蓋","de":"在窺看夜色的鏡頭尖端蓋上小蓋。讓看過星星與鳥巢的玻璃珠，不沾一絲塵埃地等待下一個夜晚。能看清黑暗的眼睛，也需要白天裡的一個逗號。"},"ICON-1679":{"nm":"鳥巢保護標誌","de":"在枝椏間發現鳥巢時，與其靠近，不如立起標誌。「這裡有鳥家庭，請安靜。」守望卻不侵犯的距離——那溫柔退後的一步，最能讓鳥巢安全。"},"ICON-1680":{"nm":"動物聲音錄音片","de":"草叢裡的歌、簷下的啁啾、夜裡的草蟲聲，不囚進片中，只暫時借來。再次播放，連那一刻的空氣都會復甦的小小聲音盒。為了讓所有聽過的，都不會消失。"},"ICON-1681":{"nm":"觀察望遠鏡套","de":"在一隻鳥即將振翅而起前，森林暫時屏住了呼吸。在那寂靜的瞬間，蓋住鏡頭的一塊布，守護著遠方的清晰，不沾一點指痕。"},"ICON-1682":{"nm":"林徑相機帶","de":"每攀上陡峭的林徑，相機便輕輕碰著胸口。怦動的心跳與快門聲以同樣的節拍搖晃，這一條帶子，把那些瞬間穩穩地繫在胸前。"},"ICON-1683":{"nm":"自然解說卡","de":"卡片靜靜告訴你，連一株草都有名字。為不知不覺錯過的事物取了稱呼，山路便忽然親切地擠滿了熟悉的臉孔。"},"ICON-1684":{"nm":"桅帆修補貼","de":"以全身承受風的布料，也會留下傷痕。只憑一小塊靜靜補上撕裂處的布，帆便重新取得了擁抱遠海的資格。"},"ICON-1685":{"nm":"繩結板","de":"向上、向下、再繞一圈——手所記住的那道順序，便成了繩結。在風暴拍打甲板的夜裡，那一道程序，把人與船緊緊綁在一起。"},"ICON-1686":{"nm":"錨鏈保護蓋","de":"別小看這頂套在鐵鏈末端的小帽。鏽會在裡頭悄悄滋長，這頂背對海風、擋在前頭的蓋子，靜靜延長了錨的壽命。"},"ICON-1687":{"nm":"航道標誌旗","de":"在霧濃得抹去前路的日子，一面旗替你說出方向。隨風飄揚的一抹顏色，終於鬆開了迷途舵手僵硬的肩膀。"},"ICON-1688":{"nm":"船艙鑰匙圈","de":"在搖晃的海上，狹窄的船艙門掛著一個小圈。只要鑰匙守在原位，便總有一間可回去的房，不會對你上鎖。"},"ICON-1689":{"nm":"防水地圖套","de":"在雨中，紙地圖會先抹去道路。在透明的套子裡，那一張保持乾爽地撐著的時候，濕透的旅程也終究不會迷失方向。"},"ICON-1690":{"nm":"船燈燈芯","de":"燈芯緩緩吸起的油，終於綻放成火焰。甲板上的一點光，僅憑那小小的顫動，夜海遙遠的距離便悄悄拉近了。"},"ICON-1691":{"nm":"求救信號布","de":"在聲音傳不到的距離，高舉揮動紅布的手，比話語走得更遠。這一幅布劃破風，替你高喊——這裡有人還活著。"},"ICON-1692":{"nm":"海風方向釘","de":"懂得風從何處吹來的人，才能決定航道。在小釘靜靜指向的一個方向上，今日一整天航行的命運，悄悄倚靠了過來。"},"ICON-1693":{"nm":"折疊鏟套","de":"把刀刃折起蓋好，勤快的鏟子也暫時喘口氣。鏟完泥土的手最後做的事，是好好照料明日的刀刃，不讓它變鈍。"},"ICON-1694":{"nm":"便攜指南針盒","de":"針總是毫不動搖地指向北方，但守護那根針的，是堅固的盒子。越是迷過一次路的人，越懂得珍惜方向。"},"ICON-1695":{"nm":"露營餐具網","de":"把洗好的碗掛在網上，曬乾在清晨的陽光裡。營地的一天，從水氣蒸乾的聲音開始，那份微不足道，把帳篷裡填得安穩踏實。"},"ICON-1696":{"nm":"露營許可卡","de":"這是在這座山留宿一晚也無妨的許可。一張紙握進手中的瞬間，陌生的森林也暫時成了我的盟友，靜靜接納了一頂小帳篷。"},"ICON-1697":{"nm":"探險路旗繩","de":"在每個岔路繫上旗子，回程便不會在黑暗中迷散。先行者留下的一個小標記，靜靜推著後來者的背。"},"ICON-1698":{"nm":"防水火柴盒","de":"火柴只要沾上一滴水，便會永遠沉默。在連一點水都進不去、密封的盒中，火種乾爽地靜靜等候，只為最冷的那一夜。"},"ICON-1699":{"nm":"便攜淨水濾芯","de":"渾濁得令人猶豫的水，經過這只濾芯也會澄清。比起渴，更先讓人放下疑慮的小裝置——「可以喝」的信任，本身就是一口的安歇。"},"ICON-1700":{"nm":"緊急毛毯包","de":"折起只有巴掌大，攤開卻是一個人的暖意。為了讓「緊急」這詞不那麼沉重，毛毯總在背包一角，隨時準備好暖起來。"},"ICON-1701":{"nm":"夜間標誌手環","de":"夜幕落下的山路上，一隻手腕靜靜發出光。那條告知彼此位置的小帶子，用看不見的繩，把同行的人溫柔地連在一起。"},"ICON-1702":{"nm":"礦工頭盔貼紙","de":"貼在頭盔上的貼紙，是礦工的另一張名牌。在連光都珍貴的深處坑道，靠映在燈光下的那一個小圖案，便能欣然認出同伴。"},"ICON-1703":{"nm":"礦脈標記釘","de":"在找到礦脈的地方，靜靜插下一根釘。在黑暗中獨自閃亮的一點，溫柔地告訴下一位來者：就從這裡開挖。"},"ICON-1704":{"nm":"裂縫測量尺","de":"測量牆上的裂縫，是緩慢而堅韌的忍耐。比昨天多裂了一掌寬嗎，尺所告知的小小數字，預先點破了崩塌。"},"ICON-1705":{"nm":"遺跡紋樣拓本紙","de":"把紙貼在刻於石上的紋樣上，輕輕拍打墨。千年前的手痕以黑色的紋理浮現的瞬間，拓本讓流逝的時光暫時與你對坐。"},"ICON-1706":{"nm":"古錢幣盒","de":"為不生鏽而靜靜沉睡的這塊小鐵片，藏著某個消失國度最後的聲音。一枚錢幣裝著一個時代，在透明的盒中緩緩老去。"},"ICON-1707":{"nm":"水晶碎片底座","de":"把光封在內裡的水晶，也需要倚靠之處。靜靜安放在小小底座上的瞬間，易碎之物才終於完整展開自己的晶瑩。"},"ICON-1708":{"nm":"洞窟地圖殘片","de":"撕裂的地圖，只悄悄露出一半的祕密。直到找出剩下的碎片那天為止，這一張仍在洞窟某處，把餘下的路藏住一半。"},"ICON-1709":{"nm":"繩索下降環","de":"要把身體交給崖底，得先完全信任這個環。把重量託付給一塊冰冷的鐵——信任，本就是如此沉甸甸的東西。"},"ICON-1710":{"nm":"發掘許可證","de":"清楚蓋著「可以挖掘」印章的一張紙。要喚醒埋藏之物，得先求得許可，發掘靜靜地教人，以禮數開始的道理。"},"ICON-1711":{"nm":"擋風包","de":"背對風攤開，便在狂野原野的正中央生出一坪的寧靜。這一層的背後守著小小的火種，讓疲憊的人暫得歇息。"},"ICON-1712":{"nm":"沙塵暴護目鏡套","de":"即便沙塵兇猛地席捲，視野也得守到最後。蓋住眼鏡的一張薄套，成了在風暴中也能睜眼走出去的勇氣。"},"ICON-1713":{"nm":"雨天訪客托盤","de":"來訪客人的鞋尖滴滴答答落下雨水。靜靜擺在玄關前的一只托盤，無言地溫暖接住了濕冷的腳尖。"},"ICON-1714":{"nm":"酷暑降溫掛牌","de":"靜靜冷卻正午熱氣的小掛牌。掛在包上含著清涼，等到汗珠快冒出時，便悄悄遞上一把陰涼。"},"ICON-1715":{"nm":"寒流暖暖包帶","de":"在腰上繞一圈的溫暖帶子。當暖暖包的熱意順著背脊蔓延，凜冽隆冬的原野也變得稍稍可以忍受。"},"ICON-1716":{"nm":"防潮吸濕包","de":"潮濕無聲地啃蝕著物件。當盒中的小包默默吸去濕氣時，珍愛之物便乾爽地守住了自己的模樣。"},"ICON-1717":{"nm":"泥地鞋套","de":"有時即便踩過泥淖，唯獨鞋子得保持乾淨。這片擋泥的薄罩，讓歸來跨過門檻的腳步輕快了許多。"},"ICON-1718":{"nm":"海霧燈套","de":"當海霧想把燈火整個吞下時，這只套子靜靜聚攏散開的光紋。即使在朦朧的清晨，港口的一盞燈也終究不滅。"},"ICON-1719":{"nm":"落雷注意釘","de":"烏雲低低壓下時，一根釘先遞來警告。在閃電劈下前放低身子——在自然面前的謙卑，總是提前學好為妙。"},"ICON-1720":{"nm":"食譜書籤","de":"夾在攤開料理書間的小書籤。在爐火前漏看的那一行重新摸索找回時，母親的手藝也在那一頁一同甦醒。"},"ICON-1721":{"nm":"調味分裝棒","de":"媽媽總只說「一撮」。目測不可能準確，可那手藝卻從未走樣。用這支棒子掂量鹽的時候才明白，比計量更陳熟的，不是估量，而是愛。"},"ICON-1722":{"nm":"發酵蓋帶","de":"你知道甕也會呼吸嗎？這條帶子把蓋子緊緊抱住，裡與外便慢慢開始交談。直到不急不徐的那幾天過去，等待才終於得到「味道」這個名字。"},"ICON-1723":{"nm":"熟成標籤片","de":"工整寫下醃漬日期貼上的小片。字跡漸漸模糊，裡頭的東西卻反而更深。裝作忘記地寫下，某天又突然取出，熟成便是這般守護的約定。"},"ICON-1724":{"nm":"湯汁濾網","de":"清澈的湯，是過濾再過濾之後才來的。看著那只攔住渣滓、只靜靜流下精華的網，舊廚房那句「捨去之處才積得起深度」的話，便從指尖傳了過來。"},"ICON-1725":{"nm":"麵糰發酵布","de":"在麵糰上靜靜蓋一塊布。在那昏暗之下酵母勤奮膨脹的時候，初次學會了那些在看不見處靜靜生長之物的溫柔。"},"ICON-1726":{"nm":"食材處理夾","de":"劃開大蔥的紋理、俐落夾住蒜頭的小夾子。處理就像對食材道的第一聲問候，用心修整多少，晚餐餐桌的光便亮上一個色階。"},"ICON-1727":{"nm":"擺盤夾","de":"盤上最後一點要擺在哪兒，終究由這只夾子決定。熟練的手在半空猶豫半拍的那短短一瞬，一餐便悄悄成了一幅畫。"},"ICON-1728":{"nm":"保溫便當套","de":"在校門前接過的便當，得一直暖到午餐鐘響。被關在這套子裡的暖意，不會冷掉——那厚度，正如某人從清晨就站在爐火前的心意。"},"ICON-1729":{"nm":"用餐邀請券","de":"「來我家吃頓飯吧。」還有比這更溫暖的話嗎？沒有誇張的約定，只是請你同坐一桌，這一張，裝著用韓語所能遞出最古老的邀請。"},"ICON-1730":{"nm":"桌位預約片","de":"寫下名字，把位置留住。一個小小的片子，把空桌暫時繫成某人的所有，那約好的時刻，便如腳步聲般緩緩走近。"},"ICON-1731":{"nm":"試吃評價卡","de":"咬下一口，神色頗為認真地打起星等的臉龐。在這張卡上工整寫下的誠實一行，是讓下一盤更美味的、最溫暖的叮嚀。"},"ICON-1732":{"nm":"便當感謝帶","de":"在乾淨吃光的便當盒上繞一條帶子送回。連終究沒說出「吃得很好」的人，至少這個結，也替他把難以開口的心意綁起傳達。"},"ICON-1733":{"nm":"過敏標示掛牌","de":"這一個小掛牌，靜靜守護某人的餐桌。把裡頭放了什麼工整地標明，是連看不見之處都用心的款待之另一個名字。"},"ICON-1734":{"nm":"味道記憶湯匙","de":"久留舌尖的那味道，其實是那天的風景。一勺便瞬間將人帶回童年的廚房，可見記憶不是由胃，而是由心舀起珍藏的。"},"ICON-1735":{"nm":"今日菜單代幣","de":"今天吃什麼。在世上最難的問題面前，我們每每敗下陣來。把這枚代幣輕輕一翻、將菜單交給命運後，心意外地輕快又愉悅。"},"ICON-1736":{"nm":"共餐餐桌鈴","de":"鈴一響，散在各房的家人便聚到一處。圓桌上那聲鈴響，是把「好了，快來」這句話譯得最溫情的版本。"},"ICON-1737":{"nm":"甜點順序表","de":"甜的總在最後。這張表替你守住那道不知是誰定下的約定。它是把口味的高潮一直留到甜點一口的、小巧而溫柔的餐桌司儀。"},"ICON-1738":{"nm":"議價代幣","de":"市場正中央，「便宜點啦」與「這已經虧本了」親切地碰撞。這枚代幣，是那場討價還價終究以笑聲收場的、老主顧的收據。"},"ICON-1739":{"nm":"庫存確認釘","de":"靜靜掃過倉庫貨架，找出空格插上釘。知道剩下什麼、缺了什麼，過日子這樁大事，總是從這微不足道的檢點開始。"},"ICON-1740":{"nm":"貨架清掃刷","de":"收市的傍晚，掃過空蕩貨架的刷聲在店裡低低鋪開。預先擦好明日要重新填滿的位置，那指尖沾著把一天好好收尾的勤勞。"},"ICON-1741":{"nm":"今日推薦卡","de":"「今天這個好喔。」老闆悄悄遞出的一張卡。在那輕推猶豫不決客人肩膀的推薦裡，端正地裝著一天份的自豪。"},"ICON-1742":{"nm":"常客集章夾","de":"集滿十次就免一次。印章格一格格填滿的這只夾子，是「常客」一詞的另一張臉，而常來，終究就是喜歡的意思。"},"ICON-1743":{"nm":"交換帳冊夾","de":"把交換歸還之物的紀錄聚在一處夾住的夾子。往來越多，帳冊便越厚，與鄰里堆起的信任，也隨那厚度而豐厚。"},"ICON-1744":{"nm":"售罄標籤","de":"最後一個貼上這張標籤的瞬間，心裡奇妙地盈滿。這是給即將前往某人餐桌、某間房一角的物件，道一聲「再見」般短短的相送。"},"ICON-1745":{"nm":"預訂商品籃","de":"掛著你名牌的籃子守著貨架上的一格。那預先留好的一個位置，靜靜對踏進門的你說：「我一直在等你。」"},"ICON-1746":{"nm":"包裝台墊","de":"鋪在包裝台上的墊子，是忙碌手勢的舞台。紙被折起、繩被工整繫好的那短短時間裡，平凡的物件便悄悄變成了某人的禮物。"},"ICON-1747":{"nm":"拜訪約定便條","de":"「明天會過來。」寫下一行，輕輕夾進門縫的便條。在彼此來不及見面的空檔，約定也乘著一張紙，比人先一步抵達，靜靜等候。"},"ICON-1748":{"nm":"鄰里禮物籃","de":"越過牆遞來的籃子裡，總一併裝著「做太多了啦」的藉口。韓國的人情便這樣裝作寬裕地佯裝若無其事，悄悄越到這一邊來。"},"ICON-1749":{"nm":"村里消息箱","de":"村裡大大小小的消息在這箱中一層層堆積。誰新搬了來、誰家辦喜事，幾張紙聚起來，傳遞著小鎮平靜的脈搏。"},"ICON-1750":{"nm":"感謝拜訪印章","de":"把感謝來訪的心意，用一枚印章重重按下。在紙上暈開的那一道墨痕，比「我不會忘記」這句話，更長久地留在那裡。"},"ICON-1751":{"nm":"親切讚美卡","de":"把今天某人遞來的親切靜靜寫下、再傳回去的卡片。在這個特地把小小溫柔寫成文字留下的村子裡，好事總是一再地兜兜轉轉回來。"},"ICON-1752":{"nm":"道歉信封緘","de":"如同熟透的紅蘋果，道歉的話也要在充分熟成後才能遞出。重重按在信封上的這道封緘，是把難以啟齒的歉意守到最後的勇氣印記。"},"ICON-1753":{"nm":"協作分工表","de":"把誰負責什麼一格格分開寫下的一張表。獨自吃力的活兒，把名字分著寫，便輕鬆許多——並肩做過事的人，都懂這個道理。"},"ICON-1754":{"nm":"鄰里喜好緞帶","de":"用各色緞帶靜靜標記鄰人喜歡什麼。把某人的喜好記在心上，是不必特地說出口的、最安靜的疼愛之告白。"},"ICON-1755":{"nm":"邀請門牌掛環","de":"用掛在門牌上的一個環，告知「今天接待客人」。雖只是巴掌大的標記，裡頭卻掛著一顆已備好迎人、敞開的心。"},"ICON-1756":{"nm":"慶典入場手環","de":"捨不得解下、戴了好幾天的一條褪色帶子。繫上手腕的那一刻，慶典才終於開始。裡頭，安睡著一個結束了卻終究未盡的一天。"},"ICON-1757":{"nm":"煙火票夾","de":"夜空爆開前的一刻，這夾子裡的票緊緊握住悸動。為了那「砰」一聲、第一朵煙火綻放的瞬間，握到掌心冒汗的約定。"},"ICON-1758":{"nm":"迎月盤","de":"曾有那樣的夜，彷彿把整輪滿月舀進碗裡。在這盤上盛好時令鮮果與松糕，向月亮行禮，一顆圓滿的心便直達天際。"},"ICON-1759":{"nm":"冬季慶典手套釘","de":"在雪地裡凍僵了手，手套也老是從手腕溜出去。直到這枚釘俐落地扣在袖口上，才終於能盡情奔跑在冬季慶典裡。"},"ICON-1760":{"nm":"迎春種子卡","de":"卡中沉睡的幾粒種子，各自等候著春天。埋進土裡，便如約定般準時冒芽，可見一切的開始，似乎都源於小而堅實的一點。"},"ICON-1761":{"nm":"夏日海灘印章","de":"海浪在沙上重重按下一印，又緩緩退去。明知很快會被抹去，仍留下「這裡有人來過」的小小標記。夏天總這樣鮮明地蓋下一回，便隨鹹味流走。"},"ICON-1762":{"nm":"秋日收穫緞帶","de":"綑紮穀粒的手，最後將緞帶細細繫好。把一年的汗水悉心收束的一個結。即便田野漸空，秋天仍以最美的色彩，如晚霞般再道一次別。"},"ICON-1763":{"nm":"紀念攝影對話框","de":"「謝謝你來到這裡。」終究沒能說出口的問候，在紙上圓圓地鼓了起來。為照片中靜止的沉默，悄悄借出聲音的、一片圓圓的心。"},"ICON-1764":{"nm":"慶典場地圖釘","de":"怕你在偌大廣場迷路，某人特地戳下的標的。即便腳步先被農樂聲拉了去，這一根釘也會把迷途的你，靜靜帶回約好的位置。"},"ICON-1765":{"nm":"專輯主鑰匙","de":"鎖住的不是唱片，而是封存其中的時間。第一次錄音的顫抖、最後混音的清晨。緩緩轉動鑰匙，只有製作者才知道的那間房門，便咿呀開啟。"},"ICON-1766":{"nm":"曲目清單卡","de":"一張紙上寫的曲序，其實是心的順序。在哪裡哽咽、在哪裡調息，紙早已全然知曉。在聽到第一個音之前便先盈滿的悸動。"},"ICON-1767":{"nm":"音源檢核掛牌","de":"只有把同一段倒帶聽了上百回的人，才會貼上這張掛牌。再一次，就再一次吧。通過印章旁，藏著某人聽到天明、不敢相信自己耳朵的夜。"},"ICON-1768":{"nm":"預購標籤","de":"對尚未問世之物，先許下等候的約定。標籤貼上的瞬間，一個空位便以某人的名字靜靜被預留。連雀躍的等待，也有號碼牌。"},"ICON-1769":{"nm":"初版封緘貼紙","de":"與從前在甕上蓋韓紙、用漿糊封緘的手痕相似。是要守住最初原樣的一張。明知撕下便會消失，便一再地、更久地端詳那道封口。"},"ICON-1770":{"nm":"回歸日曆片","de":"日曆上多畫一個圈，到那天為止剩下的夜便短了一格。握在手中的小片上，回歸的日期清清楚楚。對等待的人而言，時間就是這樣用手數的。"},"ICON-1771":{"nm":"概念照內襯","de":"在下一個概念把上一個概念的顏色推開之前，把那紋理悉心夾住的透明一張。為了即便換了季也不被遺忘，連邊角都靜靜守住昔日的色彩。"},"ICON-1772":{"nm":"預告公開代幣","de":"在揭開面紗之前，握在掌心的一枚小錢幣。遞出它的瞬間，鎖住的第一個畫面便朝世界開啟一掌寬。所謂公開，終究是誰先伸出手的事。"},"ICON-1773":{"nm":"唱片陳列底座","de":"一個低矮的底座把唱片稍稍托起的瞬間，平凡的一張便成了陳列檯的主角。無言地在背後撐起光最美落下角度的、溫柔配角。"},"ICON-1774":{"nm":"出道展示會通行證","de":"印著「初次為您獻上」一句的一張通行券。從舞台後長長的走廊，到觀眾席的第一陣掌聲，這張證讓人跨過出道那顫抖的門檻。"},"ICON-1775":{"nm":"首次舞台走位片","de":"用腳尖靜靜摸索貼在地上的片子。不必看，身體也先知道的一格。在記熟的位置精準觸到的瞬間，指尖的顫抖才終於成了清晰的動作。"},"ICON-1776":{"nm":"問候致詞卡","de":"「全是託各位的福」這般尋常的話，若以顫抖的手寫下，便不再尋常。怕激動忘詞而預先寫好的幾行。真心，有時要倚靠一張卡片。"},"ICON-1777":{"nm":"形象拍攝預約表","de":"工整寫著要站到鏡頭前那一天的一張。是慢慢備好最佳面容的時間表。空格一格格被填滿，鏡前停留的夜也跟著變長。"},"ICON-1778":{"nm":"後援會加入單","de":"把名字與心意寫在一行，羞怯遞出的入場之紙。喜歡這句話總是難以啟齒，但這一張單子，替你工整地代寫了出來。是決定同行的第一個簽名。"},"ICON-1779":{"nm":"出道禮物檢核表","de":"想著收禮的人，一一檢點的手。邊角有沒有磨損，心意有沒有遺漏。禮物在遞出之前，便已先被疼愛了一回才上路。"},"ICON-1780":{"nm":"舞台結尾標誌","de":"幕落前最後一個姿勢停留之處所放的標誌。它不是宣告結束，而是把結尾細細收束的小小一點。唯有好好闔上的舞台，才能開啟下一個舞台。"},"ICON-1781":{"nm":"訪談待命釘","de":"靜靜守著提問開始前那份寧靜的釘。在腦中挑選答案的短暫沉默裡，這個小標記溫柔地替你說：「還沒，就快了。」"},"ICON-1782":{"nm":"出道紀念信封","de":"如同從前把珍貴書信連封遞給遠行之人的心意，把首次舞台的紀錄悉心收進的一層。多年後開封那天，連那天的顫抖都會嘩啦一同傾瀉而出。"},"ICON-1783":{"nm":"聲樂呼吸吸管","de":"用細細的管口，把氣息長長地、一線地送出的練習。歌唱終究是調理好的呼吸，這支小吸管每天清晨靜靜這樣提醒。比起聲音，先從氣息開始。"},"ICON-1784":{"nm":"節拍訓練滴答片","de":"滴、滴、滴——世上最誠實的朋友。快了便拉住你，慢了便推你的背。把節拍刻進身體，就像與這塊堅實的片子進行的一場長談。"},"ICON-1785":{"nm":"舞線確認緞帶","de":"指尖在哪兒停、肩膀在哪兒打開，用一條緞帶靜靜勾勒動作的線條。畫得好的舞線，連觀眾席看不見的地方，都筆直而端正。"},"ICON-1786":{"nm":"表情回饋卡","de":"連笑都是要學的，那句話。把眼角的角度與嘴角的高度一筆筆記下的一張。鏡子來不及告知的表情，由這張卡溫柔地代為提點。"},"ICON-1787":{"nm":"饒舌flow備忘","de":"「這裡稍歇，那裡傾瀉」——預先描好話語水路的備忘。越快的段落，呼吸的路徑越要清晰。隨手寫下的箭頭裡，一段的節奏正鮮活地呼吸著。"},"ICON-1788":{"nm":"發聲溫度貼紙","de":"嗓音也有溫暖的日子與寒冷的日子。把今天的紋理選個顏色貼上的小標記。一邊溫熱一邊放涼，聲音每天都以略為不同的溫度甦醒。"},"ICON-1789":{"nm":"休息常規代幣","de":"好好休息也是實力，這樣說著塞進手裡的一枚錢幣。遞出它，便能毫無罪惡感地暫時停下。對一路奔跑的人而言，停下是最有勇氣的選擇。"},"ICON-1790":{"nm":"成長目標釘","de":"「先試著走到這裡吧」而戳下的小釘。看似觸手可及卻又遙遠，仍每天朝那方向一步步生長。所謂目標，就像在遠處招手的、溫柔的約定。"},"ICON-1791":{"nm":"週評信封","de":"把一週的汗與淚，一層層裝進一個信封遞出。做得好的與遺憾的並排放著。開封這件事，是給下週的自己留下的小小作業。"},"ICON-1792":{"nm":"舞台裝飾零件盒","de":"閃亮的舞台背後，住著無名的零件。一顆螺絲、一個掛環聚起來，托起天花板的星。打開盒子，滿是默默撐起華麗的瑣碎心意。"},"ICON-1793":{"nm":"服裝概念板","de":"把布料與顏色一片片貼上，預先試穿這世上還不存在的衣裳。在板上先行完成的舞台服。想像，總比針線早一步前行。"},"ICON-1794":{"nm":"配色試穿片","de":"同一件衣裳，隨光線也會換上截然不同的面孔。哪種顏色與那人笑得最燦爛，便一片片比對著找。所謂相襯，是久久比較之後的發現。"},"ICON-1795":{"nm":"鞋帶樣本板","de":"替舞台上堅實的一步負責的，意外地是一條小小的帶子。要不鬆脫，卻又不憋悶。把多種紋理排開挑選，是最低處的、溫柔的斟酌。"},"ICON-1796":{"nm":"飾品檢核信封","de":"越是閃亮之物，一道刮痕便越顯眼。把信封裡的飾品對著光細細端詳的手。把小東西看到最後的那份心，守護著舞台。"},"ICON-1797":{"nm":"髮色試片","de":"替頭髮預先穿上新季節的小樣本。在一綹上悄悄染上的色，靜靜透露下一個概念的第一印象。改變，總是從巴掌大的地方開始。"},"ICON-1798":{"nm":"美甲概念卡","de":"預先定好要畫在十指尖的小圖案的一張。為了連一個手勢都隱隱透出概念，連最微不足道的細節，都用心賦予了故事。"},"ICON-1799":{"nm":"造型變更券","de":"「今天要不要成為和昨天稍有不同的我」——讓這一句成真的一張券。無論髮型、衣裝還是氣氛，這張券都為你開啟通往全新模樣的、雀躍之門。"},"ICON-1800":{"nm":"尺寸修改掛牌","de":"把要收要放的地方，悉心寫下直到合身為止的掛牌。如同從前一針針替孩子改衣的手，這小小的調整，讓舞台又舒適了一寸。"},"ICON-1801":{"nm":"縮圖草稿卡","de":"一張尚未上色的畫面。在粗糙的鉛筆線條上，靜靜揣摩著下一幕將流向何方。比起完成，更令人雀躍的永遠是這未竟的第一行——安靜的剪輯室如此低語。"},"ICON-1802":{"nm":"拍攝同意貼紙","de":"「我可以入鏡嗎？」不用言語，只在胸前貼上一枚圓圓的標記。一張小小的貼紙，在鏡頭與心意之間立下了溫柔的約定。"},"ICON-1803":{"nm":"拍照牆站位釘","de":"釘在牆角的一枚小釘。是事先決定誰站在哪裡的位置。每個釘下之處都停駐著一抹笑容，化成一張照片。"},"ICON-1804":{"nm":"選鏡籌碼","de":"在數百張畫面中只點選其中一張的手指。放下這枚籌碼的瞬間，那些被收起的表情也彷彿都是為了這一張而活過。挑選一事，總是像一場安靜的告別。"},"ICON-1805":{"nm":"幕後信封","de":"鏡頭背後發生的事都收在這裡。摺起封口，笑聲、NG與睏倦的呵欠便一同沉睡。比起正片更讓人珍惜的，往往是這裡頭。"},"ICON-1806":{"nm":"剪輯需求便條","de":"「這裡再多1秒，音樂稍微調小。」寫滿紅字的紙條。某人的講究，為影片的呼吸調整了一個節拍。完成度，正是在這些細微的手藝上成長。"},"ICON-1807":{"nm":"上傳排程標籤","de":"貼在明早7點將自動現身世界的影片上的小小標記。眾人都睡著時，唯有約定醒著。預先設好的時間，從不懂得遲到。"},"ICON-1808":{"nm":"縮圖畫框護套","de":"包覆最上鏡那第一幕的罩子。讓手垢與灰塵都碰不到，把邊角端整地收攏。在被展示之前，第一印象就這樣被細心守護。"},"ICON-1809":{"nm":"影片時長籌碼","de":"估量今天拍下的時間有幾分鐘的小籌碼。長未必好，短也未必輕。懂得恰當長度的心，是剪輯的第一顆鈕扣。"},"ICON-1810":{"nm":"應援口號校對表","de":"在放聲喊出之前再核對一次的紙。一個字錯了，數千道嗓音就會散開。在吶喊的背後，看不見的校對之手早已先行造訪。"},"ICON-1811":{"nm":"粉絲畫作收藏套","de":"某人徹夜畫成的一幅畫。給它一個透明的家，不讓它被揉皺。彷彿在說用心畫的就該用心呵護才能長久，套子默默將它擁入懷中。"},"ICON-1812":{"nm":"粉絲來信分類繩","de":"依寄件人把堆積如山的信件整齊綁起的繩子。一個結裡，整理著一天份的思念。即使無法回信，也不願漏掉任何一封的那雙手，就在這裡。"},"ICON-1813":{"nm":"周邊交換預約表","de":"「有人想跟我交換嗎？」把忐忑的心寫下遞出的紙。只因喜歡同一樣東西，初次見面的彼此就短暫成了朋友。"},"ICON-1814":{"nm":"團體應援座位籌碼","de":"為穿著同色衣裳的人決定並肩而坐的籌碼。當散開的心聚到同一區，觀眾席便如一個巨人般開始歌唱。"},"ICON-1815":{"nm":"生日廣告收據","de":"在電子看板上投放愛意後收下的一張收據。金額旁沒寫出的，是徹夜攢下的心意。這張紙，將作為只朝向一人的祝福之證留存。"},"ICON-1816":{"nm":"留言冊封面","de":"包覆眾人手寫文字所匯集之冊的封皮。翻開來，各異的字跡以同一份心意交疊。外表端整，內裡卻滿是溫暖的喧鬧。"},"ICON-1817":{"nm":"粉絲俱樂部會員別針","de":"只遞給呼喚同一個名字之人的小別針。別在胸前的瞬間，獨自一人的喜歡便化作眾人的約定。歸屬感，就是這樣圓圓的形狀。"},"ICON-1818":{"nm":"線上應援代幣","de":"遠隔的雙手隔著螢幕揮舞的一點光。距離雖遙遠，節拍卻一模一樣。是即使在看不見的位置，應援也必定送達的證據。"},"ICON-1819":{"nm":"陳舊鑰匙碎片","de":"缺了齒的一塊鐵片。它曾開過哪扇門，如今已無人記得。比起被鎖之處活得更久的，總是這類失去用途的鑰匙的半片。"},"ICON-1820":{"nm":"秘密通道地圖","de":"畫著藏在常春藤後那條路的舊紙。捷徑只有知道的人才知道。攤開的瞬間，平凡的小島便悄悄換上一張冒險舞台的面孔。"},"ICON-1821":{"nm":"密碼解讀卡","de":"把雜亂散落的字還回原位的卡片。一行對上了，下一個秘密便招手示意。看似解不開的結，最終也是從第一個字開始。"},"ICON-1822":{"nm":"封印箱繩","de":"彷彿叮囑著別打開般緊緊纏繞的繩子。結裡沉睡著什麼，只有綁的人知道。想解開的心與想守護的心，並排綁在這一條繩上。"},"ICON-1823":{"nm":"遺跡拼圖籌碼","de":"從古老石牆上剝落的小碎片。拼回原位，千年前某人的手藝便在指尖復甦。把散落之物聚攏，就是把時間重新接續。"},"ICON-1824":{"nm":"島嶼傳說剪報","de":"親手抄錄漂流於島上的古老故事的紙。是真是假其實並不重要。口耳相傳而來的故事，本身便成了島嶼的年輪。"},"ICON-1825":{"nm":"隱藏標記石","de":"彷彿隨意擱在路邊的一塊石頭。只在懂得的人眼裡，靜靜指出方向。越是想深埋的秘密，越是以最平凡的面孔佇立在那裡。"},"ICON-1826":{"nm":"謎題信封","de":"封面上什麼也沒寫。拆封前的這片刻最是心跳。在把答案握在手中之前，所有可能性都還活在信封裡。"},"ICON-1827":{"nm":"偵探放大鏡蓋","de":"靜靜套在放大鏡末端的小蓋。不查看時，讓鏡片安靜地歇息。想看清，得先好好守護——偵探早早便學會了這一點。"},"ICON-1828":{"nm":"環島巴士票","de":"搭上繞島一圈的巴士的一張票。終點便是起點。在繞了又繞回到原處的路上，風景每次都看來略有不同。"},"ICON-1829":{"nm":"自行車租借標籤","de":"掛在租來的自行車把手上的一張牌。直到歸還之前，允許片刻的自由。乘風的時光結束時，這標籤便靜靜收回那份約定。"},"ICON-1830":{"nm":"小船乘船券","de":"登上一艘小船的乘船券。在搖晃的甲板上，島與島之間拉近了距離。渡過水路一事，總是同時帶來一點雀躍與一點暈眩。"},"ICON-1831":{"nm":"板車車輪釘","de":"穩穩扣住板車車輪的釘子。這一枚小鐵，讓沉重的貨物得以滾動。最不起眼的零件，往往默默承受著最多的重量。"},"ICON-1832":{"nm":"纜車代幣","de":"投入劃過空中的纜車的圓圓代幣。雙腳離地的瞬間，整座島一覽無遺。升得越高，風景就越發寬厚。"},"ICON-1833":{"nm":"熱氣球乘坐帶","de":"登上吊籃前繫於手腕的帶子。火焰膨脹、大地遠去，心也跟著輕盈起來。所謂升空，就是暫時放下重量的意思。"},"ICON-1834":{"nm":"水上計程車呼叫籌碼","de":"呼叫在水上奔馳的計程車的小籌碼。舉起手，船便劃開水波靠近。在無路之處開出路來的，終究是先呼喚之人的勇氣。"},"ICON-1835":{"nm":"登山口通行證","de":"在進山的第一道關卡接過的通行證。從這裡起，由腳尖決定路。山頂雖遠，唯有通過入口的人，才被許諾那片風景。"},"ICON-1836":{"nm":"港口置物櫃鑰匙","de":"開啟碼頭置物櫃的小鑰匙。寄放行李，以變輕的手眺望大海。有個能暫時放下的地方，便是借給人遠行的勇氣。"},"ICON-1837":{"nm":"醃漬瓶蓋","de":"把酸爽之物封藏起來的瓶蓋。緊緊鎖上，夏天的黃瓜便能把脆度守到冬天。戰勝時間的訣竅，說穿了就從好好密封開始。"},"ICON-1838":{"nm":"晾曬網標籤","de":"貼在攤在篩盤上晾曬之物上的名牌。記下何時晾了什麼，等待便不會錯亂。即便在陽光與風的時光裡，也需要一個叫做次序的東西。"},"ICON-1839":{"nm":"煙燻木屑袋","de":"盛裝香木碎片的袋子。打開封口，篝火般的氣味便先在鼻尖打招呼。被煙燻得深邃的滋味，只向懂得等待的人緩緩敞開。"},"ICON-1840":{"nm":"保存食品貼紙","de":"為了好好撐過一整年而貼在罈子上的貼紙。醃製的日子與心意都寫在上頭。久放慢食的食物，總會附上一張想記住那天手藝的小備忘。"},"ICON-1841":{"nm":"發酵時鐘標籤","de":"發酵不信任時鐘。因為它用香氣而非分針來丈量時間。酸味觸及鼻尖的瞬間，標籤便靜靜點頭說「現在好了」。等待，也各有各的刻度。"},"ICON-1842":{"nm":"冷藏格分類釘","de":"冷藏格的小小交通警察就在這裡。蔬菜放上層，配菜放下層，昨天剩的放前排。插上一枚釘，每次開門時迷路的手，不知不覺便認得了路。"},"ICON-1843":{"nm":"便當保溫帶","de":"媽媽為便當繫上了帶子。叮囑暖意別逃跑，要留到午餐。解開帶子，霧氣朦朧的蓋子下，早晨的心意仍溫熱地躺著等我。"},"ICON-1844":{"nm":"醬料熟成瓶","de":"好的調味從不急躁。靜靜給醬油與蒜頭彼此滲透的時間。在瓶中的黑暗裡滋味緩緩深化，醬缸台的慢智慧，搬進了小小的瓶中。"},"ICON-1845":{"nm":"季節果醬標籤","de":"春天草莓，夏天杏子，秋天無花果。一張標籤把季節工整地寫在瓶上。隆冬掀開蓋子，逝去的陽光便一匙匙緩緩融化流出。"},"ICON-1846":{"nm":"收集率徽章板","de":"不必特地去數收集了幾個。因為徽章板會替你炫耀。每填滿一格空格，肩膀便得意一聳——這不是數字，而是用腳尖踏出的足跡。"},"ICON-1847":{"nm":"未發現欄位卡","de":"一個尚未遇見的位置。卡中的剪影只以朦朧的輪廓遞出承諾。空著就意味著終將填滿，所以雀躍總是以問號的形狀等著你。"},"ICON-1848":{"nm":"圖鑑完成印章","de":"印章「砰」地落在最後一格的那聲響。闔上圖鑑攤開手掌，一點紅墨便如完成的勳章般沾在上頭。那是只有收集到最後的人才懂的，深深的暢快。"},"ICON-1849":{"nm":"稀有度配色籌碼","de":"即使形狀相同，顏色一變故事便不同了。一枚籌碼，在平凡與珍貴之間靜靜劃下一條線。收藏家的眼，總在那微妙的色澤差異前久久停留。"},"ICON-1850":{"nm":"重複收集兌換券","de":"又出現了，又是。在第三次撿到已有之物的那天，這張兌換券悄悄伸出了手。重複也不丟棄而珍藏，總有一天會化作珍貴之物——彷彿一句溫柔的安慰。"},"ICON-1851":{"nm":"收藏箱號碼牌","de":"給每個箱子掛上號碼，倉庫便成了小小的圖書館。17號是春天收集的，23號是海邊撿到的。我是把散落記憶一行行整理的，安靜的索引。"},"ICON-1852":{"nm":"展示位置指南","de":"展示，位置決定一半。高的擺後面，發亮的擺中間。順著指南挪動雙手，原本雜亂的陳列架不知不覺便如小美術館般，靜靜調勻了呼吸。"},"ICON-1853":{"nm":"收藏品除塵刷","de":"越是珍愛之物，灰塵越是容易落上。以柔軟的刷尖輕輕拂過，連好久沒細看的那份歉意也一併掃去。擦拭時，沉睡的回憶也短暫地，再度閃爍。"},"ICON-1854":{"nm":"收納上限擴充券","de":"收集著收集著，連位置不夠也成了幸福的煩惱。望著多出一格的層架靜靜安心的心情——這不是貪心，而是喜歡的東西就那麼多的證據。"},"ICON-1855":{"nm":"好友邀請碼卡","de":"遞出這個代碼，便是一封「一起玩吧」的最溫柔邀請函。幾個數字裡裝著的心意，當收到的朋友踏上島嶼第一步，兩人的故事才終於開始。"},"ICON-1856":{"nm":"共用倉庫鑰匙","de":"倉庫的門絕不會獨自開啟。你和我，兩雙手相聚才終於轉動的鎖。共用的空間裡，共同守護的約定，總是以鑰匙的形狀掛著。"},"ICON-1857":{"nm":"失物招領標籤","de":"遺失之物對某人而言也是珍寶。寫下「在這裡喔」一行掛上——標籤是把暫時迷路的心與主人，重新靜靜接續起來的小小繩索。"},"ICON-1858":{"nm":"求助旗","de":"說出求助並非軟弱，而是勇氣。旗子升起，某處便有人奔來。在這座島上傳得最快的不是流言，而是朝向彼此伸出的手。"},"ICON-1859":{"nm":"緊急聯絡手環","de":"繞在手腕上的一份小小安心。無論發生什麼，這上頭寫的號碼都會比誰都先奔來。平時忘了它的存在，卻在最需要的瞬間最為可靠的，安靜同伴。"},"ICON-1860":{"nm":"分工籌碼","de":"誰去買菜誰來做飯，分了籌碼便沒有爭執。一起做某件事的第一步，正是從彼此溫柔地定下各自那一份開始。"},"ICON-1861":{"nm":"協力製作表","de":"獨自連想都不敢想的事，眾人聚在一起便如謊言般成了可能。表上的名字一個個填滿，空格便減少，笑聲便增多。協作，在格與格之間靜靜生長。"},"ICON-1862":{"nm":"拜訪禮儀卡","de":"踏進別人家時，連腳尖都變得小心翼翼。卡上寫的不是什麼大道理，只是「鞋子排整齊、先問好」這類小而溫暖的約定。"},"ICON-1863":{"nm":"派對解散鈴","de":"歡樂也得有個結束，才會期待下一次。鈴聲「叮鈴」響起，大家便一臉不捨地收拾起行李。懂得好好道別的派對，最久地留在心裡。"},"ICON-1864":{"nm":"床墊邊角束帶","de":"床單再怎麼鋪平，邊角也總是翹起。多虧穩穩抓住四個角的束帶，每天早晨的床鋪都如飯店房間般平整地睜開眼。"},"ICON-1865":{"nm":"被緣鈕扣繩","de":"我是抓住被緣的鈕扣繩。整夜無論怎麼翻身，都緊握著不讓被緣逃跑。睡醒後絲毫不亂的被子，便是我徹夜值班的成就。"},"ICON-1866":{"nm":"床墊保護墊固定夾","de":"保護墊一有空就想悄悄滑開。每當這時，夾子便緊咬邊角守住位置。在看不見的角落守護睡鋪的，一個沉默的固執鬼。"},"ICON-1867":{"nm":"床單皺褶撫平器","de":"夜裡生出的床單細皺，總有幾分像心上的褶痕。但願如被撫平器一抹便平滑的布料般，紛亂的一天也能那樣細細燙整。"},"ICON-1868":{"nm":"床墊通風托架","de":"床墊也需要喘息的縫隙。托架在下方開出風路，潮濕便散去，乾爽便滲入。好眠，正是從托住背的那片空氣，靜靜開始。"},"ICON-1869":{"nm":"被套拉鍊蓋","de":"換被套時棉花老是露出來的那場深夜混亂。用蓋子把拉鍊遮住一回，睡到一半被腳勾醒的事也沒了。一個小蓋子帶來的，巨大的平和。"},"ICON-1870":{"nm":"防棉結墊","de":"枕頭棉花不知不覺便擠向一邊，堆成小丘。墊子在其間默默撐住，平坦便能保留到最後。多虧它，每晚那如新品般的蓬鬆都必定回來。"},"ICON-1871":{"nm":"床單彈力環","de":"床單總是慢慢往一邊脫落。在邊角掛上環緊緊拉住，整夜翻身也紋風不動。緊繃，就這樣靜靜成了安眠的底子。"},"ICON-1872":{"nm":"枕套更換標籤","de":"今天到底洗了枕套沒？猛然糊塗時，一張標籤便清楚作答。睡了又睡而老是忘記的行程，這個小小標記替你牢牢記住。"},"ICON-1873":{"nm":"夢日記夾書籤","de":"把醒來便從指縫散去的夢，書籤夾在它的那一頁牢牢攔住。攤開來，昨夜的海與天都還在原處——靜靜架在睡眠與文字之間的小橋。"},"ICON-1874":{"nm":"白噪音鵝卵石","de":"太安靜的夜反倒會把人吵醒。鵝卵石沙沙地放出如雨聲般的聲響，心便順著那紋理緩緩沉澱。靜靜安撫沉默的一顆小石。"},"ICON-1875":{"nm":"溫感睡眠籌碼","de":"睡著時額頭熱不熱、腳尖冷不冷，籌碼在身旁靜靜守望。多虧這位安靜尋找最合身溫度的夜守，睡眠流到天明也不中斷。"},"ICON-1876":{"nm":"遮光窗簾夾","de":"晨光是何等勤快，老是從窗簾縫隙鑽進來。用夾子緊咬兩端，房間便又黑得如深夜。一次賴床的，可靠共犯。"},"ICON-1877":{"nm":"月光投影燈","de":"關燈後天花板上便升起一輪月。燈投上的柔和光芒，把房間變成小小的夜空。把仰望月亮入睡的那份心意，就那樣留在枕邊。"},"ICON-1878":{"nm":"助眠香囊掛架","de":"盛著薰衣草與草香的香囊在枕邊輕輕搖晃。順著鑽入鼻尖的香氣，肩膀緩緩鬆開，一個香囊比枕頭更早替人喚來睡意。"},"ICON-1879":{"nm":"搖籃曲音樂盒釘","de":"靜靜上緊發條，一段小旋律便流瀉而出。從釘尖轉出的搖籃曲，恰似奶奶輕拍背脊的那個節拍。一個個音符，緩緩讓眼皮沉重起來。"},"ICON-1880":{"nm":"增濕植物杯","de":"我是以清水而非泥土培育植物的杯子。望著細根在水中漂浮搖曳，連房裡的空氣都覺得潤了幾分。凝在書桌上的，一口小小的綠色之井。"},"ICON-1881":{"nm":"夢碎片收集瓶","de":"睡夢中漏下的夢沒有形體，醒來便從指縫間溜走。用瓶蓋靜靜攔住一片即將消失的碎片，留到早晨——想記住的心，就從這樣的小地方開始。"},"ICON-1882":{"nm":"枕邊眼鏡托盤","de":"摘下眼鏡放下的瞬間，神奇地連一天份的疲憊也一併落下。枕邊這個小小的位置，就是為了接住那一個動作而存在。入睡前，靜靜把世界模糊起來的托盤。"},"ICON-1883":{"nm":"床頭櫃杯墊環","de":"水杯留下的一圈圓痕，看似瑣碎，對床頭櫃的木紋卻成了傷。為了防它而套上的小環。珍惜的心，總在這類看不見的地方靜靜做著工。"},"ICON-1884":{"nm":"疊被定角器","de":"把被子疊得方正，也有它的紋理。順著這個定角的工具對齊邊角，連紛亂的心也跟著舒展一回。整頓好的位置，是開啟一天最端整的問候。"},"ICON-1885":{"nm":"充電線枕邊掛鉤","de":"不想讓充電線整夜悄悄滑落地面，便掛在枕邊的鉤子。趁睡著時靜靜蓄滿氣力的線，到了早晨便飽滿地等候指尖。"},"ICON-1886":{"nm":"枕邊零食籃","de":"把愛吃的零食聚在伸手可及之處的籃子。是預先體貼到深夜會來的嘴饞的，溫柔備辦。在黑暗中拈起一顆咬下的窸窣聲，平添幾分親暱。"},"ICON-1887":{"nm":"睡前書架翼","de":"為了睏意湧來也不丟失讀到的那行，靜靜托住攤開書頁的翼。閉眼前蓋下的那一頁，明晚會在同一處等你。"},"ICON-1888":{"nm":"枕邊鬧鐘石托","de":"喚醒早晨的鬧鐘，也需要一個不晃動的定位。圓石托沉穩地承住那份重量，如黎明到來也不滑動的約定般，守著那個位置。"},"ICON-1889":{"nm":"眼罩掛釘","de":"把整夜遮光的眼罩，在白天掛起讓它透氣的一枚釘。給盡了用途的布料一個乾爽的位置——小小的照拂，就這樣無痕地滲入。"},"ICON-1890":{"nm":"枕邊手電筒夾","de":"把深夜所需的一束小光，固定朝向想要之處的夾子。把手電筒咬在床緣，在黑暗中摸索的手便輕鬆許多。為光指定方向的手。"},"ICON-1891":{"nm":"隔間窗簾掛環繩","de":"拉住分隔公共空間之窗簾的掛環繩。雖只是一片薄布，那一頭卻是某人私密的夜晚。在合住的房裡守護彼此睡眠的，溫柔界線。"},"ICON-1892":{"nm":"公用插座分配木板","de":"讓眾人共用唯一插座的木板。把電均勻分送，不讓任何人的夜晚變暗。共同生活，終究是從這樣的小事開始分享。"},"ICON-1893":{"nm":"燈光亮度禮讓石","de":"燈光太亮時，不用言語悄悄遞出的石。「能稍微調暗一點嗎？」這句話由這小東西代為傳達。是合住房裡最柔軟的請託。"},"ICON-1894":{"nm":"起床時間禮讓代幣","de":"交到掌心遞給先起床之人的小牌。誰多睡一會清晨覺、誰先醒，由這枚代幣無爭執地決定。以指尖定下禮讓順序的心意。"},"ICON-1895":{"nm":"共用衣架號碼環","de":"在眾人共用的衣架上編好的號碼環。為了不弄混誰的位置，一個小數字靜靜造出秩序。在容易混淆的日常裡劃下的，溫柔的線。"},"ICON-1896":{"nm":"上下舖踏板蓋","de":"套在通往上舖踏板上的蓋。讓赤腳踩上也不冰不滑，照看一階的安全。梯子末端這份小體貼，穩穩托起上舖的夢。"},"ICON-1897":{"nm":"公用衛生紙掛臂","de":"掛公用廁所衛生紙的臂形掛架。安置得讓任何人都能單手輕鬆扯下一格。看似瑣碎，卻是把眾人的早晨順暢接續起來的手。"},"ICON-1898":{"nm":"芳香劑輪值籌碼","de":"寫下誰來重新補充芳香劑、定好輪值的籌碼。連一縷淡香，也是輪流負責的約定。好聞的味道並非白來，而是從某人的輪次裡綻放。"},"ICON-1899":{"nm":"共用睡眠燈把手","de":"眾人一同開關的睡眠燈把手。醒到最晚的那雙手，最後收起光。分享一盞柔光的，合住一房之人的安靜約定。"},"ICON-1900":{"nm":"沙發扶手杯凹槽","de":"沙發扶手上凹出的圓圓杯位。手裡的杯子暫且放下也不怕打翻。歇腳的位置得有個放杯之處，心才終於能舒坦地攤開。"},"ICON-1901":{"nm":"抱枕內套拉鍊把手","de":"裝在開合抱枕內套之拉鍊上的小把手。一個環便省去換洗的辛勞。連看不見的內裡都照料周到——居家的溫柔，總藏在那裡。"},"ICON-1902":{"nm":"沙發靠背填縫抱枕","de":"填滿靠背縫隙、托住腰的抱枕。讓久坐也不硌背地填補空位。靠坐的瞬間，身體會先一步察覺「啊，就是這個」的安樂。"},"ICON-1903":{"nm":"坐墊邊角固定帶","de":"把每次一坐就悄悄跟著移動的坐墊，從邊角抓住的帶子。固定在一處不讓它滑開。所謂端整，正是從這類小而執著的固定開始。"},"ICON-1904":{"nm":"抱枕縫線保護帶","de":"抱枕最先磨損的地方，總是邊角的縫線。預先繞著包覆那一處，守它不裂的保護帶。想長久相伴的心意，如縫線般牢固。"},"ICON-1905":{"nm":"沙發縫遙控器口袋","de":"老是消失在坐墊間的遙控器，終於有了自己的家。插在沙發縫裡的小口袋。以為弄丟的東西其實一直在那裡，是比想像中更大的安心。"},"ICON-1906":{"nm":"膝毯捲收繩","de":"把膝毯捲起綁好的繩子。把攤開便散去的暖意，為下一個夜晚端整地收攏。暖意也這樣收好，明天便能再取出來蓋上。"},"ICON-1907":{"nm":"腳凳套鈕扣","de":"為了讓被腳踩而磨損最快的腳凳套易於更換而扣合的鈕扣。「啵」一扣的那一個動作，延長了布料的壽命。想長用的心，在小處便顯利落。"},"ICON-1908":{"nm":"沙發腳防滑罩","de":"再重的沙發也不該刮傷地板。套在四隻腳末端的柔軟罩，悄悄愛惜著木地板。連腳尖都小心翼翼的家具，不知怎地更惹人疼。"},"ICON-1909":{"nm":"遙控器收納座","de":"把各自滾動散開的遙控器並排立放於一處的收納座。長短不一的棒子整齊排好隊，光是這樣，房裡的空氣便沉澱得低了一度。"},"ICON-1910":{"nm":"遊戲手把充電掛架","de":"把痛快玩過一場的遊戲手把掛起充電的鉤子。懸著靜靜蓄滿氣力時，手也暫且歇息。這個短短的休止符，穩穩為下一局做好準備。"},"ICON-1911":{"nm":"桌遊棋子袋","de":"盛裝五顏六色棋子的小袋。在一袋之中等候下一局的零件，每搖一下便嘩啦作響。那聲響裡，「再來一局？」的雀躍先一步甦醒。"},"ICON-1912":{"nm":"骰子擲盤","de":"專用於擲骰子的盤。把彈出桌外便消失的運氣，邊緣將它困在裡頭。骨碌碌滾動停下的那短短一瞬，眾人的呼吸也一同暫停。"},"ICON-1913":{"nm":"牌組固定帶","de":"把一副牌綁住不讓它散開的帶子。在洗牌之前，那個順序便是約定。解帶攤牌的那個手勢裡，一局的故事才終於開始。"},"ICON-1914":{"nm":"主機線材整理夾","de":"把主機後方糾結的線抓住、整齊梳順的夾子。默默整理那連看都看不太到的雜亂。所謂整潔，總是這樣在背後靜靜完成。"},"ICON-1915":{"nm":"分數格轉盤","de":"轉動以標示分數格的小轉盤。喀噠，數字每升一格，歡呼便隨之而來。不必用腦計算，指尖便先記住了那天的勝負。"},"ICON-1916":{"nm":"牌板立架","de":"把牌板斜立起來，調好角度讓圍坐眾人都能一覽棋局的立架。為了誰都不必伸長脖子，靜靜攤開一片公平的視野。"},"ICON-1917":{"nm":"遊戲順序抽籤筒","de":"為定遊戲順序而伸手探入抽取的筒。摸索著拈起的一根棒，分出第一個次序。略略倚靠運氣的那短短一瞬，圓筒裡眾人一同心跳。"},"ICON-1918":{"nm":"分享零食分格盤","de":"把零食按種類分裝的分格盤。把位置分開，便能不撞到手地挑選喜歡的。一格格裡，都盛著體諒共食之人的心意。"},"ICON-1919":{"nm":"茶壺保溫罩","de":"繞著茶壺肩膀守住暖意的保溫罩。在茶緩緩沁出時包覆著，不讓它冷卻。是想把溫熱一杯，溫熱地奉到最後的指尖心意。"},"ICON-1920":{"nm":"茶包瀝水托","de":"把泡好的茶包撈起、暫且歇放的托。連最後一滴水珠都不灑地接住。也給盡了本分的葉子，留一個端整收尾的位置。"},"ICON-1921":{"nm":"公用馬克杯辨識環","de":"茶水間層架上六個一模一樣的馬克杯。不問是誰的，便套上五顏六色的環。一個小標記，把手藝與口味各異的六個人，靜靜繫在同一張餐桌的一席。"},"ICON-1922":{"nm":"爆米花分享籃","de":"在手與手之間傳遞時，香氣先一步打招呼。若有什麼是越分一把越奇怪地不減少，那大概就是圍坐分食的傍晚之心。"},"ICON-1923":{"nm":"方糖夾筒","de":"用夾子「啵」地把一顆方糖落入茶杯。望著白色的稜角緩緩化開消失——是在奶奶的茶几上初次學到的，不疾不徐的甜味之禮。"},"ICON-1924":{"nm":"托盤防滑墊","de":"托盤再傾斜，杯子也守著原位。一如那些在底下默默支撐之物，墊子獨自撐過險些滑落的瞬間，最終仍緘口不言。"},"ICON-1925":{"nm":"飲料吸管立杯","de":"把吸管立直，飲料與心便都不會散亂。在這不算什麼的一個直立讓書桌變端整的午後，杯子懷著一根小柱，靜靜托起慵懶的時光。"},"ICON-1926":{"nm":"餅乾屑接盤","de":"酥脆——餅乾碎裂的瞬間落下的碎屑，都聚到這裡。連最美味的一口所留下的痕跡也一併接住——是對最後一片碎屑也溫柔的，餐桌安靜的收尾。"},"ICON-1927":{"nm":"照片夾掛繩","de":"在如曬衣繩般垂下的繩上，用夾子把拍立得一張張夾上。今天拍下的笑容在風中輕搖晾乾時，一面牆便成了一小方明亮的回憶展場。"},"ICON-1928":{"nm":"回憶線團繞線軸","de":"把糾纏的線解開、整齊繞好的繞線軸。在每個斷處打結接續而來的東西。回憶也這樣一圈圈慢慢倒繞，以為變短的路便又長了起來。"},"ICON-1929":{"nm":"牆飾掛釘孔蓋","de":"遮住釘孔的小圓蓋。曾掛過什麼之處，取下後留下的小疤也靜靜遮上，牆便如什麼都沒發生過般，重新換上光滑的面孔。"},"ICON-1930":{"nm":"團體照夾框","de":"六人肩並肩緊貼著拍的團體照。嵌入夾框的瞬間，那天的笑容與溫度便一同封存。相框，是把流逝的一天最安靜地停住的手。"},"ICON-1931":{"nm":"便條板軟木板","de":"圖釘印密密麻麻的褐色板。不能忘的約定、某人貼下的應援紙條、今天的待辦事項層層插上。是替腦袋記住的，書桌旁可靠的牆。"},"ICON-1932":{"nm":"花圈掛繩結","de":"掛在門上的一個花圈，也藏著指尖的巧手。結得牢，多風的季節裡才不會掉落。歡迎某人的心意，總是從看不見的地方先變牢固。"},"ICON-1933":{"nm":"掛鐘擺錘罩","de":"包覆滴答擺錘以擋灰塵的布罩。連丈量時間一事都受到這般照看。輕輕守它不老，掛鐘便能在我們身旁稍稍多停留一些。"},"ICON-1934":{"nm":"貼紙收集插板","de":"散落各個抽屜的貼紙在一塊板上聚齊排隊。喜歡的角色、閃亮的星、一張手寫字。小小收集的喜悅整齊排列起來，連心都端正了。"},"ICON-1935":{"nm":"裝飾旗串接繩","de":"把五顏六色的旗串成一列的繩。無論生日或迎賓，繩橫越天花板的瞬間，平凡的房便變成喜慶之家。慶賀，就是把斷開的心一路接續起來。"},"ICON-1936":{"nm":"電熱水壺軟木墊","de":"墊在滾燙水壺底部的一片軟木。為了不讓餐桌被燙，獨自把那份熱攬入懷中。為了不讓某人的溫熱留成痕跡而默默托著的，小小體貼。"},"ICON-1937":{"nm":"烤麵包機屑盤","de":"烤得金黃的麵包掉下的碎屑，骨碌碌落入屑盤。咻地抽出抖一抖便完事。它默默接住忙亂的早晨，再把下一餐重新乾淨地備好。"},"ICON-1938":{"nm":"微波爐轉盤環","de":"在團團轉的環上，盤子緩緩畫出一圈。為了均勻加熱而轉的那個迴旋，把冷掉的昨日米飯，重新救成一頓熱氣騰騰的飯。"},"ICON-1939":{"nm":"迷你電磁爐爐口蓋","de":"油四處飛濺，爐口也總是乾淨。一片蓋子隔開了猛烈的熱氣與手。那些看不見地擋在前頭之物，把廚房守成不被燙傷的地方。"},"ICON-1940":{"nm":"電鍋洩氣蓋","de":"嘶——洩氣的聲響。多虧把含著的壓力悄悄放掉的小蓋子，剛煮好的飯以最柔軟的面孔掀開蓋子。在燜飯的時間裡，沒有催促。"},"ICON-1941":{"nm":"飯匙立架","de":"把攪過湯的飯匙端正立起。是不想在流理台上灑下一點汙漬的小心意。廚房的端整，總是從這類不起眼的瑣碎之處開始。"},"ICON-1942":{"nm":"鍋柄矽膠套","de":"在燒得滾燙的鍋柄上套矽膠，手便不會燙傷。夾在熱燙與手掌之間的一層。在最近之處，守護著煮熱飯的人。"},"ICON-1943":{"nm":"電熱水壺水垢濾網","de":"每天煮的水也會積下淡淡的痕跡。細密的網靜靜濾去水垢，只倒出清澈的一杯。是在看不見之處守住一口茶第一口的，勤快之手。"},"ICON-1944":{"nm":"料理計時器夾腳","de":"「再3分鐘」，以夾腳緊咬餐桌邊角的計時器。麵煮著時用小腳撐立，滴答滴答地，陪著數一天裡最令人期待的瞬間。"},"ICON-1945":{"nm":"餐具瀝水托杯","de":"剛沖洗過的餐具骨碌碌滴下水。托杯靜靜接住那水氣聚起，餐桌不知不覺便乾爽了。所謂整潔，是連一滴水也照料的溫柔勤勉。"},"ICON-1946":{"nm":"立盤隔板條","de":"把盤子縱向立起、一格格隔開。原本疊放便彼此刮傷的碗盤，各自得了一個位置。所謂整頓，終究是給每個都讓出一個不相碰的格子。"},"ICON-1947":{"nm":"筷子配對環","de":"把失了伴孤零零留下的筷子串進環裡，重新湊成一雙。只剩一隻便會失去用途，因此並排綁住的這個小環，守著抽屜裡的秩序。"},"ICON-1948":{"nm":"杯架枝形台","de":"在如枝椏般多向伸展的架台上，一個個掛上杯子。倒扣的杯子各自瀝乾水氣時，廚房一隅便如一棵小而端整的樹，靜靜佇立。"},"ICON-1949":{"nm":"餐具分格托把手","de":"湯匙、筷子、叉子一格格並排躺著的托盤。抓住把手整個提起，擺桌便輕鬆許多。抽屜之中，也必有秩序的美學棲居。"},"ICON-1950":{"nm":"水杯倒扣晾乾板","de":"把洗好的杯子倒扣，水珠便滴滴答答落下。在灑進陽光的窗邊緩緩晾乾時，玻璃杯為了下一口，沉靜地尋回最初的透明。"},"ICON-1951":{"nm":"叉齒防卡梳","de":"細密的梳齒輕輕梳過，讓食物不再卡進叉齒之間。多虧這份連縫隙都顧到的細心，下一餐總能以毫無瑕疵的乾淨第一口開始。"},"ICON-1952":{"nm":"疊碗防滑氈片","de":"碗碟相疊時，瓷器互碰會發出刺耳的聲響。夾在中間的一片氈，悄悄撫平了那份摩擦。長久相伴的祕訣，就在於彼此都留一分柔軟。"},"ICON-1953":{"nm":"茶匙懸掛掛繩","de":"把小巧的茶匙掛在掛環上垂於牆面。不再埋沒於抽屜深處，而是在隨手可及之處閃閃發亮，這是小工具堂堂正正佔據的位置。家務之中也有專屬的歸位。"},"ICON-1954":{"nm":"冷藏分隔托盤","de":"把冷藏格分隔開來，每樣食材便有了自己的小屋。原本雜亂被遺忘的東西都有了歸處，每次開門時，什麼放在哪裡都一目了然。"},"ICON-1955":{"nm":"冷凍夾鏈袋直立夾","de":"用夾子咬住用了一半的冷凍夾鏈袋，讓它筆直站立。不讓它傾倒灑出，下次也好找。即使在寒冷的冷凍庫裡，也藏著一絲不苟的能幹巧思。"},"ICON-1956":{"nm":"瓶蓋緊鎖蓋","de":"沒蓋緊的瓶子不知不覺就走了氣。把蓋子牢牢旋緊的那一下手腕之力，將瓶中的香氣與氣泡原封不動地鎖到明天早晨。能幹總在細微處閃光。"},"ICON-1957":{"nm":"蛋格防滑墊","de":"讓圓圓的雞蛋不會滾動破裂，一格一格穩穩托住的墊子。把最脆弱的東西最小心地對待，這份心意小巧而溫柔地安放在冰箱門的一側。"},"ICON-1958":{"nm":"冷藏門袋擴充帶","de":"把冷藏門袋往旁邊稍微撐開，多出一格空間。家當多了，擺放的位置也得跟著增加。在狹窄處拓寬使用的巧手裡，映照出能幹主婦的心思。"},"ICON-1959":{"nm":"剩菜壓蓋","de":"輕輕壓覆在剩菜上的蓋子。不讓它變乾、不讓它沾染別的氣味，靜靜守護著。珍惜的手，連一餐的剩餘都會妥善收存。"},"ICON-1960":{"nm":"冷氣導向風葉","de":"冷氣該往哪一邊流動，小小的風葉靜靜決定方向。用指尖稍稍撥動那看不見的風路，清涼便能抵達最深處的角落。"},"ICON-1961":{"nm":"蔬果格保濕墊","de":"冰箱蔬果格最幽暗的角落，我默默吸收著水氣。昨天蔫掉的葉子，清晨又重新挺拔起來，這是小小的奇蹟。即使無人知曉，新鮮始終由我守護。"},"ICON-1962":{"nm":"飲料罐防滾擋條","de":"靜靜貼在餐桌邊緣，攔住快要滾走的罐子。差點灑出的飲料、差點得擦拭的餐桌。家務中的安心，就從這不起眼的小擋條開始。"},"ICON-1963":{"nm":"值日輪班轉盤","de":"今天誰洗碗、誰倒垃圾。箭頭一轉，爭執便圓滿化解。在五個人擠在一起生活的家裡，順序就是溫柔的和平。"},"ICON-1964":{"nm":"成員杯區分矽膠環","de":"五個相似的杯子，分不清究竟是誰的那個早晨。套上一條手腕般的色帶，「這是我的」這個小小約定便清晰起來，早餐桌上悄悄盈滿溫柔的秩序。"},"ICON-1965":{"nm":"餐量分隔環","de":"忙碌的日子裡，碗中的刻度成了可靠的朋友。一格放飯，一格放菜。不多也不少，靜靜告訴你今天該吃多少的那道溫柔的線。"},"ICON-1966":{"nm":"零食分享夾筒","de":"整袋遞過去，碰過的地方會剩下令人尷尬。用夾子一個個分出來，這才人人份量相等。分享要的不是手感，而是雅致的習慣。"},"ICON-1967":{"nm":"水壺值日插牌","de":"燒水的活兒總落在同一雙手上。自從在水壺旁的插架輪流掛上名牌，一杯溫熱的茶，便成了輪番沖泡出的情意。"},"ICON-1968":{"nm":"勿剩提醒鏟尖牌","de":"「請別剩下」這句話小小地掛在鍋鏟尖端。雖像嘮叨，卻沒有惹人厭的地方。因為這裡寄寓著昔日餐桌珍視每一餐的心意。"},"ICON-1969":{"nm":"個人餐具袋掛架","de":"湯匙筷子不再在抽屜裡滾來滾去。當它們收進各自的口袋掛上牆的那一刻，五口人的位置便整齊排成一列。小小的整頓撐起每日的平和。"},"ICON-1970":{"nm":"餐桌座位區分軟木片","de":"把軟木片鋪在餐桌上，誰坐哪裡便一清二楚。總是坐的位置，總是相對的側臉。固定的座位，是「一起生活」這句話最安靜的證明。"},"ICON-1971":{"nm":"值日圍裙捲收掛環","de":"洗完碗的圍裙不會被隨手一扔。捲起來掛在掛環上，明天早晨再用時又是乾爽的。為下一個人著想的心意，就住在這小小的結裡。"},"ICON-1972":{"nm":"拋棄式拖鞋摺疊袋","de":"有客人來的日子，我便整袋攤開。整齊裝著的拋棄式拖鞋，柔軟地迎接初次造訪的腳。款待，總是從玄關悄然開始。"},"ICON-1973":{"nm":"棉花棒紙尾口袋","de":"棉花棒用完只剩紙尾時，我便細心收下那末端。連將被丟棄的東西也給予一席之地。整潔書桌的祕密，就是這般細微的溫柔，我懂的。"},"ICON-1974":{"nm":"縫紉組線軸束","de":"為了不讓線軸鬆開纏在一起，把各色線綁成一束。掉了的鈕扣、鬆了的袖口，有這一束就能立刻復原。在重要日子的夜晚，悄悄相救的手縫針線。"},"ICON-1975":{"nm":"肥皂單片包裝塊","de":"一塊單片精緻包好的肥皂，擺在每間客房裡。巴掌大的身軀，用一把泡沫洗去一日的塵埃。乾淨，總是這般從細微處開始。"},"ICON-1976":{"nm":"浴帽摺疊膠囊","de":"摺起皺褶便可放進掌心，攤開便能包覆頭髮。讓沖澡時打理好的髮型不致塌掉。明早的端莊，由這一層守護。"},"ICON-1977":{"nm":"牙刷保護帽套","de":"刷毛比想像中更敏感。一個套帽蓋住那末端，連包包裡的灰塵也碰不到。守護看不見的地方——這是每趟旅行學到的衛生真功夫。"},"ICON-1978":{"nm":"化妝棉單片夾","de":"化妝棉要一片片夾才能漂亮取出。一股腦倒出來，被浪費的反而更多。「一片片、用心地」——這是化妝台上靜默的規則。"},"ICON-1979":{"nm":"迷你摺疊鞋拔","de":"摺起放進口袋，攤開抵住腳跟。我自負以小小的身軀做了相當大的事。即使睡過頭的早晨，能不弄壞皮鞋穿上的，總是我。"},"ICON-1980":{"nm":"牙線單份捲器","de":"把一段牙線細心捲好，需要時就剛好扯斷來用。雖只有指甲大小的捲器，守護燦爛笑容的事卻少不了它。微笑也有看不見的準備。"},"ICON-1981":{"nm":"電熱壺蓋把手","de":"為了不被滾水的蒸氣燙到手，把我套在壺蓋上。熱燙與掌心之間的一掌距離。那小小的間隔，安全地溫熱了某個忙碌之人的早晨。"},"ICON-1982":{"nm":"熨斗墊矽膠板","de":"燙衣途中暫時放手的那一瞬最危險。把熨斗立在矽膠板上，餐桌與衣物都不會被燙焦。撫平皺褶這件事，要在墊板上才算真正完成。"},"ICON-1983":{"nm":"防盜衣架彎鉤","de":"為了不讓掛著的衣服隨意滑落，彎鉤緊緊閉上嘴。守在衣櫃裡珍愛的那一件旁的小小哨兵。守護，原來是這般安靜的事。"},"ICON-1984":{"nm":"水壺水垢濾網","de":"把漂浮在滾水中的水垢靜靜濾掉，是我的職責。連看不見的渣滓都濾淨了，一杯茶才得以清澈。誠意總在不起眼處沖泡而出。"},"ICON-1985":{"nm":"衣架防滑帶","de":"圍著防滑帶的衣架，連輕薄的絲綢也不會滑落。看過衣服掉到地上皺成一團的人才懂得，這細細一條帶子的可貴。"},"ICON-1986":{"nm":"熨斗電線整理夾","de":"鬆散的電線容易絆到腳，讓人踉蹌。用夾子俐落地綁成一束的這一手。防範事故，總是從這般細微瑣碎的整理出發。"},"ICON-1987":{"nm":"電熱壺底座凹槽","de":"為了不晃動，把壺穩穩嵌進我的凹槽裡。放回原位，就等於令人安心。每天早晨溫水都在同一處燒熱，是有原因的。"},"ICON-1988":{"nm":"褲架夾腿","de":"夾腿俐落咬住褲腳，連一絲皺褶都不留。燙得平整的一件，從掛上衣架的那一刻起便受到禮遇。俐落的版型，在衣櫃裡完成。"},"ICON-1989":{"nm":"吹風機掛環","de":"吹風機隨手亂放，電線很快就纏成一團。俐落掛在掛環上，洗手台變寬了，明天的早晨也輕鬆了。整頓好的位置，悄悄鬆開忙碌的一天。"},"ICON-1990":{"nm":"迷你吧飲料杯墊","de":"靜靜墊在杯底，水珠便不會在桌上暈開。一張杯墊的體貼，不留下圓圓的痕跡。整潔，就是不留下痕跡的溫柔。"},"ICON-1991":{"nm":"請勿打擾掛牌","de":"掛在門把上的一塊牌子，靜靜低語「現在正在休息」。守護漫長一天盡頭的一小覺午睡。休止符，也得有人用心守護。"},"ICON-1992":{"nm":"客房服務呼叫鈕蓋","de":"多虧包覆按鈕的蓋子，即使衣襬掃過也不會被隨意按下。只在真正需要的時刻清楚呼喚。一個小小的蓋子，讓忙碌的客房更顯端莊。"},"ICON-1993":{"nm":"迷你吧冰塊夾腿","de":"徒手夾冰塊既冰冷又老是滑掉。那活兒就由夾腿俐落地代勞。一杯清涼飲料的開端，藏著看不見的手。"},"ICON-1994":{"nm":"客房鑰匙卡插槽","de":"把卡片插進槽中，房裡的燈便啪地亮起。我不過是個小縫隙，卻成了開啟那卸下一日疲憊空間的第一個手勢。回來的地方，燈又重新亮起。"},"ICON-1995":{"nm":"水瓶頸帶封印環","de":"若水瓶頸上的封印環完好無缺，便表示還沒有人動過。證明依然如初的小小約定。信任，從未被破壞的封印開始。"},"ICON-1996":{"nm":"導覽手冊立架","de":"把導覽手冊斜斜立起，路過的目光便自然停留。等待被翻開的資訊那端莊的姿態。光是擺得醒目，就讓某人的路途順遂許多。"},"ICON-1997":{"nm":"迷你吧開瓶器扁片","de":"扁平身軀的一角，悄悄藏著開瓶蓋的凹槽。雖小，份內事卻做得乾淨俐落。一瓶飲料清涼的第一口，總是從這小小的扁片開啟。"},"ICON-1998":{"nm":"燈光調節旋鈕蓋","de":"輕輕轉動包著蓋子的旋鈕，房間的明暗便緩緩變化。明亮些，或是柔和些。挑選入睡時分的光，是溫柔收尾一天的儀式。"},"ICON-1999":{"nm":"行李箱輪止滑楔","de":"稍稍塞進輪下，行李箱便不會自顧自地滾走。即使在傾斜的車站月台上，行李也能守住原位。啟程之路的安心，由這小小的楔塊穩固而來。"},"ICON-2000":{"nm":"旅行打包摺疊板","de":"攤開來把衣物放上去，襯衫褲子都能方正漂亮地摺好。讓行李箱裡不致塌亂，抵達的城市裡也能毫無皺褶地出門。打包得宜的行李，從出發前就在幫襯旅程。"},"ICON-2001":{"nm":"客房保險箱鎖把","de":"轉動把手，小小的門閂便向內滑入。把貴重物品託付，便是這一夜安心放下心來的約定。鎖，不是不安，而是以安心的另一個名字佇立在那裡。"},"ICON-2002":{"nm":"行李箱把手套","de":"每一處沾染手澤的地方，都刻著某人的出發。握住這隨拖行的距離而磨損的套子，便靜靜明白，離開終究是一個懷著歸來的詞。"},"ICON-2003":{"nm":"旅行收納包掛夾","de":"把收納包掛在洗手台邊角，狹小的客房便寬出一掌。一個小夾子便開始了行李中的秩序，這是遠行過的手早已知曉的事。"},"ICON-2004":{"nm":"充電器多孔插夾","de":"把多條線材匯聚插上一個插座。等待充飽電的夜裡，這裡有一隻小手，溫柔地把散亂的線收攏在同一處。"},"ICON-2005":{"nm":"行李箱名牌掛繩","de":"在一個個同樣漆黑的包包之間，讓人認出我的那一條繩。掛上名字，便是這件行李擁有了一條歸還給某人的路途的溫柔標記。"},"ICON-2006":{"nm":"客房牆充電線掛板","de":"貼在床頭牆上的小板，整齊托住充電線。在陌生房間迎來的第一夜，只要熟悉的一盞燈亮起，那裡也暫時成了家。"},"ICON-2007":{"nm":"行李架摺疊腿","de":"撐開摺起的腿，包包便離地一掌高、遠離塵埃。尚未拆封就放上去的行李箱，靜靜懷著未竟的旅程，等待著下一個早晨。"},"ICON-2008":{"nm":"鑰匙卡插槽","de":"插上卡片，客房才會亮燈。只在停留期間亮起的光——旅人的一天，被這小小的插槽所允許的明亮溫暖著，剛剛好那麼多。"},"ICON-2009":{"nm":"鑰匙卡掛繩環","de":"把一張卡掛在頸上，兩手便輕鬆了。把怕弄丟的擔憂繫在一條繩上的小聰明，是行李繁多的旅人長久傳承的智慧。"},"ICON-2010":{"nm":"櫃台呼叫鈴鈕","de":"一按，櫃台某處便叮咚一聲清脆地響起。為了讓尋求幫助不必難為情，鈴總是溫柔地放在手勢一觸即達之處。"},"ICON-2011":{"nm":"登記排序夾","de":"把隊伍末端領到的號碼紙夾住固定。等待也有先後——秩序，自彼此靜靜珍惜彼此時間的小小約定中生長。"},"ICON-2012":{"nm":"客房鑰匙流蘇","de":"繫在鑰匙末端的流蘇，隨每一步輕輕搖曳。在實用之上悄悄添一抹風情的心思，唯有懂得指尖樂趣的人才會講究。"},"ICON-2013":{"nm":"櫃台門鈴蓋","de":"在門鈴上罩上蓋子，正午的靜謐便不被打破。為了守護某人的酣眠的小小體貼——寧靜，也是某人用心打造出來的。"},"ICON-2014":{"nm":"房號掛牌紙條","de":"掛在門把上的紙條，清楚寫著房號。幾個數字便為我定下今晚要回來的位置，在陌生的走廊裡，它成了一座小小的燈塔。"},"ICON-2015":{"nm":"鑰匙卡磁條","de":"把黑色磁條貼近門縫，鎖便悄然鬆開。看不見的訊號開門的時代——曾如魔法般的事，如今已落入掌心的日常。"},"ICON-2016":{"nm":"登記印章墊","de":"每次蓋章，墊子都均勻地承接油墨。為了讓確認的一筆清晰留下，總有一隻手在看不見的地方默默托著。"},"ICON-2017":{"nm":"行李推車掛桿","de":"掛在行李推車上的一根桿，毫無皺褶地托住衣物袋。對那些替我們扛起沉重一天的事物，偶爾也想說一句謝謝。"},"ICON-2018":{"nm":"行李箱把手吊牌","de":"在行李箱把手上掛一個小吊牌。只要寫名字的格子還空著，這個包包的下一站尚未定下的那份雀躍，便還留存著。"},"ICON-2019":{"nm":"行李推車輪鎖楔","de":"為了不讓推車在斜坡上滾走，在輪下墊塊楔子。守住停下不動這件事，有時正是最可靠的安全的另一張臉。"},"ICON-2020":{"nm":"行李帶扣環","de":"為了不讓裝滿旅程的鼓脹包包爆開，把帶子緊緊扣牢。即使旅途結束，回憶的體積也不會減少，扣環便把那份重量牢牢撐到最後。"},"ICON-2021":{"nm":"行李推車鉤套","de":"套在推車鉤上的套子，不在衣物上留下半點痕跡。連看不見的刮痕都預先顧及的心意——好的款待，就在這般細微處完成。"},"ICON-2022":{"nm":"行李箱名牌口袋","de":"掛在包包側邊的小口袋，懷著名牌。寫下這是誰的，就如同預先銘刻了即使遺失也能重逢的資格。"},"ICON-2023":{"nm":"搬運手套夾","de":"搬運重物時，為了不讓手套滑落，用夾子俐落咬住。守護雙手與把活兒做好，終究出於同一份心。"},"ICON-2024":{"nm":"行李網罩","de":"罩上網子，零碎的行李便不會四散開來。緊密的每一個網眼，在忙碌的移動中牢牢攔住，不讓小東西遺失。"},"ICON-2025":{"nm":"行李推車便條夾","de":"插在推車把手上的便條，寫著客房號碼。寫下該往哪裡去的習慣——越是忙碌的手，越靜靜倚賴那一行字。"},"ICON-2026":{"nm":"餐盤罩圓頂蓋","de":"掀起銀色的圓頂蓋，蒸氣便一口氣升騰而上。為了不讓食物變涼而蓋著的心意，正是想原原本本傳遞溫熱的那份誠意。"},"ICON-2027":{"nm":"請勿打擾門把牌","de":"把這塊牌掛在門把上，連走廊的腳步聲都變得小心翼翼。「請勿叫醒」這一句話——休息，也要有人守護才得以完整。"},"ICON-2028":{"nm":"客房服務紙巾環","de":"把紙巾套進圓環，整出端正的形狀。一餐的格調從這小小的環開始，誠意在細微處顯露得最為清晰。"},"ICON-2029":{"nm":"餐盤防滑墊板","de":"在餐盤上鋪上墊板，碗碟便不會滑動。在晃動中也守住原位的東西——安靜的穩定背後，也有某人的細心設計。"},"ICON-2030":{"nm":"早餐點餐門把牌","de":"把早餐點餐牌掛在門把上，明天的早晨便預先約定好了。今晚就寫下第一餐這件事，是溫柔的等待所帶的另一張臉。"},"ICON-2031":{"nm":"餐盤摺疊腳架","de":"撐開餐盤的腳，在床上也成了像樣的餐桌。在躺臥之處享用的一桌早餐——一個小腳架，把平凡的房間變成奢華的風景。"},"ICON-2032":{"nm":"水壺保溫罩","de":"給水壺套上保溫罩，水的暖意便久久停留。像昔日圍坐爐邊的夜晚那般，想守護溫暖的心意，不分時代。"},"ICON-2033":{"nm":"清掃請求門把吊牌","de":"把清掃請求吊牌掛在門把上，留下無聲的訊號。不開口也能傳達的請託——整潔房間的背後，有看不見的手所許下的約定。"},"ICON-2034":{"nm":"餐盤調味罐架","de":"為了不讓調味罐傾倒，架子牢牢托住。即使在晃動的餐盤上也守住味道的均衡，是這小小固定座默默的職責。"},"ICON-2035":{"nm":"預約便條立架","de":"把預約便條插立起來，順序便一目了然。為了讓忙碌的手也不致弄混，把一張紙清楚立著的小小秩序之具。"},"ICON-2036":{"nm":"景點插針地圖板","de":"在地圖上插針，把想去的地方一一點下。每一根針都是尚未抵達的雀躍——旅行，在攤開地圖的那一刻便已開始。"},"ICON-2037":{"nm":"計程車招呼旗夾","de":"招計程車時，用夾子把小旗筆直立起。代替舉手、替你呼喊的訊號——在街頭，呼喚也要清晰才得以傳達。"},"ICON-2038":{"nm":"禮賓門鈴把手","de":"按下把手，清脆的聲音便傳到禮賓櫃台。「什麼都可以問」的款待訊號，是陌生城市裡最可靠的一聲呼喚。"},"ICON-2039":{"nm":"預約號碼夾板","de":"把預約號碼紙夾在夾板上，讓它清晰可見。為了不讓約定的位置弄混，把一行數字端正地夾住的小小誠實。"},"ICON-2040":{"nm":"遊程小冊架","de":"把遊程小冊插放著，旅人的手便自然停下。每一張翻開取下的紙裡，都靜靜摺著尚未啟程的路途風景。"},"ICON-2041":{"nm":"略圖印章座","de":"為了初次踏進玄關的腳步，把略圖上的印章那一格穩穩托住，不讓它晃動。油墨不暈開，路也就不混亂。是個讓小小指引能端正站立、默默撐起重量的位置。"},"ICON-2042":{"nm":"雨傘保管吊牌","de":"屋簷下雨滴滴答答的午後，每把傘各掛上一個號碼。雨停歸來的人尋找自己那把時，吊牌便一字一句喚回那濕潤的記憶。"},"ICON-2043":{"nm":"服務台呼叫鈴掛架","de":"叮鈴一響，那端便有人笑盈盈地跑來。掛在服務台邊角的小鈴，是替你傳達連難以啟齒的話也代為說出的、最溫柔的傳譯。"},"ICON-2044":{"nm":"洗髮精按壓嘴","de":"攤開掌心輕輕一按，泡沫便撲地湧出。香氣在浴室裡瀰漫的那一次擠壓。把睏倦的早晨最溫柔喚醒的訊號音，正從這裡開始。"},"ICON-2045":{"nm":"皂盤瀝水板","de":"悄悄把肥皂底下積的水流走的板子。不讓它軟掉、不讓它爛掉。把每天一點點磨損的東西多留在身邊一掌之久的，小而溫柔的體貼。"},"ICON-2046":{"nm":"入浴劑勺","de":"舀一勺粉末化入溫水，色與香便緩緩暈染開來。手腕攪動之間，浴缸成了小小的湖，一日份的疲憊靜靜沉入其中。"},"ICON-2047":{"nm":"起泡網袋","de":"把一塊肥皂困進網裡搓揉，掌心便盈滿綿密的泡沫。把粗糙化為柔軟的，浴室一隅安靜的鍊金術師。"},"ICON-2048":{"nm":"牙刷消毒帽","de":"想讓觸碰嘴的東西總是乾淨，這份心意。一個輕輕包覆刷頭的小帽，連看不見的地方都顧到。乾淨，就是這般細微累積而成的。"},"ICON-2049":{"nm":"棉花棒罐蓋","de":"白色細棒整齊躺著的罐子，圓圓覆蓋其上的蓋。開時喀，闔時嗒。以細小的聲響為整頓收尾，浴室裡溫柔的句點。"},"ICON-2050":{"nm":"沐浴油滴瓶","de":"稍一傾斜便一滴滴滾落，芳香的油垂下。在浴缸裡暈開的光澤與淡雅的氣味。說奢侈太樸素，說日常又太溫柔的那僅僅一滴。"},"ICON-2051":{"nm":"備品托盤隔板","de":"在一格格分開的托盤上，小瓶子各自找到自己的位置。散開便雜亂、聚攏便端莊的那些東西。一個隔板，守護忙碌早晨的秩序。"},"ICON-2052":{"nm":"桑拿沙漏座","de":"是個溫柔的約定——至少在沙子全部流盡之前，好好把背暖熱吧。當斜倚在座上的沙漏滴答數著時間，在瀰漫的蒸氣中，人暫時什麼也不是地歇息著。"},"ICON-2053":{"nm":"汗蒸羊角頭巾","de":"把毛巾末端捲起，像羊耳般翹立起來，鏡中的臉便悄悄舒展開來。在炙熱的蒸氣間，人人都暫時回到童心的、汗蒸幕的小小儀式。"},"ICON-2054":{"nm":"桑拿水瓢","de":"用瓢舀滿水潑向燒熱的石頭，嗤——蒸氣直衝天花板。那一瞬全身浸入溫熱的霧中，積累的疲憊隨汗珠緩緩鬆解。"},"ICON-2055":{"nm":"足浴桶溫度棒","de":"把棒子浸入水中，刻度便悄悄開口搭話。不太燙也不太涼的恰好那個溫度。在浸入腳尖之前，最先探問水的安好的那根手指。"},"ICON-2056":{"nm":"汗蒸石夾","de":"剛燒熱的石頭無法徒手去抓。夾子俐落咬起，熱燙便移到安全的距離之外。小心謹慎也是一門手藝，汗蒸幕靜靜這麼說。"},"ICON-2057":{"nm":"桑拿坐墊","de":"在熱燙的地板上鋪一張，背貼之處便柔軟許多。默默承接汗濕一天的墊子。歇息，終究來自與地板恰當的距離。"},"ICON-2058":{"nm":"足浴鹽袋","de":"裝一把粗鹽化入溫水，倦意便從腳尖開始絲絲融化。鹹味的蒸氣裹上小腿時，走了一整天的日子才終於停下腳步。"},"ICON-2059":{"nm":"桑拿香水石碟","de":"在燒熱的石頭上滴幾滴香水，溫熱的香氣便在桑拿裡緩緩擴散。閉上眼，分不清這裡是森林還是花田。用鼻尖踏上的、最短的旅行。"},"ICON-2060":{"nm":"熱敷包保溫套","de":"把熱好的敷包包覆起來、久久留住暖意的布。如同生怕變涼而緊緊抱住的那份心意，置於腹上的溫暖徹夜陪伴在側。"},"ICON-2061":{"nm":"香氛擴香棒","de":"細長的棒子吸起香氣，緩緩流瀉於房中。隨每一口吸氣淡淡滲入的氣味。是停留的空間一點點變得像那個人的香氣的方式。"},"ICON-2062":{"nm":"日光躺椅角度把手","de":"緩緩轉動把手，椅背便徐徐傾斜。往陽光那邊一些，往陰影那邊一些。摸索著找出最舒適角度這件事，全然是我獨有的算法。"},"ICON-2063":{"nm":"泳池邊防滑帶","de":"環繞水邊一圈的防滑帶。為了讓嬉水後興奮跑來的小腳能平安停下，靜靜鋪在看不見處的安全終點線。"},"ICON-2064":{"nm":"泳圈氣塞環","de":"在封住空氣的小氣塞上，細心繫了一個環。為了不讓從泳圈脫落的氣塞漂走。預先防範盛夏正午細微遺失的智慧。"},"ICON-2065":{"nm":"泳池入水階梯帽","de":"柔軟包覆通往水中階梯末端的塞蓋。為了不刮傷赤裸的腳掌，把入水的第一步軟軟地承接下來。因為無論什麼，起步總要小心翼翼。"},"ICON-2066":{"nm":"躺椅墊繩環","de":"為了不讓墊子滑落，掛繩繫住的環。即使起風也要守住原位的小小約定。一個結，把午後的慵懶留在那個位置。"},"ICON-2067":{"nm":"泳池別墅飲料插板","de":"在泳池邊把飲料杯穩穩插入的板子。即使盡情戲水也不動搖的一個位置。把清涼放在伸手可及之處，讓盛夏的正午拉得更長。"},"ICON-2068":{"nm":"濕泳衣晾掛夾","de":"夾起滴著水的泳衣，靜靜交給風。在陽光下晾乾的期間，夾子默默咬著佇立。是為了下一次戲水的、安靜而溫柔的等待。"},"ICON-2069":{"nm":"陽傘柱底座配重","de":"為了不讓陽傘被風吹得搖晃，墊在柱底的厚重配重。陰影能久久停在一處，全靠這份重量。可靠，常常藏在最低處。"},"ICON-2070":{"nm":"泳池水溫浮標片","de":"浮在水面上、靜靜告知水溫的小片。太冷便泛紅，恰好便柔和。用一種顏色讀出水的心情的可愛小占卜師。"},"ICON-2071":{"nm":"帳篷拉鏈拉繩","de":"輕拉繫在拉鏈末端的小流蘇，帳篷門便咻地拉開。不必指尖摸索就能立刻抓到的拉柄。溫柔地引導深夜的進出。"},"ICON-2072":{"nm":"帳篷繩固定蝶夾","de":"把繩子咬成蝴蝶形、牢牢扣住的夾子。在風中飄動的布終於安定下來。露營的夜，由這些小而俐落的結扣靜靜守護。"},"ICON-2073":{"nm":"豪華露營墊氣塞","de":"嘴貼上去呼呼地吹，墊子便緩緩鼓起。充飽後把氣塞蓋緊，地板變得鬆軟，星光下安身的位置這才完成。"},"ICON-2074":{"nm":"帳篷頂掛環","de":"懸掛在帳篷頂、用來掛提燈或手帕的環。連頭頂那一小塊空間都妥善利用的家務智慧。就如同把一顆星掛在天花板代替天空。"},"ICON-2075":{"nm":"睡袋捲收固定帶","de":"為了不讓捲好的睡袋鬆開而纏繞扣住的帶子。一到早晨又縮回小巧的睡鋪。整裝待發，便是把昨夜的暖意端正摺起的事。"},"ICON-2076":{"nm":"帳篷入口鞋墊板","de":"放在帳篷入口、把鞋整齊托住的板子。泥土留在外頭，裡頭保持乾淨。用一道門檻溫柔劃分內外的、露營的小小禮儀。"},"ICON-2077":{"nm":"豪華露營提燈掛鉤","de":"掛提燈的彎鉤。往這兒一掛，光便在帳幕裡圓圓暈開。在黑暗中懸起一盞燈的那個位置，成了今晚我們的客廳。"},"ICON-2078":{"nm":"帳篷通風窗捲收夾","de":"把通風窗捲起夾住的夾子。稍稍敞開風路，帳篷裡的空氣便清爽許多。一道小縫隙，靜靜留出徹夜呼吸的餘地。"},"ICON-2079":{"nm":"帳篷地面防泥墊","de":"鋪在帳篷地面、阻擋泥土與濕氣的墊子。即使在草地上也鋪出乾爽睡鋪的一層。讓人棲身於自然卻不被自然浸濕，靜靜在旁幫襯。"},"ICON-2080":{"nm":"槓鈴卡扣環","de":"扣在槓鈴兩端、防止槓片脫落的環。全然信任舉起之人的重量的小小鎖扣。當安全穩穩托住時，極限才終於更新一格。"},"ICON-2081":{"nm":"壺鈴握把套","de":"鐵把磨得掌心生疼的最後一組，靠這一個小套子疼痛便消失。比起舉起重量，撐到最後握住更難——這道理，手在收尾的那一點上最先領會。"},"ICON-2082":{"nm":"槓片嵌入楔","de":"槓片只要稍有晃動，還沒舉起姿勢便先垮了。薄薄嵌入縫隙的楔子，無聲地穩住中心。穩固，總在看不見的地方悄然開始。"},"ICON-2083":{"nm":"槓鈴卡鎖夾","de":"扣上卡鎖的指尖不該有絲毫猶豫。喀的一聲那細小的上鎖聲，撐起接下來的整個動作。把信任交給一個夾子，身體先學會了這件事。"},"ICON-2084":{"nm":"槓片重量色片","de":"依重量各異其色的色片，就算不識字，手也先察覺。紅色重、藍色輕，用顏色記住重量這件事。身體出乎意料地透過眼睛來衡量力道。"},"ICON-2085":{"nm":"壺鈴底座墊","de":"多虧加寬觸地面的墊子，木地板不會被壓凹。運動的痕跡只要留在汗水與肌肉上就夠了。連腳下都不願留下傷痕的小小心意，就鋪在這裡。"},"ICON-2086":{"nm":"槓鈴中心標記","de":"刻在槓桿正中央的標記，是左右平衡的基準點。精準掐住中央的手，能把晃動減半。明白哪裡是中心的那一刻，才終於能安全地舉起。"},"ICON-2087":{"nm":"槓片收納掛架","de":"用完的槓片就歸回原位。在掛架上依重量整齊掛起的景象，是為下一個人的安靜體貼。整頓好的空間就是最可靠的安全裝置，有人這麼相信。"},"ICON-2088":{"nm":"槓片止滾擋","de":"放在地上的槓片悄悄滾來砸到腳背的事故，總在大意的一瞬發生。止滾擋靜靜攔住那一剎那。大事不從大處來，而是從小縫隙裡滾來。"},"ICON-2089":{"nm":"臥推椅靠背墊","de":"撐住背的墊子太硬，連呼吸都會變淺。適度堅實又適度柔軟的那道界線，是久坐之人才能用指尖摸索找到的平衡點。"},"ICON-2090":{"nm":"架高度插梢","de":"只要一根定高的插梢，便能讓槓桿契合任何人的肩。身高不同的人們和睦共用同一件器材——一個小小的調節孔，造就那份溫柔的平等。"},"ICON-2091":{"nm":"器械滑輪罩","de":"在包覆滑輪的罩子裡，鋼索無聲地一圈圈轉動。把摩擦藏於內，只將順滑交到手上的零件。好的裝置，始終不把自己付出的辛勞顯露出來。"},"ICON-2092":{"nm":"臥推椅腳防滑墊","de":"套在四隻腳末端的防滑墊，把臥推椅牢牢固定在地。唯有不晃動，才能放心使出全力。穩定，終究是從腳尖那一點小小的摩擦開始的。"},"ICON-2093":{"nm":"架槓鈴擱置鉤","de":"擱放槓桿的鉤子，總得在伸手可及的高度。疲憊的手臂最後輕輕放下槓桿的位置——那一掌的高度，安全地為今天的訓練收尾。"},"ICON-2094":{"nm":"器械配重梢把手","de":"插梢挑選重量的把手得光滑，才不會傷到指甲。連改變重量那一剎的小動作裡，也靜靜藏著體恤人手的收尾，這份用心我感受到了。"},"ICON-2095":{"nm":"臥推椅角度鎖桿","de":"鎖椅背角度的桿子若鬆動，姿勢便悄悄垮掉。喀地固定的那一瞬的確信。經營者每天早晨開門時，總是先靜靜檢查這聲音。"},"ICON-2096":{"nm":"架安全槓托","de":"在槓鈴脫手的最壞瞬間，安全槓托代為承接那份重量。因為有總在下方默默待命的托座，人才終於能推到自己的極限去試。"},"ICON-2097":{"nm":"器械鋼索末端帽","de":"收束鋼索末端的小帽，是防止鬆脫的最後一個結。為了不讓股線散開而端正束住——收尾的格調，總停留在那不顯眼的末端。"},"ICON-2098":{"nm":"鎂粉袋","de":"抹在手上、抹去滑膩的一把白粉。像舞台幕後的妝容般不顯眼，今日所有動作的安定，卻自這一把方才開始。準備，永遠從指尖起步。"},"ICON-2099":{"nm":"握力訓練夾","de":"默默反覆握緊張開的小夾子，鍛鍊手掌的力量。握力比大肌肉長得更慢，所以這也是靜靜放下急躁的練習。"},"ICON-2100":{"nm":"手指外展帶","de":"夾在手指間、緩緩向外撐開的帶子。只用過握緊肌肉的手，重新找回張開的力量。如同緊握一般，靜靜放開也需要練習，手這麼說。"},"ICON-2101":{"nm":"粉筆粉盒蓋","de":"粉盒蓋只要稍微鬆動，整個背包裡就會染成一片雪白。一個密合扣緊的小蓋子，便能預先擋下這樁微不足道的狼狽。防患的成敗，總是取決於那個小小的瓶塞。"},"ICON-2102":{"nm":"護膝纏繞帶","de":"纏繞撐托膝蓋的帶子，必須恰好停在適中的壓力上。太緊會阻斷血流，太鬆又毫無用處，那微妙的分寸，老練的手憑著記憶悄悄拿捏。"},"ICON-2103":{"nm":"彈力阻力圈帶","de":"可伸可縮的彈力帶，無需鐵塊也能喚醒沉睡的肌肉。所謂阻力，未必非得沉重不可。即使面對柔和的拉力，身體也總是誠實地回應。"},"ICON-2104":{"nm":"腳踝負重沙袋","de":"纏在腳踝上的沙袋，讓一步一步都沉甸甸地往下沉。稍微加點重量，平凡的走路也能成為像樣的訓練。這是悄悄為日常添上一點負擔的小智慧。"},"ICON-2105":{"nm":"手腕強化捲軸棒","de":"用手腕慢慢捲起繫在繩上的重物的捲軸棒。手腕是最小、也最常被遺忘的關節，而這個簡單的工具，靜靜喚回了那份被遺忘的力量。"},"ICON-2106":{"nm":"握力強化橡膠球","de":"在掌心一握一鬆的橡膠球，連坐在桌前也能悄悄延續鍛鍊。零碎時間累積的力量，比一次拚命使出的力更持久。恆心，總是從這樣的小處生長。"},"ICON-2107":{"nm":"心率帶扣環","de":"纏在胸前的帶子扣環只要稍有偏差，數字就會跳動。連聆聽自己心跳這件事，也得先牢牢扣緊。所有的測量，終究始於毫無縫隙的貼合。"},"ICON-2108":{"nm":"脈搏夾夾","de":"輕咬指尖的夾子，靜靜數著脈搏。夾上後調勻呼吸，小小的螢幕上便清晰浮現心臟的節拍。身體總是毫無虛假地告知自己的狀態。"},"ICON-2109":{"nm":"腕式心率帶收納盒","de":"用來收放腕式測量器的盒子雖小，卻認得自家的成員。越是容易遺失的小裝置，越需要一個可以回去的家。妥善保管，也是一種溫柔的方式。"},"ICON-2110":{"nm":"配速旗釘","de":"為跑者標出目標地點的小旗釘。「就到這裡。」一個預先定下的點，能把沉重的雙腳一路帶到終點。心中的終點線，總是親手插下的。"},"ICON-2111":{"nm":"心跳燈帽","de":"隨著心跳靜靜閃爍的小燈。凝視著那忽明忽暗的節奏，會忽然心頭一暖——原來活著，竟是如此規律的一件事。"},"ICON-2112":{"nm":"計圈算珠串","de":"一次撥動一顆珠子來計數。不必用腦袋去記數字，手指會代為記住。把計數交給手，心便能全然停留在動作上。"},"ICON-2113":{"nm":"血氧夾墊","de":"夾在指尖的夾墊，靜靜讀取血中氧氣的含量。當看不見的呼吸深度化作數字浮現時，才再次領悟：照顧身體，終究是好好凝視的一件事。"},"ICON-2114":{"nm":"心率區間色帶","de":"用顏色劃分運動強度的帶子，一眼便能看出此刻自己有多努力。藍色是餘裕，紅色是極限。顏色化作溫柔的語言，成了一個靜默的約定。"},"ICON-2115":{"nm":"測量果凍膠囊","de":"測量身體狀態的小果凍膠囊，一顆便盛裝著一天份的資訊。無論透明殼裡裝著什麼，那份想更了解自己一點的心，也一同盛在裡頭。"},"ICON-2116":{"nm":"毛巾掛環","de":"不隨手一搭，而是必定掛回專屬掛環的一個小習慣，便守護了整個空間的整潔。就像它為毛巾預先定下歸處一樣，整理總在小處閃光。"},"ICON-2117":{"nm":"水壺蓋繫繩","de":"繫在水壺蓋上的短繩，防止瓶蓋骨碌碌滾走的意外。把易失之物悄悄繫在身上的智慧——一條小繩，靜靜收走了一天份的麻煩。"},"ICON-2118":{"nm":"通風扇翼板","de":"完全展開便能掀起風的扇翼。就像炎日裡為人拭去汗水的舊扇子，最簡單的工具遞上最清涼的慰藉。一縷清風，總在指尖綻放。"},"ICON-2119":{"nm":"冰涼毛巾袋","de":"用來收放沾濕後便會變涼的毛巾的小袋。一條退熱的布巾在裡頭悄然安睡，待疲憊的後頸湊近時，輕輕落下，靜靜帶走正午的暑氣。"},"ICON-2120":{"nm":"水珠承接碟","de":"預先為凝結的水珠備好落腳之處的承接碟。不責怪那滴落，而是先讓出承接的位置。廚房的溫柔，總是這般無聲地停駐。"},"ICON-2121":{"nm":"送風機方向翼","de":"正面襲來的風順著小翼稍稍偏移的那一刻，悶熱的練習室空氣才終於緩過一口氣。改變氣流的，總是這般微小的角度。"},"ICON-2122":{"nm":"額頭束髮帶夾","de":"洗臉時瀏海若被水沾濕，一整天都會跟著亂套。這條把髮絲輕輕撥到額上的帶子，給了鏡前的人五分鐘的清爽。沒有它，才終於察覺它的好。"},"ICON-2123":{"nm":"飲水杯夾架","de":"當杯子在桌緣搖搖欲墜時，這夾子靜靜扶住了一側。一口水告訴你：沒打翻而平安度過的一天，是有人替你扶住了那個邊角。"},"ICON-2124":{"nm":"通風窗鉤把手","de":"緊閉的窗悶，敞開的窗冷。這把鉤把手記住了兩者之間恰到好處的那道縫。所謂通風，終究是顆懂得適度敞開的心。"},"ICON-2125":{"nm":"軟木磚邊角護蓋","de":"撞傷人的，總是那尖銳的邊角。於是削下一塊軟木，套在每一個角上。被柔軟包覆的地方，如今再也不會弄疼任何人的膝蓋。"},"ICON-2126":{"nm":"抱枕繩把手","de":"搬動長枕，比想像中更惱人。只要繫上一條繩，便能一手輕鬆提起。把沉重之物提得輕巧的訣竅，全在於把手繫在何處。"},"ICON-2127":{"nm":"腰帶扣緊扣","de":"有把腰帶多扣緊一格的日子，也有鬆開一格的日子。最誠實地知曉那天狀態的，正是這個小小的緊扣。一塊默默記錄身體坦白的鐵件。"},"ICON-2128":{"nm":"四分之一磚墊","de":"切成四等分的磚塊，穩穩撐起地面。不高也不低，恰恰那麼一分的平衡。它默默示範著：所謂承托，是放低自己以托起上方。"},"ICON-2129":{"nm":"蛋形抱枕套","de":"為蛋一般圓潤的枕頭穿上合身的衣裳。即使浸了汗，脫下來洗便是。越是天天貼身的，越得有一件可替換的——這個道理，居家生活最懂。"},"ICON-2130":{"nm":"磚高度調整楔","de":"地面只要稍微傾斜，費心堆起的一切便全都搖晃。往那縫隙裡塞進一塊薄楔，世界便尋回了水平。要扶正一物，無需任何浮誇。"},"ICON-2131":{"nm":"繩帶末端結珠","de":"為防繩帶末端散開磨損，牢牢打上結珠。把末端收得俐落的繩子才耐久。收尾比起頭更難——這個道理，一個小結便教會了人。"},"ICON-2132":{"nm":"護膝可摺墊","de":"每當膝蓋抵著硬地時，那股痠疼。一張可摺可展的墊子悄悄塞進膝蓋與地面之間。那是替誰的膝蓋分擔承托的溫柔。"},"ICON-2133":{"nm":"磚防滑底板","de":"再堅硬的磚塊，一打滑也成了廢物。刻在底板上的細密紋路，緊緊咬住地面。不晃動之物的秘密，總藏在看不見的下方。"},"ICON-2134":{"nm":"對齊棒夾","de":"把棒子排得筆直，再用夾子輕輕一夾。熟於對齊之事的人都明白——把錯落之物擺得整齊時，那股湧上的、奇妙而微小的滿足感。"},"ICON-2135":{"nm":"膕繩肌拉帶環","de":"當大腿後側緊繃得幾乎要叫出聲時，這個環代替搆不著的腳尖把它拉過來。在獨自無法觸及之處，一條繩為雙腿架起了橋。"},"ICON-2136":{"nm":"腳趾分隔墊","de":"整日被困在鞋裡的腳趾，也需要喘息的片刻。在一根根間隔撐開的墊子上，腳難得伸了個懶腰。一個從最遠處開始舒緩的夜晚。"},"ICON-2137":{"nm":"姿勢角度量尺","de":"我的姿勢究竟歪了幾度，光憑眼睛實在無從拿捏。當量尺靜靜告知角度，身體才終於站直。一把刻度，讓人看見了看不見的傾斜。"},"ICON-2138":{"nm":"骨盆對齊楔","de":"骨盆偏向一側僵住的慵懶午後。墊上一塊楔子，慢慢尋回重心。不是硬扳開，而是重新找回那恰當的位置。"},"ICON-2139":{"nm":"開肩帶扣環","de":"靜靜舒展蜷縮雙肩的帶子。扣緊扣環，佝僂的背便慢慢敞開。以挺直的雙肩深深吸一口氣，那才終於有了登台謝幕的姿態。"},"ICON-2140":{"nm":"脊椎支撐楔","de":"仰躺下來，脊椎便描出本來的曲線。不違逆那弧度、靜靜承托的楔子。懂得好好休息，始於承認身體與生俱來的曲線。"},"ICON-2141":{"nm":"腳背伸展楔","de":"拉伸腳背的伸展，總覺得哪裡差了一點。墊上一塊合適的楔子，連搆不著的深度也舒暢地展開了。一道小斜坡，助人多搆遠那麼一些。"},"ICON-2142":{"nm":"手腕對齊托座","de":"當鍵盤前折起的手腕開始發麻時，托座悄悄滑進手腕下方。最先照顧長時間工作之手的，正是這些身居低位的物件。"},"ICON-2143":{"nm":"護腕纏帶","de":"提起重物之前，先在手腕上纏一圈。纏得多牢，心便多踏實。在受傷前先預先包覆的習慣，是長久運動之人沉默的秘訣。"},"ICON-2144":{"nm":"臂帶手機袋","de":"跑步時手機該擱哪兒，一直是個煩惱。這個綁在前臂上的袋子帶走了那份煩惱。把喜歡的歌夾在臂上奔跑，路便覺得短了許多。"},"ICON-2145":{"nm":"握力器彈簧帽","de":"為防握力器彈簧末端刺到手掌而套上的帽。在反覆一握一鬆之間，這個小塞子守護著手與鐵之間的和平。是看不見之處的體貼。"},"ICON-2146":{"nm":"手套指尖護頂針","de":"熟於針線的奶奶手指上，總戴著頂針。套在手套指尖的這枚頂針，守護著指尖。珍惜久勞之手的心意，隔了世代，依舊一模一樣。"},"ICON-2147":{"nm":"握把繭墊","de":"掌心磨出的繭，是努力留下的指紋。覆在其上的墊子，讓下一次成為可能。再次包覆已然堅硬的地方，人又一次攀了上去。"},"ICON-2148":{"nm":"掌心防滑膠帶","de":"掌心一再打滑，便會放開好不容易握住的東西。纏上粗糙的膠帶，手與工具便合為一體。不鬆手的力量，意外地來自摩擦。"},"ICON-2149":{"nm":"前臂吸汗帶","de":"運動中流下的汗水抵達手腕之前，前臂上的這條帶先一步吸收了它。一塊濕透的布默默作證：汗水並不是什麼難為情的事。"},"ICON-2150":{"nm":"手套晾乾掛架","de":"隨手一扔，隔天早上便是場折磨；好好掛起，整夜的風便自會把它吹得鬆爽。晾乾的手套那股潔淨的氣味，清新地揭開明天。"},"ICON-2151":{"nm":"運動服拉鍊把手","de":"用濕淋淋的手，實在抓不住那小小的拉鍊頭。只要繫上一個把手，一拉便順暢到底。一個不起眼的環，整個救回了手忙腳亂的那一分鐘。"},"ICON-2152":{"nm":"排汗透氣貼片","de":"在身上最熱的部位貼上透氣貼片。被困住的熱氣，悄悄從貼片之間溜了出去。在最悶的正中央，鑿出一個小小的呼吸孔。"},"ICON-2153":{"nm":"鞋墊緩衝塊","de":"從舊鞋墊上只挖去磨損的部分，換上新的一塊。不整個丟棄，只替換疼痛之處的手。腳下的小修補，輕巧地改變了一天的步伐。"},"ICON-2154":{"nm":"運動服號碼燙印片","de":"用熨斗緊緊壓上，把背號烙進衣服。在熱度冷卻之際，數字牢牢落定在布上。那是讓掛著同一號碼的人成為一隊的、起點的印章。"},"ICON-2155":{"nm":"鞋頭加固蓋","de":"鞋子腳尖總愛磕碰的宿命，被套在鞋頭的加固蓋靜靜擋下。最先磨損的地方，便要最為堅固。越是要久穿的鞋，越是從鞋尖開始紮實。"},"ICON-2156":{"nm":"運動服束繩結","de":"拉一下運動服腰繩打上結的那一刻，鬆垮的衣服便緊緊貼合身體。這個牢實不鬆的結，在激烈的動作中始終穩住不亂。"},"ICON-2157":{"nm":"踝襪防滑帶","de":"踝襪總愛捲進鞋裡的那份惱人。一條帶子扣住了那股滑動。小到讓人無心在意的一隻襪子，這才終於守住了自己的位置。"},"ICON-2158":{"nm":"運動服腋下汗墊","de":"預先貼在最易冒汗之處的墊子。即使濕透，衣服外側也不露一絲痕跡。在看不見之處默默工作的東西，把舞台守得乾淨俐落。"},"ICON-2159":{"nm":"鞋跟提環","de":"穿上鞋後輕輕一拉鞋跟提環，腳便順勢滑了進去。不必蹲下身的那份短暫便利。忙碌的早晨，這樣一個環便立了大功。"},"ICON-2160":{"nm":"按摩槍頭帽","de":"依敲打的部位更換槍頭。每一處僵硬的肌肉，都另有合適的形狀。為撐過一天的肩膀，挑出恰好的慰藉力道遞上的夜晚。"},"ICON-2161":{"nm":"按摩槍充電座","de":"整日替人鬆筋的手，也得充飽電才會甦醒。在紅燈轉為綠燈之間，暫且歇息也無妨。閃爍一停，便又輪到它去撫慰僵硬的肩膀，那一刻悄然臨近。"},"ICON-2162":{"nm":"按摩槍強度旋鈕","de":"弱一點、再強些、就到這裡。轉著旋鈕，指尖靜靜與自己的身體討價還價。只在受得住的範圍內變強健——今天的約定，一筆一畫寫在小小的刻度之間。"},"ICON-2163":{"nm":"震動球承托環","de":"再會滾動的球，也需要一個暫時歇腳的地方。這個圓形承托靜靜抱住那顆想咕嚕滾走的心，守住原位，直到下一輪到來。歇息，也是運動的一部分。"},"ICON-2164":{"nm":"指壓棒握把帽","de":"套在末端的一頂小帽，掌心的疼痛便悄然消散。堅硬與肌膚之間，總需要一層柔軟。先把觸碰之處磨得圓潤的、溫柔的一寸。"},"ICON-2165":{"nm":"花生滾筒袋","de":"用來收放花生形滾輪的小布袋。從包包一角咕嚕滾出時，連昨天那句「今天也好好照顧身體吧」的決心，也一併跟了出來。小布袋記住了那個約定。"},"ICON-2166":{"nm":"足部指壓滾筒立座","de":"託付雙腳的位置若搖晃，放鬆也跟著搖晃。撐起滾輪的這個立座牢牢咬住地面，為疲憊的雙腳備好一處可安心倚靠的位置。踏實，源於不搖晃。"},"ICON-2167":{"nm":"滾筒中軸塞","de":"塞住空心軸的小塞子。看不見的內裡得先填實，外觀才不致散亂。在滾動之間誰也看不見的那個位置，這個沉默的零件默默撐著。"},"ICON-2168":{"nm":"按摩棒末端塞","de":"圓圓套在棒子末端的帽。不磨損、不刮傷——守護末端，終究是讓它長久相伴之道。把最先碰撞的地方，最柔軟地包覆起來的一份心意。"},"ICON-2169":{"nm":"貼紮卷裁切器","de":"單手一拉，膠帶便俐落裁斷。打結與收尾也自有一套小竅門，而這刀刃懂得那份俐落收尾的手感。乾淨的收尾，讓下一回更輕鬆。"},"ICON-2170":{"nm":"膠帶末端黏蓋","de":"為防鬆脫而靜靜壓住末端的蓋子。起頭人人都會，難的總是黏到最後。這隻扶住最後一寸的小手，默默擔起了今日的收尾。"},"ICON-2171":{"nm":"手腕加壓護套","de":"為勞累過度的手腕裹上一層，疼痛便慢了一拍才到來。就像有人靜靜扶住的手，加壓有時是最溫柔的守護。那不是緊勒，而是承托。"},"ICON-2172":{"nm":"護踝扣環","de":"扣上扣環那短短一聲「喀」，心便安了下來。把腳踝牢牢包住，彷彿再多邁出一步也無妨的勇氣，悄悄湧上。一聲輕響，成了踏實的出發。"},"ICON-2173":{"nm":"膝部加壓繩緊扣","de":"繩子拉得多緊，膝蓋便多踏實。不鬆脫、卻又不疼痛——在那之間某處，藏著恰好的一格。緊扣每一次都不忘記住那個位置。"},"ICON-2174":{"nm":"手指貼紮剪","de":"把纏在指節上的膠帶精準剪斷的小剪刀。刀尖圓鈍，不會傷及肌膚。越是照護的工具，越要把刀刃磨得更溫柔——這把剪刀靜靜示範了這一點。"},"ICON-2175":{"nm":"加壓帶捲收架","de":"把散開的加壓帶整齊捲收的架子。用心捲好用過之物的手，下次解開時也不會散亂。一圈圈捲起的每一層裡，都浸著今日的整潔。"},"ICON-2176":{"nm":"護脛墊繩","de":"綁住守護小腿前側護墊的繩子。先察看會被撞之處的心，便是準備。以牢牢打結的雙腿踏進運動場，心中的怯意便消了一半。"},"ICON-2177":{"nm":"護肘夾","de":"為防護具滑落而牢牢咬住的小夾子。雖瑣碎得像夾一張紙，可它一鬆，一切便都鬆了。一個小小的固定，牢牢扣住了一天份的安心。"},"ICON-2178":{"nm":"伸展圈把手","de":"握住圈環把身體拉長，便看見比昨天又遠了一寸的指尖。被拉伸的不只是肌肉，僵硬的心也在那之間漸漸舒展開來。"},"ICON-2179":{"nm":"腳趾分隔指套","de":"把整日困在鞋裡的腳趾間撐開，狹窄的縫隙便有了風。世上有些東西，得暫且分開才終於舒坦。腳尖，也需要一絲喘息的空隙。"},"ICON-2180":{"nm":"小腿放鬆楔板","de":"像楔子般墊在小腿下，雙腿便緩緩鬆開。一個傾斜的角度，靜靜流走一天份的重量。微微倚靠著躺下，有時那便是最舒坦的姿勢。"},"ICON-2181":{"nm":"頸部放鬆掛托","de":"把脖子擱上去，暫且閉上眼。這個小小的托座總在同一處，低聲對肩膀說：把沉重的頭暫且放下也無妨。連倚靠這件事，也是需要勇氣的。"},"ICON-2182":{"nm":"伸展棒末端帽","de":"覆在長長伸出的棒子末端的一頂帽。末端柔軟，碰到哪兒都安心。無論朝著誰伸去，都先把邊角磨圓——體貼，總是這般無聲地開始。"},"ICON-2183":{"nm":"指壓墊凸點板","de":"把身體躺在凹凸的凸點上，每一處被戳壓的地方都流走了一天。在那痛又舒服的交界，僵了一整天的肩膀彷彿緩緩繳械般鬆開。"},"ICON-2184":{"nm":"放鬆呼吸沙漏","de":"在沙子流到最後一粒之前，把氣息長長調勻——那是一個靜默的約定。細細的沙流靜靜數著吸氣與吐氣的節拍。匆忙的心，也在那之間暫且沉澱。"},"ICON-2185":{"nm":"腳底指壓球承托","de":"把球承托在腳底正中央，輕輕壓下。對著撐了全身一整天的腳說：現在輪到我來承托你了——小小的承托靜靜讓出位置。承托者，也有歇息的時候。"},"ICON-2186":{"nm":"肩部放鬆環繩","de":"掛上肩頭往下拉的環繩。朝僵硬之處把繩拉長，糾結的關節便一格格鬆解開來。它告訴我們：連獲得自由這件事，也需要有可以攙扶一把的什麼。"},"ICON-2187":{"nm":"水道繩浮盤","de":"分隔水道的泳道繩，那一顆圓圓的節。是劃在水面上、叫人別與鄰人相撞的溫柔界線。守護各自水道的小隔板，讓所有人並肩前行到最後。"},"ICON-2188":{"nm":"泳道繩張力環","de":"把泳道繩繃緊掛住的環。太鬆便被水波拗彎，太緊又會斷裂。尋找恰當張力之事，與收束心神極為相似，總在那之間某處摸索著尋找。"},"ICON-2189":{"nm":"泳道顏色帽","de":"為每條泳道塗上不同顏色的小塞子。是為了讓人遠遠便能一眼認出自己的道而塗下的記號。以一抹顏色讓人不再迷失——指引，本就始於這般瑣碎的善意。"},"ICON-2190":{"nm":"水道繩掛板","de":"不用時把泳道繩整齊掛起的板子。為下一次出發把繩子細心理好的手中，靜靜盛著一份「要把今天好好收尾」的沉穩心意。"},"ICON-2191":{"nm":"泳道繩捲收把手","de":"轉動把手一圈圈，把長長散開的繩捲收進來。把散落之物收攏起來，總是需要耐心。一圈、又一圈——收尾便是這樣不疾不徐地完成的。"},"ICON-2192":{"nm":"泳道末端結夾","de":"為防繩端的結鬆開而牢牢咬住的夾子。連零碎的一節也不放過。要有一隻把守到最後的手，長長的繩才不致散亂，好好保住自己的形狀。"},"ICON-2193":{"nm":"水道繩浮標珠","de":"在水面上漂浮的泳道繩浮標珠。為了不下沉，在自己體內飽含了滿滿的空氣。某種輕盈，源自費心填滿的空心——晃蕩的水波，每每把它托起示人。"},"ICON-2194":{"nm":"泳道號碼旗","de":"告知泳道號碼的小旗。一塊在風中翻飛的布，清晰地告訴你「這裡是你的位置」。讓人不必徬徨、徑直走進自己的道——雖小卻分明的路標。"},"ICON-2195":{"nm":"泳道繩連接鉤","de":"把一條條泳道繩接連掛起的鉤。靠這一只重新接合斷路的鉤子，水道才終於完整。所謂連接，終究是悄悄向斷開之物伸出手的、一塊小鐵件的工作。"},"ICON-2196":{"nm":"起跳台踏板","de":"起跑線上的踏板，完整地承接第一躍的重量。奮力蹬出的那0.1秒，腳尖所踏的那份堅實，推動了一場比賽的開端。所有起飛，都從踏實之處出發。"},"ICON-2197":{"nm":"出發握把桿","de":"出發信號前的一刻，手緊緊握住的桿。得把顫抖的心安放在某處，出發才不會搖晃。光是有個可以抓握之處，下一個動作便清晰而踏實了許多。"},"ICON-2198":{"nm":"仰泳旗繩","de":"向仰望天花板游泳的人告知牆已接近的旗繩。是預先告知看不見之處的一份溫柔。一個體貼地照看背後的信號，便讓最後一下變得安全。"},"ICON-2199":{"nm":"轉身牆墊","de":"貼在轉向之牆上的柔軟墊子。即使用力撞上也不會疼，把轉身之處包得軟綿綿。歸返的路口，總有人的一份靜默體貼，早已先鋪在那裡。"},"ICON-2200":{"nm":"終點觸碰板","de":"指尖觸到的那一刻，一切便結束了。漫長而喘息的路，盡頭終究是這輕輕的一觸。終點並非什麼了不起的事，而是準確點到自己的位置——觸碰板靜靜如此回答。"},"ICON-2201":{"nm":"出發台滑行帶","de":"站上斜坡末端的人，誰都會屏息那麼一次。越過那短暫的恐懼滑下去，撲通——伴著水花，笑聲也跟著迸發。出發，總是始於跨過小小一格恐懼的那一頭。"},"ICON-2202":{"nm":"轉身距離標示錐","de":"在岔路前猶豫時，這個小小的點先開了口。從這裡轉身就好，別迷路了。總有人看著這一抹顏色，重新尋回自己的方向走下去。"},"ICON-2203":{"nm":"起跳台角度楔","de":"起跳前，身體蜷得最低的那半拍。為了不讓腳尖打滑而撐住角度的小小立足點，就在那裡。所有高高躍起的瞬間，都誕生於這道傾斜。"},"ICON-2204":{"nm":"牆角緩衝蓋","de":"為了讓嬉鬧中撞上也不疼，牆角讓出了自己的鋒利、磨得圓潤。一份「別受傷」的心意，削了又削，貼附在牆上。最溫柔的守護，大多這般無聲。"},"ICON-2205":{"nm":"救生圈掛環","de":"平時不過是靜靜掛著的一處。然而當有人落水的瞬間，最先伸手去夠的，正是這裡。不被用到反而更好的那種踏實，世上也是有的。"},"ICON-2206":{"nm":"救援鉤長桿","de":"把搆不著的距離一舉拉近的長臂。當手不夠長時，這鉤子便代為成了手。救援，終究是把自己的指尖，遞向遠處某人的一件事。"},"ICON-2207":{"nm":"泳池畔淋浴頭","de":"「下水前一定要先沖洗一下喔。」就像泳道引導員的口頭禪，水柱從頭頂傾瀉而下。冰涼的一沖，一天的塵埃便嘩啦啦地脫落了。"},"ICON-2208":{"nm":"防滑踏板地磚","de":"為了讓赤腳不打滑而細細凸起的紋理。在看不見的地方，靜靜扶住腳底。最堅實的安全，總藏在不顯眼的地方。"},"ICON-2209":{"nm":"水深標示牌","de":"踏入之前，數字先告知深度。不知情便踏進去會教人害怕的地方，讀過一次，心裡便有了底。這塊牌子做的事，是幫人做點小小的準備。"},"ICON-2210":{"nm":"安全線浮標繩","de":"漂浮水面、劃分區域的色彩繩。浮標們手牽著手約定：到這裡為止都安全。有了界線，才終於能安心地盡情暢泳。"},"ICON-2211":{"nm":"泡腳消毒槽","de":"入水之前，赤腳暫且停留的小槽。一場從腳尖開始潔淨的短短儀式，便盛在那裡。潔淨，總是始於這般踏出一步的用心。"},"ICON-2212":{"nm":"濕滑地面警示錐","de":"一個黃色的錐筒，悄悄放緩了腳步。「這裡濕了，小心。」以顏色代替言語遞上的體貼。某人險些滑倒的一天，被這個小小的警示靜靜守住了。"},"ICON-2213":{"nm":"急救包壁櫃","de":"牆邊的白色櫃子難得被打開。然而打開的那一刻，便成了某人的安心。緊急，總是在最近的地方靜靜等候。"},"ICON-2214":{"nm":"水面濾網撈杓","de":"把漂在水面的葉子與塵埃靜靜撈起。澄澈不會自己到來，每天都得有人的手撈上那麼一回。寧靜的水背後，有一只勤勞的撈杓。"},"ICON-2215":{"nm":"池底清掃機器人軟管","de":"即使在眾人沉睡的夜裡，也摸索著池底慢慢遊走。在無人注視的時刻最為勤懇的工人。清晨那份清澈，是這軟管整夜描繪下的軌跡。"},"ICON-2216":{"nm":"氯投放藥桶","de":"把水保持清澈這件事，也自有恰當的分量。多了便毒辣，少了便混濁，那之間的平衡。一隻看不見的手，每天靜靜對準那道刻度。"},"ICON-2217":{"nm":"水質檢測水瓶","de":"用小瓶盛來一口水，問候今天的安否。眼睛看來雖一模一樣，數字卻不說謊。所謂安心，便是這樣每天確認那麼一次。"},"ICON-2218":{"nm":"戲水板撈取耙","de":"把漂在水面的板子與浮游物聚攏一處的長耙。把散落之物耙攏的手，不知怎地像極了人心。再凌亂之物，掃過一回也就齊整了。"},"ICON-2219":{"nm":"排水口蓋網","de":"守住水流出口的細密網。靜靜分辨出該放走的與該攔下的。放手送別這件事，也需要過濾——這張小網無聲地如此告知。"},"ICON-2220":{"nm":"水溫計浮標","de":"漂浮水面、讀取溫度的小小偵察兵。冷不冷、適不適中，在身體碰到之前便先告知的溫柔。入水的第一份安心，總是從這浮標開始。"},"ICON-2221":{"nm":"泳池蓋捲收桿","de":"把寬大的覆蓋捲成一團、收到一旁的把手。懂得何時展開、何時收起的工具，不知怎地教人安心。休息時間，等於也替水蓋上了一床被子。"},"ICON-2222":{"nm":"撇渣器籃桶","de":"漂在水面的浮游物最後聚集的籃子。有了在看不見之處承接渣滓的器皿，上層的水才總是清澈。潔淨的背後，堆著辛勞。"},"ICON-2223":{"nm":"泳帽晾乾掛架","de":"把含著水氣的泳帽倒掛起來。在一滴滴咕嚕落下的同時，帽子慢慢調勻著氣息。所謂晾乾，終究是等待的另一個名字。"},"ICON-2224":{"nm":"泳衣肩帶環","de":"為了不讓肩帶從肩上滑落而扶住它的小環。在看不見的地方，靜靜守著儀容。整潔，總是在這般瑣碎的支撐上完成。"},"ICON-2225":{"nm":"泳帽收納袋","de":"讓濕泳帽一個個尋回歸處的袋子。是把容易散落之物攬進一懷的小小居所。整理，是一份不願弄丟的溫柔習慣。"},"ICON-2226":{"nm":"泳衣胸墊","de":"悄然安放在衣服內側的一片墊。即使外表看不見，也悄悄為穿者挺直了肩膀。某種踏實，不在外頭，而在內裡靜靜被填滿。"},"ICON-2227":{"nm":"泳帽名牌夾","de":"在泳帽邊角夾住名牌的小夾子。在一模一樣的東西當中，清楚地說一句「這是我的」。只要一個標示，混淆便一舉了結。"},"ICON-2228":{"nm":"泳衣拉鍊環","de":"「能幫我拉一下背後的拉鍊嗎？」獨自搆不著的那個位置，這個小環代替了手把它拉了上去。是攙扶最後一格的、一段溫柔的距離。"},"ICON-2229":{"nm":"泳帽防捲板","de":"把捲成習性的泳帽撐直承托好。是靜靜幫彎曲之物尋回原形的承托。要有撫平的手，無論什麼才能重新變得端正。"},"ICON-2230":{"nm":"泳衣腰繩緊扣","de":"恰好包住腰際、不讓它滑落而扶住的緊扣。不太勒也不太鬆，剛好那麼一分的適中。舒適，總是住在那之間的某處。"},"ICON-2231":{"nm":"泳帽翻面夾","de":"抓住裡外翻轉的泳帽、一舉翻正的夾子。把翻面之物好好翻回來的手感，著實挺暢快。整頓的小快意，便是這般從瑣碎處而來。"},"ICON-2232":{"nm":"浮板握繩","de":"為了不放開浮板而纏在手上的繩。即使被水流推搡，有個可抓之處便是莫大的安心。初學打水那天的悸動，至今仍留在這條繩上。"},"ICON-2233":{"nm":"夾腳浮標緊繩","de":"把夾在兩腿之間的浮標牢牢扶住的繩。得不鬆脫，才終於能專注於姿勢。在被好好扶住的基礎上，那天的練習一寸寸地深入。"},"ICON-2234":{"nm":"蛙鞋壁掛","de":"蛙鞋並排掛在牆上時，活像一群在水邊歇息的鴨子。游完泳的腳們甩著水滴，等待著明天。連休止符也圓圓的、哪兒都透著可愛的一處。"},"ICON-2235":{"nm":"浮板邊角蓋","de":"輕輕套在浮板邊角的一頂小蓋。為了撞到也不疼、磨損也不傷，把末端包裹起來。長久相伴的訣竅，就在於從邊角開始珍惜。"},"ICON-2236":{"nm":"蛙鞋收納網","de":"形似蹼足的蛙鞋們，在網中曬著太陽。就像剛出水的鴨子晾乾羽毛般，在網裡慢慢風乾。是為了下一次暢泳而從容的午睡。"},"ICON-2237":{"nm":"浮標整理標籤","de":"在每個浮標上貼名牌，清楚標明主人。越是眾人分用之處，「是誰的」越要分明，心才安穩。一張小小的標籤，便立起了秩序。"},"ICON-2238":{"nm":"浮板瀝水承托","de":"為了讓積在浮板上的水咕嚕流下而斜斜承托的位置。它默默告知：得把含著的東西倒空，才會輕盈。晾乾的第一步，是好好承托起來。"},"ICON-2239":{"nm":"蛙鞋繩緊扣","de":"把蛙鞋繩調得合腳的小零件。鬆了會脫落、緊了又疼，那微妙的一格。要像戴著蹼的鴨子般輕快前進，便少不了這一分巧勁。"},"ICON-2240":{"nm":"打水節奏晶片","de":"每次蹬腳便告知節拍的小晶片。一、二、三——節奏一旦入了身，連水也不知不覺成了歌。游泳也有節拍這件事，這晶片悄悄教會了人。"},"ICON-2241":{"nm":"濕泳衣收納袋","de":"走出泳池的包包裡，最先佔位的總是我。就算別的行李給我臉色看也沒辦法，濕的東西得單獨收著，大家才一起鬆爽。水氣的隔離室，便是我擔下的溫柔職務。"},"ICON-2242":{"nm":"擰水擠壓板","de":"水氣有種一按便悄悄逃走的脾性。一次用力按、兩次用力按——擺上板子壓上重量，它才終於繳械。對沒處使手腕力氣的人，這般舞台可不多見。"},"ICON-2243":{"nm":"泳具袋隔板","de":"全裝進一個袋裡，濕的與乾的便彼此沾染。悄悄擠進那之間、靜靜劃下一道線。若一塊隔板就能帶來和平，那和解也許意外地簡單。"},"ICON-2244":{"nm":"防水鞋袋","de":"把沾滿沙的鞋整個吞下，臉色也不變一下。無論裡頭發生什麼，外頭都乾爽如常——那便是防水所守的禮數。口風緊的袋子，到哪兒都受歡迎。"},"ICON-2245":{"nm":"泳具袋排水蓋","de":"扭開塞子，積在包底的一天便嘩啦啦地流走。盡興玩過後的善後，總是繫於這一個小小的孔。懂得放水流走這件事，背後自有一番設計。"},"ICON-2246":{"nm":"吸水踏墊","de":"靜靜趴在玄關前，接住每一隻進門的腳上的水氣。即使無人知曉，地板卻明白——今天也沒人滑倒。沉默的位置，棲著沉默的成就感。"},"ICON-2247":{"nm":"濕泳帽承接碟","de":"脫下隨手一扔的泳帽若失了去處，便由我來承接。雖名為碟子，盛的卻是水珠而非食物，可若是為某物備好一席之地，承托者也算挺挺有面子。"},"ICON-2248":{"nm":"毛巾晾乾夾","de":"在曬衣繩上把一條毛巾緊緊咬住的活兒。風再怎麼逗弄也不鬆口的執拗，是我的驕傲。直到曬得鬆爽為止，一旦咬住的手，絕不先鬆。"},"ICON-2249":{"nm":"防水收納包掛架","de":"掛上鉤的那一刻，漂泊的收納包終於有了門牌。即使只是借牆上一格懸著，可像這般不必擔心遺失的位置，還有什麼比它更教人安心呢。"},"ICON-2250":{"nm":"滑水道入場手環","de":"靜靜排隊等候的雀躍，全都繫在這一個小小的手環上。直到扣上手腕，滑水道的隊伍才開始晃動起來——所謂入場，或許就是把一個約定繞上手腕的事。"},"ICON-2251":{"nm":"滑水墊碎片","de":"腳下早已破損，人們卻渾然不覺，依舊歡快地奔跑。它鋪在那裡是為了讓人不滑倒，直到掉了這一塊，存在才終於被看見。這世上，有不少東西是以缺席的方式被記住的。"},"ICON-2252":{"nm":"置物櫃鑰匙防水腕帶","de":"守護置物櫃鑰匙不被水浸濕，是我一輩子的職業。纏在手腕上一同戲水，也獨獨把那把鑰匙護得乾爽。弄丟了連衣服都找不回，這麼說來，我可是責任重大的管理者。"},"ICON-2253":{"nm":"滑道出發信號燈板","de":"從紅燈轉為綠燈的那一瞬間，滑梯上每個人的心跳一起加速。准許出發的權限——沒想到這小小的信號板，竟能承載如此巨大的悸動。"},"ICON-2254":{"nm":"漂流池救生衣扣","de":"把漂浮在漂流池上的人牢牢扣住的釦環。喀嚓一聲響起，人才終於安心地把身子交給水流。所謂安心，有時就從這樣一個小小的鎖扣開始。"},"ICON-2255":{"nm":"造浪池指示旗","de":"提前告訴大家海浪將要湧來的時刻。旗子升起便是歡呼，落下便是稍稍喘口氣。在波濤起伏的池畔為大家掌握節拍的，竟是一塊布。"},"ICON-2256":{"nm":"滑道號碼牌項鍊","de":"把排在第幾號掛在脖子上，就不會搞混了。一個號碼牌就定下了先後順序——秩序，常常就從這樣一條小小的項鍊開始。"},"ICON-2257":{"nm":"水上腕帶儲值代幣","de":"輕輕貼一下手腕上的腕帶，儲值就完成了。在不帶現金也不帶卡就能暢遊水中的時代，這枚小代幣便扛起了錢包的職責。手腕變輕了，心也跟著輕鬆起來。"},"ICON-2258":{"nm":"水槍握把蓋","de":"要握得緊才夠味的水槍握把。蓋子一掉，瞄準什麼的全沒了，只能在手裡團團轉——盛夏水仗的勝負，全押在這一個小小的收尾上。"},"ICON-2259":{"nm":"沙堡塔模杯","de":"把濕沙用力壓實裝進去再倒扣，一座小塔便聳了起來。明知會塌卻還要再堆，最懂這份心思的就是我。對沙的建築師而言，模具就是圖紙。"},"ICON-2260":{"nm":"沙耙梳齒","de":"像梳頭那樣拖過沙地，便留下齊整的溝痕。明知是海浪馬上就要抹去的花紋，梳齒仍勤快地刻出紋理。把終將消逝的事物用心去造，自有它的一番情致。"},"ICON-2261":{"nm":"陽傘立柱配重","de":"為了不讓陽傘被風吹走，它在傘腳默默撐著。守護陰涼的不是華麗的傘布，而是沉甸甸紮下的配重。看不見的重量，往往最教人安心。"},"ICON-2262":{"nm":"篩沙網握把","de":"搖一搖把沙篩過，手裡便只剩下貝殼和小小的寶物。握著把手晃呀晃——海邊尋寶的成敗，一半就靠這一張網來定奪。"},"ICON-2263":{"nm":"貝殼造型沙模","de":"填滿濕沙再輕輕拍打，巴掌大的貝殼便一個接一個盛開在海灘上。真貝殼雖然吃不到，這形狀卻誰都能做出來。這是夏天樸素的魔法。"},"ICON-2264":{"nm":"陽傘角度調節銷","de":"太陽每移動一回，陽傘也得跟著轉頭。把銷拔出再插上，陰涼便悄悄換了位置。躲避陽光的訣竅，就藏在這小小的角度裡。"},"ICON-2265":{"nm":"沙鏟刃尖蓋","de":"套在鋒利的鏟刃尖端，包包裡就安全了。挖沙時的勇猛暫且收起，戴上一個蓋子，便成了溫順的玩具。懂得收起鋒芒，也是一種體貼。"},"ICON-2266":{"nm":"沙灘墊邊角夾","de":"風想掀起墊子的邊角時，是我緊緊咬住。守住鋪在沙地上的這方天地，終究靠的是四角的固執。沒有翻飛聲的午後，是小夾子們的功勞。"},"ICON-2267":{"nm":"陽傘陰涼衣架掛鉤","de":"順手掛在陽傘柱上，濕衣服便能在陰涼裡晾乾。避開烈日、迎著清風，一個掛鉤就搭起了臨時的晾衣繩。海邊也藏著過日子的智慧。"},"ICON-2268":{"nm":"防水手機掛頸袋","de":"把手機抱在懷裡掛上脖子，連在水裡也生出拍照的勇氣。把多留一張照片的心意以防水守護住。作為回憶的護衛，可說相當能幹。"},"ICON-2269":{"nm":"濕衣防水收納袋","de":"把換下的濕衣服一聲不吭地整個接過來抱住。不讓外頭的行李沾上一滴水是它的自尊，便緊閉著口，守住包包的一角。乾淨俐落的收尾，從我開始。"},"ICON-2270":{"nm":"戲水涼鞋腳背帶","de":"為了不讓赤腳的涼鞋脫落，輕輕裹住腳背。在沙地上蹦蹦跳跳，有一條帶子就安心。它是腳步穩穩的同伴，雖不顯眼，卻總在身旁。"},"ICON-2271":{"nm":"防水卡片掛頸套","de":"把門票和卡片抱在懷裡掛上脖子，一同戲水。為了讓人不必擔心掉落、盡情戲水，它以己身為盾守護卡片。一副可靠保鏢的姿態。"},"ICON-2272":{"nm":"泳鏡防霧布套","de":"用布把霧濛濛的泳鏡內側擦一擦，水中的世界便再次變得清晰。一個小小的布套，便是把模糊視野重新擦亮的鑰匙。"},"ICON-2273":{"nm":"濕沙清掃刷","de":"連腳趾縫裡的沙都細細地撣下來。把暢遊大海的痕跡，在家門前做最後的整理。刷子掃過一回，這一天份的沙也終於可以道別了。"},"ICON-2274":{"nm":"防水硬幣拉鍊袋","de":"把幾枚硬幣牢牢關在拉鍊裡。即便浸了水，叮噹聲依舊，去小賣部的零用錢便守到了最後。雖小，卻是過日子很有一套的口袋。"},"ICON-2275":{"nm":"戲水毛巾捲帶","de":"把捲好的毛巾用一條帶子綁起，便能掛在包包背帶上。雙手自由，毛巾上肩。行李輕便戲水的秘訣，就藏在這小小的一捆裡。"},"ICON-2276":{"nm":"防水腕帶鑰匙圈蓋","de":"守護鑰匙不被水浸的腕帶的收尾扣。蓋子喀噠扣好，人才終於安心跳進泳池。它為鎖扣的末端負責，雖小，卻是滴水不漏的句點。"},"ICON-2277":{"nm":"浮潛入水咬嘴","de":"含在嘴裡，呼吸的通道便打開，海底的風景近在眼前。一個讓人在水下也能呼吸的小咬嘴。借出一口呼吸，竟能這般令人雀躍。"},"ICON-2278":{"nm":"面鏡防霧墊","de":"面鏡內側一霧，水下的觀覽也就掃了興。一張墊片擋住那層霧氣，清晰的視野，是這看不見的一層的功勞。"},"ICON-2279":{"nm":"蛙鞋腳尖束緊夾","de":"把蛙鞋尖端束得與腳貼合，不鬆不晃地踢水。為了不讓每一次踢腿的力氣外洩，夾子在腳尖默默打下緊實的結。"},"ICON-2280":{"nm":"面鏡帶套","de":"輕柔地裹住面鏡帶，免得它扯到頭髮。把每次摘下時那刺痛的瞬間給消去的一層體貼。小小的套子所照顧的，竟是一份溫柔。"},"ICON-2281":{"nm":"浮潛排水閥蓋","de":"含著一口氣的事，也悄悄有滲漏的縫隙。一個小小的閥門默默把那道水路引回去，把吸氣的位置守到最後。大海最感念的，正是這份細微的把關。"},"ICON-2282":{"nm":"蛙鞋收納掛鉤","de":"牆上釘著的一個掛鉤把蛙鞋齊整地掛起，雜亂的裝備室裡也落下一份整潔的心情。把東西放回原位，是面向下一次潛水最安靜的約定。"},"ICON-2283":{"nm":"面鏡夾鼻墊","de":"一小片輕輕按住鼻子的墊片。多虧這擋住灌水的小小溫柔，臉龐在冰冷的海中也不會失去自己的神情。"},"ICON-2284":{"nm":"浮潛上端護蓋","de":"圓圓包住浮潛管頂端的護蓋，在浪漫過頭頂時靜靜把水推開。越是默默工作的零件，越深深托起這一口呼吸的安全。"},"ICON-2285":{"nm":"蛙鞋鞋底防滑帶","de":"貼在蛙鞋底的一條細帶。在濕滑的甲板上，為了不滑倒，腳尖抓住的那一道摩擦。安全，總是從這樣細微的紋理裡悄悄開始。"},"ICON-2286":{"nm":"氧氣瓶閥蓋","de":"為裝滿空氣的瓶子閥門蓋上的帽子。不讓灰塵落下，不讓呼吸的通道被弄髒。蓋上它，就是把下一個人的第一口呼吸也預先照料周全。"},"ICON-2287":{"nm":"調節器咬嘴蓋","de":"碰觸嘴唇的地方，永遠該是最乾淨的。這一張套在咬嘴上的蓋子，默默為呼吸的入口擋下鹹風與沙塵。"},"ICON-2288":{"nm":"潛水衣拉鍊繩環","de":"繫在潛水衣拉鍊上的一截短繩環。是為了讓凍僵的手在冷水裡也能一把拉起而備下的體貼。連繫好一件衣服，也滲著某人的一番琢磨。"},"ICON-2289":{"nm":"氣壓表保護蓋","de":"告知剩餘空氣的儀表，包住那塊玻璃的保護蓋。因為刻度不能模糊。越是讀著性命的刻度，越要用心擦拭、蓋好。"},"ICON-2290":{"nm":"配重腰帶扣","de":"把重量繫在腰間、向深處下潛的人們。在扣環解開與扣上的那一剎那，上浮與下沉的抉擇靜靜匯聚於指尖。"},"ICON-2291":{"nm":"潛水手電腕帶","de":"漆黑的水中，繫在手腕上的一條帶子牢牢握住手電筒。即便鬆了手，光也跟著來。在黑暗中不丟失一點微光，因此格外令人安心。"},"ICON-2292":{"nm":"呼吸軟管整理夾","de":"把散亂的軟管收攏到一處的小夾子。預先防住纏結，緊急時刻手也不會慌亂摸索。整理，是為未來的自己準備的一份安靜的善意。"},"ICON-2293":{"nm":"潛水手套指尖加固","de":"每個指尖都加上的補強布。拉繩、撐石的地方總是最先磨損，為了預先擁抱那份磨耗，便多疊上一層。"},"ICON-2294":{"nm":"氧氣瓶底座環","de":"把沉重的瓶子穩穩立直的一個底座環。將險些傾倒的重量圓圓地擁住，給出平衡。所謂支撐，就是為了不讓它跌倒而把身旁讓出的心意。"},"ICON-2295":{"nm":"衝浪板鰭蓋","de":"包住板底鰭板鋒利尖端的蓋子。為了走在沙地上也不受傷，把劃開海浪的刀尖暫且哄睡。休息的時候，誰變鈍一點都無妨。"},"ICON-2296":{"nm":"槳葉尖端保護蓋","de":"守護槳葉尖端的保護蓋。擋下與岩石碰撞的刮痕，免得它擾亂水路。愛惜末端，每一次划槳就能往更遠處前進。"},"ICON-2297":{"nm":"獨木舟槳握把把套","de":"纏在手掌與槳相遇之處的握套。柔柔托住那會起水泡的地方，讓人在逆流而上時，手也不會嫌惡起槳來。"},"ICON-2298":{"nm":"衝浪蠟收納鐵盒","de":"裝著一塊蠟的小小馬口鐵盒。讓腳穩穩黏在板上的那份魔法，總是從這巴掌大的盒子裡取出。今天的準備，就從一個整潔的盒子開始。"},"ICON-2299":{"nm":"腳繩腳踝束緊環","de":"把連接腳踝與板子的腳繩束緊的環。即便被大浪捲走也絕不放開你的一個結。所謂連結，是為了不被沖遠而牢牢抓住的約定。"},"ICON-2300":{"nm":"槳板充氣塞","de":"含著風變得堅硬的板子，把那口氣關住的塞子。打開便扁扁地摺起，關上便能立於水上。一個小小的塞子裡，裝著鼓脹又消癟的一天。"},"ICON-2301":{"nm":"獨木舟座墊帶","de":"把坐墊綁在座位上的帶子。為了久坐划槳的腰背，讓那份柔軟不致滑落，把它牢牢繫在原位。連舒適，也需要一個結實的結。"},"ICON-2302":{"nm":"衝浪板鼻緩衝","de":"包住板頭船首的緩衝。越是常撞的鼻尖，越要它先變鈍，於是多加了一層肉。在打頭陣的位置放上柔軟，是要長久使用的一份決心。"},"ICON-2303":{"nm":"防水包封口扣","de":"為了不讓一滴水進來，摺上兩三回再扣緊的釦環。把珍貴的東西乾乾地守住，總得多費一道手。牢牢封好的那一回，便成了安心。"},"ICON-2304":{"nm":"五人制足球門網碎片","de":"曾撼動球門的網的一塊碎片。它把球灌進去那一刻的歡呼，一絲一絲都記得。每個網結裡都進過球，每處磨破的地方，那天的比賽都還活著。"},"ICON-2305":{"nm":"足球打氣噴嘴","de":"為洩了氣的球吹進一口氣的打氣噴嘴。蔫蔫滾來滾去的皮球，又彈跳了起來。所謂填滿，就是把停下的遊戲重新扶起。"},"ICON-2306":{"nm":"角旗底座","de":"在運動場邊角把旗子穩穩立直的底座。雖只是宣告邊界的小小標記，但有了這一點，泥土地才終於有了賽場的模樣。"},"ICON-2307":{"nm":"護脛帶","de":"把護脛綁在小腿上的帶子。牢牢護住常受撞擊的部位，讓人在激烈的拼搶中，每一步也不致畏縮。"},"ICON-2308":{"nm":"鞋釘更換銷","de":"把磨損的鞋釘換上新的銷子。那是抓住草皮的腳尖上一顆顆小小的牙。想要不打滑，有時得從腳底重新立起。"},"ICON-2309":{"nm":"足球氣閥蓋","de":"堵住球的氣孔的小小氣閥蓋。看守入口，不讓灌進的氣洩出。守住那份飽滿，就像直到下一場比賽都不鬆懈那份緊張。"},"ICON-2310":{"nm":"界線標記角錐","de":"在地上劃線、把場地分開的角錐。到這裡是我方，那裡開始是對方。一個小小的角錐，就把雜亂的空地變成了有規則的遊樂場。"},"ICON-2311":{"nm":"足球鞋除塵刷","de":"掃去卡在足球鞋縫裡的泥塵的刷子。比賽一結束，鞋上也積了一天份的泥。撣去的手，是向跑得賣力的腳道一聲安靜的問候。"},"ICON-2312":{"nm":"守門員手套掛架","de":"把守門員的手套晾起來掛著的掛架。是那雙與撲出的射門一樣被汗浸濕的手，暫時歇息的地方。為了下一場比賽，濕的晾乾，僵的心慢慢鬆開。"},"ICON-2313":{"nm":"籃網掛鉤","de":"把網子掛在籃圈上的小小掛鉤們。有了它們，球穿過時才有沙沙的聲響。那清脆的得分聲，其實就從這些小鉤開始。"},"ICON-2314":{"nm":"籃球放氣器","de":"把太硬的球稍微放點氣的工具。太過飽滿，彈跳就兇猛。恰到好處地放掉一些——手感好的球，總誕生於那份適度。"},"ICON-2315":{"nm":"籃板感應墊","de":"貼在籃板背後的感應墊。把球碰到的那一剎那以數字清楚讀出。連肉眼漏掉的瞬間，這小小的感官也記得，判決便更顯公平。"},"ICON-2316":{"nm":"運球障礙錐","de":"在運球練習路上排成一列的障礙錐。在左閃右避的那些縫隙間，腳上的功夫漸漸長成。所謂攔阻，也是一份教人更會穿越的善意。"},"ICON-2317":{"nm":"籃球氣閥刷","de":"清理球氣閥孔的小刷子。灰塵一堵，針就插不進去，於是從看不見的入口先弄乾淨。灌氣之前，總要先清空、先擦淨。"},"ICON-2318":{"nm":"手指貼紮捲","de":"纏在手指上的一捲貼紮。把扭傷的關節牢牢扶住，遞上再次握球的勇氣。把傷處包紮起來，是不會停下的一句小小宣言。"},"ICON-2319":{"nm":"背號夾","de":"把背號夾在衣服上的夾子。代替你的名字，是數字奔馳在球場上。為了不讓它掉落而緊緊夾住的那一回，便清楚寫下今天是誰在場上奔跑。"},"ICON-2320":{"nm":"投籃練習目標環","de":"嵌進籃圈裡、把靶子縮窄的目標環。把進球的位置縮小，逼人忍受偏出。朝著窄門投擲久了，指尖不知不覺便學會了精準。"},"ICON-2321":{"nm":"籃球鞋鞋底擦","de":"踏進球場前，彎下膝蓋先從鞋底擦起。不想在木地板上留下一絲一毫的打滑。以乾淨的腳尖踏出第一步，今天的我，便比昨天稍微更堅實了一些。"},"ICON-2322":{"nm":"排球網張力環","de":"繃緊是看不見的。只有當環把繩拉到底而停住的那一刻，球網才以一指的緊張把球場一分為二。看不見的手所握住的平衡，喚醒了整場比賽。"},"ICON-2323":{"nm":"天線固定夾","de":"總被風吹得搖晃的天線，一夾便筆直地立起。以小者制住大幅的搖晃。在後台默默固定一條纜線的手，也正是以這般的心意在動。"},"ICON-2324":{"nm":"自由人背心掛架","de":"專司防守的那件異色背心掛在牆上，等候下一場比賽。雖不華麗，卻是撐起整片球場的名字——自由人。在最低的位置上看得最遠的眼，就在那裡。"},"ICON-2325":{"nm":"護膝收納袋","de":"越是在地上翻滾，膝蓋越常碰撞。這把護膝細心收進去的小袋子知道：唯有先學會好好跌倒的人，最終才能飛得更遠。"},"ICON-2326":{"nm":"排球氣壓表","de":"用指尖輕輕一彈是測不出來的。氣壓表的指針細細顫動，指向一道刻度。丈量一顆球的呼吸，是比賽的第一顆鈕扣。誠實的氣壓，才生出誠實的軌跡。"},"ICON-2327":{"nm":"躲避球界線膠帶","de":"用膠帶在運動場泥地上劃下的一個圓圈。那圈內與圈外，分隔出半天玩鬧的宇宙。劃線的手知道，規則正是遊戲的開始。"},"ICON-2328":{"nm":"裁判哨座","de":"尖銳的哨聲一停，便又靜靜地放回座上的原位。那是最近距離聽見裁判呼吸的地方。公正，總是從固守原位的小事開始。"},"ICON-2329":{"nm":"托球練習牆靶","de":"沒有人接球的清晨，朝著貼在牆上的靶子，把指尖托舉上千回。牆是最寬厚的隊友。彈回來的球，把疲憊的我再次扶起。"},"ICON-2330":{"nm":"網高測量桿","de":"球網只要低了一根手指，比賽就走了樣。舉起測量桿的那一刻，公正不是數字，而成了每天的習慣。看不見的精準守護著球場。"},"ICON-2331":{"nm":"起跑器角度銷","de":"趴下的姿勢裡，腳尖觸到的角度，那一度便分出了起跑。用一根銷固定起跑器，調勻呼吸。起跑的姿勢，會一路安靜地跟到終點線。"},"ICON-2332":{"nm":"跑道分道號碼旗","de":"每條跑道上插著的小旗在風中搖晃著號碼。大家朝同一個方向跑，卻各有各自的道。跑道同時擁抱了並肩與不同。"},"ICON-2333":{"nm":"接力棒端蓋","de":"為了觸及最後一棒選手之手的那一刻，端蓋把稜角圓圓地裹住。接力裡最珍貴的不是速度，而是遞向下一個人的那隻手。"},"ICON-2334":{"nm":"成績測量捲尺掛架","de":"把記錄成績的捲尺掛在牆上，免得纏成一團。那是把昨日的距離與今日的距離並排掛起的地方。成長，總是先以一點小小的數字之差到來。"},"ICON-2335":{"nm":"跑道彎道標記錐","de":"放在曲線路段內側的小錐子，道出了賽道的心意。別太往裡擠，也別往外散。會轉彎的人，終究跑在最前。"},"ICON-2336":{"nm":"終點線彩帶夾","de":"那條將最先觸到胸口的彩帶，夾子繃緊地握著、等候。是為了被扯斷而存在的一條線。為了某人的短短1秒，整日承受著風。"},"ICON-2337":{"nm":"起跑槍蓋","de":"在砰的信號響起之前，槍口在蓋子下沉睡。是盛著出發的聲音的器皿。寂靜越深，第一響的迴盪便傳得越遠。"},"ICON-2338":{"nm":"跨欄高度調節銷","de":"每把要跨的高度升高一格，銷的位置也跟著移動。恐懼也恰好那麼一點一點地長大。即便如此，腳每一次仍掂量著更高處奔馳而去。"},"ICON-2339":{"nm":"圈數計數轉盤","de":"搞不清還剩幾圈時，把轉盤轉一格。數字遞減的小小聲響，又為雙腿注入力量。為剩餘距離計數的手，守住了配速。"},"ICON-2340":{"nm":"撐竿收納立架","de":"又長又晃的撐竿，需要另備一處倚靠之地。正因是要彎曲才能騰躍的工具，更要小心立放。妥善收存的柔韌，孕育著最高的躍起。"},"ICON-2341":{"nm":"沙坑整平耙","de":"用耙子慢慢梳平前一位選手留下的腳印。沙坑每一次都像最初那樣重新變得平坦。為了某人的躍起而抹去痕跡的手，就在那裡默默忙著。"},"ICON-2342":{"nm":"助跑距離標記帶","de":"少一步不行，多一步也不行。地上的距離標記帶誠實地指出該踏地起跳的位置。好的助跑不是一味貪心，而是源於沉著的計算。"},"ICON-2343":{"nm":"鐵餅握把把套","de":"手指一滑，擲出之前便已先擲了出去。包住鐵餅的把套那粗糙的觸感抓住了旋轉。放開的時機，總是從握住的感覺開始。"},"ICON-2344":{"nm":"鉛球底座環","de":"為了不讓沉重的鐵球滾走，底座環靜靜地擁住它。是守護擲出前那份寧靜的小小巢。越是要爆發的力量，停駐的地方就越要堅實。"},"ICON-2345":{"nm":"標槍尖保護蓋","de":"套在鋒利槍尖上的蓋子，覆上一層柔軟的沉默。當要飛向遠方的器具靜靜橫躺時，危險便以體貼被馴服。收存之中，也住著安全。"},"ICON-2346":{"nm":"跳高橫桿托架卡榫","de":"為了輕碰橫桿也不致掉落，卡榫以絕妙的平衡托著。過與不過，那份顫動的界線由它負責。公正，棲身於微小的細節裡。"},"ICON-2347":{"nm":"落地墊邊角固定件","de":"落地墊的邊角一翹起，人就會受傷。固定件把四個角牢牢壓住。為了讓飛得最高的身體最安全地落下，它在看不見的地方撐著。"},"ICON-2348":{"nm":"投擲圈界線膠帶","de":"投擲位置的邊界，靠一條膠帶劃出。踩不踩那條線，記錄便由此而生或滅。那是自由與規則相遇的一條細細的約定。"},"ICON-2349":{"nm":"平衡木橡膠腳墊","de":"為了不讓狹窄的平衡木晃動，橡膠腳墊緊緊咬住地面。在那之上展開的、毫無顫抖的平衡，其實是看不見的底下那份堅實所造就的。"},"ICON-2350":{"nm":"單槓握把纏帶","de":"為了不讓手掌打滑，把纏帶纏在單槓握把上。團團旋轉的秘密不在華麗，而在緊握的手。落在墊子上的汗水知道這一點。"},"ICON-2351":{"nm":"吊環繩高度固定件","de":"兩條繩的高度只要錯開一個手掌寬，動作就會崩塌。固定件默默扶住那份平衡。唯有在精準對齊的高度之上，自由的飛翔才終於開始。"},"ICON-2352":{"nm":"鞍馬握把套","de":"包住握把的套子擋住了手掌的水泡。那團團旋轉的動作之下，有一雙無數次磨破又癒合的手。所謂保護，是面向下一次練習的一份溫柔約定。"},"ICON-2353":{"nm":"高低槓間距銷","de":"用銷子把兩槓之間的間距精準調好。身體往來的那片空檔，便成了舞台。在精準的距離之上，最大膽的躍起才會誕生——指尖最先明白。"},"ICON-2354":{"nm":"跳馬踏板彈簧蓋","de":"踏板被一蹬，彈簧便把身體推上天空。蓋子穩穩地包住那份彈躍之力。最短的助跑，造就最長的滯空。"},"ICON-2355":{"nm":"鎂粉袋","de":"抹在手上的白色粉末，是抹去打滑的小小護符。把手伸進袋裡再抽出的那短短儀式，平息了恐懼。緊張，終究也是從指尖去馴服。"},"ICON-2356":{"nm":"體操繃帶手腕纏帶","de":"把繃帶纏上手腕，心中的繩結也一同收緊。預先扶住將要動搖的關節。一隻纏好的手腕，便靜靜地允許了更果敢的旋轉。"},"ICON-2357":{"nm":"空中飛人安全環","de":"把身體拋向半空的前一刻，安全環便成了看不見的手。當墜落的擔憂消失，人才終於能飛得最遠。信任，成就了飛行。"},"ICON-2358":{"nm":"網球罐儲存蓋","de":"堵住罐口的蓋子之下，新球們含著氣壓沉睡。打開一罐的那聲小小「啵」，喚醒了比賽的悸動。封存，是守護新鮮的約定。"},"ICON-2359":{"nm":"球拍線張力夾","de":"夾子牢牢咬住線的繃緊度，到最後也不鬆開。因為一根線的張力，決定了球的彈回。看不見的手感，就從這小小的夾子開始。"},"ICON-2360":{"nm":"網球場界線清掃刷","de":"比賽結束後，沿著球場的白線慢慢掃。撣去泥塵，線便再次清晰。為下一場比賽鋪好道路，那最後一份用心讓球場重獲新生。"},"ICON-2361":{"nm":"球拍頭護框","de":"把球拍框纏上一圈，再粗暴的碰撞也能圓融地接化過去。我知道，邊框是最先磨損的地方。替別人擔下磨耗是我的本分，所以今天也站在最外側。"},"ICON-2362":{"nm":"球館氣溫晶片","de":"門一開灌進來的清晨寒風，巴掌大的晶片比人更先讀到。在鼻尖發冷之前就察覺——這是為空蕩體育館開啟一天最安靜的問候。"},"ICON-2363":{"nm":"底線踏板","de":"對於猶豫該把腳尖擱在哪兒的選手，地上劃的一條線就夠了。不該越過的那條線，便成了跳得最遠的起跑線——踏板無言地道出。"},"ICON-2364":{"nm":"網球籃掛架","de":"一口含住數十顆球，卻一顆也不漏。把散落在球場上的東西收攏起來、交給下一次練習——在角落默默忙碌的手，今天也掛在這裡。"},"ICON-2365":{"nm":"球拍握把底蓋","de":"啪地嵌進握把末端的那一刻，球拍才終於落進手掌裡。一個小小的底蓋，分隔了打滑與安心。把末端牢牢堵好，第一次揮拍才扎實。"},"ICON-2366":{"nm":"場邊毛巾夾","de":"即便風颳得猛烈，為了不讓辛苦擰好的毛巾飛走，它在球場旁緊閉著口撐著。守護片刻喘息的休憩，也有某人扎實的指尖觸及其上。"},"ICON-2367":{"nm":"羽球理羽夾","de":"只要一根羽毛亂了，飛行便會晃動。小心地把皺起的羽翼撫平，羽球便又準備好筆直地飛。飛得遠，總是從這樣細微的整理開始。"},"ICON-2368":{"nm":"羽球筒蓋","de":"為了讓排成一列裝好的羽球不變軟，把筒口牢牢堵住。一點濕氣就能使羽毛塌軟，這是看久了才懂的道理。好好收存，便已是比賽的一部分。"},"ICON-2369":{"nm":"桌球滾動托座","de":"咕嚕嚕滾動的小球在我身上稍稍喘口氣。為了不讓它滴溜溜掉下去而靜靜托住——這是桌球桌旁遞出的、最圓潤形狀的體貼。"},"ICON-2370":{"nm":"桌球拍橡膠滾輪","de":"在橡膠面上輕輕滾過滾輪，陳年灰塵便揚起，黏性也復甦。旋轉活了，球才會拐彎。球拍今天的狀態，就從這一回溫柔的保養中甦醒。"},"ICON-2371":{"nm":"網高測量桿","de":"球網只要高了一掌，比賽的紋理就不一樣了。始終不肯相信目測的人們，會把我拿來比。所謂公正，就是這樣以尺一格一格量出的高度，才終於到來。"},"ICON-2372":{"nm":"羽球速度測量晶片","de":"劃破半空的羽球的快慢，我靜靜地估量著。當看不見的速度化作清晰的數字落定，教練接下來的一句話便更分明了。這是把感覺換成事實的事。"},"ICON-2373":{"nm":"桌球收納膠囊","de":"把一顆圓圓的球輕輕躺進膠囊裡，刮痕與灰塵便退到一旁。願它直到下一場比賽都平安無事，這是把一整間小房整個讓出的心意。"},"ICON-2374":{"nm":"羽球拍線掛架","de":"把鬆掉的線齊整地掛起，下一輪的手便不至於摸索。整理終究是給明天的自己預先寫下的一張溫柔便條。今天，讓明天輕鬆。"},"ICON-2375":{"nm":"桌球拍邊緣護條","de":"膠皮容易翹起的邊緣，我以一條靜靜地把它攬住。末端一裂，連球的紋理都會亂掉。守住邊角的事，最終成了守住一分的事。"},"ICON-2376":{"nm":"壁球暖球袋","de":"冰冷的球怎麼也彈不太起來。賽前，把它像手掌一樣暖暖地捂在懷裡的袋子。傳到手上的那一點溫熱，預先定下了一回合的呼吸與節奏。"},"ICON-2377":{"nm":"袋棍球網夾","de":"網眼悄悄要鬆開時，我默默咬住那一格。網要結實，球才留得住。在看不見的位置撐住整場比賽的手，就在這裡。"},"ICON-2378":{"nm":"壁球拍尖護條","de":"越是朝牆用力揮舞，球拍越從尖端先哭起。把那哭著的尖端靜靜包好，便能多陪打一個賽季。懂得愛惜末端的人，終究能久握球拍。"},"ICON-2379":{"nm":"曲棍球桿刃蓋","de":"在鋒利的刃上罩上蓋子，包包裡與指尖才終於安心。把危險的東西靜靜哄睡——這是收拾球桿時最先備好的、一份古老的禮數。"},"ICON-2380":{"nm":"板球擦亮布","de":"用布把紅球擦一擦，一側便像鏡子般含住了光。光要活，球才會拐彎，投手用指尖的感覺懂得這道理。用心擦拭的事裡，也藏著安靜的策略。"},"ICON-2381":{"nm":"袋棍球儲存筒蓋","de":"為了不讓堅硬的球任意滾出，把筒口牢牢堵實。把容易散落的東西哄攏到一處——運營的基本，總是這樣瑣碎。"},"ICON-2382":{"nm":"壁球牆靶片","de":"嵌在牆上的一個小小靶子，把選手游移的目光聚成一點。指明該瞄向何處的那唯一一點——再寬的牆，在這片靶子面前也收窄成分明的靶心。"},"ICON-2383":{"nm":"曲棍球桿握把套筒","de":"把用慣的握把移套到陌生的新桿上，那一刻器具便瞬間成了我的。把熟悉原樣換穿上去的小小套筒——這正是通往適應的捷徑。"},"ICON-2384":{"nm":"球門網掛鉤","de":"把網掛上球門，進球才終於有了進球的樣子。把球深深灌進去那短短的瞬間牢牢守住的，向來是網。在承接迸發歡呼之形的位置上，有我。"},"ICON-2385":{"nm":"冰刀蓋","de":"刃立著時，在冰面外連一步都無法安心。離開了冰，請務必把我罩上。把鋒利靜靜哄睡，也是冰上人長久守著的禮法。"},"ICON-2386":{"nm":"冰鞋鞋帶掛架","de":"把脫下的鞋靴那長長的鞋帶，一條一條齊整地掛起。不打結地解開的鞋帶，順順地開啟下一片冰場。今天的收尾，就成了為明天而備的準備。"},"ICON-2387":{"nm":"冰刀擦布","de":"剛離開冰面的刃上，會密密地凝起小水珠。把那濕氣細細擦去，鏽便繞道而過。靜靜收去寒冷留下的痕跡，那便是我的一天。"},"ICON-2388":{"nm":"冰鞋腳踝墊","de":"腳踝一晃，整段滑行就崩了。緊緊裹住、扶穩踏點的墊子。冰上那優雅的平衡，總是從看不見的地方最先開始。"},"ICON-2389":{"nm":"冰刀護套收納袋","de":"包包一角有個小袋子，好好收著刀刃護套。不漏掉任何該收的東西的習慣，讓裝備長長久久地活著。整潔的包，便是好滑行的第一個畫面。"},"ICON-2390":{"nm":"冰鞋鞋墊夾","de":"為了不讓鞋靴裡的鞋墊悄悄移位，在腳底牢牢扶住。踏的地方一錯，跳躍也跟著錯。抓住最低處的手，最終助成了最高的躍起。"},"ICON-2391":{"nm":"冰刀護套環","de":"為了不讓護套滑溜溜地脫落，用環牢牢扣鎖。我知道，鬆垮的保護終究不是保護。一個扣好的環，把那刀刃守護到最後。"},"ICON-2392":{"nm":"冰鞋鞋帶束緊蓋","de":"把鞋帶使勁拉緊再用蓋子鎖住，從此再不會鬆開。從腳尖開始滴水不漏地扎實繫好——在踏上冰面第一步之前，繫得最安心的那個結。"},"ICON-2393":{"nm":"冰刀拭水布","de":"從滑完一場的刃上，靜靜收去凝結的水氣。我知道濕著放會讓刃哭。唯有乾爽的刃，才能在冰面上清晰地畫出下一道弧線。"},"ICON-2394":{"nm":"滑雪杖握把蓋","de":"柔柔地包住雪杖握把的末端，握著的手掌便舒坦許多。劃開雪原的力量，終究來自牢牢握住的那一處。一個小小的蓋子，把長長的滑降撐到最後。"},"ICON-2395":{"nm":"單板固定器銷","de":"連接板與腳的那枚小銷脫落的瞬間，眼前的山便停了下來。即便不顯眼，也是最該先檢查的一塊——這份堅實的連接，便化作雪原上的自由。"},"ICON-2396":{"nm":"滑雪板刃尖護夾","de":"為了不讓鋒利的邊刃刮傷包包，靜靜把尖端咬住。把鋒利哄撫沉睡——這是痛快下山之後遞出的一份溫柔收尾。"},"ICON-2397":{"nm":"單板鼻頭護片","de":"把板的前頭整個包住，連正面承受的撞擊也能柔柔地化開。默默守護最先撞上的位置——面向陡峭下坡的勇氣，正是從這裡開始。"},"ICON-2398":{"nm":"雪鞋扣具蓋","de":"為了不讓扣具與冰冷的雪碰撞而受損，靜靜地蓋著。守護鎖扣的另一道鎖——這一個小小的蓋子，悄悄為雪鞋延長了一個賽季。"},"ICON-2399":{"nm":"單板腳繩環","de":"即便板子離了手，也不讓它跑遠，我把腳踝與板連成一線。就算失手也終究不會弄丟——這是繫在長繩末端、一個安靜安心的環。"},"ICON-2400":{"nm":"滑雪板底刮板尖","de":"把凝固黏在板底的陳年蠟，俐落地刮去。要把舊的清得乾乾淨淨，新的滑順才會活過來。用心整理過的板底，會把下一片雪原開得更快一些。"},"ICON-2401":{"nm":"滑雪板頭緩衝膠","de":"在板面劃開雪地之前，是它的尖端最先觸碰到世界。每一次撞擊，總是這小小的橡膠先替它擋下。在最前方磨損卻不聲張的位置——某人的滑降，正是滑行在這份遲鈍的奉獻之上。"},"ICON-2402":{"nm":"滑雪杖籃環","de":"雪杖正要陷進深雪的那一刻，這圓圈替它探向地面。靜靜托住那一步差點踏空的腳。即使看不見，它也像一隻不讓人滑倒、始終守在身旁的手。"},"ICON-2403":{"nm":"刃口打蠟刷帽","de":"保養完成後，趁粉末未乾便輕輕蓋上。不讓一絲紋理散亂，把今日的柔順封存起來。為了下次再打開時，昨日的用心仍原封不動地等著。"},"ICON-2404":{"nm":"防寒耳罩掛勾","de":"還記得嗎？春天一來，耳罩便被遺忘在書包旁。可是聽到初雪消息的夜裡，它總是最先被喚起。掛起季節的位置自有其所，這枚掛勾從不忘記那個約定。"},"ICON-2405":{"nm":"磨刃磨石盒","de":"要磨利刀，得先把石頭沾濕——像奶奶手藝般滲入的順序。連馴服鈍化的工具也需要自己歇息的地方，於是這小盒子懷抱磨石，等候下一次的保養。"},"ICON-2406":{"nm":"蠟塊小袋","de":"造就閃亮滑降的材料，自己卻在袋裡緊緊凝結沉睡。懷抱凝固蠟塊的厚重感。滑順總是從這份寧靜的重量中釋放，蔓延於雪原之上。"},"ICON-2407":{"nm":"暖手寶袋掛環","de":"冬日散步路上，手指在口袋裡最先摸索尋找的位置。為溫暖凍手的那點小暖意，騰出一個固定的家。越是寒冷的日子，越顯溫柔的小掛環。"},"ICON-2408":{"nm":"刃尖研磨石托座","de":"一晃動刃便會磨歪，所以它先把自己穩穩固定。為了承擔別人的精準，自己卻紋絲不動的托座。某人筆直的刀尖，便立於這份默默之上。"},"ICON-2409":{"nm":"防寒圍脖夾","de":"寒風吹拂的上學路上，圍脖正要滑落的瞬間，「喀噠」一聲扣在衣領。溫暖也得守住位置，才終於成為溫暖。一聲小小的喀噠，留住了清晨的暖意。"},"ICON-2410":{"nm":"打蠟熨斗罩","de":"曾炙熱工作的面在冷卻時，一塊布靜靜替它擋去灰塵。為滑降做準備的工具，由另一件工具來照料。照顧，就這樣靜靜延續著。"},"ICON-2411":{"nm":"刃油筆蓋","de":"一旦打開放到乾涸，便畫不出下一道線。所以蓋上，正是為了開啟下一次——封住筆尖的濕潤，為明日那一筆預先許下約定的小蓋子。"},"ICON-2412":{"nm":"應援彩球頭結","de":"數百縷穗子從這一點出發，隨節拍一齊飛揚。搖曳的華麗，總是始於牢牢繫住的位置。在舞台之下，讓觀眾席掀起波浪的第一個結。"},"ICON-2413":{"nm":"應援棒手腕繩","de":"歡呼度過兩小時，差點鬆手丟了應援棒的那一刻，這繩子又把它領回手中。即使掉落也不願失去的心。那份溫柔的焦急，在手腕上化成一個環。"},"ICON-2414":{"nm":"觀眾坐墊折疊扣","de":"應援時猛地起身又坐下，反覆了數十次。其間把坐墊俐落折好、守住位置的小扣子。在沸騰的觀眾席裡，也夾著一隻替人照看座位的手。"},"ICON-2415":{"nm":"應援頭巾環","de":"同樣的圖案鋪滿整個觀眾席的日子，一塊布把千萬顆心繫成同一種顏色。那波浪起始的第一點，正是這小小的環——讓孤單的應援，化為「我們」的地方。"},"ICON-2416":{"nm":"應援拍手板片","de":"獨自拍是微弱的聲音，匯聚在觀眾席便成了浪潮。最誠實地懂得「相擊才會響」這道理的一片。當你的掌心遇上我的掌心，應援就變大了。"},"ICON-2417":{"nm":"應援手幅邊角帽","de":"把尖銳的邊角圓圓包起，好讓鄰座的人不會受傷。連熱烈揮舞的心意裡，也夾著對彼此的體貼。應援，就在這份圓潤之處更顯溫暖。"},"ICON-2418":{"nm":"應援緞帶旗桿座","de":"即使飄揚停下的瞬間，旗桿仍筆直矗立，等待下一聲吶喊。為了搖曳，而暫時靜靜停留的位置。在吶喊與吶喊之間，緞帶調勻呼吸的短暫靜默。"},"ICON-2419":{"nm":"應援傳聲扇","de":"為了讓一個人的呼喊傳到舞台盡頭，扇形替聲音收窄出一條路。比起心意的大小，更總在苦惱傳達方法的嘴邊。是渴望傳得更遠，所造就的形狀。"},"ICON-2420":{"nm":"應援徽章背針盒","de":"別上胸前之前與摘下之後，徽章的歇息都在這裡開始與結束。把尖銳的背針安全收納的小盒子。曾閃耀的一點，也需要躺下小憩的地方。"},"ICON-2421":{"nm":"計分板數字片","de":"每進一球便用手替換的那個年代的用心，浸潤其中。在數位之前，勝負是由人的指尖一格格刻下的。連一個數字裡，也曾盛著某人的悸動。"},"ICON-2422":{"nm":"戰術板磁吸子","de":"隨教練的指尖，防守與進攻交換了位置。賽前腦海裡所有的構圖，都先在這些小點的移動中描繪出來。勝負，先在板上預演了一回。"},"ICON-2423":{"nm":"電子看板遮光簷","de":"為了不讓刺眼的數字模糊選手的視線，簷把光切了下來。明亮，有時也得適度遮擋才能盡其本分。在最明亮之處，最安靜工作的陰影。"},"ICON-2424":{"nm":"計分翻牌環","de":"一張張翻過，數字隨之改變，吶喊也跟著高漲。用手感更新紀錄的類比時代痕跡。在計分翻過的聲響裡，心也跟著一起翻動的歲月。"},"ICON-2425":{"nm":"戰術繪線筆盒","de":"更衣室白板上畫出的所有跑動路線，都出自這支筆。懷抱勝負草圖的小小堅固收納盒。在決戰前的沉默中，它是含著最多話語的位置。"},"ICON-2426":{"nm":"計分喀噠器","de":"每按一次便進一格，以清脆的喀噠聲累加計數。把數字交給手指，心便能全然投向比賽。是為你卸下計數重擔的小小節奏。"},"ICON-2427":{"nm":"電子看板電線蓋","de":"華麗的光背後，總糾纏著一堆未整理的線。它把那份雜亂整齊地蓋住。看不見的地方收拾乾淨了，看得見的地方才終於閃耀。"},"ICON-2428":{"nm":"戰術板擦拭刷","de":"一局結束，便為了下一張圖把面清乾淨。新的戰略，總只能在空白的位置上開始。擦拭的刷子，其實正是下一場戰術的第一筆。"},"ICON-2429":{"nm":"計分旗夾","de":"把要被風吹走的旗子俐落咬住，絕不鬆口。讓飄揚的布守在原處。連向世界宣告紀錄這件事，也得先有一隻穩穩抓牢的手。"},"ICON-2430":{"nm":"裁判哨繩夾","de":"一聲哨響，比賽停下又重新流動。把那份權威牢牢繫於頸間的小結。在哨聲響起之前，把沉默整齊綁好，也是這夾子的職責。"},"ICON-2431":{"nm":"測量捲尺捲輪","de":"把展開量過的長度，再收回自身之內。所謂測量，終究是展開又收攏的反覆。這把手默默協助那單純的往返，在精準的背後每每旋轉。"},"ICON-2432":{"nm":"判定旗折疊盒","de":"曾果斷劃分界內與界外的旗子，比賽結束便整齊折起歇息。那分明的信號，也為了下一次而暫時調勻呼吸。果斷的背後，也有一段靜靜的休息。"},"ICON-2433":{"nm":"碼錶掛環","de":"把流逝的時間掛在一處，而非手腕上。計時前靜止著，一被呼喚便立刻奔出的時間驛站。屏息等待出發信號的，小小秒針的家。"},"ICON-2434":{"nm":"畫線器滾輪","de":"滾過之處，都清晰留下一條白色的路。規則的界線，就這樣一圈圈端正地刻在地上。在比賽開始之前，最先在運動場留下足跡的滾輪。"},"ICON-2435":{"nm":"裁判卡片袋","de":"判決的瞬間，從胸前掏出的那一張，正沉睡於此。在亮出之前始終緘默的判定候場室。盼著不被掏出，卻總是備妥等候的口袋。"},"ICON-2436":{"nm":"測量砝碼托座","de":"稱重這件事，只有在不晃動的地面上才誠實。托著砝碼，把自己平整地獻出的托座。精準測量的第一步，總始於寧靜的位置。"},"ICON-2437":{"nm":"出發信號喀噠器","de":"一聲響，所有的腳同時蹬地。開始極為短暫，但造就那份短暫的手，比誰都沉著。用唯一一聲喀噠，鬆開起跑線顫動的手。"},"ICON-2438":{"nm":"賽事三角錐底座","de":"名字雖陌生，做的事卻分明——穩穩撐起如舞台般賽場的正中央。在眾人閃耀的中心，總有一條看不見的腿默默支撐著。"},"ICON-2439":{"nm":"腹式呼吸帶扣","de":"好的聲音來自深處的呼吸而非喉嚨，這是腰最先懂得的。讓手掌感受腹部鼓起又收縮的扣環。歌唱的起點，總在這一口呼吸之下。"},"ICON-2440":{"nm":"呼吸練習羽毛板","de":"氣息一吹，羽毛輕輕搖曳，便是呼吸均勻的信號。為看不見的氣息悄悄賦予形狀，教導歌唱的底子。是在第一個音之前，用眼睛學習呼吸的練習。"},"ICON-2441":{"nm":"吸氣沙漏計時器","de":"玻璃裡的沙，如呼吸般流瀉而下。吸入、稍停、緩緩呼出的節拍，由沙粒替你細數。靜靜望著無聲落下的沙，不知不覺間，散亂的呼吸便調勻了。"},"ICON-2442":{"nm":"燭火練習底座","de":"點燃燭芯，嗓音便隨搖曳的火苗一同顫動。為了讓那細微的顫動有處暫歇，有人用心削出了這個位置。蠟淚凝結堆積的厚度裡，沉澱著一個個獨自歌唱的夜晚。"},"ICON-2443":{"nm":"壓腹墊繩","de":"不用手按腹，由一條繩子靜靜替它壓著那個位置。氣息湧上便繃緊，全數呼盡便悄悄鬆開。是在身旁協助身體先記住節拍的，無言的小夥伴。"},"ICON-2444":{"nm":"持氣氣球帽","de":"別一口氣把氣球吹完。要長、要慢、要推到最後。含著帽子吐氣的同時，空氣抵達肺最深的角落。歌唱，終究會隨你忍住的呼吸長度，飛向遠方。"},"ICON-2445":{"nm":"調息握把","de":"心越是動搖，手越想緊緊握住些什麼。握住這把手，肩膀便緩緩落下，吸氣也長了一寸。學會握的方法，便是修整自己的方法——手掌最先懂得。"},"ICON-2446":{"nm":"腹肌震動帶環","de":"把彈力帶掛上環，細微的震動便往腹部正中蔓延而來。在開懷大笑時顫動的正是那個位置，靜靜地匯聚力量。堅實的中心總是這樣，在無人看見之處慢慢生長。"},"ICON-2447":{"nm":"吸氣計數轉盤","de":"一、二、三——轉盤每進一格，吸入氣息的深度便刻下一筆。數字多一格，歌也能多撐一個小節。在這小小的轉盤上，靜靜記下今日練就的肺活量。"},"ICON-2448":{"nm":"舌部運動匙板","de":"把舌尖該觸碰的位置，工整地刻在板上。捲動、彈跳、稍歇的法門。在流暢吐出的發音背後，藏著舌頭如此背熟路徑的無數清晨。"},"ICON-2449":{"nm":"口型鏡夾","de":"鏡中映出的口型，由夾子輕輕替它定住。「啊」要圓圓的，「咿」要往兩旁拉長。直視自己的臉，琢磨聲音的形狀——只有鏡子與我，安靜的二人課堂。"},"ICON-2450":{"nm":"發音軟木海豹","de":"軟木削成的小海豹坐在書桌一角聽著發音。捲舌韻尾老是滑掉而沮喪的夜裡，海豹圓圓的眼睛靜靜說：沒關係，再試一次吧。"},"ICON-2451":{"nm":"歌詞換氣標示針","de":"歌詞何處該換氣，這枚針先替你指出。在一行尾端輕輕一插，那裡便成了歌的溫柔休止符。想盡情歌唱，句子裡也需要一格喘息的空白。"},"ICON-2452":{"nm":"咬字練習托下巴","de":"只要稍稍托住下巴，原本要散掉的發音便找回了位置。清晰的話語不只是嘴的事，而是下巴、喉嚨與氣息共同完成的事。這小小的托座，默默協助那難拿捏的平衡。"},"ICON-2453":{"nm":"母音口型架","de":"啊‧耶‧咿‧喔‧嗚，把五個母音穿出口腔的路徑原樣立好的架子。靜靜擺在鏡旁，每天捏定聲音的骨架。任何歌的骨幹，終究都始於這五個母音。"},"ICON-2454":{"nm":"繞口令卡","de":"醬油工廠廠長——讀著讀著舌頭打結，終於笑出聲來的一張卡。讀錯真的沒關係，因為讀錯本身就是練習。每跨過這調皮的句子一次，便有一個發音清晰地甦醒。"},"ICON-2455":{"nm":"鬆唇蓋","de":"顫動嘴唇、喚醒僵硬嘴角的暖身。含著蓋子長長吐氣，沉睡的嘴唇便柔軟地鬆開。是為了輕柔開啟第一句，最小巧也最溫柔的準備運動。"},"ICON-2456":{"nm":"歌詞段落橡皮筋","de":"在老是卡住的那一段繞上橡皮筋作記號。每次看到手腕上那個位置，便想起今日要翻越的一座山。越難的小節，越要常常端詳、越久放在心上。"},"ICON-2457":{"nm":"護頸圍巾掛環","de":"為了不讓喉嚨被換季清晨的空氣鎖住，把圍巾牢牢掛在環上。在溫暖包裹的脖頸裡，清亮的聲音才終於鬆綁。守護嗓音，總是從先疼惜脖頸開始。"},"ICON-2458":{"nm":"聲帶震動滾頭","de":"滾頭沿著頸側緩緩滾過，整夜沉睡的聲帶便悄悄甦醒。輕微的震動鬆開僵硬的緊張，猶豫的第一個音也柔和了許多。是在歌唱前替身體暖身的手。"},"ICON-2459":{"nm":"哼鳴暖嗓杯墊","de":"閉著嘴哼哼唱唱，雙手捧住冒著熱氣的暖杯，喉嚨也一同暖了起來。杯墊上，低低的哼鳴圓圓地蔓延開來。歌唱，就從這樣一口溫吞的暖意開始。"},"ICON-2460":{"nm":"潤喉糖收納膠囊","de":"為了喉嚨乾啞沉下去的日子，把糖果靜靜收進膠囊裡。登台前含一顆在嘴裡滾動，沁涼的薄荷便清爽地打通堵住的喉嚨。小盒裡裝著，專屬於我的應急慰藉。"},"ICON-2461":{"nm":"蒸氣熱敷頸袋","de":"把滲入溫熱蒸氣的袋子圍在脖子上，因長時間練習而僵硬的位置便緩緩融化。如剛加熱的毛巾那般溫暖，靜靜遞給疲憊低沉的聲帶一拍歇息。"},"ICON-2462":{"nm":"聲帶休息沙漏","de":"今天決定不說話，那靜靜許下的約定，由纖細的沙粒安靜替你細數。暫時閉上嘴、珍惜嗓音。那段也是最好照料的寧靜時光，在此緩緩流淌。"},"ICON-2463":{"nm":"暖身唇顫蓋","de":"輕輕顫動嘴唇、隨音上下滑動的唇顫。稍稍含住蓋子，原本隨意亂晃的顫動便平穩了許多。是為發聲扣好第一顆鈕扣的、手掌般大小的小工具。"},"ICON-2464":{"nm":"護喉噴霧帽","de":"為了不讓喉嚨在乾燥的舞台上發乾，按下帽子噴出一道細緻的水霧。深深吸一口濕潤的空氣，乾涸的嗓音便重新含住清亮的光澤。"},"ICON-2465":{"nm":"發聲放鬆震動球","de":"靜靜握住在手掌上細細顫動的球，那震動便沿著手臂柔和地上行至喉嚨。把因緊張而僵硬的發聲器官輕輕搖醒——圓潤又溫柔的暖身好友。"},"ICON-2466":{"nm":"隊形定點標記","de":"牢牢釘在舞台地面上的一枚小標記。這裡是你的位置，那邊是我的位置。眾人聚在一起描繪一幅畫時，靜靜守著誰也不散開的、看不見的約定。"},"ICON-2467":{"nm":"走位箭頭片","de":"箭頭狀的片清楚指出下一步的方向。在何處轉、在何處停下，地面先替你指明，好讓你不迷路。所謂走位，是腳尖反覆踩過、背熟的地圖。"},"ICON-2468":{"nm":"隊形中心點針","de":"眾人聚攏時，靜靜成為基準的唯一一點。以這枚針為中心，圓圓地畫出圓，隊形也豁然展開。各自散亂的動作，只要有中間這一點，不知不覺便找回了秩序。"},"ICON-2469":{"nm":"交叉點楔子","de":"在兩條路相會於一處之地，把楔子牢牢釘下。好讓彼此不相撞、不錯身偏離。在喘不過氣擦身而過的那短暫瞬間，也不讓任何一人迷失方向。"},"ICON-2470":{"nm":"退場方向旗","de":"最後一個音的餘韻消散後，便朝旗子所指的那一側靜靜退去。退場時也得如入場般不能散亂。連舞台的收尾，也有預先約定好的方向。"},"ICON-2471":{"nm":"間距測量捲尺夾","de":"用夾子牢牢咬住捲尺一端，一拃、又一拃，便分毫不差地精準。連人與人之間的間距，也如尺量般整齊對齊。一幕好看的畫面，總是誕生於這般細心的指尖。"},"ICON-2472":{"nm":"對齊基準繩環","de":"把繩子掛上環、繃緊成一直線，那細細的線便成了眾人並排站立的基準。排成一列的模樣之所以那麼整齊，全靠這條看不見的筆直直線。"},"ICON-2473":{"nm":"移動路徑虛線片","de":"在地面以虛線靜靜畫出路的片片。沿著這淡淡的痕跡走，即使在黑暗中也不會迷失。一點點把點與點串起的同時，散亂的腳步便連成了一道流動。"},"ICON-2474":{"nm":"定位地面圖釘","de":"為了不忘記自己的位置，「咚」地按釘在地上的圖釘。即使在漆黑之中，腳尖也會摸索那小小的凸起，硬是把它找出來。準確地停在那一點時，燈光才終於灑落頭頂。"},"ICON-2475":{"nm":"頸部分離專注帶","de":"下巴跟著晃動，嗓音也會一同顫散。為了學會頭部靜止、只讓頸部單獨移動的法門，繞上這條帶子。在看似無比自由的動作背後，藏著這般默默的分離練習。"},"ICON-2476":{"nm":"固肩坐墊夾","de":"為了不讓肩膀隨意聳動，用夾子靜靜把坐墊固定住。好讓身體清楚分辨該晃動之處與該靜止之處。節制的線條，總是從這般小小的拿捏中才終於誕生。"},"ICON-2477":{"nm":"肋骨感知腰帶扣","de":"肋骨張開又收攏的細微紋理，由腰帶靜靜替你讀取。扣上扣環，呼吸的動向便清晰地傳到指尖。深沉堅實的發聲，源自這看不見的骨骼運動。"},"ICON-2478":{"nm":"骨盆擺錘","de":"錘子左右緩緩擺動，靜靜指點骨盆所描繪的節奏。身體的重心如何移轉承重，由這手掌般大的小重量無言地教導。原來搖擺之中，也有紋理。"},"ICON-2479":{"nm":"手腕旋轉環","de":"把環掛在手腕上，往內、往外慢慢旋轉，整夜僵硬的關節便柔和地鬆開。為了讓動作鮮活地觸達指尖，得先讓手腕變柔軟。這小小的旋轉，開啟更大的表現。"},"ICON-2480":{"nm":"腳踝阻力環繩","de":"腳踝套上環、拉緊繩子，每踏出一步，腳尖便掛上一陣輕微的阻力。踏得越沉，腿便靜靜長出力量。羽毛般輕盈的跳躍，總是立於這般沉重的練習之上。"},"ICON-2481":{"nm":"核心專注沙袋","de":"繞在腹部後才終於明白，我身體的正中央原來在哪裡。重量拉扯肩膀的同時，搖晃的中心慢慢找回了位置，解下之處留下了一個筆直站立的姿態。"},"ICON-2482":{"nm":"脊椎對齊棒帽","de":"整天彎著生活的背，一碰到小小的帽子，便像有誰悄悄替它挺直了肩膀。彎著也能活下去，但筆直站立，是得慢慢重新學習的溫柔技藝。"},"ICON-2483":{"nm":"肌肉放鬆指壓珠","de":"用力按壓僵結之處，起初微微發痠，隨即舒爽。如同兒時奶奶手背揉搓後背的那份溫暖，所謂鬆開，是稍微多疼一會、陪在身旁的事。"},"ICON-2484":{"nm":"鏡子角度調節螺絲","de":"只轉一個手掌寬，鏡子便映出截然不同的臉。一圈螺絲，世界便傾斜又擺正，看來連直面自己這件事，也需要靜靜地瞄準。"},"ICON-2485":{"nm":"鏡面除霧擦拭墊","de":"在被熱氣模糊的鏡前，人暫時失去了自己的臉。輕輕一抹便回來的臉。多虧這拭去霧氣的手，每天清晨我才能重新遇見自己。"},"ICON-2486":{"nm":"攝影三腳架腳膠","de":"三腳架的腳尖，一點指甲大的橡膠決定了畫面的命運。緊咬地面的力量平息了晃動，無顫的畫面總是從看不見的摩擦中靜靜開始。"},"ICON-2487":{"nm":"角度參考格線膜","de":"膜上細細的格線，像為眼睛裝的輔助輪。構圖越上手，線便悄悄消失，只留下感覺。學習的痕跡，越是嫻熟，越是看不見。"},"ICON-2488":{"nm":"錄影啟動踏板","de":"雙手抱滿東西的人，最後的手指總是腳尖。輕輕一踩便開始錄影，幕後的雜務就這樣連腳尖也俐落地盡了自己那份本分。"},"ICON-2489":{"nm":"燈光方向夾","de":"光該落往何處，全繫於這指甲大小的夾子指尖。把影子挪移一拃、勾勒出輪廓，為了那細微的差別，有人會苦思良久、躊躇不已。"},"ICON-2490":{"nm":"影像對比遮幕","de":"把昨日與今日並排，變化這才開口說話。遮幕緩緩落下的瞬間，跨越其間的那段時間距離，誠實地顯現在畫面上。"},"ICON-2491":{"nm":"遙控器手腕繩","de":"手腕繞上一條繩，怕摔落而提心吊膽的心便鬆了下來。小小的安全裝置反倒讓手更自由，被綁住的東西放開了心——多麼溫柔的悖論。"},"ICON-2492":{"nm":"鏡頭遮蓋","de":"相機歇息的同時，鏡頭也靜靜閉上眼。在一粒灰塵都會在畫面留下疤痕的世界裡，輕輕蓋上，便是想長久珍藏的心意。"},"ICON-2493":{"nm":"嘴角上揚帶","de":"稍稍把嘴角拉起，僵硬的表情便緩緩鬆開。笑容終究也是肌肉，起初借工具之力，某個清晨便能憑自己燦爛地笑了。"},"ICON-2494":{"nm":"臉頰肌肉按摩滾","de":"緩緩滾動鬆開臉頰內側，話語便流出得更為順暢。歌唱之前，靜靜喚醒臉龐的準備。表情暖過之後，也會更溫暖。"},"ICON-2495":{"nm":"微笑角度量規","de":"相機知道，連笑容也有恰當的角度。拿量規這裡那裡量了又量，終於明白——最美的微笑，綻放於怎麼也量不出的真心。"},"ICON-2496":{"nm":"眉毛動作夾","de":"眉毛即使只動1毫米，心情的紋理便整個改變。靜靜抓住表情最小零件的夾子，演戲就是這般馴服細微之處的指尖功夫。"},"ICON-2497":{"nm":"顴骨提升貼","de":"稍稍把顴骨拉起貼上，臉上便生出一處光停駐的地方。指甲般大的一張貼紙造就的立體感，舞台妝裡就藏著這般看不見的秘密。"},"ICON-2498":{"nm":"眨眼遮罩眼罩","de":"遮住一隻眼，心思便完整地匯聚到剩下的那隻。眨眼練習，終究是學會把一半好好藏起的法門。遮住多少，便有多清晰的表情。"},"ICON-2499":{"nm":"口型模具夾","de":"嘎、嘎、噶……把口型套進模具比對，模糊的發音便清晰起來。每一個母音都即是臉的姿勢，在鏡前慢慢刻進身體裡。"},"ICON-2500":{"nm":"表情暖身袋","de":"登台前一刻，靜靜溫暖臉龐的暖袋。手一冷演奏便僵，表情也是如此。微笑也需要預熱，這是幕後的一個小真理。"},"ICON-2501":{"nm":"撫平額紋帶","de":"額上繞起一條帶，深陷的皺眉便悄悄舒展開來。讓被憂愁刻出的皺紋暫時歇息的物件。舒展的額頭之下，人會顯得年輕一些。"},"ICON-2502":{"nm":"劇本翻頁指套","de":"套在翻紙指尖的小指套。一張張翻過厚厚劇本的那份節奏，不知不覺成了故事的節拍。連閱讀，也寄寓著溫柔的手部習慣。"},"ICON-2503":{"nm":"情感塗色旗","de":"喜悅是黃、悲傷是藍。為心情上色立起旗子，看不見的情感便迎風飄揚、有了形狀。原來感受，也能這樣用手描畫出來。"},"ICON-2504":{"nm":"台詞重音夾","de":"「在這個詞上加重」，夾子靜靜替你指點。同樣的台詞，只憑一個重音，意思便整個改變，可說是抓住話語重心的小標記。"},"ICON-2505":{"nm":"讀劇休止積木","de":"放在此處、提醒「在這裡歇一拍」的積木。台詞裡的休止不是停頓，而是為了下一句而吸入的氣息。懂得好好歇息的人，終究說得好。"},"ICON-2506":{"nm":"呼吸標示夾帶","de":"帶子沿著夾子上下移動，把氣息的長度描在眼前。看著吸氣呼氣的節拍跟著做，歌唱的開頭，總是從馴服呼吸開始開啟。"},"ICON-2507":{"nm":"情感骰子袋","de":"從袋裡骨碌碌滾出的骰子，決定了今天的情感。擲出喜悅便試著喜悅，擲出憤怒便試著憤怒。演技練習，成了把心交給偶然的遊戲。"},"ICON-2508":{"nm":"劇本支架斜台","de":"把劇本放上斜傾的支架，便不必低頭。守住視線高度的這小小斜度，靜靜照料因長時間練習而痠痛的後頸。"},"ICON-2509":{"nm":"低語遮板","de":"從這裡起要低語的標記。在遮板後壓低嗓音，觀眾席反倒屏息傾耳。說得越小，反而傳得越大——舞台溫柔的悖論。"},"ICON-2510":{"nm":"角色互換代幣盒","de":"把代幣輕輕翻面，擔任的角色便改變。今天是主角，明天是守在身旁的朋友。在共同成長的島上，人人都會輪到站上舞台正中央的時候。"},"ICON-2511":{"nm":"視線定點貼","de":"把目光靜靜放在相機旁的一個小點上。搖晃的視線觸及一處的瞬間，畫面中的眼神便清晰地活了過來。所謂凝視，終究始於停駐。"},"ICON-2512":{"nm":"取景三角尺","de":"畫面一角不知為何顯得傾斜時，悄悄拿三角尺一比便有了答案。把歪斜的擺正。在相信眼睛之前，先試著相信一下尺。"},"ICON-2513":{"nm":"鏡頭視線高度托座","de":"把鏡頭對準人的視線高度，畫面便少撒些謊。不在上、也不在下，以同樣的目光相望時，才終於拍下不加修飾的真實表情。"},"ICON-2514":{"nm":"視線引導箭羽","de":"箭羽所指的那一側，目光便緩緩跟去。悄悄牽引觀者視線的小箭。好的畫面，會親切地揮手示意該看向何處。"},"ICON-2515":{"nm":"拍攝走位地面片","de":"踩上那磨到爛熟的走位的一點，下一個位置便立刻到手。穿梭舞台的腳步，是把地上咚咚釘下的這些小標記串起、織成的看不見的路。"},"ICON-2516":{"nm":"相機距離捲尺帶","de":"用帶子量好被攝體與相機之間的距離。在一拃便分開遠近的世界裡，捲尺成了守護模糊與清晰之界的寧靜守望者。"},"ICON-2517":{"nm":"歪頭引導器","de":"頭該歪多少，才顯得最溫柔呢。順著引導走，便悄悄明白了。歪頭的角度，終究與敞開心扉的程度，極為相似。"},"ICON-2518":{"nm":"對視手鏡夾","de":"用夾子把手鏡放在相機旁，便能一邊看著自己的眼，一邊與你對視。在鏡中的我與畫面中的你之間，悄悄搭起視線之橋的小裝置。"},"ICON-2519":{"nm":"拍攝指示亮燈器","de":"燈一亮，便是此刻正在拍攝的信號。一盞小燈把沸騰現場的緊張匯聚一處。從那道光亮起的瞬間，眾人的呼吸便整齊成同一個節拍。"},"ICON-2520":{"nm":"反應鈴按鈕","de":"一按按鈕，便響起清亮悅耳的鈴聲。如同好場面之後嘩然爆出的掌聲，某人「做得好」的溫暖一句，就裝在這小小的鈴鐺裡。"},"ICON-2521":{"nm":"反應力抽籤筒","de":"一搖，木籤便嘩啦作響，先把氣氛炒熱。由誰來開場，全憑手腕一甩定奪——抽中的人靦腆地笑，剩下的人撫胸鬆口氣。連分配運氣，也有溫柔的規則。"},"ICON-2522":{"nm":"音效搖鈴","de":"手腕輕輕一抖，便「叮鈴」一聲插進一句助興。靜默正要尷尬的縫隙，由這小鈴先補上。數笑點的節拍，總是這邊快上一步。"},"ICON-2523":{"nm":"驚喜盒蓋","de":"在打開之前，誰也猜不透裡頭。這就是這蓋子擔負的唯一一件事。輕輕掀起的剎那，好讓尖叫與笑聲一同爆發，它把悸動掛在一枚鉸鏈上。"},"ICON-2524":{"nm":"反應折扇","de":"「啪」地展開的聲音，便成了回答。把來不及用言語說出的讚嘆，由扇骨替它搧送出去。在開合的手勢之間興致來去，隨風搖曳一縷心思。"},"ICON-2525":{"nm":"懲罰輪盤轉盤","de":"指針會停在哪一格，誰也無從預知。轉盤越慢，心跳反而越快——「喀噠」停下之處，寫著今日好笑的命運。連顫慄都樂在其中的幾秒。"},"ICON-2526":{"nm":"感嘆對話框板","de":"往頭頂猛地一舉，「哇」便化成字浮現出來。嘴還來不及跟上的心，由一張紙搶先替它喊出。因為反應，也需要舞台的演出。"},"ICON-2527":{"nm":"瞬間定格手旗","de":"旗子舉起的瞬間，眾人便當場凝固原地。連呼吸聲都鎖進靜止畫面的信號。一放下，定格的笑聲便一齊嘩啦傾瀉而出。"},"ICON-2528":{"nm":"搞怪答案夾筒","de":"越搞怪的答案，越是俐落地夾起掛上。曬衣繩上掛的錯答隨風搖曳時，比起正確答案，那份錯位反倒更受寵愛。是個答錯也沒關係的日常風景。"},"ICON-2529":{"nm":"姿勢矯正靠背楔","de":"倚靠的瞬間，彎著的脊椎便悄悄摸索找回自己的路。無言撐持的一個小楔子。正確的姿勢要有人撐著才終於舒適——它在背後靜靜地這樣告訴你。"},"ICON-2530":{"nm":"骨盆對齊托塊","de":"重心動搖時墊在腳下的一點堅固。身體的平衡，終究是從地面慢慢往上湧起。在看不見的位置撐起姿勢的，無名的配角。"},"ICON-2531":{"nm":"腹部收束平衡球","de":"夾在腹部靜靜收緊，散亂的重心便匯聚成一點。呼吸調得越深，球便越堅實，身體一口氣一口氣找回了遺忘已久的自身之軸。"},"ICON-2532":{"nm":"脊椎曲線檢測尺","de":"沿著背貼上尺，看不見的彎曲便顯現在刻度上。所謂筆直站立，不是抹去曲線，而是連那細微的彎曲也溫柔地讀懂。"},"ICON-2533":{"nm":"展肩彈力環","de":"掛在肩上慢慢拉，蜷縮的胸膛便豁然敞開。彈力總在低語「回到原位吧」，一天份彎著的背，便在那柔和的呼喚中一點點舒展。"},"ICON-2534":{"nm":"核心刺激沙袋","de":"繞在腰上，沉甸甸的沙粒便喚醒沉睡的核心。再輕的動作，在這重量面前也一瞬間變得認真。撐多久便堅實多少——每一粒沙都靜靜這樣告訴你。"},"ICON-2535":{"nm":"尾骨墊吊牌","de":"靜靜墊在尾骨下方的坐墊，末端垂著的小吊牌。對久坐疲憊的一天寫上「這裡可以稍微靠一下」貼上——是個如溫柔字條般的工具。"},"ICON-2536":{"nm":"腰部支撐角度三腳架","de":"以三條腿撐持，靜靜抓住腰好倚靠的角度。悄悄插進快要崩塌姿勢裡的支架。要撐住搖晃的東西，三個點意外地就夠了。"},"ICON-2537":{"nm":"收下巴姿勢夾","de":"稍稍把下巴收起托住，散亂的頸線便找回了位置。手指般大的夾子那份嘮叨，總帶著幾分溫柔。把頭擺正的法門，由這小工具教導。"},"ICON-2538":{"nm":"腳步梯帶","de":"在地上展開的帶子，依序替腳畫出該踏的格子。一格一格誠實地踩，不知不覺間，步伐便刻進了身體。路，越踩越清晰。"},"ICON-2539":{"nm":"轉向圓錐片","de":"立起來便「在這裡轉彎」地指點方向的小標記。為只會直直跑的腳，送上一個轉角。連繞進去的路，也藏著各自的節奏。"},"ICON-2540":{"nm":"單腳站立晃板","de":"一隻腳踏上去的瞬間，板子便悄悄傾斜。為了不被晃動打敗而拼命撐住的那幾秒，是平衡最誠實的課。不願跌倒的腳尖，道盡了一切。"},"ICON-2541":{"nm":"反應速度閃燈","de":"信號亮起的剎那，比的是手快還是眼快。閃爍的燈光不給人猶豫的餘地。敏捷的手，總比想法早半拍動起來。"},"ICON-2542":{"nm":"Z字踏點標記","de":"斜貼在地、引領腳呈Z字起舞的小點。比直線更難的，永遠是錯位。順著點來回摸索，碎步便俐落地練成。"},"ICON-2543":{"nm":"平衡走索扁桿","de":"腳踏上細細的桿，世界便窄如一條單索。像走在半空的走索藝人，把全身的專注托在一拃寬上。平衡，越窄反而越清晰。"},"ICON-2544":{"nm":"敏捷反彈球手環","de":"戴在手腕上，小球便藉反彈「咚」地彈回來。在投擲與接住的剎那，反應的速度刻進指尖。所謂迅速，終究是不錯過彈回之物的事。"},"ICON-2545":{"nm":"靈巧足掛呼啦繩","de":"掛在腳上轉圈，呼啦繩便不斷慫恿小腿。一停下便掉，腳尖只好不停擺動。在彷彿嬉戲的動作之間，步法便靈巧地練熟了。"},"ICON-2546":{"nm":"腳尖平衡木陀螺","de":"在手掌上旋轉的陀螺，一失去重心便當場停住。如同在院子裡打陀螺的童年，所謂平衡，是得不停旋轉才終於站得住的東西。"},"ICON-2547":{"nm":"護踝收束繩","de":"包住腳踝收緊，搖晃的踏步便俐落了許多。越是容易受傷之處，越要溫柔地扶住。一根繩，成了一步的安心。"},"ICON-2548":{"nm":"暖膝纏繞帶","de":"纏在冰涼的膝上，暖意便滲進關節之間。僵硬的關節要暖過才終於變柔軟。在活動之前，向我的身體道一聲最溫暖的清晨問候。"},"ICON-2549":{"nm":"肌肉放鬆指壓球粒","de":"輕輕按壓僵結之處，球粒便靜靜撫慰那個結。痛多少便鬆多少的奇妙慰藉。連手碰不到的痠緊，也由這小球替你輕拍安撫。"},"ICON-2550":{"nm":"暖身順序轉盤","de":"從轉盤停下的那格開始喚醒身體。脖子、肩膀、腳踝——順序交給運氣，心便輕鬆放下。準備運動裡摻點遊戲，僵硬的身體便先悄悄笑了。"},"ICON-2551":{"nm":"關節暖敷熱敷包","de":"把熱呼呼的敷包擱在關節上，一股如冬日暖炕般的安心便緩緩散開。這是僵硬關節慵懶舒展的時光。暖過的身體，這才慢慢準備好開始活動。"},"ICON-2552":{"nm":"伸展拉力把手環","de":"握住環往外一拉，僵硬的肌肉便長長地伸展開來。撐住的手與舒展的身體之間，正進行著一場緊繃的對話。伸展多少，明日的動作便輕盈幾分。"},"ICON-2553":{"nm":"腳底刺激凸點板","de":"赤腳站上凸點，沉睡的腳底便猛地驚醒。如同赤足走過碎石路的那股微麻刺激，踏地的感覺自腳尖一路漫了上來。"},"ICON-2554":{"nm":"傷處備忘磁鐵釘","de":"寫下「別逞強」，啪地貼在鐵板上。疼痛的記憶總是輕易被忘卻，於是用磁鐵掛在眼前。愛惜身體的心意，終究也是從一行備忘開始的。"},"ICON-2555":{"nm":"筋膜放鬆節棒","de":"緩緩滾動帶節的棒子，黏連的筋膜便一格格鬆開。輕輕推開糾結的手。緊繃的一天，也像這樣一節節舒展，便會輕鬆許多。"},"ICON-2556":{"nm":"步行線鋪墊帶","de":"筆直鋪在地上，便有了一條讓腳跟著走的線。再凌亂的步伐，踩上這條線也不知不覺端正起來。為它畫出路，腳便不再迷惘。"},"ICON-2557":{"nm":"肩膀水平棒","de":"橫擱在肩上，偏向一邊的失衡便悄悄顯露。所謂水平，總是壓低一邊、抬高另一邊。一根棒子，靜靜點出了歪斜的習慣。"},"ICON-2558":{"nm":"頭頂平衡錘","de":"要讓頂在頭頂的錘子不掉下來，全身就得挺成一條直線。如同昔日頭頂水缸行走的身影，重心是從最高處一路穩穩落下來的。"},"ICON-2559":{"nm":"下巴角度托架","de":"輕輕托住下巴，老是低垂的頭便找回了該有的角度。倚著一個托架片刻的歇息。所謂端正的線條，唯有在底下有人撐住時，才得以完成。"},"ICON-2560":{"nm":"步幅間距木樁","de":"釘在地上的木樁，預先量好了腳該踏出的間距。不寬也不窄的一個步幅，那份誠實的距離。步伐的平衡，正是從這小小的標記悄悄開始。"},"ICON-2561":{"nm":"腳尖方向楔","de":"猶豫不決的第一步，腳尖先替我躊躇著該往何處去。當這小小的楔子定下方向，心也悄悄朝那邊傾去。決定去路的，不是什麼了不起的決心，而是腳尖所指的那一寸。"},"ICON-2562":{"nm":"腰桿挺直腰帶","de":"那聲聲叮嚀「挺直背、挺直背」，彷彿就活在這條腰帶裡。把佝僂的一天輕輕扶直，壓在肩上的重量，竟也神奇地輕了些。一個姿勢，連心都一併扶了起來。"},"ICON-2563":{"nm":"體重分配踏板","de":"左腳七分，右腳三分。重量多放在哪邊，平衡便往哪邊偏。踏板靜靜地問——此刻的你，正朝哪一邊傾斜地站著。站直一事，其實也是不斷的調整。"},"ICON-2564":{"nm":"視線高度標的棒","de":"眼睛總是往腳尖垂落。這種時候，遠處立著的一根棒子，會慢慢把視線牽引上來。練習看遠，便是練習走遠，抬頭的那一刻，原以為觸不到的地方也近了。"},"ICON-2565":{"nm":"鞠躬角度卡片夾","de":"十五度、三十度、四十五度。腰彎下的深度有多少，心也跟著低下幾分。卡片上記的角度不只是數字，而是丈量對對方那份誠意的小小刻度。"},"ICON-2566":{"nm":"雙手合攏禮儀環","de":"把雙手端正合攏，浮躁的心也朝一處沉靜下來。這小小的環，溫柔地接住那不知所措、亂晃的指尖，悄悄定下了行禮的第一個姿勢。"},"ICON-2567":{"nm":"動線箭頭磁鐵","de":"迷路的腳，最先東張西望尋找的便是箭頭。啪地吸上磁鐵的一個方向，斬斷了猶豫，悄悄把腳步牽向該去的地方。迷惘的心，這才終於有了一個方向。"},"ICON-2568":{"nm":"退場方向標示釘","de":"離開的路，往往比進來的路更難走。即便在熄燈的黑暗中也清晰發光的這枚釘子，靜靜指明了最後的動線。原來好好離場也是舞台的一部分，到了最後才明白。"},"ICON-2569":{"nm":"正式行禮順序帶","de":"曾有那麼一個年代，先行禮者與後行禮者的次第分明。按著帶子上記的順序俯身，連鄭重都生出了層次，連禮節都流動起來。這是守住心意先後的事。"},"ICON-2570":{"nm":"對齊腳步磁鐵片","de":"一個人錯了步，整排隊伍便會搖晃。如同對齊腳尖喀地吸合的磁片，所謂並肩而立，便是把自己的步幅悄悄讓給身旁的人。同一拍子踏出的腳步聲，最是教人安心。"},"ICON-2571":{"nm":"舞台行禮定位馬蹄","de":"就連一次舞台行禮也有該站的位置。把腳踏上如馬蹄般圓圓鋪開的印記，那因緊張而老是出錯的第一個禮，這才終於找到了該有的模樣。知道了位置，顫抖也稍稍平息。"},"ICON-2572":{"nm":"致謝手勢卡片","de":"言語中道不盡的感謝，自指尖流淌出來。比個愛心、把手放上胸口——卡片上記的每一個手勢，都成了把心意謄寫下來的翻譯。想觸及的真心，總是有它的形狀。"},"ICON-2573":{"nm":"候位間距卡片樁","de":"就連排隊一事，也有著溫柔的禮節。如同與前一個人剛好保持一掌距離的木樁，等待，是從不去推擠彼此的小小體貼開始的。稍微隔開一些站著，也是用心的事。"},"ICON-2574":{"nm":"台詞提示卡翻頁環","de":"下一句台詞老在嘴邊打轉時，手指悄悄翻過一張。穿在環上的小紙片靜靜按住那份悸動，從容地攤開下一句該說的話。即使顫抖，流程也不會中斷。"},"ICON-2575":{"nm":"進行順序沙漏","de":"靜靜望著簌簌流下的沙粒，下一個環節便在心裡從容地理順。在最後一粒落下之前，不急不徐、用眼睛讀取時間的方法，這只小小的漏教會了我。"},"ICON-2576":{"nm":"麥克風握持練習棒","de":"還沒上手前，一根空棒子也重如千斤。握的角度、與嘴的距離、手腕使的力——握起又放下、反覆無數次的練習，某天忽然綻放成一個自然的動作。"},"ICON-2577":{"nm":"發音清晰舌棒","de":"ㄍ、ㄋ、ㄉ、ㄌ。含著棒子滾動發音，直到舌尖變得清晰。一句清晰吐出的話語，是在數百次含糊、模糊的時光之上，靜靜綻放的花。"},"ICON-2578":{"nm":"提示信號手旗","de":"開始、停止、歇一拍。一面不發一語的旗子，指揮著舞台的呼吸。在觀眾席看不見的位置靜靜揮動的手，密密地牽住了所有的拍子。"},"ICON-2579":{"nm":"段落轉換鈴鐺","de":"叮鈴一聲清脆響起，場景便轉換。如同黃昏市集間飄散的鈴聲，這一小聲清響，輕盈地把躊躇的心送進下一個段落。轉換總是從聲音開始。"},"ICON-2580":{"nm":"口白呼吸節拍錘","de":"吸一口氣——一、二——慢慢吐出。跟著左右搖擺的錘子調勻呼吸，急急傾瀉的話語也不知不覺找回了自己的拍子。話的速度，原來就是呼吸的速度。"},"ICON-2581":{"nm":"主持劇本摺疊板","de":"摺起又攤開的一個動作裡，原原本本裝著今日的次第。攤開那塊浸滿手澤的板子的瞬間，不知該先拿出什麼的紛亂心緒，從容地排起了隊。一個攤開，便理清了一天。"},"ICON-2582":{"nm":"呼吸節拍沙漏","de":"吸氣三、停四、吐氣六。沙在流動的時候，我的氣息也靜靜跟著流。一口一口數著呼吸，是慢慢照看忙碌的自己最古老、最溫柔的方式。"},"ICON-2583":{"nm":"冥想坐墊流蘇飾","de":"繫在坐墊角的流蘇，無風也靜靜地晃。盤腿坐下，那古人坐在簷廊上修養心性的寧靜，便悄悄來到身旁，停留片刻而去。"},"ICON-2584":{"nm":"調息手風鈴","de":"一縷風拂過，便響起一聲清音。如同掛在屋簷下的風鈴，這東西在紛亂沸騰的心上，啪地落下一滴沁涼清爽。原來聲音也有撫平的力量。"},"ICON-2585":{"nm":"薰香煙承接盤","de":"香燃盡後留下的煙，緩緩落在盤上。如同節慶清晨供桌前裊裊升起的那股香氣，一縷煙靜靜安撫了喧鬧的空氣，把寧靜注滿了房間。"},"ICON-2586":{"nm":"吸氣吐氣搖擺錘","de":"緩緩升起又落下的一個錘子，載著我的呼吸。吸氣時浮起、吐氣時沉下——在忘了身體如何呼吸的日子，這只小小的時計從頭再教我一次。"},"ICON-2587":{"nm":"冥想鐘鳴杵","de":"輕輕敲鐘一下，餘韻便悠長地擴散開來。如同山寺裡迴盪的風鈴聲，只是靜靜聽著那聲響徹底消散於空氣中，心的一角便被洗得清明。"},"ICON-2588":{"nm":"呼吸引導羽毛","de":"把羽毛靜靜放在鼻前，看不見的呼吸之路這才得見。輕輕晃動，便是呼吸順暢；停住不動，便是憋得太久。最輕的東西，有時成了最誠實的嚮導。"},"ICON-2589":{"nm":"撫平心緒鵝卵石","de":"握在掌心的鵝卵石又涼又滑。如同在河邊久久翻滾、磨去了所有稜角的石頭，指尖一遍遍摩挲著，沸騰的心那尖銳的部分也漸漸磨得圓潤起來。"},"ICON-2590":{"nm":"鼻息溫度夾","de":"鼻尖的溫度，靜靜告知呼吸的深淺。涼涼進來、暖暖出去的空氣，夾子悄悄讀取出來，把平時毫無察覺的呼吸清晰地呈現眼前。原來呼吸也有表情。"},"ICON-2591":{"nm":"心情天氣貼紙板","de":"今天我的心是晴天，還是陰天呢。挑一張小貼紙啪地貼上板子的瞬間，難以言說的心情也化作一種天氣，有了清晰的形狀。原來心也需要一份天氣預報。"},"ICON-2592":{"nm":"情緒色彩手印章","de":"喜悅是黃，悲傷是藍。挑好顏色用力按印在紙上，心的色澤便留作印記。再怎麼難以命名的情緒，顏色也會先一步靠近，靜靜替我察覺。"},"ICON-2593":{"nm":"今日心情花瓣片","de":"在一片花瓣上，輕輕擱下今日這一天的心情。如同春日紛飛的杜鵑般輕盈柔嫩的一片籌碼，在落幕的一天盡頭，低聲問候我過得好不好。"},"ICON-2594":{"nm":"加油對話框磁鐵","de":"想說的話老在嘴邊打轉。啪地貼上對話框磁鐵的瞬間，那句沒能出聲遞出的加油，靜靜抵達某人疲憊的一天之上。心意，便是這樣傳遞的。"},"ICON-2595":{"nm":"心底信封封蠟","de":"來不及說出口的話，便細細裝進信封封印起來。如同古人用指尖塗膠、封緘書信，一張封蠟安全地守護著心底話。靜靜等待著有朝一日取出展開的那天。"},"ICON-2596":{"nm":"情緒溫度花苞","de":"緊閉的花苞觸到溫暖，便一層層小心翼翼地綻開。心的溫度一升，便一同盛放——今天我被暖了多少，這朵花比話語更早知道。原來心裡也住進了春天。"},"ICON-2597":{"nm":"自我稱讚手鏡繩","de":"舉起鏡子，與映在裡頭的自己靜靜對望。繫在繩上的小小鏡面映出的，不是臉龐，而是該對它說一句「辛苦撐過來了」的昨日的我。原來安慰並不在遠方。"},"ICON-2598":{"nm":"心情表情印章組","de":"燦爛的笑、含淚的眼、噘起的賭氣嘴。一個個按下表情印章，寫著心的日記。在難以化作文字的日子，一張小小的臉，替我靜靜道出那天的心情。"},"ICON-2599":{"nm":"情緒線團整理環","de":"再怎麼糾結的線團，一縷縷耐心解開，終究會回到一根線。把錯亂鬱悶的情緒一個個掛上環，怎麼也理不清的我的心，也抓到了一絲細細的頭緒。"},"ICON-2600":{"nm":"入眠香囊繩","de":"掛在枕邊的香囊，隱隱散出淡淡草香。如同奶奶把香放進衣櫃深處的那股氣味，撫弄繩子之間，整日緊繃的神經便緩緩睡去。"},"ICON-2601":{"nm":"睡眠順序翻面板","de":"輾轉到天快亮才好不容易入睡的夜。輕輕替躺臥的姿勢翻個面，昨日的輾轉便悄悄交接給今晨的清爽。歇息也是一種練習，這塊小板默默搭把手。"},"ICON-2602":{"nm":"枕邊月光掛","de":"把從窗簾縫隙透進的光，掛一片在枕邊。一條柔和的河流淌過熟睡的臉龐，連那害怕黑暗的練習生之夜，這才變得溫柔。那是頭一次出現的小小慰藉。"},"ICON-2603":{"nm":"狀態花苞片","de":"今天的狀態，像花苞一樣緊閉著。啪地按下籌碼，便慢慢綻開，睡得好不好，身體最先知道。連盛放前那份猶豫，都靜靜地惹人憐愛。"},"ICON-2604":{"nm":"夜燈燈芯罩","de":"「別關燈。」為了怕黑的老么，有人在燈芯上輕輕罩了個罩子。不太亮也不太暗，只在入睡前陪伴在側，那是個小小而溫柔的約定。"},"ICON-2605":{"nm":"晨起向日葵釘","de":"插在枕邊，便會像向日葵般，朝第一道晨光悄悄轉過頭去。就算是不想起床的日子，光的召喚也自有它的道理，把清晨領往一個方向。"},"ICON-2606":{"nm":"助眠草本枕刷","de":"把薰衣草與洋甘菊沾上刷尖，往枕頭輕輕一掃。香氣滲進枕套之間，一整天的緊繃便自肩頭緩緩鬆落。好眠，是從這一縷小小的香開始的。"},"ICON-2607":{"nm":"被褥邊角夾","de":"破曉時分，腳尖老是溜出被外。用夾子牢牢咬住邊角，整夜暖意便逃不掉。這是代替一句「好好睡」，扣上的一道小小看守。"},"ICON-2608":{"nm":"狀態鵝卵石收集籃","de":"一天一件好事，一顆掌心大的鵝卵石。籃裡攢的石頭越沉，心也悄悄越踏實。把不起眼的瞬間握進手裡收藏，幸福原本就是這樣數的。"},"ICON-2609":{"nm":"決心集星罐","de":"每天夜裡，把今日的決心捏成星星的形狀，啪地丟進罐子。攢滿了，罐子便成了一片小小的夜空。空蕩的瓶口知道，約定要攢起來才會發光。"},"ICON-2610":{"nm":"小獎勵糖果掛","de":"在疲憊的一天盡頭，遞給自己的一顆糖。從掛架上取一顆含進嘴裡的瞬間，就算沒人知曉也沒關係了。因為小小的獎勵，是最誠實的加油。"},"ICON-2611":{"nm":"今日做到了印章模","de":"沾上墨，往筆記本上一蓋。「今天做到了。」做得好的日子，與只是撐過去的日子，同樣一格格填滿。每天不必完美，只要別停下蓋章便好。"},"ICON-2612":{"nm":"加油旗插座底","de":"牢牢插在地上，風越是猛，旗子便揮得越是有勁。連搖擺的東西也需要一隻撐住的手。為某人加油的心，便是這樣在底下撐著。"},"ICON-2613":{"nm":"目標種子栽種盆","de":"目標不是用嘴背誦的，而是埋進土裡的。種下一顆種子、澆著水等待的時候，急躁便慢慢化作根。在花盆裡長大的，不只是新芽。"},"ICON-2614":{"nm":"稱讚貼紙黏貼板","de":"做得好的事，便貼上一張貼紙。板子被五彩繽紛填滿，那些不經意流逝的日子，便以色彩復活過來。年幼的我們懂得，稱讚越是貼著，就越鮮明。"},"ICON-2615":{"nm":"決心緞帶綁束環","de":"把緞帶穿過環、打結的手。牢牢地不讓它鬆開，卻又別太緊。所謂決心，正像這個結，繫太緊會斷，太鬆又會悄悄滑落。"},"ICON-2616":{"nm":"小成就貝殼片","de":"在海邊撿來的貝殼上，記下小小的成就。如同被浪削了又磨、一路來到此處的一片貝，你的一天也滾過漫長歲月，磨得閃閃發亮。熬過時間的，都會發光。"},"ICON-2617":{"nm":"獎勵獎牌掛鉤","de":"費心贏來的獎牌，不掛進抽屜，而是掛在與眼齊高處。掛在鉤上的那份重量，讓每天清晨都挺直了肩膀。獎勵不是藏起來的，而是掛在那兒，要人好好望著。"},"ICON-2618":{"nm":"梅雨傘水承接杯","de":"梅雨順著傘尖滴滴答答流下。墊上一個杯子，玄關便不會濕。雖然擋不住傾瀉的雨，卻能替它定下落下的地方。"},"ICON-2619":{"nm":"消暑冷敷袋","de":"盛夏的後台，悄悄貼上頸後的一袋冰涼。火燙升騰的熱氣便沉下一拍。「喘口氣吧。」比起暑氣，那隻先照看我的手最是可靠。"},"ICON-2620":{"nm":"風扇葉片固定夾","de":"猛烈旋轉的葉片，也被一個夾子靜靜止住。風越是強勁，便越需要牢牢抓住的什麼。轉得快的東西，終究是靠有人抓住才安全的。"},"ICON-2621":{"nm":"濕鞋烘乾棒","de":"淋了雨的鞋，一夜之間連心都弄得潮濕。把棒子塞進裡頭，早晨便能乾爽地重新穿上。濕了的東西不是該丟，而是該好好晾乾的。"},"ICON-2622":{"nm":"雨靴抖泥踏板","de":"沾滿田埂泥土回來的雨靴。在踏板上唰唰蹭掉，這才上了地板。把外頭的泥濘留在門前再進屋，是潔淨守家的古老禮節。"},"ICON-2623":{"nm":"夏日踏腳涼磚塊","de":"赤腳最先知道。把腳底貼上夏日地板鋪的磚塊，正午的暑氣便在一掌涼意中悄悄消退。光是一點點冰涼，漫長的季節也變得可以忍受。"},"ICON-2624":{"nm":"擋雨門檻帶","de":"明明只是在門檻上圍了一條帶子，雨水便再也越不進來。一條劃分內外的細線。該守護的地方，比起了不起的牆，更適合一道牢靠的界線。"},"ICON-2625":{"nm":"蚊香承接盤","de":"夏夜，把蚊香擱上承盤，便升起一縷嗆人卻又親切的煙。如同圓圓燃盡的香，夜也慢慢深了。那是躺在涼床上數星星的那段時光的氣味。"},"ICON-2626":{"nm":"消暑涼袖環","de":"用袖套遮住被太陽曬得刺痛的手臂。用環牢牢扣在衣袖上，正午的活兒也變得能撐下去。所謂清涼，是替貼著的部位遮上一掌的小小心意。"},"ICON-2627":{"nm":"掃落葉手掃帚","de":"把落滿院子的落葉用手掃帚唰唰掃攏。一個季節在腳下沙沙作響。所謂整理某樣東西，有時也是替即將離去的事物，好好送上一程。"},"ICON-2628":{"nm":"通風窗支撐棒","de":"在悶滯的房裡塞上一根棒子，把窗稍稍撐開。秋風悄悄進來，把陳濁的空氣帶走。所謂通風，是把屋內積著的，靜靜與屋外交換的一個小小氣口。"},"ICON-2629":{"nm":"橡實口袋塞","de":"像松鼠般把橡實塞滿口袋，再用塞子堵住袋口。牢牢地，怕滾了出去。想守住攢下之物的心，是過冬的小生靈們古老的本能。"},"ICON-2630":{"nm":"秋被抖塵拍","de":"把蓋了整夏的被子晾在院裡，用拍子啪啪地拍。塵埃間飄散著陽光的氣味。要抖掉陳舊的季節，才能蓋上新的季節，這道理手腕先記得。"},"ICON-2631":{"nm":"窗縫擋風繩","de":"自窗縫滲入的冷風，用一條繩子牢牢擋住。一根細細的線，把房裡的暖意守到最後。嚴寒總是從小小的縫隙開始的，這道理過冬的準備懂得。"},"ICON-2632":{"nm":"落葉濾網蓋","de":"蓋在雨水槽上的濾網。把落葉細細濾出，只讓水流過。要暢通無阻地流，就得定下讓什麼通過、把什麼攔住，秋日的屋簷這麼說。"},"ICON-2633":{"nm":"乾草捆夾","de":"把曬得乾透的草捆用夾子牢牢束緊。把即將散開的東西攏作一處的手。即便在夏日青翠盡褪的地方，攢起來，用處便原原本本地留著。"},"ICON-2634":{"nm":"秋風溫度搖擺片","de":"風一吹，搖擺片便輕輕晃。憑那晃動的幅度，揣摩今日秋意有多深。溫度不是數字，而是化作搖晃的某樣東西，最先觸到手上的。"},"ICON-2635":{"nm":"外套口袋暖手包套","de":"「手冷了吧。」放在外套口袋裡的暖手包套，悄悄暖著凍僵的手指。先替某人著想寒冷的心，總是靜靜躺在口袋裡。"},"ICON-2636":{"nm":"窗戶結露承水檻","de":"冬日窗戶整夜流下的淚，由檻靜靜接住。那是內外溫差造就的小小水路。溫差越大的地方，流下的便越多，破曉的窗每天展示著這道理。"},"ICON-2637":{"nm":"暖爐擋火安全網","de":"在熊熊燃燒的暖爐前立起安全網。暖意拉近，危險擱遠剛好一掌。把火擺在身旁卻又不受傷，是照看某人最基本的距離。"},"ICON-2638":{"nm":"冬被壓固夾","de":"厚實的冬被老是滑落時，用夾子壓著靜靜替它定住位置。沉甸甸的暖意，要牢牢扣住才值回票價。冬夜的安穩，便是這樣牢靠地守護下來的。"},"ICON-2639":{"nm":"除霜刮刀鏟","de":"破曉車窗上白白結成的霜，用鏟子唰唰刮掉。朦朧的視野一條條開闊起來。就連凍結之物終究也能刮掉，冬日清晨的指尖這樣告訴我。"},"ICON-2640":{"nm":"熱水壺蓋保溫套","de":"替裝了熱水的壺套上保溫套。怕它一夜放涼，多裹上一層暖意。把溫暖長久留住的方法，終究是用什麼悉心地把它抱住。"},"ICON-2641":{"nm":"門縫紙壓棒","de":"自門縫鑽入的刀刃般寒風，遇上你的瞬間便怔了一下。一根壓住窗紙下緣的棒子。房裡的暖意這才守住了自家人，冬天便靠這種小小的執拗暖暖地過。"},"ICON-2642":{"nm":"腳爐承接盤","de":"墊在腳爐底下的圓盤。獨自承受所有的熱燙，地板上卻不留一絲焦痕。在某人的腳尖慵懶暖起的時候，屬於我那份的一天，靜靜結束。"},"ICON-2643":{"nm":"結露擦拭吸水布環","de":"為了讓擦過破曉窗上水珠的布不至於無處可去，一個環掛在牆上等著。比起飽吸水分，再以乾爽之姿等待明早，才是吸水真正的心意。"},"ICON-2644":{"nm":"冬季手套烘乾掛","de":"打完一場雪仗的手套，在暖氣旁張開五指。掛在掛架上嫋嫋冒著熱氣的光景。那是鼻尖凍紅的午後盡頭，冬日裡最祥和的一場晾曬。"},"ICON-2645":{"nm":"撢子羽毛替換","de":"羽毛磨損了，便換上新羽毛。趕灰塵的那端重新變得蓬鬆的瞬間。原來清掃工具也有換季，這小小的替換，在掌心上悄悄告訴我。"},"ICON-2646":{"nm":"抹布擰水手柄","de":"為了替手腕省點力而裝上的手柄。一扭，抹布便自個兒把水吐出來。在搓衣板前吃力的日子再見了。在家務裡，一撮訣竅便成了一份溫柔。"},"ICON-2647":{"nm":"地刷更換刷板","de":"地刷磨損了，便只把刷頭抽出來換掉。柄還是那把柄，握慣的重量也還是那份重量。耐用之物裡，住著一份不願整件丟棄、小小而堅實的溫柔。"},"ICON-2648":{"nm":"黏塵滾筒替換芯","de":"撕下滾筒最後一張，總覺得有些空落。這時換上一個新芯。連黏在毛衣上的一絲毛球都要負責到底，那是執著而溫柔的替換之約。"},"ICON-2649":{"nm":"角落灰塵刮","de":"就連掃帚搆不著的牆角，灰塵也悄悄安了家。用細細的尖端把角落摳出來。連看不見的地方都顧到的心，便是家務的自尊。"},"ICON-2650":{"nm":"掃帚清理梳","de":"掃過地的掃帚，也需要一隻歇息的手。用這把梳子把卡在刷毛間的頭髮唰唰梳出來，幹完一場活的掃帚，這才備好了下一次的清掃。"},"ICON-2651":{"nm":"木地板紋理打蠟墊","de":"順著木地板的紋理上一層蠟，木頭便慢慢憶起久違的光澤。腳底似滑非滑，整個家光潤亮澤、心情愉快地微笑的午後。"},"ICON-2652":{"nm":"門縫灰塵掃","de":"我盯著住在門縫裡的灰塵。每當門開開合合便悄悄堆積的那些，用我輕薄的身軀掃進來。縫隙越窄越深，便越是輪到我出場。"},"ICON-2653":{"nm":"踏墊濾塵蓋","de":"為了不讓玄關踏墊吞下的灰塵再溜出去，一個濾網蓋當起最後的門衛。沾泥的鞋從外頭世界帶來的灰塵，就決定只放進到這裡為止。"},"ICON-2654":{"nm":"水龍頭水垢刷","de":"悄悄盤踞在水龍頭頸上的水垢，小刷子繞著一圈刮除。每天手都會掠過的地方，越是該閃亮。那便是這把小刷子守護的浴室禮節。"},"ICON-2655":{"nm":"排水口濾髮蓋","de":"把要漂進排水口的頭髮，由我靜靜接住。用一個蓋子擋下「堵塞」這場小小災難的事。圓圓而牢靠的英雄之日，總在腳下悄悄流淌。"},"ICON-2656":{"nm":"磁磚填縫刮","de":"白磁磚間黑黝黝暈開的填縫，那積年的歲月，用尖端輕輕刮除。狹窄的縫隙乾淨了，整間浴室便如新的一般，輕鬆地喘了口氣。"},"ICON-2657":{"nm":"蓮蓬頭清潔針","de":"把堵住的蓮蓬頭孔用針尖一戳通開，一直只是涓涓細流的水，便又痛快地傾瀉而下。一個小小堵塞被解開，那暢快清晨的水聲。"},"ICON-2658":{"nm":"馬桶刷收納杯","de":"馬桶刷也要在乾爽的地方歇息，才稱得上衛生。端正地插在接住水氣的小杯裡，等著下一輪。工具的品格，不在使用而在收納中流露。"},"ICON-2659":{"nm":"黴菌擦拭海綿","de":"在磁磚邊角黑黑暈開的黴菌，這位執著的客人，海綿鄭重地請它退場。被唰地擦過一次，浴室便又明亮地回到本來的白。"},"ICON-2660":{"nm":"鏡面除霧刮","de":"沐浴完站在霧濛濛模糊的鏡前，刮片一劃，清晰的我便回來了。與在霧氣那頭短暫躲藏的今日表情，再度相對的瞬間。"},"ICON-2661":{"nm":"浴室拖鞋掛","de":"把濕拖鞋倒掛起來，水便滴滴答答流下，裡頭乾爽地晾乾。為了讓下一個人的腳不至冰涼。小小掛架的體貼，總是早一步迎候在前。"},"ICON-2662":{"nm":"指甲刷盒","de":"就連刷去指甲底污垢的小刷子也有自己的家。鑽進盒裡無水氣地乾爽晾著，等候下一個洗手台。整潔，總是從收拾中靜靜開始。"},"ICON-2663":{"nm":"牙刷殺菌杯蓋","de":"每天兩度與嘴相對的牙刷，也需要一處小小的安身所。殺菌杯蓋啪地蓋上的瞬間，一格的潔淨，便靜靜守護著、不受浴室裡飄散的濕氣侵擾。"},"ICON-2664":{"nm":"棉花棒攜帶膠囊","de":"為了讓旅行箱裡的棉花棒不折斷、不散落，一個膠囊溫溫地把它們攬入懷中。越是小的東西越要事先備好，才不會在陌生的路上手足無措。"},"ICON-2665":{"nm":"呵氣檢測迷你板","de":"往掌心呼一口氣，輕輕貼上迷你板，呵氣一觸便白白霧開。寒冷的日子裡我在此活著的最可愛證據，這塊小板默默替我記了下來。"},"ICON-2666":{"nm":"挖耳棒收納集","de":"挖耳棒搭著包包外出，尖端容易變鈍。於是備了一個小小的家。即便帶著走、尖端也不會受傷的那裡頭，細緻的工具好好地睡著。"},"ICON-2667":{"nm":"手帕摺疊夾","de":"把四角端正摺好的手帕，由夾子輕輕咬住，防它在包裡散亂。整齊疊好的一方，無論在哪個瞬間取出，都遞來一份靜靜的品格。"},"ICON-2668":{"nm":"衛生OK繃盒","de":"膝蓋擦破的日子，打開盒子，各式OK繃便排成排等著你。連小傷也懂得大驚小怪的溫柔。急救盒總要擺在伸手可及的近處。"},"ICON-2669":{"nm":"掌心指紋擦","de":"把留在玻璃上的指紋一擦，那躊躇手勢的痕跡便消失了。每一處被觸碰過、原本朦朧的窗外世界，再度變得透明，是一掌大的小小魔法。"},"ICON-2670":{"nm":"垃圾分類投入隔板","de":"紙在這邊，罐在那邊。一塊隔板，分開了險些混作一團的命運。所謂分類回收，終究是悉心區分的心意，而這道首行，由這塊牢靠的隔格一筆一劃劃下。"},"ICON-2671":{"nm":"貼紙撕除鏟","de":"黏得牢牢的貼紙，在我面前也悄悄投降。把扁平的鏟刃輕輕推進邊角，便不留一絲痕跡、乾乾淨淨地剝落，那是場痛快的告別。"},"ICON-2672":{"nm":"紙膠帶裁切鋸齒","de":"用紙膠帶不必再翻找剪刀。對著鋸齒一拉，便順著紋理啪地斷開。那是手帳愛好者指尖最珍愛、又小又俐落的好搭檔。"},"ICON-2673":{"nm":"邊角黏合角鐵","de":"從內側牢牢抓住翹起邊角的小小鐵件。在看不見的位置默默守住角度。外表端正之物的背後，大多有著這般隱身的支柱。"},"ICON-2674":{"nm":"貼紙保護膜筒","de":"為了不讓珍貴的貼紙皺折或受潮，便與保護膜並排睡在筒裡。蒐集的喜悅旁，總伴隨著想好好守護它的那份用心。"},"ICON-2675":{"nm":"印台印章清潔刷","de":"沾滿墨水的印章縫隙，刷子順著紋理輕輕掃，褪去陳舊的顏色。為了下一次蓋下的一點清晰分明，預先擦拭的小小而勤快的手。"},"ICON-2676":{"nm":"透明內頁夾翼","de":"為了不讓活頁夾內頁滑溜溜地溜走，翼片把兩側緊緊夾住。多虧一張張都待在原位，翻頁的指尖才不會散亂。"},"ICON-2677":{"nm":"裝飾碎片收納鏟","de":"把零碎散落的裝飾碎片，用小鏟子一下唰地舀起裝好。用手指一個個撿拾的繁瑣消失後，悉心做點什麼的時光，便愈發愉快了。"},"ICON-2678":{"nm":"書籤流蘇固定鐵","de":"為了不讓書籤末端的流蘇鬆脫，固定鐵牢牢把它綁住。指引回到讀到一半那頁的嚮導，也得自己儀容端正，心裡才踏實。"},"ICON-2679":{"nm":"裝飾筆尖筆蓋夾","de":"為了不讓裝飾筆尖乾掉，把筆蓋牢牢夾住的夾子。免去了一時忘了蓋、筆便乾硬的狼狽，顏色便總像初時般濕潤地流淌出來。"},"ICON-2680":{"nm":"螺絲起子刀頭插嘴","de":"螺絲起子的手柄不動，只把末端的刀頭咻地換掉。十字也好、一字也罷，樣樣順手。一支便能利落辦妥多樣活兒的精明，牢牢藏在這小小的刀頭尖上。"},"ICON-2681":{"nm":"砂紙邊角繞捲","de":"把粗糙的那面圓圓地繞握住，掌心便成了工具。唰、唰，每順著紋理推一回，毛糙的邊角便圓潤起來，那最後的光滑，總由人的指尖辨出。"},"ICON-2682":{"nm":"螺絲分類漏斗","de":"散落的螺絲穿過窄窄的頸口，滴溜溜匯到一處。在桌上滾來滾去的小東西找到歸位的聲音，連紛亂的心也有了被整齊收拾妥當的感覺。"},"ICON-2683":{"nm":"捲尺末端掛鉤","de":"捲尺末端的掛鉤，是獨自作業之人的第二隻手。往邊角啪地一掛，尺便不會晃動，量出的長度有多少，手與心也跟著誠實幾分。"},"ICON-2684":{"nm":"扳手手柄護套","de":"套在冰冷鐵柄上的一層。握住的瞬間，觸到的不是冰涼，而是柔軟的暖意。工具唯有先體貼握它的人，才能在身旁停留得更久。"},"ICON-2685":{"nm":"錐尖保護尖帽","de":"每根尖端都各套上一個小小的尖帽。就算在抽屜裡摸索也不會被扎到的安心——越是銳利之物，悉心包好，便誰也不會受傷。"},"ICON-2686":{"nm":"電線剝皮刃","de":"只薄薄剝去外皮，不傷到裡頭的線。輕輕褪下一層，銅色的線芯閃亮顯露的瞬間，好的刀刃精準地知道該在哪裡停下。"},"ICON-2687":{"nm":"水平儀氣泡窗擦","de":"氣泡得恰好停在正中央，這才稱得上水平。把小窗擦得清亮一事，與畫線前先勻好氣息的靜靜準備，何其相似。"},"ICON-2688":{"nm":"釘釘子手指護套","de":"把握釘子的手指牢牢裹住的小小護套。就算鎚子偏了也沒關係，要人毫無懼意地揮下，已備妥要替手指挨那一下的牢靠覺悟。"},"ICON-2689":{"nm":"餵食碗防滑墊","de":"撐住飯碗、不讓它在地上滑開的一層橡膠。吃得起勁時碗也不會逃跑，一餐的安寧，是從不搖晃的位置開始的。"},"ICON-2690":{"nm":"飼料勺掛","de":"把舀飼料的勺子掛在牆上輕鬆晾乾。每一餐都在同一個地方迎接手的小小秩序——有張要照看的嘴，原來是這般溫柔的事。"},"ICON-2691":{"nm":"水碗溢水盤","de":"把沿著水碗邊溢出來的一口水，靜靜接住。多虧這寬寬的盤子怕地板濕、預先把水攬住，腳下總是乾爽地乾著。"},"ICON-2692":{"nm":"零食配給夾","de":"精準夾起一塊零食遞過去的夾子。即便面對湊著鼻子等候的小嘴，分食之中也有著不亂分寸的溫柔指尖。"},"ICON-2693":{"nm":"飼料袋口捲合夾","de":"把拆開用過的飼料袋口捲一捲咬住的小夾子。啪地一闔，便擋住了受潮，明早那一把酥脆，原原本本地守住了。"},"ICON-2694":{"nm":"水壺嘴塞","de":"與水壺嘴剛好咬合的一個塞子。滴答漏下的水珠止住，四周乾爽起來。封得好的東西不會漏，便能長久清澈地存著。"},"ICON-2695":{"nm":"餵食量刻度杯","de":"順著刻度精準舀出一杯。不多也不少——在公平估量今日這一餐的手裡，小小家人的一天恰如其分地盛了進去。"},"ICON-2696":{"nm":"撒落飼料墊邊緣","de":"擋住撒落的飼料、不讓它越出墊外的邊緣。稍稍立起的一道邊，把險些散開的碎屑，牢靠地攏了回來。"},"ICON-2697":{"nm":"雙層碗分離環","de":"把疊在一起的兩個碗輕輕分開的小環。緊緊黏住、費勁掰扯的手變得輕鬆了。把東西好好分開，說起來也是一份溫柔的照看。"},"ICON-2698":{"nm":"庭院滾球漏斗","de":"把滾到院子裡咕嚕嚕跑遠的球攏到一處的漏斗。盡情奔跑了一場的傍晚，把四處散落的東西收攏回來的手，自然浮上心頭。"},"ICON-2699":{"nm":"圍欄木樁帽","de":"替每根圍欄木樁戴上圓圓的帽子。怕末端被風雨吹裂，連小小一根都細心覆蓋的心意，滲滿了整座院子。"},"ICON-2700":{"nm":"遊戲隧道摺疊環","de":"把玩盡了的遊戲隧道一層層摺起來掛上的環。把沾泥的一天好好收拾掛起，整理妥當的遊戲，必定許下明天的約定。"},"ICON-2701":{"nm":"拉繩握把軟墊","de":"把拉繩握把鬆軟包覆起來的軟墊。即使用力拉扯，手掌也不會被磨痛。握得越久手越舒服，是因為有人那份小小的體貼。"},"ICON-2702":{"nm":"庭院遮陽布扣鉤","de":"牢牢扣住院子裡那片遮陽布的扣鉤。連正午的涼意，也得拴住才肯停留。在扣鉤撐起的陰影下，慵懶的午後好好地歇了長長一陣。"},"ICON-2703":{"nm":"挖土鏟刃護套","de":"靜靜套在挖土鏟刃上的護套。讓忙過一場的日子好好休息，刀刃便不至於變鈍，來年春天還能再次與泥土相見。"},"ICON-2704":{"nm":"滾球斜坡板","de":"一塊讓球咕嚕咕嚕滾下來的斜坡板。順著微微傾斜的坡面，球興高采烈地奔跑而下。小小的一個坡度，便造出了一整天的歡樂。"},"ICON-2705":{"nm":"圍欄門閂環","de":"鎖住圍欄門的門閂環。喀嚓一聲輕響鎖上，心也隨之安定。一扇結實關好的門，把小小的院子守成了一個完整的世界。"},"ICON-2706":{"nm":"繫鈴遊戲繩","de":"輕輕晃動繫著鈴鐺的繩子，清脆的聲音便蕩漾開來。叮鈴、叮鈴——原本靜謐的一方房間醒了過來，一聲小小的迴響，便讓整顆心豎起了耳朵。"},"ICON-2707":{"nm":"花盆底盤接水盤","de":"靜靜承接從花盆底滲流而出的水的盤子。為了不讓窗台被沾濕，把溢出的水攬入懷中。心意若也滿溢時，總得有個承接它的位置。"},"ICON-2708":{"nm":"幼苗移植插秧鏟","de":"把嫩幼苗移到土裡輕輕插下的小鏟子。在一株一株小心翼翼為它們安頓位置的指尖下，連手掌大的菜園也探出了青翠的春意。"},"ICON-2709":{"nm":"菜畦標記插牌","de":"在每道菜畦上寫明種了什麼、插下去的標記牌。在還未冒芽的泥土上，一枚小小的名牌，靜靜記住了這裡將會長出什麼。"},"ICON-2710":{"nm":"灑水壺出水口濾網","de":"套在灑水壺出水口上的細網。原本一股傾瀉而下的水，化作如毛毛雨般分散成數條細流。唯有柔和的水流，才不會傷到嫩葉。"},"ICON-2711":{"nm":"支架固定夾","de":"把搖晃的莖靜靜繫綁到支架上的夾子。在還柔弱的它能挺直站立之前，暫且借予的依靠——成長，正需要這樣的支撐。"},"ICON-2712":{"nm":"種子袋密封夾","de":"把剩下的種子袋牢牢夾住封好的夾子。輕輕一扣，便一粒也不外漏。一個與來年春天的小小約定，就寄託在這一次的夾合裡。"},"ICON-2713":{"nm":"土壤肥料量勺","de":"把土壤與肥料剛好舀起盛裝的小勺子。不多也不少，恰恰一勺——在精準衡量的份量之上，泥土才終於做起了它該做的事。"},"ICON-2714":{"nm":"吊盆掛架鉤","de":"把花盆輕盈懸在半空的掛架鉤。被高高托起的綠意，把陽光與微風又拉近了一寸。窗邊，一座小花園悠悠浮現。"},"ICON-2715":{"nm":"嫩芽遮蔽罩網","de":"輕柔遮護剛冒出的嫩芽的罩網。在還柔嫩的葉子能熬過初寒與烈陽之前，最纖弱的，總是最先得到照看。"},"ICON-2716":{"nm":"梳毛清理掛架","de":"把脫落的毛輕拍乾淨、再整齊掛好的位置。清爽空淨的梳子，等待著下一次的撫觸。整潔，總是始於愛惜工具的小小習慣。"},"ICON-2717":{"nm":"洗腳盆防滑環","de":"撐著洗腳盆不讓它滑動的環。在拍打水花的小腳下，盆子穩穩不動，於是替它洗腳的手、被洗的那顆心，都不再搖晃。"},"ICON-2718":{"nm":"牽繩掛鉤","de":"把牽繩掛在玄關上的一只鉤子。在門旁的固定位置，出發的準備總在那裡等候。取下繩子的那一刻，一段雀躍的腳步也跟著一同出門。"},"ICON-2719":{"nm":"剪趾甲護套帽","de":"修剪趾甲時守護嫩肉的護套帽。正因為有了一道「就到這裡為止」劃出的安全界線，握著剪刀的手才不顫抖、沉得住氣。"},"ICON-2720":{"nm":"洗澡水溫度帶","de":"悠悠漂在洗澡水上、告知水溫的帶子。從前用手背浸入水中、揣度合適暖度的那份心，如今被翻譯成一道清晰的色彩，浮在水面上。"},"ICON-2721":{"nm":"脫毛黏黏滾筒","de":"黑衣上一根白毛，在登台前一刻看來最是顯眼。隨著咕嚕咕嚕的滾動聲，一整天的碎屑一格一格地黏附到黏紙上。整潔便是這樣，撕去多少，便完成多少。"},"ICON-2722":{"nm":"散步便便袋夾","de":"散步路的盡頭，總有彎下腰來的溫柔一刻。把袋子套在夾子尖端，手便乾淨，心也輕快。一同行走這件事，也包含著照看身後的小小禮貌——這只夾子，比誰都先懂。"},"ICON-2723":{"nm":"擦腳墊邊條","de":"門前墊子的邊條，是雙腳最先觸到的歡迎問候。濕濕的腳尖在此停一下，裡頭的地板便能保持乾爽。它無聲地擦淨並迎接每一位進門的人——是最低處的那個位置。"},"ICON-2724":{"nm":"梳毛繫鈴打結繩","de":"連繫上一顆鈴鐺，也是有順序的。把繩子繞兩圈、再穿過一次，每一步都會跟來清脆的鈴聲。所謂打扮，終究是不漏掉這小小收尾的那份用心。"},"ICON-2725":{"nm":"隨身雨傘接水袋","de":"雨停後的大廳，折好的傘尖上水珠點點滴落在地。一只袋子靜靜接住它，某個人的腳下便不再濕滑。體貼大多是這樣，無聲地守在身旁。"},"ICON-2726":{"nm":"外出包包固定夾","de":"掛在椅子上的包包總是不停往下滑落。用固定夾夾住一次，便不必擔心掉落，雙手也輕鬆了。外出的從容，正是從可以暫時忘掉行李的那一刻開始。"},"ICON-2727":{"nm":"暖手布袋","de":"寒風吹拂的巷子裡，袋中的布囊把暖意悄悄傳到手掌。把滾燙之物輕柔包上一層、暖得恰到好處的紋理。冬日的溫柔，總是隔著一層布傳遞而來。"},"ICON-2728":{"nm":"隨身鏡展開支架","de":"一展開，小鏡子便斜斜定好自己的角度。不必用手拿著，也能與自己的臉相對，支架替你站在那兒。在整理儀容的那短短空檔裡，也有一位可靠的配角陪在身旁。"},"ICON-2729":{"nm":"外出濕紙巾蓋帽","de":"濕紙巾的第一張總是在不斷變乾。把蓋帽喀嗒一扣，到最後一張都還留著濕潤。守護你用到最後一張——耐久持家的祕訣，就藏在這些瑣碎之處。"},"ICON-2730":{"nm":"錢包硬幣隔板","de":"硬幣一旦散落到鈔票之間，收銀台前總會手忙腳亂。一片隔板把圓圓的硬幣聚到一側，指尖便不再摸索徘徊。所謂整理，就是為每樣東西的位置取個名字。"},"ICON-2731":{"nm":"外出口罩折疊收納盒","de":"折起來放進去，口罩在包裡也不會皺。乾淨地收納起暫時取下的那一張的收納盒。為了再次使用而細心保存——一個溫柔的習慣，就裝在這裡。"},"ICON-2732":{"nm":"隨身梳齒護罩","de":"包裡的梳齒總愛刮傷其他行李。套上齒護罩，梳子安全，一同放著的物品也安然無恙。一層小小的保護能彼此守護——細心過的人才懂。"},"ICON-2733":{"nm":"抽屜分格夾","de":"每次拉開抽屜，混亂的物品便如嘆息般傾瀉而出。用一個夾子分出格子，小東西們才終於找到了各自的區域。整齊的抽屜，靜靜改變了每天早晨的心情。"},"ICON-2734":{"nm":"硬幣立放底座","de":"把一枚古老的硬幣立起來，它本身便成了一場小小的展示。底座斜斜托著它，把正面的紋路清晰呈現。把沾染指痕的時光擺到視線高度——收藏的樂趣，便在此處更深了。"},"ICON-2735":{"nm":"耳機收線繞圈鉤","de":"曾因解開纏成一團的耳機線，而流走了半個早晨。順著繞圈鉤一圈圈纏好，下次取出時便滑順無比。小小的整理，是悄悄遞給明天的自己的一份禮物。"},"ICON-2736":{"nm":"充電線壁掛鉤","de":"垂在地上的充電線總是被腳踩到。在牆上貼一個鉤子掛起來，書桌便寬敞了不少。整治雜亂並非什麼了不起的事，只需一根釘子大小的小位置。"},"ICON-2737":{"nm":"遙控器直立架","de":"總愛消失在沙發縫裡的遙控器，終於有了可以回去的家。立在架上，便不必到處翻找，也不會被壓在身下。有個固定的位置，對物品而言也是一種小小的安歇。"},"ICON-2738":{"nm":"眼鏡腳掛夾","de":"摘下的眼鏡總是悄悄滑去某個地方。把鏡腳輕輕掛在夾子上，鏡片便不會碰到地面。想讓它毫無刮痕地迎接明天的那份心，就裝在這個小小的掛架裡。"},"ICON-2739":{"nm":"鑰匙圈分類夾","de":"鑰匙串越沉，哪把對哪扇門便越模糊。用分類夾綁好，光憑指尖就能認出它的另一半。為每天開合的門無聲地賦予秩序——一位沉默的嚮導。"},"ICON-2740":{"nm":"便條紙直立夾","de":"寫好的便條在桌上總愛東倒西歪。夾子把紙立著夾住，字便端端正正地與眼睛相對。把不能忘的那一行，安放在總能看見的位置的方法。"},"ICON-2741":{"nm":"筆尖直立座","de":"為了撿起滾落的筆，曾彎了多少次腰。把筆尖插在座上立好，到下一行的距離便縮短了一寸。是位總在書寫者身旁清醒守候的小小待命所。"},"ICON-2742":{"nm":"沙漏翻轉底座","de":"沙漏流完之後，得有人替它翻轉，它才能再次活過來。底座承住那最後一粒沙的瞬間，把它滑順地翻立過來。讓時間回到最初的那雙手，就停留在這一小塊木頭上。"},"ICON-2743":{"nm":"奶油烤馬鈴薯","de":"奶油在帶皮烤好的馬鈴薯上緩緩融化。金黃的紋路順著熱氣滲入，鬆軟的內裡靜靜攬住了那股香醇。正是帶著泥土氣息的根莖類最溫暖的那一刻。"},"ICON-2744":{"nm":"奶油烤玉米","de":"一粒粒嵌著的金黃玉米在烤盤上發出噗噗聲響。一塊奶油滑過其上，甜香便撲鼻而起。夏日田野的甜味，就這麼原封不動地移進了一口之中。"},"ICON-2745":{"nm":"鬆餅","de":"靜靜等候糖漿在格子紋的每一格裡積聚。外酥內鬆——咬下一口，溫熱的熱氣便絲絲透出。那一格格的方塊，像是分裝著小小幸福的器皿。"},"ICON-2746":{"nm":"美式鬆餅","de":"還記得麵糊在平底鍋上烤得金黃膨起的那股香氣。在層層疊起的圓餅上，奶油緩緩塌融。只在悠閒早晨才悄悄被允許的，柔軟一盤。"},"ICON-2747":{"nm":"巧克力","de":"含一塊在口中，觸到體溫便緩緩化開。微苦盡頭蕩漾開的甜味，悄悄鬆開了心頭的緊繃。疲憊的日子裡，從口袋掏出來吃的那一小塊褐色慰藉。"},"ICON-2748":{"nm":"草莓蛋糕","de":"紅色的草莓坐在白色鮮奶油之上，搶先報來了春天。叉子劃開柔軟的切面，酸甜的香氣便悄悄綻放。值得慶祝的日子裡，擺在餐桌正中央的溫柔主角。"},"ICON-2749":{"nm":"起司蛋糕","de":"厚實的一塊在舌尖上濃郁地崩融。鹹味的尾韻牽住甜味的手，不住地誘人再吃一口。是喜歡黏稠濃郁之人靜靜珍惜著吃的甜點。"},"ICON-2750":{"nm":"香蕉餅乾","de":"搗碎的香蕉香氣在烤箱裡漸漸烤成金黃。咬下一口，柔和的甜味便在口中滿溢開來。一顆熟透的水果重新化作餅乾的，溫暖的蛻變瞬間。"},"ICON-2751":{"nm":"巧克力餅乾","de":"麵糰裡的巧克力豆隨著烘烤濃稠地化開。趁熱掰開時，濃濃的褐色便沾上指尖。若配上一杯牛奶，午後便會溫柔許多的那一塊。"},"ICON-2752":{"nm":"可可粒餅乾","de":"細碎的可可粒在麵糰間咯吱咯吱地咀嚼著。不甜而深沉的苦味，靜靜撫慰著成人的味蕾。原封保留著加工前那股本然香氣的，有點認真的餅乾。"},"ICON-2753":{"nm":"起司吐司","de":"起司在烤得金黃的麵包上拉出長長的絲。外層的酥脆與內裡的香醇，在一口之中重疊。為晚起的早晨填飽肚子的，最簡單也最溫柔的一餐。"},"ICON-2754":{"nm":"三明治","de":"兩片麵包之間，一天份的心意層層填滿。咬下去時，層層堆疊的滋味一齊前來問候。能帶往任何地方的，掌心上的小小餐桌。"},"ICON-2755":{"nm":"法式吐司","de":"在蛋液裡浸得透透的麵包，在平底鍋上烤成金黃。隨奶油香一起膨起的邊角，最先變得酥脆。淋上一道糖漿，平凡的麵包也成了假日的奢侈。"},"ICON-2756":{"nm":"蘑菇拉麵","de":"蘑菇深沉的香氣隨熱氣在沸騰的湯上升起。夾起一片有嚼勁的菇傘，帶著泥土氣息的甜味便在口中散開。比起麵條，先以香氣填飽肚子的，有點特別的一碗。"},"ICON-2757":{"nm":"炒拉麵","de":"無湯拌好的麵上，香辣的醬料裹著油亮的光澤。用筷子夾起時，熱氣間飄散出香噴噴的鑊氣。想念一頓又快又濃的飯時，最可靠的朋友。"},"ICON-2758":{"nm":"起司拉麵","de":"在滾燙的麵上放一片起司，它便緩緩塌融進去。辛辣的湯與柔和的香醇相遇，稜角便圓潤了起來。是最適合那種想稍稍緩和刺激的夜晚的一碗。"},"ICON-2759":{"nm":"咖哩拉麵","de":"濃郁的咖哩香纏繞著麵條，升起金黃的熱氣。呼嚕喝下一口，溫熱的香辣便暖了腸胃。在熟悉的湯頭裡添上一抹稍陌生香氣的，愉快變奏之麵。"},"ICON-2760":{"nm":"海鮮拉麵","de":"滿是海味的湯上，蝦子與貝類飽滿地浮起。清爽又深沉的鮮味滲入麵條之間。不必走遠，便把潮汐氣息盛進一碗裡的小小魔法。"},"ICON-2761":{"nm":"醃蘿蔔紫菜飯捲","de":"黃色的醃蘿蔔擺在中央，飯粒圓圓地圍坐一圈，一張海苔便把它們全都溫柔地捆成一條。郊遊的清晨，在砧板上誕生的最樸實的一餐。"},"ICON-2762":{"nm":"鮪魚紫菜飯捲","de":"拌了美乃滋的鮪魚一勺滲入飯間的那一刻，即使在深夜便利店的燈光下，一餐也足夠溫暖。忙碌的手最常拿起的慰藉。"},"ICON-2763":{"nm":"水果沙拉","de":"蒐羅當季的色彩，在一只碗裡初次相遇。紅、綠與黃互不爭執卻又相融的方法，水果唯有被切開、一同盛裝之後才終於展現。"},"ICON-2764":{"nm":"雞肉沙拉","de":"把清爽烤好的雞胸肉，整齊地擺在青綠葉菜之上。在為明日舞台做準備之人的餐桌上，總擺著這樣端正的一盤。"},"ICON-2765":{"nm":"番茄小黃瓜涼拌","de":"把熟透的番茄與爽脆的小黃瓜酸甜地涼拌起來。蟬鳴濃密的正午，送一筷子入口，夏天便在其中清涼地降了一拍。"},"ICON-2766":{"nm":"萵苣沙拉","de":"把剛從菜園摘下的葉子用冷水沖洗，指尖便沁涼地醒了過來。最尋常的蔬菜，在餐桌上佔據最青翠新鮮位置的那一刻。"},"ICON-2767":{"nm":"玉米沙拉","de":"每當甜甜的玉米粒咯吱迸開，灑滿陽光的盛夏田野便展現在眼前。金黃的玉米，即使在沙拉碗裡也終究不忘自己的那束陽光。"},"ICON-2768":{"nm":"高麗菜沙拉","de":"切絲的高麗菜含著酸甜醬汁，爽脆便柔和地緩和了下來。無論擺在哪道主菜旁都不爭光、盡好本分的，配菜的美德。"},"ICON-2769":{"nm":"萊姆鮮蝦沙拉","de":"稍稍擠入萊姆，蝦子的甜味便更鮮明地醒了過來。酸酸的一滴為整盤注入生氣的，小而關鍵的最後一筆。"},"ICON-2770":{"nm":"漢堡排","de":"捏得厚實的肉餅在燒熱的鐵板上烤得金黃。刀尖觸到的瞬間滲出的肉汁——在家常與西餐之間，被愛得最久的一餐。"},"ICON-2771":{"nm":"披薩","de":"起司拉出長長絲線的那一口，眾人圍坐著從手傳到手。一起把一張圓餅分成片片時，聚會才終於成了真正的聚會。"},"ICON-2772":{"nm":"蘑菇奶油義大利麵","de":"蘑菇深沉的泥土氣息與奶油的柔滑，把每一根麵條包覆懷抱。雨聲輕緩的傍晚，濃郁的香氣緩緩漫到盤底。"},"ICON-2773":{"nm":"鮮蝦義大利麵","de":"把飽滿的蝦子用橄欖油稍稍炒過，再與麵條拌在一起。海的鹹味與麵的清淡相遇時，平淡無事的傍晚便多了一分特別。"},"ICON-2774":{"nm":"橄欖油義大利麵","de":"蒜、油與麵，僅此三樣。有些味道越是減去，反而越發鮮明——蒜香橄欖油麵不帶累贅，靜靜地證明了這件事。"},"ICON-2775":{"nm":"蛤蜊義大利麵","de":"蛤蜊張口釋出的湯汁，深深滲進每一根麵條。一口白酒的香氣在盤上如春日般久久不散。"},"ICON-2776":{"nm":"奶油義大利麵","de":"濃郁的奶油靜靜攬住麵條，從第一口起心頭一角便暖了起來。越是颳風的日子越顯深沉，是柔滑所遞來的安慰。"},"ICON-2777":{"nm":"番茄義大利麵","de":"久熬的番茄醬在麵上紅紅地暈染開來。甜與酸慢慢收乾、終於找到平衡時，最基本的一盤反而最是踏實。"},"ICON-2778":{"nm":"蛋包飯","de":"柔軟的蛋像被子一樣，輕輕蓋住溫熱的飯。若用番茄醬寫上哪怕一個字的名字，那天的餐桌便成了某人遞來的一封小信。"},"ICON-2779":{"nm":"烤鮭魚","de":"為了讓魚皮烤得酥脆，在火前慢慢地烤。粉色的內裡順著紋理裂開、升起的一縷熱氣——等待，總會被鮭魚誠實地回報。"},"ICON-2780":{"nm":"義式烤麵包片","de":"在烤得酥脆的麵包上，滿滿堆起切碎的番茄與羅勒。用手指捏起咬下一口的那份輕盈，溫柔地拉開了聚會的第一句問候。"},"ICON-2781":{"nm":"芒果冰沙","de":"把熟透的芒果細細打成泥，與冰塊清涼地攪在一起。當水珠在黃澄澄的一杯上密密凝結時，慵懶的盛夏午後便漲到了吸管尖端。"},"ICON-2782":{"nm":"檸檬汽水","de":"放入現榨的檸檬、糖與冷水，整杯搖晃調勻。黃澄澄的酸味順著喉嚨清涼滑下時，逞威的暑氣也暫且舉手投降。"},"ICON-2783":{"nm":"草莓牛奶","de":"把搗碎的草莓化進牛奶裡，粉紅色的雲便在杯中緩緩沉澱。兒時猛地拉開冰箱門時指尖的那份雀躍，原原本本盛在一杯之中。"},"ICON-2784":{"nm":"香蕉牛奶","de":"光憑那圓罐的渾圓姿態，便已是一個時代回憶的飲料。在澡堂木板凳上插下吸管的那段黃色記憶，每一口都溫柔地復甦。"},"ICON-2785":{"nm":"藍莓牛奶","de":"把紫色的果粒咯吱搗碎放入，雪白的牛奶便染上淡雅的天空色。那一小撮小小的果實，把整整一杯換上了全新的顏色。"},"ICON-2786":{"nm":"綜合果汁","de":"把多種水果一同榨入，便成了無法只以任何一個名字稱呼的味道。彼此交融、漲得更豐盈飽滿的，甜味們的小小合唱。"},"ICON-2787":{"nm":"可可","de":"在飄雪的窗邊，用雙手靜靜捧住溫熱的馬克杯。一杯裊裊冒著熱氣的褐色飲品，從指尖到心頭緩緩暖了開來。"},"ICON-2788":{"nm":"咖啡","de":"點亮凌晨練習室的燈的，永遠是這一杯。微苦的香氣靜靜推開睡意時，又一日的舞台便那樣悄悄開始了。"},"ICON-2789":{"nm":"鮭魚壽司","de":"把飯握在手中，揣度著緊實與柔軟之間那微妙的分寸。薄薄削下的一片鮭魚輕輕躺上去的那一刻，一口便成了一份小小心意的完成。"},"ICON-2790":{"nm":"南瓜粥","de":"把金黃的南瓜燉得熟透、細細搗碎熬下。每舀一勺送入口中，秋日陽光便溫暖地在口中化開。生病時最先想起的粥。"},"ICON-2791":{"nm":"魚肉咖哩","de":"用香料稍稍燉煮的魚肉，在咖哩中柔軟地散開。在熟悉的一碗裡添上海洋的紋理，平凡的傍晚便往遠方旅行了一寸。"},"ICON-2792":{"nm":"炸蝦","de":"捏著尾巴裹上麵糊、放入沸油的那短短一瞬便是勝負。披上金黃外衣的蝦，要趁酥脆尚未冷卻時吃，才最是燦爛閃耀。"},"ICON-2793":{"nm":"炸魷魚","de":"圓圓的環在滾燙的油中飽滿地膨起。嚼勁被酥脆包裹的那一口，在路邊攤黃色燈光下最是相襯。"},"ICON-2794":{"nm":"烤雞肉","de":"抹上醬料在火前慢慢地烤，雞皮便閃著油亮的光澤。火候一個拿捏便決定味道，正因最簡單，反而最是誠實的一道菜。"},"ICON-2795":{"nm":"辣炒泡菜豬肉","de":"把熟透的泡菜與豬肉一同翻炒，酸味便熟成了甜味。自然引人添上一碗白飯的，韓國餐桌上最踏實的搭檔。"},"ICON-2796":{"nm":"辣炒豬肉","de":"用大火快炒，把表面煎得焦香。香噴噴的油氣充滿廚房時，今晚的菜單便不必再問，早已定下。"},"ICON-2797":{"nm":"牛肉炒蘑菇","de":"把香氣好的蘑菇與牛肉一同翻炒，彼此的味道便更深了一層。泥土與田野在一盤中靜靜牽起手的，秋天端正的一餐。"},"ICON-2798":{"nm":"起司辣炒雞排","de":"在香辣的雞排上化開滿滿的起司、長長地拉起。眾人圍著滾燙的鐵板坐下時，連火辣的辣味也化作了笑聲。"},"ICON-2799":{"nm":"泡菜鍋","de":"越是久放的泡菜，越能熬出更深更濃的湯頭。在咕嘟咕嘟沸騰的砂鍋前對坐時，「家人」這個詞便又溫暖地熱了起來。"},"ICON-2800":{"nm":"大醬湯","de":"化開香醇的大醬，放入豆腐與櫛瓜慢慢燉煮。砂鍋裡咕嘟到最後的那聲響，是回到家最確切的信號。"},"ICON-2801":{"nm":"牛肉蘿蔔湯","de":"直到蘿蔔變得透明，在小火前靜靜等候的半日。清澈的湯一勺觸到嘴邊，便想起那段毫不華麗的歲月裡的飯桌。淡淡的，反而留得最久。"},"ICON-2802":{"nm":"蛤蜊湯","de":"蛤蜊張口的那一刻，鍋裡的春天便深了。一縷潮香隨熱氣升起，海邊村落清晨的廚房便浮現眼前。每道張開的縫隙裡，都積著鹹鹹的海。"},"ICON-2803":{"nm":"地瓜拔絲","de":"放學路上，裝在紙杯裡、像暖手寶一樣握在手中的金黃塊狀物。咬下金黃的外層，裡頭便轟地冒出熱氣。甜甜熬好的外層與滾燙的內裡，是冬天最溫柔的味道。"},"ICON-2804":{"nm":"炒茄子","de":"紫色遇上油，倏地軟化散開的那一瞬。被嫌軟爛的蔬菜，其實比誰都更會攬住醬料。咬下一口，柔和滲入的手藝便先傳了過來。"},"ICON-2805":{"nm":"醬燒馬鈴薯","de":"醬油慢慢收乾的同時，甜香瀰漫整個廚房的傍晚。把油亮的褐色一塊塊填進便當格的那雙手。沒寫進食譜裡的那份心意，浸在每一小塊裡。"},"ICON-2806":{"nm":"醃紫蘇葉","de":"把整個夏天的香氣醃漬起來、帶到冬天餐桌上的事。撕下一片鋪在飯上，逝去的那個季節便在口中再次綻放。層層疊起的葉子之間，沉睡著那一年的陽光。"},"ICON-2807":{"nm":"涼拌白菜","de":"等不到醃泡菜的手，當天便立刻三兩下涼拌起來。唯有在爽脆的葉子剛開始入味的那一刻才能享有的清新。發酵前的青澀，是只屬於今天的奢侈。"},"ICON-2808":{"nm":"炒蘑菇","de":"雨過後，在樹蔭裡靜靜冒出的那些。用紫蘇油翻炒之際，泥土味便轉成了香醇。越是在暗處默默長成的，香氣越是深沉濃郁。"},"ICON-2809":{"nm":"涼拌菠菜","de":"把汆燙後便縮成一把的葉菜，用指尖三兩下涼拌起來。那謙遜的份量，正是春季野菜的美德。一盤綠意，餐桌上便多進了一寸春陽。"},"ICON-2810":{"nm":"涼拌海藻","de":"剛從海裡撈起的滑溜溜的絲條，與酸甜的醋醬交融。每咀嚼一下便咯吱迸開的鹹味。把浪花搖盪的口感原原本本盛進碗裡的一盤。"},"ICON-2811":{"nm":"炒南瓜","de":"有些蔬菜越是老去，甜味越是漲滿。薄薄切片用蝦醬一炒，連憨厚的南瓜也悄悄獻出自己的甜味。在口中一路柔和化開的金黃。"},"ICON-2812":{"nm":"泡菜炒飯","de":"陳泡菜變得深沉之際，與冷飯在同一個鍋裡相遇。剩下的與剩下的相加，化作最踏實的一碗。深夜租屋的燈光下，最溫柔的救贖。"},"ICON-2813":{"nm":"雞肉咖哩","de":"金黃的湯汁蓋上白飯，餐桌便明亮了起來。香料還陌生的那個時代，最先親近的外面世界的味道。雞肉鬆軟散開的某個週日午餐。"},"ICON-2814":{"nm":"炒飯","de":"冰箱角落剩下的零碎食材，在一個鍋裡和睦地交融。無論什麼都寬容接納的那份大度。把零散的聚到一處，那便是持家的開始。"},"ICON-2815":{"nm":"烤肉蓋飯","de":"用甜甜醬料醃過的肉，順著熱氣升騰的飯滑下。當宴客桌上的主角降臨為平日的一碗時，特別便更添了一分溫柔。"},"ICON-2816":{"nm":"拌飯","de":"在鬆軟的飯上，五色野菜圓圓地圍坐一圈。配色盛裝的指尖間，流淌著昔日細細端詳的審美。唯有拌在一起，才終於完成的交融之味。"},"ICON-2817":{"nm":"鮮蝦炒飯","de":"飽滿的蝦子在飯粒間以粉紅色突顯出來。炒進一把海洋，平凡的一餐也學起了宴席的模樣。咯吱咬下時蕩漾開的甜味，叫人歡喜。"},"ICON-2818":{"nm":"辣炒豬肉蓋飯","de":"醃得入味的香辣豬肉，與熱氣升騰的飯相遇。一到午餐時間便最先見底的那碗。輕拍著撫慰忙碌一天的，一餐的慰藉。"},"ICON-2819":{"nm":"鮪魚美乃滋飯","de":"一個罐頭、一條美乃滋，再加一碗溫熱的飯。材料雖簡單，慰藉卻很足。晚自習結束後在教室書桌上偷偷拌起的，那夜的味道。"},"ICON-2820":{"nm":"咖哩飯","de":"濃稠的金黃色填滿整個盤子。為了把馬鈴薯與紅蘿蔔燉到軟爛而久久攪拌的那份用心。想起全家人盯著同一鍋飯的那個傍晚的團圓。"},"ICON-2821":{"nm":"海藻拌飯","de":"帶著海洋氣息的絲條與辣椒醬相遇，唰唰地拌在一起。滑溜又酸爽的口感裹住飯粒時，海女屏息撈起的那片海，便在一碗裡展開。"},"ICON-2822":{"nm":"烤鯖魚","de":"銀色的魚背在烤盤上烤得金黃。挑出魚刺、把魚肉夾到飯上的那雙手。一段青背魚裡，浸著那樣餵養長大的、默默的愛。"},"ICON-2823":{"nm":"馬鈴薯煎餅","de":"下雨的日子，在江原道山村廚房裡磨碎煎成的東西。Q彈的邊緣與酥脆的尾端，並排住在同一張裡。最適合敲打窗戶的雨聲的麵糊。"},"ICON-2824":{"nm":"泡菜煎餅","de":"酸泡菜碰到抹油的平底鍋的那一刻，整間屋子便充滿滋滋作響。自然引人來上一碗馬格利酒的金黃圓餅。與屋簷下雨聲成對的常客菜。"},"ICON-2825":{"nm":"蔥煎餅","de":"把細蔥整齊鋪好，倒上麵糊慢慢地煎。在酥脆與柔軟之間來回的一張。一如趕集日攤位上裊裊升著熱氣的那番親切景象。"},"ICON-2826":{"nm":"櫛瓜煎餅","de":"在薄切的櫛瓜上裹衣，金黃地煎好。端正守在祭祀桌一角的嫩綠圓片。要費上許多工夫才終於齊備的，那份用心的格調。"},"ICON-2827":{"nm":"辣炒魷魚","de":"裹著紅醬的觸足油亮得發光。即使辣得額頭沁出細汗，筷子也停不下來。汗水與歡樂交纏在一起的那一盤。"},"ICON-2828":{"nm":"辣炒年糕","de":"在熬得紅紅的辣椒醬湯裡，年糕與魚板浸得透透的。湊零錢兩人分著吃的小吃店午後，整個盛在裡頭。光聽名字就教人流口水的回憶滋味。"},"ICON-2829":{"nm":"魚板湯","de":"魚板在湯裡搖曳的路邊攤，熱氣把玻璃窗熏得白濛濛。握著一串、用紙杯接湯呼嚕一喝，凜冽的冬夜便溫暖了許多。"},"ICON-2830":{"nm":"豆腐泡菜","de":"在柔嫩的豆腐旁，香辣炒好的泡菜並排坐下。冰冷與滾燙、溫順與強烈，在一盤中交融。長久守護大人們夜晚的搭檔。"},"ICON-2831":{"nm":"香腸炒蔬菜","de":"紅色香腸與蔬菜染上番茄醬色，滋滋地交融在一起。打開運動會便當的蓋子時最先被清空的那一格。那一天的色彩，再久也始終鮮明。"},"ICON-2832":{"nm":"地瓜拿鐵","de":"細細搗碎的地瓜柔順地化進溫熱的牛奶裡。菜單上以韓文寫著的本土甜味。指尖發冷的日子，用雙手捧住，暖意便緩緩漫開的一杯。"},"ICON-2833":{"nm":"美乃滋","de":"一款尚未送達廚房的醬料。很快會以奶油色的圖示呈現。（準備中）"}};